// ── HISTORY ───────────────────────────────────────
function History({ user, history, allUsers, mobile }: any) {
  const [mode, setMode]           = useState<'date'|'person'>('date')
  const [dateFilter, setDateFilter] = useState('')
  const p = mobile ? '16px' : '24px'
  const perm = getPerm(user)
  const dids = allUsers.filter((u: any) => u.dept_id === user.dept_id).map((u: any) => u.id)
  const myH = perm.viewAllDashboard ? history
    : perm.viewDeptChecklist ? history.filter((h: any) => dids.includes(h.assignee_id))
    : history.filter((h: any) => h.assignee_id === user.id)
  const dates = [...new Set(myH.map((h: any) => h.date))].sort().reverse() as string[]
  const filtered = dateFilter ? myH.filter((h: any) => h.date === dateFilter) : myH
  const groupBy = (key: string) => {
    const g: any = {}
    filtered.forEach((h: any) => { if (!g[h[key]]) g[h[key]] = []; g[h[key]].push(h) })
    return g
  }

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="Lịch sử công việc" subtitle="Kết quả các kỳ đã qua"/>
      {myH.length === 0 ? (
        <EmptyState icon={Ico.history} title="Chưa có lịch sử" description="Các công việc đã hoàn thành sẽ hiển thị tại đây."/>
      ) : (<>
        <div style={{ display:'flex', gap:8, marginBottom:14, flexWrap:'wrap' }}>
          {([['date','📅 Theo ngày'],['person','👤 Theo người']] as [string,string][]).map(([m, l]) => (
            <button key={m} onClick={() => setMode(m as any)}
              style={{ padding:'6px 14px', borderRadius:8, cursor:'pointer', fontFamily:'inherit', fontSize:12,
                border:`1.5px solid ${mode===m?T.gold:T.border}`,
                background:mode===m?T.goldBg:'transparent',
                color:mode===m?T.goldText:T.med, fontWeight:mode===m?600:400 }}>{l}</button>
          ))}
          <select value={dateFilter} onChange={e => setDateFilter(e.target.value)}
            style={{ padding:'6px 11px', borderRadius:8, border:`1px solid ${T.border}`, fontSize:12, fontFamily:'inherit', color:T.dark, background:T.bg, cursor:'pointer' }}>
            <option value="">Tất cả ngày</option>
            {dates.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
        {Object.entries(mode==='date'?groupBy('date'):groupBy('assignee_id'))
          .sort(([a],[b]) => b.localeCompare(a))
          .map(([key, items]: any) => {
            const done = items.filter((h: any) => h.status==='done').length
            const label = mode==='date' ? `📅 ${key}` : `👤 ${allUsers.find((u: any) => u.id===key)?.name||key}`
            return (
              <Card key={key} style={{ padding:0, overflow:'hidden', marginBottom:14 }}>
                <div style={{ padding:'11px 16px', background:'#F8F6F2', borderBottom:`1px solid ${T.border}`,
                  display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:8 }}>
                  <div style={{ fontWeight:700, color:T.dark, fontSize:13 }}>{label}</div>
                  <div style={{ display:'flex', gap:10, fontSize:11 }}>
                    <span style={{ color:T.green, fontWeight:600 }}>✅ {done}</span>
                    <span style={{ color:T.red, fontWeight:600 }}>❌ {items.length-done}</span>
                    <span style={{ color:T.light }}>Tỷ lệ: {Math.round(done/items.length*100)}%</span>
                  </div>
                </div>
                <div>
                  {/* Grid header */}
                  <div style={{ display:'grid',
                    gridTemplateColumns:'minmax(0,1fr) 170px 110px 130px 100px',
                    padding:`${SP[2]}px ${SP[4]}px`, background:T.bg,
                    borderBottom:`1px solid ${T.border}`,
                    fontSize:FS.xs, fontWeight:700, color:T.light,
                    textTransform:'uppercase', letterSpacing:.8, gap:SP[3] }}>
                    <span>Công việc</span>
                    <span>Nhân viên</span>
                    <span style={{ textAlign:'center' }}>Tần suất</span>
                    <span style={{ textAlign:'center' }}>Kết quả</span>
                    <span style={{ textAlign:'right' }}>Xong lúc</span>
                  </div>
                    {items.map((h: any, i: number) => {
                      const assignee = allUsers.find((u: any) => u.id===h.assignee_id)
                      return (
                        <div key={h.id||i} style={{ display:'grid',
                          gridTemplateColumns:'minmax(0,1fr) 170px 110px 130px 100px',
                          padding:`${SP[3]}px ${SP[4]}px`, gap:SP[3], alignItems:'center',
                          borderBottom:i<items.length-1?`1px solid ${T.border}`:'none',
                          background:i%2===0?'#fff':T.rowAlt }}>
                          <div style={{ fontSize:FS.base, fontWeight:500, color:T.dark,
                            lineHeight:1.4, minWidth:0,
                            overflow:'hidden', textOverflow:'ellipsis' }}>{h.title}</div>
                          <div style={{ minWidth:0 }}>
                            {assignee && <Av u={assignee} size={24} showTitle/>}
                          </div>
                          <div style={{ textAlign:'center' }}>
                            <span style={{ fontSize:FS.xs, fontWeight:600, padding:'3px 9px',
                              borderRadius:RD.full, display:'inline-block', whiteSpace:'nowrap',
                              color:FREQ_COLOR[h.freq]?.color, background:FREQ_COLOR[h.freq]?.bg }}>
                              {h.freq}
                            </span>
                          </div>
                          <div style={{ textAlign:'center' }}>
                            <span style={{ fontSize:FS.xs, fontWeight:600, padding:'3px 9px',
                              borderRadius:RD.full, display:'inline-block', whiteSpace:'nowrap',
                              color:h.status==='done'?T.green:T.red,
                              background:h.status==='done'?T.greenBg:T.redBg }}>
                              {h.status==='done'?'✅ Hoàn thành':'❌ Chưa xong'}
                            </span>
                          </div>
                          <div style={{ fontSize:FS.xs, color:h.done_at?T.green:T.light,
                            textAlign:'right', whiteSpace:'nowrap' }}>{h.done_at||'—'}</div>
                        </div>
                      )
                    })}
                </div>
              </Card>
            )
          })}
      </>)}
    </div>
  )
}

// ── USER MANAGEMENT ───────────────────────────────
function UserManagement({ user, allUsers, setAllUsers, departments, positions, mobile }: any) {
  const isAdmin = getPerm(user).viewAllDashboard  // admin: được sửa ini
  const [show, setShow]   = useState(false)
  const [edit, setEdit]   = useState<any>(null)
  const [form, setForm]   = useState({ name:'', dept_id:'kho', position_id:'', ini:'', pin:'1234', active:true, birthday:'' })
  const [deptF, setDeptF] = useState('all')
  const [showPwModal, setShowPwModal] = useState<any>(null)
  const [newPw, setNewPw] = useState('')
  const p = mobile ? '16px' : '24px'

  const autoIni = (name: string) => {
    const w = name.trim().split(' ')
    return (w.length >= 2 ? w[0][0]+w[w.length-1][0] : name.slice(0,2)).toUpperCase()
  }

  const openCreate = () => {
    setEdit(null)
    setForm({ name:'', dept_id:'kho', position_id:'', ini:'', pin:'1234', active:true, birthday:'' })
    setShow(true)
  }
  const openEdit = (u: any) => {
    setEdit(u)
    setForm({ name:u.name, dept_id:u.dept_id, position_id:u.position_id||'', ini:u.ini, pin:u.pin, active:u.active, birthday:u.birthday||'' })
    setShow(true)
  }

  const save = async () => {
    if (!form.name) return
    const pos = positions.find((p: any) => p.id===form.position_id)
    const posName = pos?.name||''
    // Vị trí 'all' (GĐ/Admin) → dept_id = 'all'
    const finalDeptId = (pos?.dept_id === 'all' || pos?.perm_view_all_dashboard) ? 'all' : form.dept_id
    const deptName = departments.find((d: any) => d.id===finalDeptId)?.name || (finalDeptId==='all'?'Toàn công ty':'')
    const role = pos?.perm_view_all_dashboard ? 'admin' : pos?.perm_manage_users ? 'mgr' : pos?.perm_mark_attendance ? 'mgr' : 'staff'

    if (edit) {
      const updated = {...edit, ...form, dept_id:finalDeptId, dept_name:deptName, position_name:posName, role}
      setAllUsers((prev: any) => prev.map((u: any) => u.id===edit.id ? updated : u))
      await db.from('users').update({ name:form.name, dept_id:finalDeptId, position_id:form.position_id, ini:form.ini, active:form.active, role, birthday:form.birthday||'' }).eq('id', edit.id)
    } else {
      const newId = form.name.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s/g,'_')+'_'+Date.now().toString().slice(-4)
      const newUser = { id:newId, ...form, dept_id:finalDeptId, dept_name:deptName, position_name:posName, role, must_change_password:true }
      setAllUsers((prev: any) => [...prev, newUser])
      await db.from('users').insert({ id:newId, ...form, dept_id:finalDeptId, role, birthday:form.birthday||'', must_change_password:true })
    }
    setShow(false)
  }

  const resetPassword = async () => {
    if (!newPw || newPw.length < 4) return
    await db.from('users').update({ pin:newPw, must_change_password:true }).eq('id', showPwModal.id)
    setAllUsers((prev: any) => prev.map((u: any) => u.id===showPwModal.id ? {...u, pin:newPw, must_change_password:true} : u))
    setShowPwModal(null); setNewPw('')
  }

  const filtered = deptF==='all' ? allUsers : allUsers.filter((u: any) => u.dept_id===deptF)
  const deptGroups = ['kho','sale','vp'].map(d => ({
    id:d, name:DEPT_NAME[d], users:filtered.filter((u: any) => u.dept_id===d)
  }))

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="Quản lý nhân viên"
        subtitle={`${allUsers.filter((u: any) => u.active).length} nhân viên đang hoạt động`}
        action={<GoldBtn small onClick={openCreate}>+ Thêm nhân viên</GoldBtn>}/>

      <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
        {[{value:'all',label:'Tất cả'},...departments.filter((d: any) => d.id!=='all').map((d: any) => ({value:d.id,label:d.name}))].map((f: any) => (
          <button key={f.value} onClick={() => setDeptF(f.value)}
            style={{ padding:'5px 12px', borderRadius:7, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${deptF===f.value?T.gold:T.border}`,
              background:deptF===f.value?T.goldBg:'transparent',
              color:deptF===f.value?T.goldText:T.med,
              fontWeight:deptF===f.value?600:400 }}>{f.label}</button>
        ))}
      </div>

      {deptGroups.map(group => group.users.length===0 ? null : (
        <Card key={group.id} style={{ padding:0, overflow:'hidden', marginBottom:14 }}>
          <div style={{ background:DEPT_COLOR[group.id], padding:'11px 16px' }}>
            <span style={{ color:'#fff', fontWeight:700, fontSize:14 }}>{group.name} — {group.users.length} người</span>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:mobile?'1fr':'repeat(auto-fill,minmax(280px,1fr))' }}>
            {group.users.map((u: any) => (
              <div key={u.id} style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px',
                borderBottom:`1px solid ${T.border}`, opacity:u.active?1:0.5 }}>
                <div style={{ width:42, height:42, borderRadius:'50%', background:DEPT_COLOR[u.dept_id]||T.gold,
                  flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center',
                  color:'#fff', fontSize:13, fontWeight:700 }}>{u.ini}</div>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:13, fontWeight:600, color:T.dark }}>{u.name}</div>
                  <div style={{ fontSize:11, color:T.gold, fontWeight:500 }}>{u.position_name||'Chưa có vị trí'}</div>
                  <div style={{ display:'flex', gap:6, marginTop:3, flexWrap:'wrap' }}>
                    {!u.active && <span style={{ fontSize:10, color:T.red }}>Đã khóa</span>}
                    {u.must_change_password && <span style={{ fontSize:10, color:T.amber }}>⚠️ Chưa đổi mật khẩu</span>}
                    {getPerm(user).viewBirthday && u.birthday && (
                      <span style={{ fontSize:10, color:T.blue }}>🎂 {u.birthday}</span>
                    )}
                  </div>
                </div>
                <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
                  <button onClick={() => openEdit(u)}
                    style={{ padding:'4px 10px', borderRadius:6, border:`1px solid ${T.border}`,
                      background:'transparent', cursor:'pointer', fontSize:11, fontFamily:'inherit', color:T.med }}>Sửa</button>
                  <button onClick={() => { setShowPwModal(u); setNewPw('') }}
                    style={{ padding:'4px 10px', borderRadius:6, border:`1px solid ${T.amberBg}`,
                      background:T.amberBg, cursor:'pointer', fontSize:11, fontFamily:'inherit', color:T.amber }}>🔑 Mật khẩu</button>
                </div>
              </div>
            ))}
          </div>
        </Card>
      ))}

      {/* Modal thêm/sửa */}
      <Modal open={show} onClose={() => setShow(false)} title={edit?'Sửa tài khoản':'Thêm nhân viên mới'}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <Inp label="Họ tên *" value={form.name}
            onChange={(v) => setForm(f => ({...f, name:v, ini:autoIni(v)}))} placeholder="Nguyễn Văn A"/>
          {isAdmin ? (
            <Inp label="Tên đăng nhập (ini) 🔐 Admin" value={form.ini}
              onChange={(v) => setForm(f => ({...f, ini:v.toUpperCase().slice(0,4)}))} placeholder="VA"/>
          ) : (
            <div style={{ marginBottom:13 }}>
              <div style={{ fontSize:12, fontWeight:500, color:T.med, marginBottom:5 }}>Tên đăng nhập (ini)</div>
              <div style={{ padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8, fontSize:13, color:T.light, background:T.bg }}>{form.ini} <span style={{ fontSize:11, color:T.amber }}>(Chỉ Admin được sửa)</span></div>
            </div>
          )}
        </div>
        {/* Vị trí — chọn trước để auto-fill phòng ban */}
        <Sel label="Vị trí *" value={form.position_id} onChange={(v) => {
          const pos = positions.find((p: any) => p.id === v)
          const autoDept = pos?.dept_id || ''
          setForm(f => ({...f, position_id:v, dept_id: autoDept || f.dept_id}))
        }} options={[{value:'',label:'— Chọn vị trí —'},...positions.map((pos: any) => ({value:pos.id,label:`${pos.name}${pos.dept_id&&pos.dept_id!=='all'?' — '+DEPT_NAME[pos.dept_id]:' — Toàn cty'}`}))]}/>
        {/* Phòng ban — ẩn nếu vị trí là "all" (GĐ/Admin) */}
        {(() => {
          const selPos = positions.find((p: any) => p.id === form.position_id)
          const isAllDept = selPos?.dept_id === 'all' || selPos?.perm_view_all_dashboard
          if (isAllDept) return (
            <div style={{ padding:'8px 12px', background:T.goldBg, borderRadius:8, marginBottom:13, fontSize:12, color:T.goldText }}>
              🏢 Vị trí này có quyền toàn công ty — không cần chọn phòng ban
            </div>
          )
          return (
            <Sel label="Phòng ban" value={form.dept_id} onChange={(v) => setForm(f => ({...f, dept_id:v}))}
              options={departments.filter((d: any) => d.id!=='all').map((d: any) => ({value:d.id,label:d.name}))}/>
          )
        })()}
        <div style={{ padding:'10px 12px', background:T.goldBg, borderRadius:8, marginBottom:13, fontSize:12, color:T.goldText }}>
          💡 Mật khẩu mặc định khi tạo mới: <b>1234</b> — nhân viên sẽ được yêu cầu đổi khi đăng nhập lần đầu.
        </div>
        <Inp label="🎂 Ngày sinh (DD/MM/YYYY)" value={form.birthday}
          onChange={(v) => setForm(f => ({...f, birthday:v}))} placeholder="VD: 15/08/1995"/>
        <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:16 }}>
          <input type="checkbox" id="uact" checked={form.active} onChange={e => setForm(f => ({...f, active:e.target.checked}))}/>
          <label htmlFor="uact" style={{ fontSize:13, color:T.dark, cursor:'pointer' }}>Tài khoản đang hoạt động</label>
        </div>
        <div style={{ display:'flex', justifyContent:'flex-end', gap:10 }}>
          <GoldBtn outline small onClick={() => setShow(false)}>Hủy</GoldBtn>
          <GoldBtn small onClick={save} disabled={!form.name||!form.position_id}>Lưu</GoldBtn>
        </div>
      </Modal>

      {/* Modal đổi mật khẩu */}
      <Modal open={!!showPwModal} onClose={() => setShowPwModal(null)} title={`Đổi mật khẩu: ${showPwModal?.name}`}>
        <div style={{ padding:'10px 12px', background:T.bg, borderRadius:8, marginBottom:14, fontSize:12, color:T.med }}>
          Sau khi admin đặt lại, nhân viên sẽ được yêu cầu đổi mật khẩu khi đăng nhập lần tiếp theo.
        </div>
        <Inp label="Mật khẩu mới *" type="password" value={newPw} onChange={setNewPw} placeholder="Tối thiểu 4 ký tự"/>
        <div style={{ display:'flex', justifyContent:'flex-end', gap:10 }}>
          <GoldBtn outline small onClick={() => setShowPwModal(null)}>Hủy</GoldBtn>
          <GoldBtn small onClick={resetPassword} disabled={!newPw||newPw.length<4}>Đặt lại mật khẩu</GoldBtn>
        </div>
      </Modal>
    </div>
  )
}

// ── POSITIONS MANAGEMENT ──────────────────────────
function PositionsManagement({ user, positions, setPositions, mobile }: any) {
  const [show, setShow] = useState(false)
  const [edit, setEdit] = useState<any>(null)
  const [form, setForm] = useState<any>({
    name:'', dept_id:'all', reports_to:'',
    ...Object.fromEntries(ALL_PERMS.map(p => [p.key, false]))
  })
  const p = mobile ? '16px' : '24px'

  const openCreate = () => {
    setEdit(null)
    setForm({ name:'', dept_id:'all', reports_to:'', ...Object.fromEntries(ALL_PERMS.map(p => [p.key, false])) })
    setShow(true)
  }
  const openEdit = (pos: any) => {
    setEdit(pos)
    setForm({ name:pos.name, dept_id:pos.dept_id||'all', reports_to:pos.reports_to||'',
      ...Object.fromEntries(ALL_PERMS.map(p => [p.key, !!pos[p.key]])) })
    setShow(true)
  }

  const save = async () => {
    if (!form.name) return
    // Fix: KHÔNG ghi đè created_at khi edit — chỉ set khi tạo mới
    const data: any = { ...form }
    delete data.created_at  // Bảo toàn created_at gốc của record
    if (edit) {
      const { error } = await db.from('positions').update(data).eq('id', edit.id)
      if (error) {
        alert('❌ Lỗi lưu vị trí: ' + error.message + '\n\nCó thể do thiếu column DB. Liên hệ admin để kiểm tra migration.')
        return
      }
      const updated = {...edit, ...data}
      setPositions((prev: any) => prev.map((p: any) => p.id===edit.id ? updated : p))
    } else {
      const newPos = { id:'pos_'+Date.now(), ...data, created_at:fmtNow() }
      const { error } = await db.from('positions').insert(newPos)
      if (error) {
        alert('❌ Lỗi tạo vị trí: ' + error.message)
        return
      }
      setPositions((prev: any) => [...prev, newPos])
    }
    setShow(false)
  }

  const [confirmDelete, setConfirmDelete] = useState<any>(null)

  const remove = (id: string) => {
    const pos = positions.find((p: any) => p.id === id)
    if (!pos) return
    setConfirmDelete({
      title: 'Xóa vị trí',
      message: `Bạn sắp xóa vị trí "${pos.name}".`,
      detail: `Vị trí này nếu có NV đang giữ sẽ mất quyền truy cập. Đề nghị chuyển NV sang vị trí khác trước khi xóa.`,
      action: async () => {
        await logAudit({
          user,
          action: 'delete',
          table: 'positions',
          recordId: id,
          snapshot: pos,
          note: `Xóa vị trí "${pos.name}"`,
        })
        await db.from('positions').delete().eq('id', id)
        setPositions((prev: any) => prev.filter((p: any) => p.id!==id))
        setConfirmDelete(null)
      }
    })
  }

  const groups = ALL_PERMS.reduce((acc: any, p) => {
    if (!acc[p.group]) acc[p.group] = []
    acc[p.group].push(p)
    return acc
  }, {})

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="Quản lý vị trí & quyền"
        subtitle="Thiết lập quyền hạn cho từng vị trí trong công ty"
        action={<GoldBtn small onClick={openCreate}>+ Thêm vị trí</GoldBtn>}/>

      {/* Hierarchical view — group by dept, sort by level */}
      {['all','kho','sale','vp'].map(dept => {
        const deptPos = positions.filter((p: any) => p.dept_id === dept)
        if (deptPos.length === 0) return null

        // Sort by hierarchy: no reports_to first (top), then children
        const sorted: any[] = []
        const addLevel = (parentId: string, level: number) => {
          const children = deptPos.filter((p: any) => (p.reports_to||'') === parentId)
          children.sort((a: any, b: any) => a.name.localeCompare(b.name))
          children.forEach((p: any) => { sorted.push({...p, _level:level}); addLevel(p.id, level+1) })
        }
        // Top-level: no reports_to or reports_to is outside this dept
        deptPos.filter((p: any) => !p.reports_to || !deptPos.find((x: any) => x.id===p.reports_to))
          .sort((a: any, b: any) => a.name.localeCompare(b.name))
          .forEach((p: any) => { sorted.push({...p, _level:0}); addLevel(p.id, 1) })

        return (
          <Card key={dept} style={{ padding:0, overflow:'hidden', marginBottom:14 }}>
            {/* Dept header */}
            <div style={{ padding:'10px 16px', background:DEPT_COLOR[dept]||T.gold,
              display:'flex', alignItems:'center', justifyContent:'space-between' }}>
              <div style={{ color:'#fff', fontWeight:700, fontSize:13 }}>
                {dept==='all'?'🏢 Toàn công ty':dept==='kho'?'📦 Kho':dept==='sale'?'💰 Sale':'🖥️ Văn phòng'}
                <span style={{ fontSize:11, fontWeight:400, marginLeft:8, opacity:.8 }}>{deptPos.length} vị trí</span>
              </div>
            </div>
            {/* Positions rows */}
            {sorted.map((pos: any, idx: number) => {
              const activePerms = ALL_PERMS.filter(p => pos[p.key]).length
              const isAdmin = pos.perm_view_all_dashboard
              return (
                <div key={pos.id} style={{ display:'flex', alignItems:'center', gap:12,
                  padding:'10px 16px', borderBottom:idx<sorted.length-1?`1px solid ${T.border}`:'none',
                  paddingLeft: `${16 + pos._level*24}px`,
                  background:idx%2===0?'#fff':T.bg }}>
                  {/* Level indicator */}
                  {pos._level>0 && (
                    <span style={{ color:T.border, fontSize:14, marginLeft:-12, flexShrink:0 }}>└</span>
                  )}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:8, flexWrap:'wrap', marginBottom:4 }}>
                      <span style={{ fontSize:13, fontWeight:700, color:T.dark }}>{pos.name}</span>
                      {isAdmin && <span style={{ fontSize:10, fontWeight:700, color:'#fff', background:T.gold, padding:'1px 7px', borderRadius:20 }}>Admin</span>}
                      {activePerms>0 && !isAdmin && (
                        <span style={{ fontSize:10, color:T.green, background:T.greenBg, padding:'1px 7px', borderRadius:20, fontWeight:600 }}>
                          {activePerms} quyền
                        </span>
                      )}
                    </div>
                    <div style={{ display:'flex', gap:4, flexWrap:'wrap' }}>
                      {ALL_PERMS.filter(p => pos[p.key] && !pos.perm_view_all_dashboard).slice(0,4).map(p => (
                        <span key={p.key} style={{ fontSize:10, padding:'1px 6px', borderRadius:20,
                          background:T.greenBg, color:T.green }}>{p.label}</span>
                      ))}
                      {activePerms>4 && !isAdmin && (
                        <span style={{ fontSize:10, color:T.light }}>+{activePerms-4}...</span>
                      )}
                    </div>
                  </div>
                  <div style={{ display:'flex', gap:6, flexShrink:0 }}>
                    <button onClick={() => openEdit(pos)}
                      style={{ padding:'5px 11px', borderRadius:7, border:`1px solid ${T.border}`,
                        background:'transparent', cursor:'pointer', fontSize:11, fontFamily:'inherit', color:T.med }}>Sửa</button>
                    <button onClick={() => remove(pos.id)}
                      style={{ padding:'5px 10px', borderRadius:7, border:`1px solid ${T.redBg}`,
                        background:T.redBg, cursor:'pointer', fontSize:11, fontFamily:'inherit', color:T.red }}>✕</button>
                  </div>
                </div>
              )
            })}
          </Card>
        )
      })}

      <Modal open={show} onClose={() => setShow(false)} title={edit?'Sửa vị trí':'Thêm vị trí mới'} wide>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <Inp label="Tên vị trí *" value={form.name} onChange={(v) => setForm((f: any) => ({...f, name:v}))} placeholder="VD: Kế toán, Phó kho..."/>
          <Sel label="Phòng ban" value={form.dept_id} onChange={(v) => setForm((f: any) => ({...f, dept_id:v}))}
            options={[{value:'all',label:'Tất cả'},{value:'kho',label:'Kho'},{value:'sale',label:'Sale'},{value:'vp',label:'Văn phòng'}]}/>
        </div>
        <Sel label="Báo cáo cho vị trí" value={form.reports_to} onChange={(v) => setForm((f: any) => ({...f, reports_to:v}))}
          options={[{value:'',label:'— Không (cấp cao nhất) —'},...positions.filter((p: any) => p.id!==edit?.id).map((pos: any) => ({value:pos.id,label:pos.name}))]}/>

        <div style={{ marginBottom:14 }}>
          <div style={{ fontSize:12, fontWeight:600, color:T.dark, marginBottom:10 }}>Phân quyền</div>
          {Object.entries(groups).map(([groupName, perms]: any) => (
            <div key={groupName} style={{ marginBottom:14 }}>
              <div style={{ fontSize:11, fontWeight:700, color:T.gold, textTransform:'uppercase', letterSpacing:.5, marginBottom:8 }}>
                {groupName}
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:6 }}>
                {perms.map((perm: any) => (
                  <label key={perm.key} style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer',
                    padding:'7px 10px', borderRadius:8, background:form[perm.key]?T.greenBg:T.bg,
                    border:`1px solid ${form[perm.key]?T.green:T.border}` }}>
                    <input type="checkbox" checked={!!form[perm.key]}
                      onChange={e => setForm((f: any) => ({...f, [perm.key]:e.target.checked}))}/>
                    <span style={{ fontSize:12, color:form[perm.key]?T.green:T.med, fontWeight:form[perm.key]?600:400 }}>
                      {perm.label}
                    </span>
                  </label>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div style={{ display:'flex', justifyContent:'flex-end', gap:10 }}>
          <GoldBtn outline small onClick={() => setShow(false)}>Hủy</GoldBtn>
          <GoldBtn small onClick={save} disabled={!form.name}>Lưu vị trí</GoldBtn>
        </div>
      </Modal>

      {confirmDelete && (
        <ConfirmDeleteModal
          title={confirmDelete.title}
          message={confirmDelete.message}
          detail={confirmDelete.detail}
          onConfirm={confirmDelete.action}
          onCancel={() => setConfirmDelete(null)}
        />
      )}
    </div>
  )
}

// ── SETTINGS ──────────────────────────────────────
// ── Export Data Card ─────────────────────────────────────────
function ExportDataCard() {
  const [exporting, setExporting] = useState<string|null>(null)
  const [msg, setMsg] = useState('')

  const tableGroups = [
    {
      group: '💰 Tài chính & Kinh doanh',
      color: '#FEF3C7',
      tables: [
        { key:'payment_orders',     label:'Lệnh chuyển khoản',    icon:'💸', query: () => db.from('payment_orders').select('*').order('created_at',{ascending:false}) },
        { key:'brand_programs',     label:'Chương trình nhãn hàng',icon:'🎯', query: () => db.from('brand_programs').select('*').order('created_at',{ascending:false}) },
        { key:'price_configs',      label:'Báo giá sản phẩm',     icon:'💰', query: () => db.from('price_configs').select('*') },
        { key:'price_tiers',        label:'Mốc giá theo SL',      icon:'📊', query: () => db.from('price_tiers').select('*') },
        { key:'suppliers',          label:'Nhà cung cấp',         icon:'🏢', query: () => db.from('suppliers').select('*') },
        { key:'supplier_accounts',  label:'Tài khoản NCC',        icon:'🏦', query: () => db.from('supplier_accounts').select('*') },
      ]
    },
    {
      group: '📦 Kho & Sản phẩm',
      color: '#DCFCE7',
      tables: [
        { key:'return_items',       label:'Hàng hoàn',            icon:'🔄', query: () => db.from('return_items').select('*').order('date',{ascending:false}) },
        { key:'wrong_orders',       label:'Đơn sai',              icon:'⚠️', query: () => db.from('wrong_orders').select('*').order('created_at',{ascending:false}).limit(3000) },
        { key:'shortage_items',     label:'Hàng thiếu',           icon:'📦', query: () => db.from('shortage_items').select('*').order('created_at',{ascending:false}) },
        { key:'inventory_sessions', label:'Phiên kiểm kê',        icon:'🗂️', query: () => db.from('inventory_sessions').select('*').order('date',{ascending:false}) },
        { key:'inventory_checks',   label:'Chi tiết kiểm kê',     icon:'✅', query: () => db.from('inventory_checks').select('*').order('session_id') },
        { key:'product_batches',    label:'Date sản phẩm (HSD)',  icon:'📅', query: () => db.from('product_batches').select('*').order('expiry_date',{ascending:true}) },
      ]
    },
    {
      group: '👥 Nhân sự & Công việc',
      color: '#DBEAFE',
      tables: [
        { key:'users',              label:'Danh sách nhân viên',  icon:'👤', query: () => db.from('users').select('id,name,dept_id,position_id,role,active,birthday') },
        { key:'attendance',         label:'Chấm công',            icon:'🕐', query: () => db.from('attendance').select('*').order('date',{ascending:false}).limit(3000) },
        { key:'leave_requests',     label:'Đơn nghỉ phép',        icon:'🏖️', query: () => db.from('leave_requests').select('*').order('created_at',{ascending:false}) },
        { key:'overtime_requests',  label:'Đăng ký OT',           icon:'⏰', query: () => db.from('overtime_requests').select('*').order('created_at',{ascending:false}) },
        { key:'tasks',              label:'Giao việc',            icon:'📌', query: () => db.from('tasks').select('*').order('created_at',{ascending:false}) },
        { key:'history',            label:'Lịch sử checklist',    icon:'📜', query: () => db.from('history').select('*').order('date',{ascending:false}).limit(5000) },
        { key:'checklist_templates',label:'Template checklist',   icon:'📋', query: () => db.from('checklist_templates').select('*') },
      ]
    },
  ]

  const allTables = tableGroups.flatMap(g => g.tables)

  const toCSV = (rows: any[]) => {
    if (!rows || rows.length === 0) return ''
    const headers = Object.keys(rows[0])
    const escape = (v: any) => {
      const s = v === null || v === undefined ? '' : String(v)
      return s.includes(',') || s.includes('"') || s.includes('\n')
        ? `"${s.replace(/"/g, '""')}"` : s
    }
    return [
      headers.join(','),
      ...rows.map(r => headers.map(h => escape(r[h])).join(','))
    ].join('\n')
  }

  const downloadCSV = (csv: string, filename: string) => {
    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8' })
    const url  = URL.createObjectURL(blob)
    const a    = document.createElement('a')
    a.href = url; a.download = filename; a.click()
    URL.revokeObjectURL(url)
  }

  const exportOne = async (t: typeof allTables[0]) => {
    setExporting(t.key); setMsg('')
    try {
      const { data, error } = await t.query()
      if (error) throw new Error(error.message)
      if (!data || data.length === 0) { setMsg(`⚠️ ${t.label}: Không có dữ liệu`); return }
      const date = new Date().toISOString().split('T')[0]
      downloadCSV(toCSV(data), `${t.key}_${date}.csv`)
      setMsg(`✅ Đã xuất ${data.length.toLocaleString()} dòng — ${t.label}`)
    } catch(e: any) {
      setMsg(`❌ Lỗi: ${e.message}`)
    } finally {
      setExporting(null)
      setTimeout(() => setMsg(''), 4000)
    }
  }

  const exportAll = async () => {
    setExporting('all'); setMsg('⏳ Đang xuất tất cả bảng...')
    const date = new Date().toISOString().split('T')[0]
    let totalRows = 0, totalFiles = 0
    for (const t of allTables) {
      try {
        const { data } = await t.query()
        if (data && data.length > 0) {
          downloadCSV(toCSV(data), `${t.key}_${date}.csv`)
          totalRows += data.length
          totalFiles++
          setMsg(`⏳ Đang xuất... (${totalFiles}/${allTables.length}) — ${t.label}`)
          await new Promise(r => setTimeout(r, 400))
        }
      } catch {}
    }
    setMsg(`✅ Hoàn tất! ${totalFiles} file — ${totalRows.toLocaleString()} dòng`)
    setExporting(null)
    setTimeout(() => setMsg(''), 6000)
  }

  return (
    <Card>
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:14, flexWrap:'wrap', gap:8 }}>
        <div>
          <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>💾 Xuất dữ liệu (Backup CSV)</div>
          <div style={{ fontSize:11, color:T.light, marginTop:2 }}>
            Download toàn bộ dữ liệu để lưu trữ dự phòng. Nên xuất định kỳ hàng tuần.
          </div>
        </div>
        <button onClick={exportAll} disabled={!!exporting}
          style={{ padding:'8px 18px', borderRadius:8, border:`1.5px solid ${T.gold}`,
            background: exporting ? T.bg : T.gold, color: exporting ? T.light : '#fff',
            cursor: exporting ? 'not-allowed' : 'pointer', fontFamily:'inherit',
            fontSize:12, fontWeight:700, display:'flex', alignItems:'center', gap:6 }}>
          {exporting === 'all' ? '⏳ Đang xuất...' : '📦 Xuất tất cả'}
        </button>
      </div>

      {tableGroups.map(group => (
        <div key={group.group} style={{ marginBottom:14 }}>
          <div style={{ fontSize:11, fontWeight:700, color:T.med, marginBottom:7,
            padding:'4px 10px', borderRadius:6, background:group.color, display:'inline-block' }}>
            {group.group}
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:6 }}>
            {group.tables.map(t => (
              <button key={t.key} onClick={() => exportOne(t)} disabled={!!exporting}
                style={{ display:'flex', alignItems:'center', gap:8, padding:'8px 12px',
                  borderRadius:8, border:`1px solid ${exporting===t.key ? T.gold : T.border}`,
                  background: exporting===t.key ? T.goldBg : '#fff',
                  cursor: exporting ? 'not-allowed' : 'pointer', fontFamily:'inherit',
                  transition:'all .15s', textAlign:'left' as any }}>
                <span style={{ fontSize:15, flexShrink:0 }}>{t.icon}</span>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:11, fontWeight:600, color:T.dark,
                    overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{t.label}</div>
                  <div style={{ fontSize:9, color:T.light }}>{t.key}.csv</div>
                </div>
                {exporting===t.key
                  ? <span style={{ fontSize:11, color:T.gold, flexShrink:0 }}>⏳</span>
                  : <span style={{ fontSize:11, color:T.light, flexShrink:0 }}>↓</span>}
              </button>
            ))}
          </div>
        </div>
      ))}

      {msg && (
        <div style={{ marginTop:10, padding:'8px 12px', borderRadius:8, fontSize:12, fontWeight:600,
          color: msg.startsWith('✅') ? T.green : msg.startsWith('❌') ? T.red : T.amber,
          background: msg.startsWith('✅') ? T.greenBg : msg.startsWith('❌') ? T.redBg : T.amberBg }}>
          {msg}
        </div>
      )}

      <div style={{ marginTop:12, padding:'8px 12px', borderRadius:8, background:T.bg,
        fontSize:11, color:T.light, lineHeight:1.7 }}>
        💡 File CSV có BOM UTF-8 — mở bằng Excel đọc được tiếng Việt.<br/>
        📁 Nên tạo folder Google Drive theo tháng để lưu trữ có tổ chức.<br/>
        🕙 n8n tự động backup hàng đêm sẽ thay thế việc xuất thủ công.
      </div>
    </Card>
  )
}

function Settings({ user, setUser, settings, setSettings, onManualReset, mobile }: any) {
  const [oldPw, setOldPw]     = useState('')
  const [newPw, setNewPw]     = useState('')
  const [confPw, setConfPw]   = useState('')
  const [pwMsg, setPwMsg]     = useState('')
  const [monthDay, setMonthDay] = useState(String(settings?.monthly_reset_day||1))
  const [weekInt, setWeekInt]   = useState(String(settings?.weekly_reset_interval||7))
  const [overdayThreshold, setOverdayThreshold] = useState(String(settings?.overdue_days_threshold||7))
  const [saved, setSaved]       = useState(false)
  const [resetting, setResetting] = useState(false)
  const p = mobile ? '16px' : '24px'

  const changePassword = async () => {
    if (oldPw !== user.pin) { setPwMsg('❌ Mật khẩu hiện tại không đúng!'); return }
    if (newPw.length < 4) { setPwMsg('❌ Mật khẩu mới phải từ 4 ký tự!'); return }
    if (newPw !== confPw) { setPwMsg('❌ Mật khẩu xác nhận không khớp!'); return }
    await db.from('users').update({ pin:newPw, must_change_password:false }).eq('id', user.id)
    setUser((prev: any) => ({...prev, pin:newPw}))
    setOldPw(''); setNewPw(''); setConfPw('')
    setPwMsg('✅ Đổi mật khẩu thành công!')
    setTimeout(() => setPwMsg(''), 3000)
  }

  const saveSettings = async () => {
    const updated = {...settings, id:'main', monthly_reset_day:Number(monthDay), weekly_reset_interval:Number(weekInt), overdue_days_threshold:Number(overdayThreshold)||7}
    await db.from('settings').upsert(updated)
    setSettings(updated); setSaved(true); setTimeout(() => setSaved(false), 2000)
  }

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="Cài đặt"/>
      <div style={{ maxWidth:560, display:'flex', flexDirection:'column', gap:14 }}>
        <Card>
          <div style={{ fontSize:13, fontWeight:700, color:T.dark, marginBottom:14 }}>Tài khoản của tôi</div>
          <div style={{ display:'flex', alignItems:'center', gap:14, padding:14, background:T.bg, borderRadius:10, marginBottom:16 }}>
            <div style={{ width:50, height:50, borderRadius:'50%', background:DEPT_COLOR[user.dept_id]||T.gold,
              display:'flex', alignItems:'center', justifyContent:'center', color:'#fff', fontSize:16, fontWeight:700 }}>{user.ini}</div>
            <div>
              <div style={{ fontSize:16, fontWeight:700, color:T.dark }}>{user.name}</div>
              <div style={{ fontSize:12, color:T.gold, marginTop:2, fontWeight:600 }}>{user.position_name||'Chưa có vị trí'}</div>
              <div style={{ fontSize:11, color:T.light, marginTop:2 }}>{user.dept_name}</div>
            </div>
          </div>
          <div style={{ fontSize:13, fontWeight:600, color:T.dark, marginBottom:12 }}>🔐 Đổi mật khẩu</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10 }}>
            <Inp label="Mật khẩu hiện tại" type="password" value={oldPw} onChange={setOldPw} placeholder="••••"/>
            <Inp label="Mật khẩu mới" type="password" value={newPw} onChange={setNewPw} placeholder="••••"/>
            <Inp label="Xác nhận" type="password" value={confPw} onChange={setConfPw} placeholder="••••"/>
          </div>
          {pwMsg && <div style={{ fontSize:12, color:pwMsg.includes('✅')?T.green:T.red, marginBottom:10 }}>{pwMsg}</div>}
          <GoldBtn small onClick={changePassword}>Đổi mật khẩu</GoldBtn>
        </Card>

        {getPerm(user).resetChecklist && (
          <Card>
            <div style={{ fontSize:13, fontWeight:700, color:T.dark, marginBottom:14 }}>⚙️ Lịch reset tự động</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <Inp label="Reset hàng tháng vào ngày (1-28)" type="number" min="1" max="28" value={monthDay} onChange={setMonthDay}/>
              <Inp label="Chu kỳ reset hàng tuần (số ngày)" type="number" min="1" max="30" value={weekInt} onChange={setWeekInt}/>
            </div>
            <div style={{ marginBottom:14, paddingTop:10, borderTop:`1px solid ${T.border}` }}>
              <div style={{ fontSize:12, fontWeight:600, color:T.dark, marginBottom:8 }}>🕐 Cảnh báo đơn hàng KiotViet quá hạn</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 2fr', gap:12, alignItems:'center' }}>
                <Inp label="Ngưỡng cảnh báo (ngày)" type="number" min="1" max="30" value={overdayThreshold} onChange={setOverdayThreshold}/>
                <div style={{ fontSize:11, color:T.light, paddingTop:16 }}>
                  Đơn "Phiếu tạm" trong KiotViet chưa được xử lý quá <b style={{ color:T.amber }}>{overdayThreshold} ngày</b> sẽ hiện cảnh báo cho sale và manager
                </div>
              </div>
            </div>
            <div style={{ display:'flex', gap:10, alignItems:'center' }}>
              <GoldBtn small onClick={saveSettings}>Lưu cài đặt</GoldBtn>
              {saved && <span style={{ color:T.green, fontSize:12 }}>✅ Đã lưu!</span>}
              <div style={{ flex:1 }}/>
              <GoldBtn outline small disabled={resetting}
                onClick={async () => { if (!confirm('Reset checklist ngay?')) return; setResetting(true); await onManualReset(); setResetting(false) }}>
                {resetting ? 'Đang reset...' : '🔄 Reset ngay'}
              </GoldBtn>
            </div>
          </Card>
        )}

        {/* Export Data */}
        {getPerm(user).viewAllDashboard && (
          <ExportDataCard/>
        )}
      </div>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ NOTIFICATION CENTER — Hook + Page Component ══════════════════════
// ══════════════════════════════════════════════════════════════════════
function useNotifications({ user, wrongOrders, returnSlips, shortageItems, batches, paymentOrders, overdueOrders, reads, settings }: any) {
  const perm         = getPerm(user)
  const isSale       = user?.dept_id === 'sale'
  const isAdmin      = perm.viewAllDashboard
  const isMgrSale    = isSale && perm.approveLeave
  const canManageExp = perm.manageExpiry || perm.manageInventory || isAdmin
  const canPay       = perm.managePayment || isAdmin
  const threshold    = settings?.overdue_days_threshold ?? 7

  const norm2 = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const today = new Date()
  const staleThreshold = new Date(Date.now() - 7*86400000).toISOString()

  const groups: any[] = []

  // ─ 1. Đơn sai pending (Sale) ─
  if (isSale && !isAdmin) {
    const items = (wrongOrders||[]).filter((r: any) =>
      r.status==='pending' && (r.sale_id===user.id || !r.sale_id)
    ).map((r: any) => ({
      key: `wo:${r.id}`, icon:'🔴',
      title: `Đơn sai: ${r.order_code||r.id}`,
      meta: r.customer_name || 'Khách',
      timestamp: r.created_at, urgency:'high',
      targetPage: 'wrongord',
    }))
    if (items.length>0) groups.push({ id:'wo', title:'🔴 Đơn sai chưa xử lý', items })
  }

  // ─ 2. Phiếu hoàn chưa điền (Sale) ─
  if (isSale && !isAdmin) {
    const items = (returnSlips||[]).filter((r: any) => !r.sale_id).map((r: any) => ({
      key: `ret:${r.slip_id}`, icon:'↩️',
      title: `Phiếu hoàn: ${r.slip_id}`,
      meta: 'Chưa điền thông tin',
      timestamp: r.created_at, urgency:'med',
      targetPage: 'returns',
    }))
    if (items.length>0) groups.push({ id:'ret', title:'↩️ Phiếu hoàn chưa điền', items })
  }

  // ─ 3. Hàng thiếu (QM Sale) ─
  if (isMgrSale) {
    const items = (shortageItems||[]).filter((r: any) =>
      r.status==='pending' && !r.manager_note
    ).map((r: any) => ({
      key: `sh:${r.id}`, icon:'⚠️',
      title: r.product_name || r.product_code,
      meta: `Thiếu ${r.qty_short||0} ${r.unit||''}`.trim(),
      timestamp: r.created_at, urgency:'high',
      targetPage: 'shortage',
    }))
    if (items.length>0) groups.push({ id:'shortage', title:'⚠️ Hàng thiếu chưa xử lý', items })
  }

  // ─ 4. Lô <6 tháng còn tồn (Sale) ─
  if (isSale) {
    const items = (batches||[]).filter((b: any) => {
      if (!b.expiry_date || (b.qty_remaining||0) <= 0) return false
      const exp = new Date(b.expiry_date)
      const ml  = (exp.getFullYear() - today.getFullYear()) * 12 + (exp.getMonth() - today.getMonth())
      return ml < 6
    }).map((b: any) => ({
      key: `exp:${b.id}`, icon:'📅',
      title: b.product_name || b.product_code,
      meta: `HSD: ${b.expiry_date}, còn ${b.qty_remaining}`,
      timestamp: b.last_updated_at || b.created_at, urgency:'med',
      targetPage: 'expiry',
    }))
    if (items.length>0) groups.push({ id:'expiry', title:'📅 Date sản phẩm sắp hết', items })
  }

  // ─ 5. Lô chưa update >7 ngày (QM Kho/Admin) ─
  if (canManageExp) {
    const items = (batches||[]).filter((b: any) => {
      if ((b.qty_remaining||0) <= 0) return false
      const lastUpd = b.last_updated_at || b.created_at || ''
      return lastUpd < staleThreshold
    }).map((b: any) => ({
      key: `stale:${b.id}`, icon:'🧮',
      title: b.product_name || b.product_code,
      meta: `Chưa update từ ${b.last_updated_at||b.created_at||'?'}`,
      timestamp: b.last_updated_at || b.created_at, urgency:'low',
      targetPage: 'expiry',
    }))
    if (items.length>0) groups.push({ id:'stale', title:'🧮 Lô chưa update >7 ngày', items })
  }

  // ─ 6. Lệnh CK chờ duyệt (Admin/canPay) ─
  if (canPay) {
    const items = (paymentOrders||[]).filter((o: any) => o.status === 'pending').map((o: any) => ({
      key: `pay:${o.id}`, icon:'💰',
      title: o.supplier_name || 'Supplier',
      meta: `${(o.amount||0).toLocaleString('vi-VN')}đ`,
      timestamp: o.created_at, urgency:'high',
      targetPage: 'payment',
    }))
    if (items.length>0) groups.push({ id:'pay', title:'💰 Lệnh CK chờ duyệt', items })
  }

  // ─ 7. Lệnh CK đã paid chờ nhập KV (QM Sale) ─
  if (isSale && !isAdmin) {
    const items = (paymentOrders||[]).filter((o: any) =>
      o.status === 'paid' && o.created_by === user.id
    ).map((o: any) => ({
      key: `kiot:${o.id}`, icon:'📦',
      title: o.supplier_name || 'Supplier',
      meta: `${(o.amount||0).toLocaleString('vi-VN')}đ — chờ nhập KV`,
      timestamp: o.created_at, urgency:'med',
      targetPage: 'payment',
    }))
    if (items.length>0) groups.push({ id:'kiot', title:'📦 CK đã paid chờ nhập KiotViet', items })
  }

  // ─ 8. Đơn KV quá hạn ─
  {
    const all = overdueOrders || []
    let items: any[] = []
    if (isAdmin || isMgrSale) {
      items = all.map((o: any) => ({
        key: `overdue:${o.code}`, icon:'🕐',
        title: `${o.code} — ${o.customerName||'KH lẻ'}`,
        meta: `Sale: ${o.soldByName||'?'} • ${o.daysOld}N trước`,
        timestamp: o.purchaseDate, urgency: o.daysOld>14?'high':'med',
        overdueOrder: o,  // payload để mở modal chi tiết
      }))
    } else if (isSale) {
      items = all.filter((o: any) => norm2(o.soldByName||'') === norm2(user.name||'')).map((o: any) => ({
        key: `overdue:${o.code}`, icon:'🕐',
        title: `${o.code} — ${o.customerName||'KH lẻ'}`,
        meta: `${o.daysOld}N trước • Kiểm tra và xử lý`,
        timestamp: o.purchaseDate, urgency: o.daysOld>14?'high':'med',
        overdueOrder: o,  // payload để mở modal chi tiết
      }))
    }
    if (items.length>0) groups.push({ id:'overdue', title:`🕐 Đơn KiotViet quá ${threshold} ngày`, items })
  }

  groups.forEach((g: any) => {
    g.total = g.items.length
    g.unread = g.items.filter((it: any) => !reads.has(it.key)).length
    g.items.forEach((it: any) => { it.isRead = reads.has(it.key) })
  })

  const totalUnread = groups.reduce((sum: number, g: any) => sum + g.unread, 0)
  const totalItems  = groups.reduce((sum: number, g: any) => sum + g.total, 0)

  return { groups, totalUnread, totalItems }
}

function NotificationPage({ user, mobile, groups, totalUnread, totalItems, reads, setReads, setPage, overdueMeta, overdueLoading, overdueRefresh }: any) {
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set())
  const [overdueDetail, setOverdueDetail] = useState<any>(null)
  const p = mobile ? '16px' : '24px'

  const toggle = (gid: string) => {
    setCollapsed(prev => {
      const next = new Set(prev)
      if (next.has(gid)) next.delete(gid); else next.add(gid)
      return next
    })
  }

  const markRead = async (key: string) => {
    setReads((prev: Set<string>) => new Set([...prev, key]))
    try {
      await db.from('notification_reads').upsert({
        user_id: user.id, noti_key: key, read_at: new Date().toISOString()
      })
    } catch(e) { /* silent */ }
  }

  const markGroupRead = async (group: any) => {
    const keys = group.items.filter((it: any) => !it.isRead).map((it: any) => it.key)
    if (keys.length === 0) return
    setReads((prev: Set<string>) => new Set([...prev, ...keys]))
    try {
      await db.from('notification_reads').upsert(
        keys.map((key: string) => ({
          user_id: user.id, noti_key: key, read_at: new Date().toISOString()
        }))
      )
    } catch(e) { /* silent */ }
  }

  const markAllRead = async () => {
    const keys = groups.flatMap((g: any) => g.items.filter((it: any) => !it.isRead).map((it: any) => it.key))
    if (keys.length === 0) return
    setReads((prev: Set<string>) => new Set([...prev, ...keys]))
    try {
      await db.from('notification_reads').upsert(
        keys.map((key: string) => ({
          user_id: user.id, noti_key: key, read_at: new Date().toISOString()
        }))
      )
    } catch(e) { /* silent */ }
  }

  const handleItemClick = (item: any) => {
    markRead(item.key)
    // Nếu là item đơn KV quá hạn → mở modal chi tiết
    if (item.overdueOrder) {
      setOverdueDetail(item.overdueOrder)
      return
    }
    if (item.targetPage) setPage(item.targetPage)
  }

  const relTime = (iso: string) => {
    if (!iso) return ''
    const diff = Date.now() - new Date(iso).getTime()
    const mins = Math.floor(diff/60000)
    if (mins < 60) return `${mins}p trước`
    const hrs = Math.floor(mins/60)
    if (hrs < 24) return `${hrs}h trước`
    const days = Math.floor(hrs/24)
    return `${days} ngày trước`
  }

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="🔔 Thông báo"
        subtitle={totalUnread>0 ? `${totalUnread} chưa đọc trong ${totalItems} thông báo` : 'Tất cả đã đọc'}
        action={totalUnread>0 && (
          <button onClick={markAllRead}
            style={{ padding:'6px 14px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', cursor:'pointer', fontFamily:'inherit',
              fontSize:12, color:T.med }}>
            ✓ Đánh dấu tất cả đã đọc
          </button>
        )}/>

      {/* Overdue cache info + refresh button */}
      {overdueMeta && overdueRefresh && (
        <div style={{ marginBottom:10, padding:'8px 12px', background:T.bg, borderRadius:6,
          border:`1px solid ${T.border}`, display:'flex', justifyContent:'space-between',
          alignItems:'center', gap:10, flexWrap:'wrap', fontSize:10 }}>
          <div style={{ color:T.med, lineHeight:1.5 }}>
            🕐 Đơn quá hạn —
            {overdueMeta.fromCache ? (
              <span> dùng cache {overdueMeta.cacheAgeSec > 60
                ? `${Math.floor(overdueMeta.cacheAgeSec/60)} phút`
                : `${overdueMeta.cacheAgeSec}s`} trước</span>
            ) : (
              <span> vừa quét xong ({overdueMeta.durationMs ? `${(overdueMeta.durationMs/1000).toFixed(1)}s` : '?'})</span>
            )}
            {overdueMeta.scanned !== undefined && (
              <span> • scan {overdueMeta.scanned} đơn → {overdueMeta.total} quá hạn</span>
            )}
          </div>
          <button onClick={overdueRefresh} disabled={overdueLoading}
            style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.gold}`,
              background: overdueLoading ? T.bg : T.goldBg,
              color: T.goldText,
              cursor: overdueLoading?'wait':'pointer',
              fontFamily:'inherit', fontSize:10, fontWeight:600,
              whiteSpace:'nowrap' }}>
            {overdueLoading ? '⏳ Đang quét...' : '🔄 Quét lại'}
          </button>
        </div>
      )}

      {groups.length === 0 ? (
        <div style={{ padding:'60px 20px', textAlign:'center', color:T.light }}>
          <div style={{ fontSize:48, marginBottom:12 }}>🎉</div>
          <div style={{ fontSize:14, color:T.med }}>Tuyệt vời! Không có thông báo nào đang chờ.</div>
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          {groups.map((g: any) => {
            const isCol = collapsed.has(g.id)
            return (
              <Card key={g.id} style={{ padding:0, overflow:'hidden' }}>
                <div style={{ padding:'12px 16px', background:T.bg,
                  borderBottom:isCol?'none':`1px solid ${T.border}`,
                  display:'flex', alignItems:'center', gap:10, cursor:'pointer' }}
                  onClick={() => toggle(g.id)}>
                  <span style={{ fontSize:11, color:T.light, width:14 }}>{isCol?'▶':'▼'}</span>
                  <div style={{ flex:1, fontSize:13, fontWeight:700, color:T.dark }}>
                    {g.title}
                  </div>
                  <span style={{ fontSize:11, color:g.unread>0?T.red:T.light, fontWeight:700 }}>
                    {g.unread}/{g.total}
                  </span>
                  {g.unread > 0 && (
                    <button onClick={(e) => { e.stopPropagation(); markGroupRead(g) }}
                      style={{ padding:'3px 10px', borderRadius:20, border:`1px solid ${T.border}`,
                        background:'#fff', cursor:'pointer', fontFamily:'inherit',
                        fontSize:10, color:T.med }}>
                      ✓ Đánh dấu đọc
                    </button>
                  )}
                </div>
                {!isCol && (
                  <div>
                    {g.items.map((item: any, i: number) => {
                      const urgColor = item.urgency==='high'?T.red : item.urgency==='med'?T.amber : T.blue
                      return (
                        <div key={item.key}
                          onClick={() => handleItemClick(item)}
                          style={{
                            padding:'10px 16px',
                            borderBottom:i<g.items.length-1?`1px solid ${T.border}`:'none',
                            display:'flex', alignItems:'center', gap:12, cursor:'pointer',
                            background: item.isRead ? T.bg : '#fff',
                            opacity: item.isRead ? 0.65 : 1,
                            transition:'background .15s'
                          }}
                          onMouseEnter={e => (e.currentTarget as any).style.background = T.goldBg}
                          onMouseLeave={e => (e.currentTarget as any).style.background = item.isRead?T.bg:'#fff'}>
                          <span style={{ width:8, height:8, borderRadius:4, flexShrink:0,
                            background: item.isRead ? 'transparent' : urgColor,
                            border: item.isRead ? `1px solid ${T.border}` : 'none' }}/>
                          <span style={{ fontSize:18, flexShrink:0 }}>{item.icon}</span>
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ fontSize:13, fontWeight: item.isRead?400:600, color:T.dark,
                              whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                              {item.title}
                            </div>
                            <div style={{ fontSize:11, color:T.light, marginTop:2 }}>
                              {item.meta}
                            </div>
                          </div>
                          <span style={{ fontSize:10, color:T.light, flexShrink:0 }}>
                            {relTime(item.timestamp)}
                          </span>
                          <span style={{ fontSize:12, color:T.light, flexShrink:0 }}>→</span>
                        </div>
                      )
                    })}
                  </div>
                )}
              </Card>
            )
          })}
        </div>
      )}

      {overdueDetail && (
        <OverdueOrderDetailModal order={overdueDetail} onClose={() => setOverdueDetail(null)}/>
      )}
    </div>
  )
}

// ── Modal hiển thị chi tiết đơn KV quá hạn ──
function OverdueOrderDetailModal({ order, onClose }: any) {
  const fmtMoney = (n: number) => Number(n||0).toLocaleString('vi-VN')
  const items = order.items || []
  const totalItems = items.length
  const totalQty = items.reduce((s: number, it: any) => s + (it.qty||0), 0)
  const statusColor = order.status === 1 ? T.amber : T.blue
  const statusLabel = order.status === 1 ? 'Phiếu tạm' : order.status === 5 ? 'Đã xác nhận — Kho chưa xử lý' : String(order.status)

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
      onClick={onClose}>
      <div onClick={e => e.stopPropagation()}
        style={{ background:'#fff', borderRadius:12, maxWidth:640, width:'100%',
          maxHeight:'90vh', overflow:'auto', boxShadow:'0 8px 24px rgba(0,0,0,0.2)' }}>

        {/* Header */}
        <div style={{ padding:'16px 20px', borderBottom:`1px solid ${T.border}`,
          position:'sticky', top:0, background:'#fff', zIndex:1 }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:10 }}>
            <div style={{ flex:1 }}>
              <div style={{ display:'flex', alignItems:'center', gap:10, flexWrap:'wrap' }}>
                <div style={{ fontSize:16, fontWeight:800, color:T.dark }}>
                  🕐 {order.code}
                </div>
                <div style={{ padding:'3px 10px', borderRadius:12,
                  background: statusColor + '22', color: statusColor,
                  fontSize:10, fontWeight:700 }}>
                  {statusLabel}
                </div>
                <div style={{ padding:'3px 10px', borderRadius:12,
                  background: order.daysOld > 14 ? T.redBg : T.amberBg,
                  color: order.daysOld > 14 ? T.red : T.amber,
                  fontSize:10, fontWeight:700 }}>
                  Đã {order.daysOld} ngày
                </div>
              </div>
              <div style={{ fontSize:13, color:T.dark, marginTop:6, fontWeight:600 }}>
                {order.customerName}
                {order.customerPhone && <span style={{ color:T.med, fontWeight:400 }}> • {order.customerPhone}</span>}
              </div>
              <div style={{ fontSize:11, color:T.med, marginTop:4 }}>
                Sale: <b style={{ color:T.dark }}>{order.soldByName || '—'}</b>
                {' • '}Ngày tạo: <b style={{ color:T.dark }}>{new Date(order.purchaseDate).toLocaleString('vi-VN')}</b>
              </div>
            </div>
            <button onClick={onClose}
              style={{ padding:'6px 10px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:12, flexShrink:0 }}>
              ✕ Đóng
            </button>
          </div>
        </div>

        <div style={{ padding:20 }}>
          {/* Ghi chú */}
          {order.description ? (
            <div style={{ marginBottom:14, padding:'10px 14px', background:T.goldBg,
              border:`1px solid ${T.goldBorder}`, borderRadius:8 }}>
              <div style={{ fontSize:10, color:T.goldText, fontWeight:700, marginBottom:4 }}>
                📝 GHI CHÚ ĐƠN
              </div>
              <div style={{ fontSize:12, color:T.dark, lineHeight:1.5, whiteSpace:'pre-wrap' }}>
                {order.description}
              </div>
            </div>
          ) : (
            <div style={{ marginBottom:14, padding:'8px 14px', background:T.bg,
              borderRadius:8, fontSize:11, color:T.light, fontStyle:'italic' }}>
              (Đơn chưa có ghi chú)
            </div>
          )}

          {/* Items */}
          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:11, fontWeight:700, color:T.med, marginBottom:8,
              display:'flex', justifyContent:'space-between' }}>
              <span>📋 SẢN PHẨM ({totalItems} dòng • {totalQty} SP)</span>
              <span style={{ color:T.goldText }}>Tổng: {fmtMoney(order.totalAmount)}</span>
            </div>
            {totalItems === 0 ? (
              <div style={{ padding:20, textAlign:'center', color:T.light, fontSize:11,
                background:T.bg, borderRadius:8 }}>
                Không có dữ liệu SP
              </div>
            ) : (
              <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                {items.map((it: any, i: number) => (
                  <div key={i} style={{ padding:10, borderRadius:8, background:'#fff',
                    border:`1px solid ${T.border}` }}>
                    <div style={{ display:'flex', justifyContent:'space-between',
                      alignItems:'flex-start', gap:10, marginBottom:4 }}>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:T.dark, lineHeight:1.35 }}>
                          {it.name}
                        </div>
                        <div style={{ fontSize:9, color:T.light, marginTop:2, display:'flex',
                          gap:8, flexWrap:'wrap' }}>
                          <span>{it.code}</span>
                          {it.unit && <span>• {it.unit}</span>}
                          <span>• Đơn giá: {fmtMoney(it.price)}</span>
                          {it.discount > 0 && <span style={{ color:T.red }}>• CK: -{fmtMoney(it.discount)}</span>}
                        </div>
                      </div>
                      <div style={{ textAlign:'right', flexShrink:0 }}>
                        <div style={{ fontSize:18, fontWeight:800, color:T.dark, lineHeight:1 }}>
                          ×{it.qty}
                        </div>
                        <div style={{ fontSize:10, color:T.goldText, fontWeight:600, marginTop:3 }}>
                          {fmtMoney(it.subTotal)}
                        </div>
                      </div>
                    </div>
                    {it.note && (
                      <div style={{ fontSize:10, color:T.amber, marginTop:4,
                        padding:'3px 8px', background:T.amberBg, borderRadius:4 }}>
                        💬 {it.note}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Info */}
          <div style={{ padding:10, background:T.bg, borderRadius:6, fontSize:10,
            color:T.med, lineHeight:1.5 }}>
            💡 <b>Hành động gợi ý:</b>
            <br/>• {order.status === 1
                ? 'Đơn đang ở Phiếu tạm — Sale cần chốt hoặc huỷ để không chiếm công nợ'
                : 'Đơn đã xác nhận nhưng Kho chưa bắt đầu xử lý — cần nhắc Kho'}
            <br/>• Kiểm tra trực tiếp đơn trên KiotViet để xem lịch sử + comment
          </div>
        </div>
      </div>
    </div>
  )
}

// ── MAIN APP ──────────────────────────────────────
// ── NOTIFICATION BANNER (legacy — sẽ bỏ) ────────────
function NotifBanner({ user, wrongOrders, returnSlips, shortageItems, batches, paymentOrders, overdueOrders, settings, setPage }: any) {
  const [dismissedCats, setDismissedCats] = useState<Set<string>>(new Set())
  const dismiss = (cat: string) => setDismissedCats(prev => new Set([...prev, cat]))
  const isDismissed = (cat: string) => dismissedCats.has(cat)

  const perm         = getPerm(user)
  const isSale       = user.dept_id === 'sale'
  const isAdmin      = perm.viewAllDashboard
  const isMgrSale    = isSale && perm.approveLeave
  const canManageExp = perm.manageExpiry || perm.manageInventory || isAdmin
  const canPay       = perm.managePayment || isAdmin
  const canKiot      = perm.managePayment || isAdmin

  // NV Sale: đơn sai pending của họ
  const pendingWO  = (!isDismissed('wo') && isSale && !isAdmin) ? wrongOrders.filter((r: any) =>
    r.status==='pending' && (r.sale_id===user.id || !r.sale_id)
  ) : []
  // NV Sale: phiếu hoàn chưa điền
  const pendingRet = (!isDismissed('ret') && isSale && !isAdmin) ? (returnSlips||[]).filter((r: any) => !r.sale_id) : []
  // QM Sale: hàng thiếu mới chờ xử lý
  const pendingShortage = (!isDismissed('shortage') && isMgrSale) ? (shortageItems||[]).filter((r: any) =>
    r.status==='pending' && !r.manager_note
  ) : []

  // Sale (tất cả): lô <6 tháng còn tồn
  const today = new Date()
  const allBatches = batches || []
  const expiryAlertSale = (!isDismissed('expiry') && isSale) ? allBatches.filter((b: any) => {
    if (!b.expiry_date || (b.qty_remaining||0) <= 0) return false
    const exp = new Date(b.expiry_date)
    const ml  = (exp.getFullYear() - today.getFullYear()) * 12 + (exp.getMonth() - today.getMonth())
    return ml < 6
  }) : []

  // QM Kho: lô chưa update quá 7 ngày
  const staleThreshold = new Date(Date.now() - 7 * 86400000).toISOString()
  const staleBatches = (!isDismissed('stale') && canManageExp) ? allBatches.filter((b: any) => {
    if ((b.qty_remaining||0) <= 0) return false
    const lastUpd = b.last_updated_at || b.created_at || ''
    return lastUpd < staleThreshold
  }) : []

  // Admin/canPay: lệnh CK đang chờ chuyển khoản
  const pendingPayments = (!isDismissed('pay') && canPay) ? (paymentOrders||[]).filter((o: any) =>
    o.status === 'pending'
  ) : []

  // QM Sale: lệnh của mình đã CK xong, chờ nhập KiotViet
  const myKiotPending = (!isDismissed('kiot') && isSale && !isAdmin) ? (paymentOrders||[]).filter((o: any) =>
    o.status === 'paid' && o.created_by === user.id
  ) : []

  // Đơn hàng KiotViet quá hạn chưa xử lý
  const threshold = settings?.overdue_days_threshold ?? 7
  const norm2 = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()

  // Sale chỉ thấy đơn của mình (match tên); Manager/Admin thấy tất cả
  const myOverdue = (!isDismissed('overdue') && isSale && !isAdmin)
    ? (overdueOrders||[]).filter((o: any) => norm2(o.soldByName||'') === norm2(user.name||''))
    : []
  const allOverdue = (!isDismissed('overdue') && (isAdmin || isMgrSale))
    ? (overdueOrders||[])
    : []
  const overdueList = isAdmin || isMgrSale ? allOverdue : myOverdue

  const totalPending = pendingWO.length + pendingRet.length + pendingShortage.length
    + expiryAlertSale.length + staleBatches.length + pendingPayments.length + myKiotPending.length
    + overdueList.length

  if (totalPending === 0) return null

  const hasWO    = pendingWO.length > 0
  const hasRet   = pendingRet.length > 0
  const hasSh    = pendingShortage.length > 0
  const hasExp   = expiryAlertSale.length > 0
  const hasStale = staleBatches.length > 0
  const hasPay   = pendingPayments.length > 0
  const hasKiot  = myKiotPending.length > 0
  const hasOverdue = overdueList.length > 0
  const accent   = hasWO ? T.red : hasRet ? T.amber : hasExp ? T.red : hasPay ? T.blue : T.teal

  const DismissBtn = ({ cat }: any) => (
    <button onClick={() => dismiss(cat)}
      style={{ background:'none', border:'none', cursor:'pointer', color:T.light, fontSize:13, padding:0, flexShrink:0 }}>✕</button>
  )
  const sep = (prev: boolean) => prev ? `1px solid ${T.border}` : 'none'

  return (
    <div style={{ position:'fixed', top:16, left:'50%', transform:'translateX(-50%)',
      zIndex:9999, background:'#fff', border:`2px solid ${accent}`,
      borderRadius:14, boxShadow:`0 8px 32px rgba(0,0,0,0.14)`,
      padding:'14px 18px', maxWidth:440, width:'calc(100vw - 32px)' }}>
      <div style={{ display:'flex', alignItems:'flex-start', gap:12 }}>
        <span style={{ fontSize:22, flexShrink:0 }}>{hasWO?'⚠️':hasKiot?'📥':hasExp?'📅':'🔔'}</span>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:13, fontWeight:700, color:accent, marginBottom:8 }}>
            {totalPending} việc cần xử lý
          </div>
          {hasWO && (
            <div style={{ marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:3 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.red }}>⚠️ {pendingWO.length} đơn sai chờ bạn điền</div>
                <DismissBtn cat="wo"/>
              </div>
              {pendingWO.slice(0,2).map((r: any) => (
                <div key={r.id} style={{ fontSize:11, color:T.med }}>• {r.order_code} — {r.customer_name||'?'}</div>
              ))}
              {pendingWO.length>2 && <div style={{ fontSize:11, color:T.light }}>...+{pendingWO.length-2} đơn nữa</div>}
            </div>
          )}
          {hasRet && (
            <div style={{ paddingTop:hasWO?8:0, borderTop:sep(hasWO), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.amber }}>🔄 {pendingRet.length} phiếu hoàn chờ điền thông tin</div>
                <DismissBtn cat="ret"/>
              </div>
            </div>
          )}
          {hasSh && (
            <div style={{ paddingTop:(hasWO||hasRet)?8:0, borderTop:sep(hasWO||hasRet), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:3 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.blue }}>📦 {pendingShortage.length} mã thiếu hàng chưa xử lý</div>
                <DismissBtn cat="shortage"/>
              </div>
              {pendingShortage.slice(0,2).map((r: any) => (
                <div key={r.id} style={{ fontSize:11, color:T.med }}>• {r.product_name}</div>
              ))}
              {pendingShortage.length>2 && <div style={{ fontSize:11, color:T.light }}>...+{pendingShortage.length-2} nữa</div>}
            </div>
          )}
          {hasExp && (
            <div style={{ paddingTop:(hasWO||hasRet||hasSh)?8:0, borderTop:sep(hasWO||hasRet||hasSh), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:3 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.red }}>📅 {expiryAlertSale.length} lô hàng dưới 6 tháng cần đẩy</div>
                <DismissBtn cat="expiry"/>
              </div>
              {expiryAlertSale.slice(0,2).map((b: any) => (
                <div key={b.id} style={{ fontSize:11, color:T.med }}>• {b.product_name} (tồn: {b.qty_remaining})</div>
              ))}
              {expiryAlertSale.length>2 && <div style={{ fontSize:11, color:T.light }}>...+{expiryAlertSale.length-2} lô nữa</div>}
            </div>
          )}
          {hasStale && (
            <div style={{ paddingTop:(hasWO||hasRet||hasSh||hasExp)?8:0, borderTop:sep(hasWO||hasRet||hasSh||hasExp), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.amber }}>⏰ {staleBatches.length} lô chưa cập nhật tồn quá 7 ngày</div>
                <DismissBtn cat="stale"/>
              </div>
            </div>
          )}
          {hasPay && (
            <div style={{ paddingTop:(hasWO||hasRet||hasSh||hasExp||hasStale)?8:0, borderTop:sep(hasWO||hasRet||hasSh||hasExp||hasStale), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:3 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.blue }}>💸 {pendingPayments.length} lệnh chuyển khoản chờ thực hiện</div>
                <DismissBtn cat="pay"/>
              </div>
              {pendingPayments.slice(0,2).map((o: any) => (
                <div key={o.id} style={{ fontSize:11, color:T.med }}>• {o.supplier_name} — {(o.amount||0).toLocaleString('vi-VN')}</div>
              ))}
              {pendingPayments.length>2 && <div style={{ fontSize:11, color:T.light }}>...+{pendingPayments.length-2} lệnh nữa</div>}
            </div>
          )}
          {hasKiot && (
            <div style={{ paddingTop:(hasWO||hasRet||hasSh||hasExp||hasStale||hasPay)?8:0, borderTop:sep(hasWO||hasRet||hasSh||hasExp||hasStale||hasPay), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:3 }}>
                <div style={{ fontSize:11, fontWeight:700, color:T.teal }}>📥 {myKiotPending.length} lệnh đã CK — chờ bạn nhập KiotViet</div>
                <DismissBtn cat="kiot"/>
              </div>
              {myKiotPending.slice(0,2).map((o: any) => (
                <div key={o.id} style={{ fontSize:11, color:T.med }}>• {o.supplier_name} — {(o.amount||0).toLocaleString('vi-VN')}</div>
              ))}
            </div>
          )}
          {/* ── Đơn hàng quá hạn chưa xử lý ── */}
          {hasOverdue && (
            <div style={{ paddingTop:(hasWO||hasRet||hasSh||hasExp||hasStale||hasPay||hasKiot)?8:0,
              borderTop:sep(hasWO||hasRet||hasSh||hasExp||hasStale||hasPay||hasKiot), marginBottom:6 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
                <div style={{ fontSize:11, fontWeight:700, color:'#C62828' }}>
                  🕐 {overdueList.length} đơn KiotViet quá {threshold} ngày chưa xử lý
                </div>
                <DismissBtn cat="overdue"/>
              </div>
              {(isAdmin || isMgrSale) ? (
                // Manager: nhóm theo sale, hiện số lượng
                (() => {
                  const byName: Record<string,any[]> = {}
                  overdueList.forEach((o: any) => {
                    const n = o.soldByName || 'Không rõ'
                    if (!byName[n]) byName[n] = []
                    byName[n].push(o)
                  })
                  return Object.entries(byName).slice(0,4).map(([name, ords]) => (
                    <div key={name} style={{ fontSize:11, color:T.med, marginBottom:2 }}>
                      • <b style={{ color:T.dark }}>{name}</b>: {ords.length} đơn
                      <span style={{ color:T.light, marginLeft:4 }}>
                        (cũ nhất: {Math.floor((Date.now()-new Date(ords[ords.length-1].purchaseDate).getTime())/86400000)}N)
                      </span>
                    </div>
                  ))
                })()
              ) : (
                // Sale: hiện chi tiết đơn của mình
                overdueList.slice(0,3).map((o: any) => (
                  <div key={o.id} style={{ fontSize:11, color:T.med, marginBottom:2 }}>
                    • <b style={{ color:T.dark }}>{o.code}</b> — {o.customerName||'KH lẻ'}
                    <span style={{ color:'#C62828', marginLeft:4, fontWeight:700 }}>
                      ({Math.floor((Date.now()-new Date(o.purchaseDate).getTime())/86400000)}N)
                    </span>
                  </div>
                ))
              )}
              {overdueList.length > (isAdmin||isMgrSale ? 4 : 3) && (
                <div style={{ fontSize:11, color:T.light }}>...+{overdueList.length-(isAdmin||isMgrSale?4:3)} đơn nữa</div>
              )}
            </div>
          )}
          <div style={{ display:'flex', gap:8, marginTop:12, flexWrap:'wrap' }}>
            {hasWO && <button onClick={() => { setPage('wrongord'); dismiss('wo') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.red,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Xem đơn sai →</button>}
            {hasRet && <button onClick={() => { setPage('returns'); dismiss('ret') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.amber,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Xem phiếu hoàn →</button>}
            {hasSh && <button onClick={() => { setPage('shortage'); dismiss('shortage') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.blue,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Xem hàng thiếu →</button>}
            {(hasExp||hasStale) && <button onClick={() => { setPage('expiry'); dismiss('expiry'); dismiss('stale') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.red,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Xem Date SP →</button>}
            {hasPay && <button onClick={() => { setPage('payment'); dismiss('pay') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.blue,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Xem lệnh CK →</button>}
            {hasKiot && <button onClick={() => { setPage('payment'); dismiss('kiot') }}
              style={{ padding:'5px 13px', borderRadius:20, border:'none', background:T.teal,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>Nhập KiotViet →</button>}
          </div>
        </div>
        <button onClick={() => setDismissedCats(new Set(['wo','ret','shortage','expiry','stale','pay','kiot','overdue']))}
          style={{ background:'none', border:'none', cursor:'pointer', color:T.light,
            fontSize:18, padding:0, lineHeight:1, flexShrink:0 }}>✕</button>
      </div>
    </div>
  )
}

// ── TaskNotifBanner — thông báo task được giao ─────────────────
function TaskNotifBanner({ user, tasks, allUsers, setPage, onDismiss }: any) {
  const today = new Date().toISOString().split('T')[0]
  const in3days = new Date(Date.now() + 3*24*60*60*1000).toISOString().split('T')[0]

  const myTasks = tasks.filter((t: any) =>
    (t.assignee_id === user.id || (Array.isArray(t.assignee_ids) && t.assignee_ids.includes(user.id)))
    && t.status !== 'done'
  )

  // Tasks mới (tạo trong 24h qua)
  const newTasks = myTasks.filter((t: any) => {
    if (!t.created_at) return false
    const created = new Date(t.created_at).getTime()
    return Date.now() - created < 24 * 60 * 60 * 1000
  })

  // Tasks sắp tới hạn (deadline trong 3 ngày tới, chưa done)
  const nearDeadline = myTasks.filter((t: any) => {
    if (!t.deadline) return false
    return t.deadline >= today && t.deadline <= in3days && !newTasks.find((n: any) => n.id === t.id)
  })

  // Tasks đã quá hạn
  const overdue = myTasks.filter((t: any) => {
    if (!t.deadline) return false
    return t.deadline < today
  })

  if (newTasks.length === 0 && nearDeadline.length === 0 && overdue.length === 0) return null

  return (
    <div style={{ margin:'0 0 10px', borderRadius:10, overflow:'hidden',
      border:`1.5px solid #7C3AED`, background:'#EDE9FE' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center',
        padding:'8px 14px', background:'#7C3AED' }}>
        <span style={{ color:'#fff', fontWeight:700, fontSize:12 }}>📌 Công việc được giao cho bạn</span>
        <button onClick={onDismiss}
          style={{ background:'none', border:'none', cursor:'pointer', color:'#fff', fontSize:16, padding:0, lineHeight:1 }}>✕</button>
      </div>
      <div style={{ padding:'8px 14px', display:'flex', flexDirection:'column', gap:5 }}>
        {overdue.map((t: any) => {
          const assigner = allUsers.find((u: any) => u.id === t.created_by)
          return (
            <div key={t.id} onClick={() => setPage('tasks')}
              style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer',
                padding:'5px 8px', borderRadius:7, background:'#FEE2E2' }}>
              <span style={{ fontSize:13 }}>🔴</span>
              <div style={{ flex:1 }}>
                <span style={{ fontSize:12, fontWeight:600, color:'#991B1B' }}>{t.title}</span>
                <span style={{ fontSize:10, color:'#B91C1C', marginLeft:6 }}>Quá hạn: {t.deadline}</span>
                {assigner && <span style={{ fontSize:10, color:'#6B7280', marginLeft:6 }}>— {assigner.name} giao</span>}
              </div>
            </div>
          )
        })}
        {nearDeadline.map((t: any) => {
          const assigner = allUsers.find((u: any) => u.id === t.created_by)
          const daysLeft = Math.ceil((new Date(t.deadline).getTime() - Date.now()) / 86400000)
          return (
            <div key={t.id} onClick={() => setPage('tasks')}
              style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer',
                padding:'5px 8px', borderRadius:7, background:'#FEF3C7' }}>
              <span style={{ fontSize:13 }}>⚠️</span>
              <div style={{ flex:1 }}>
                <span style={{ fontSize:12, fontWeight:600, color:'#92400E' }}>{t.title}</span>
                <span style={{ fontSize:10, color:'#B45309', marginLeft:6 }}>Còn {daysLeft} ngày ({t.deadline})</span>
                {assigner && <span style={{ fontSize:10, color:'#6B7280', marginLeft:6 }}>— {assigner.name} giao</span>}
              </div>
            </div>
          )
        })}
        {newTasks.map((t: any) => {
          const assigner = allUsers.find((u: any) => u.id === t.created_by)
          return (
            <div key={t.id} onClick={() => setPage('tasks')}
              style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer',
                padding:'5px 8px', borderRadius:7, background:'#F3F0FF' }}>
              <span style={{ fontSize:13 }}>🆕</span>
              <div style={{ flex:1 }}>
                <span style={{ fontSize:12, fontWeight:600, color:'#5B21B6' }}>{t.title}</span>
                {t.deadline && <span style={{ fontSize:10, color:'#6B7280', marginLeft:6 }}>Deadline: {t.deadline}</span>}
                {assigner && <span style={{ fontSize:10, color:'#6B7280', marginLeft:6 }}>— {assigner.name} giao</span>}
              </div>
              <span style={{ fontSize:9, padding:'2px 6px', borderRadius:10,
                background:'#7C3AED', color:'#fff', fontWeight:700 }}>MỚI</span>
            </div>
          )
        })}
      </div>
    </div>
  )
}

// ══ ERROR BOUNDARY — bắt lỗi render, hiển thị message thay vì màn đen ══
class AppErrorBoundary extends React.Component<
  { children: any },
  { error: any; info: any }
> {
  constructor(props: any) {
    super(props)
    this.state = { error: null, info: null }
  }
  componentDidCatch(error: any, info: any) {
    this.setState({ error, info })
    console.error('[AppErrorBoundary]', error, info)
  }
  render() {
    if (this.state.error) {
      return (
        <div style={{ padding: 32, fontFamily: 'monospace', maxWidth: 800, margin: '0 auto' }}>
          <h2 style={{ color: '#B91C1C' }}>⚠️ Lỗi hiển thị</h2>
          <p style={{ color: '#555' }}>
            Vui lòng chụp màn hình này và báo lại cho Admin.
          </p>
          <pre style={{ background: '#FEE2E2', padding: 16, borderRadius: 8,
            fontSize: 12, overflow: 'auto', whiteSpace: 'pre-wrap' }}>
            {String(this.state.error?.message || this.state.error)}
            {'\n\n'}
            {this.state.info?.componentStack?.slice(0, 800)}
          </pre>
          <button onClick={() => window.location.reload()}
            style={{ marginTop: 16, padding: '10px 24px', background: '#C4973A',
              color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer',
              fontSize: 14, fontWeight: 700 }}>
            🔄 Tải lại trang
          </button>
        </div>
      )
    }
    return this.props.children
  }
}

export default function App() {
  // Inject global CSS để đảm bảo full màn hình
  useEffect(() => {
    const style = document.createElement('style')
    style.id = 'la-global'
    style.textContent = `
      *, *::before, *::after { box-sizing: border-box; }
      html, body { margin: 0; padding: 0; width: 100%; height: 100%; background: #F7F5F2; }
      #root { width: 100%; height: 100%; display: flex; flex-direction: column; }
    `
    if (!document.getElementById('la-global')) document.head.appendChild(style)
    return () => { const el = document.getElementById('la-global'); if (el) el.remove() }
  }, [])

  const [user, setUser] = useState<any>(() => {
  try {
    const saved = localStorage.getItem('la_user')
    if (!saved) return null
    const savedVer = localStorage.getItem('la_app_version')
    const u = JSON.parse(saved)
    // Fix "quyền bị reset": nếu APP_VERSION thay đổi (deploy mới),
    // invalidate cached position — sẽ được fetch fresh từ DB ngay.
    // Keep user id/ini/name để không phải re-login.
    if (savedVer !== APP_VERSION) {
      return { ...u, position: null, _stale: true }
    }
    return u
  } catch { return null }
})
  const [page, setPage]             = useState('checklist')
  const [allUsers, setAllUsers]     = useState<any[]>([])
  const [departments, setDepts]     = useState<any[]>([])
  const [checklist, setChecklist]   = useState<any[]>([])
  const [tasks, setTasks]           = useState<any[]>([])
  const [history, setHistory]       = useState<any[]>([])
  const [settings, setSettings]     = useState<any>(null)
  const [templates, setTemplates]   = useState<any[]>([])
  const [attendance, setAttendance] = useState<any[]>([])
  const [leaveRequests, setLeaveReqs] = useState<any[]>([])
  const [positions, setPositions]   = useState<any[]>([])
  const [products, setProducts]     = useState<any[]>([])
  const [wrongOrders, setWrongOrders] = useState<any[]>([])
  const [returnSlips, setReturnSlips] = useState<any[]>([])
  const [shortageNoti, setShortageNoti] = useState<any[]>([])
  const [invSessions, setInvSessions] = useState<any[]>([])
  const [batches, setBatches]         = useState<any[]>([])
  const [paymentOrders, setPaymentOrders] = useState<any[]>([])
  const [taskNotiDismissed, setTaskNotiDismissed] = useState(false)
  const [priorityAckOpen, setPriorityAckOpen] = useState(false)
  const [overdueOrders, setOverdueOrders] = useState<any[]>([])
  const [overdueMeta, setOverdueMeta] = useState<any>(null)  // { scannedAt, fromCache, cacheAgeSec, total, scanned }
  const [overdueLoading, setOverdueLoading] = useState(false)

  const fetchOverdueOrders = async (threshold = 7, forceRefresh = false) => {
    setOverdueLoading(true)
    try {
      const qs = new URLSearchParams({ threshold: String(threshold) })
      if (forceRefresh) qs.set('refresh', '1')
      const res = await fetch(
        `https://uzloxzrqtzuucxlokqfm.supabase.co/functions/v1/kiotviet-orders?${qs.toString()}`,
        { headers: { 'Authorization': `Bearer ${SUPABASE_ANON}` } }
      )
      if (!res.ok) {
        console.error('[Overdue] HTTP', res.status, await res.text())
        return
      }
      const json = await res.json()
      ;(window as any).__overdueDebug = { ...json, fetchedAt: new Date().toISOString() }
      if (json.error) { console.error('[Overdue]', json.error); return }
      if (Array.isArray(json.data)) {
        setOverdueOrders(json.data)
        setOverdueMeta({
          scannedAt: json.scannedAt,
          fromCache: json.fromCache,
          cacheAgeSec: json.cacheAgeSec,
          total: json.total,
          scanned: json.scanned,
          durationMs: json.durationMs,
          hint: json.hint,
          breakdown: json.breakdown,
        })
        console.log(`[Overdue] ${json.fromCache ? 'Cache' : 'Fresh'} ${json.data.length} đơn quá hạn, scanned ${json.scanned}`)
      }
    } catch(e: any) {
      console.error('[Overdue] Exception:', e?.message || e)
    } finally {
      setOverdueLoading(false)
    }
  }
  const [notificationReads, setNotificationReads] = useState<Set<string>>(new Set())
  const [priceConfigs, setPriceConfigs]   = useState<any[]>([])
  const [priceTiers, setPriceTiers]       = useState<any[]>([])
  const [priceHistory, setPriceHistory]   = useState<any[]>([])
  const [brandPrograms, setBrandPrograms] = useState<any[]>([])
  const [loading, setLoading]       = useState(false)
  const width   = useWindowWidth()
  const mobile  = width < 768

  const performReset = useCallback(async (curCl: any[], tmpl: any[], st: any, manual = false) => {
    const today = todayStr(); const s = st || {}
    const now   = new Date()
    const dom   = now.getDate()
    // Số ngày cuối tháng (28/29/30/31 tùy tháng)
    const lastDomOfMonth = new Date(now.getFullYear(), now.getMonth()+1, 0).getDate()

    // ── Daily reset ───────────────────────────────────────
    const r_daily = manual || s.last_daily_reset !== today

    // ── Weekly reset ──────────────────────────────────────
    const wDiff = s.last_weekly_reset ? (() => {
      try { const p=s.last_weekly_reset.split('/'); return Math.floor((Date.now()-new Date(`${p[2]}-${p[1]}-${p[0]}`).getTime())/86400000) }
      catch { return 999 }
    })() : 999
    const r_weekly = manual || wDiff >= (s.weekly_reset_interval || 7)

    // ── Monthly reset — per-template day_of_month ─────────
    // Mỗi template hàng tháng có ngày riêng (day_of_month)
    // Hỗ trợ: ngày cụ thể (1-28) hoặc "cuối tháng" (99 = ngày cuối tháng)
    const monthKey = `${now.getMonth()}-${now.getFullYear()}`
    const monthlyDone: Record<string, boolean> = (() => {
      try { return JSON.parse(s.monthly_done || '{}') } catch { return {} }
    })()

    // Tìm các template hàng tháng chưa được tạo tháng này
    const monthlyTmplDue = tmpl.filter(t => {
      if (t.freq !== 'Hàng tháng' || !t.active) return false
      const tmplKey  = `${t.id}_${monthKey}`
      if (monthlyDone[tmplKey]) return false  // đã tạo tháng này rồi
      const targetDay = Number(t.day_of_month) || 1
      const actualDay = targetDay >= 99 ? lastDomOfMonth : targetDay  // 99 = cuối tháng
      return manual || dom >= actualDay  // đến ngày hoặc qua ngày rồi thì tạo
    })

    const r_monthly = monthlyTmplDue.length > 0

    // ── Specific-date templates ───────────────────────────
    const specificDueTmpl = tmpl.filter(t => {
      if (t.freq !== 'Ngày cụ thể' || !t.active || !t.specific_date) return false
      const specKey = `${t.id}_done`
      try {
        const done = JSON.parse(s.monthly_done || '{}')
        if (done[specKey]) return false // đã tạo rồi
      } catch {}
      const specDate = t.specific_date.split('T')[0] // lấy phần YYYY-MM-DD
      return manual || today >= specDate  // đến ngày hoặc qua ngày
    })

    if (!r_daily && !r_weekly && !r_monthly && specificDueTmpl.length === 0) return false

    // ── Archive history ───────────────────────────────────
    if (curCl.length > 0) {
      const archDate = s.last_daily_reset || today
      const freqsToArch = ['Hàng ngày', 'Hàng tuần', ...(r_monthly ? ['Hàng tháng'] : [])]
      const hist = curCl.filter(c => freqsToArch.includes(c.freq)).map(c => ({
        id:`hist_${c.id}_${Date.now()}_${Math.random().toString(36).slice(2,5)}`,
        date:archDate, assignee_id:c.assignee_id, title:c.title,
        freq:c.freq, status:c.status, done_at:c.done_at, dept_id:c.dept_id||''
      }))
      if (hist.length > 0) { await db.from('history').insert(hist); setHistory(prev => [...prev, ...hist]) }
    }

    // ── Xóa checklist cũ ─────────────────────────────────
    const freqs: string[] = []
    if (r_daily)   freqs.push('Hàng ngày')
    if (r_weekly)  freqs.push('Hàng tuần')
    // Monthly: chỉ xóa item cũ của các template sắp tạo lại
    if (r_monthly) {
      const dueIds = monthlyTmplDue.map(t => t.id)
      const oldMonthly = curCl.filter(c => c.freq==='Hàng tháng' && dueIds.includes(c.template_id))
      for (const old of oldMonthly) await db.from('checklist').delete().eq('id', old.id)
    }
    for (const freq of freqs) await db.from('checklist').delete().eq('freq', freq)

    // ── Tạo checklist mới ─────────────────────────────────
    const dailyWeeklyTmpl = tmpl.filter(t => t.active && freqs.includes(t.freq))
    const allNewTmpl = [...dailyWeeklyTmpl, ...monthlyTmplDue, ...specificDueTmpl]

    const newItems = allNewTmpl.map(t => ({
      id:`cl_${t.id}_${Date.now()}_${Math.random().toString(36).slice(2,5)}`,
      template_id:t.id, title:t.title, description:t.description||`~${t.mins} phút`,
      assignee_id:t.assignee_id, priority:t.priority, freq:t.freq,
      time_start:t.time_start||'', time_end:t.time_end||'',
      deadline:t.time_end||t.deadline_suggest||'', status:'notyet', done_at:'', date:today,
      dept_id: ''
    }))
    if (newItems.length > 0) await db.from('checklist').insert(newItems)
    setChecklist(prev => {
      const removeFreqs = new Set(freqs)
      const removeTmplIds = new Set(monthlyTmplDue.map(t => t.id))
      return [
        ...prev.filter(c => !removeFreqs.has(c.freq) && !(c.freq==='Hàng tháng' && removeTmplIds.has(c.template_id))),
        ...newItems
      ]
    })

    // ── Ghi nhận monthly templates đã tạo ────────────────
    const updatedMonthlyDone = { ...monthlyDone }
    for (const t of monthlyTmplDue) {
      updatedMonthlyDone[`${t.id}_${monthKey}`] = true
    }
    // Ghi nhận specific-date templates đã tạo (chỉ tạo 1 lần)
    for (const t of specificDueTmpl) {
      updatedMonthlyDone[`${t.id}_done`] = true
    }
    // Dọn key cũ (> 2 tháng) để tránh phình to
    const cutoff = `${new Date(now.getFullYear(), now.getMonth()-1, 1).getMonth()}-${new Date(now.getFullYear(), now.getMonth()-1, 1).getFullYear()}`
    Object.keys(updatedMonthlyDone).forEach(k => { if (k.endsWith(cutoff)) delete updatedMonthlyDone[k] })

    const newSt = { ...s, id:'main',
      last_daily_reset:  r_daily  ? today : s.last_daily_reset||'',
      last_weekly_reset: r_weekly ? today : s.last_weekly_reset||'',
      monthly_done: JSON.stringify(updatedMonthlyDone),
    }
    await db.from('settings').upsert(newSt); setSettings(newSt)
    return true
  }, [])

  useEffect(() => {
    if (!user) return
    setLoading(true)
    Promise.all([
      db.from('departments').select('*'),
    db.from('users').select('*').eq('active', true),
      db.from('checklist_templates').select('*').eq('active', true).limit(5000),
      db.from('checklist').select('*').limit(5000),
      db.from('tasks').select('*').limit(5000),
      db.from('history').select('*').order('date').limit(10000),
      db.from('settings').select('*').eq('id','main').single(),
      db.from('attendance').select('*').gte('date', new Date(Date.now()-30*86400000).toISOString().split('T')[0]).limit(5000),
      db.from('leave_requests').select('*').order('created_at', { ascending:false }).limit(3000),
      db.from('positions').select('*').limit(1000),
    ]).then(async ([depts, users, tmpl, cl, tk, hist, st, att, lr, pos]) => {
      const deptsData = depts.data || []
      const posData   = pos.data   || []
      const usersData = (users.data || []).map((u: any) => {
  const pos = posData.find((p: any) => p.id === u.position_id)
  return {
    ...u,
    dept_name: deptsData.find((d: any) => d.id===u.dept_id)?.name || '',
    position: pos || null,
    position_name: pos?.name || '',
    position_id: u.position_id || '',
    reports_to: pos?.reports_to || '',
  }
})
      const tmplData = tmpl.data || []
      const clData   = cl.data   || []
      const stData   = st.data

      setDepts(deptsData); setAllUsers(usersData); setTemplates(tmplData)
      setTasks(tk.data||[]); setHistory(hist.data||[])
      setSettings(stData); setAttendance(att.data||[])
      setPositions(posData)
      ;(async () => {
        const all: any[] = []; let from = 0
        while (true) {
          const { data } = await db.from('products').select('*').eq('active',true).order('name').range(from,from+999)
          if (!data||data.length===0) break
          all.push(...data); if (data.length<1000) break; from+=1000
        }
        setProducts(all)
      })()
      db.from('wrong_orders').select('*').order('created_at',{ascending:false})
        .then(({data}) => { if (data) setWrongOrders(data) })
      db.from('shortage_items').select('id,product_name,status,manager_note').eq('status','pending')
        .then(({data}) => { if (data) setShortageNoti(data) })
      db.from('product_batches').select('*').order('expiry_date', { ascending:true }).limit(5000)
        .then(({data}) => { if (data) setBatches(data) })
      db.from('payment_orders').select('id,supplier_name,amount,status,created_at')
        .eq('is_history',false).eq('status','pending').order('created_at',{ascending:false}).limit(50)
        .then(({data}) => { if (data) setPaymentOrders(data) })
      db.from('price_configs').select('*')
        .then(({data}) => { if (data) setPriceConfigs(data) })
      db.from('price_tiers').select('*').order('min_qty',{ascending:true})
        .then(({data}) => { if (data) setPriceTiers(data) })
      db.from('price_history').select('*').order('changed_at',{ascending:false}).limit(500)
        .then(({data}) => { if (data) setPriceHistory(data) })
      db.from('brand_programs').select('*').order('created_at',{ascending:false})
        .then(({data}) => { if (data) setBrandPrograms(data) })
      db.from('notification_reads').select('noti_key').eq('user_id', user.id)
        .then(({data}) => {
          if (data) setNotificationReads(new Set(data.map((r: any) => r.noti_key)))
        })
      // Fetch đơn hàng quá hạn từ KiotViet (qua Edge Function)
      fetchOverdueOrders(stData?.overdue_days_threshold ?? 7, false)
      // Fetch return slips for notifications (last 30 days)
      const thirtyAgo = new Date(Date.now()-30*86400000).toISOString().split('T')[0]
      db.from('return_items').select('id,slip_id,sale_id,created_at,created_by,date')
        .gte('date', thirtyAgo).order('created_at',{ascending:false})
        .then(({data}) => {
          if (!data) return
          const seen = new Set<string>()
          const slips = data.filter((r: any) => {
            const sid = r.slip_id||r.id; if (seen.has(sid)) return false; seen.add(sid); return true
          }).map((r: any) => ({ slip_id:r.slip_id||r.id, sale_id:r.sale_id, created_at:r.created_at, created_by:r.created_by }))
          setReturnSlips(slips)
        })

      // Merge DB data với localStorage backup để tránh mất đơn khi Supabase RLS chặn SELECT
      const dbLeave = lr.data || []
      const dbLeaveIds = new Set(dbLeave.map((r: any) => r.id))
      try {
        const localLeave = JSON.parse(localStorage.getItem('la_leave_backup') || '[]')
        // Chỉ giữ local items chưa có trong DB (chưa sync được)
        const localOnly = localLeave.filter((r: any) => !dbLeaveIds.has(r.id))
        const merged = [...dbLeave, ...localOnly]
        setLeaveReqs(merged)
        // Xóa local items đã sync thành công với DB
        const stillLocal = localLeave.filter((r: any) => !dbLeaveIds.has(r.id))
        localStorage.setItem('la_leave_backup', JSON.stringify(stillLocal))
      } catch {
        setLeaveReqs(dbLeave)
      }

      // Cập nhật user hiện tại với data mới nhất
      const freshUser = usersData.find((u: any) => u.id === user.id)
      if (freshUser) {
        setUser(freshUser)
        // Fix: refresh localStorage + stamp APP_VERSION để lần reload sau dùng position mới nhất
        // (trước đây cache user vẫn ở snapshot cũ → menu/quyền không update sau deploy)
        try {
          localStorage.setItem('la_user', JSON.stringify(freshUser))
          localStorage.setItem('la_app_version', APP_VERSION)
        } catch {}
      }

      const wasReset = await performReset(clData, tmplData, stData)
      if (!wasReset) {
        if (clData.length > 0) {
          setChecklist(clData)
        } else if (tmplData.length > 0) {
          const newItems = tmplData.filter((t: any) => t.active).map((t: any) => ({
            id:`cl_${t.id}_${Date.now()}_${Math.random().toString(36).slice(2,5)}`,
            template_id:t.id, title:t.title, description:t.description||`~${t.mins} phút`,
            assignee_id:t.assignee_id, priority:t.priority, freq:t.freq,
            deadline:t.deadline_suggest, status:'notyet', done_at:'', date:todayStr()
          }))
          await db.from('checklist').insert(newItems)
          setChecklist(newItems)
        }
      }
      setLoading(false)
    }).catch(() => setLoading(false))
  }, [user?.id])

  const addLog = useCallback(async (_: any) => {}, [])

  const manualReset = useCallback(async () => {
    const { data:cl } = await db.from('checklist').select('*')
    // Reset monthly_done để force tạo lại tất cả template hàng tháng
    const clearedSettings = { ...settings, monthly_done: '{}' }
    await performReset(cl||[], templates, clearedSettings, true)
  }, [settings, templates, performReset])

  // Login
  if (!user) return <LoginScreen onLogin={(u: any) => {
    setUser(u)
    setPage(getPerm(u).viewAllDashboard || getPerm(u).viewDeptChecklist ? 'dashboard' : 'checklist')
  }}/>

  if (loading) return (
    <div style={{ minHeight:'100vh', background:T.sidebar, display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:16 }}>
      <LALogo size={60}/>
      <div style={{ color:T.gold, fontSize:14 }}>Đang tải dữ liệu...</div>
    </div>
  )

  const nav = getNav(getPerm(user), user?.dept_id||'')
  const validPage = nav.find(n => n.id===page) ? page : nav[0].id
  const pp = { user, allUsers, mobile }

  const dids = allUsers.filter((u: any) => u.dept_id===user.dept_id).map((u: any) => u.id)
  const pendingLeave = leaveRequests.filter((r: any) => {
    if (r.status !== 'pending') return false
    const step = r.status || 'pending_mgr'
    if (getPerm(user).viewAllDashboard) return ['pending_mgr','pending_admin'].includes(step)
    return getPerm(user).approveLeave && dids.includes(r.user_id) && step === 'pending_mgr'
  }).length
  const pendingOT = 0 // will be updated from Overtime component

  // ── Notification Center: compute once, reuse for sidebar badge + page ──
  const { groups: notifGroups, totalUnread: notifUnread, totalItems: notifTotal } = useNotifications({
    user, wrongOrders, returnSlips, shortageItems: shortageNoti, batches,
    paymentOrders, overdueOrders, reads: notificationReads, settings
  })

  return (
    <div style={{ display:'flex', minHeight:'100vh', flexDirection: mobile?'column':'row',
      fontFamily:"'Segoe UI',system-ui,sans-serif", background:T.bg }}>
        {!mobile && (
          <Sidebar user={user} page={validPage} setPage={setPage}
            pendingLeave={pendingLeave} pendingOT={pendingOT} notifUnread={notifUnread}
            onLogout={() => {
              localStorage.removeItem('la_user')
              localStorage.removeItem('la_app_version')
              setUser(null); setAllUsers([]); setChecklist([])
            }}/>
        )}
        {/* Mobile top bar — slim, professional */}
        {mobile && (
          <div style={{ position:'sticky', top:0, zIndex:50,
            background:'#fff', borderBottom:`1px solid ${T.border}`,
            padding:'10px 14px', display:'flex', alignItems:'center', gap:10,
            boxShadow:'0 1px 3px rgba(0,0,0,0.03)' }}>
            {/* Logo + brand */}
            <div style={{ display:'flex', alignItems:'center', gap:8, flex:1 }}>
              <div style={{ width:28, height:28, borderRadius:6,
                background:T.goldBg, display:'flex', alignItems:'center', justifyContent:'center',
                border:`1px solid ${T.goldBorder}` }}>
                <span style={{ fontSize:12, fontWeight:900, color:T.goldText,
                  fontFamily:'Georgia,serif', letterSpacing:.5 }}>LA</span>
              </div>
              <div style={{ display:'flex', flexDirection:'column', lineHeight:1.1 }}>
                <span style={{ fontSize:13, fontWeight:700, color:T.dark, letterSpacing:.3 }}>
                  Global Beauty
                </span>
                <span style={{ fontSize:9, color:T.light, letterSpacing:.5 }}>
                  {user.position_name||user.dept_name}
                </span>
              </div>
            </div>
            {/* Notification bell */}
            <button onClick={() => setPage('notifications')}
              style={{ position:'relative', width:36, height:36, borderRadius:RD.md,
                border:'none', background:T.bg, cursor:'pointer',
                display:'flex', alignItems:'center', justifyContent:'center',
                color:T.med }}>
              {Ico.bell(18)}
              {notifUnread > 0 && (
                <span style={{ position:'absolute', top:4, right:4,
                  background:T.red, color:'#fff', borderRadius:RD.full,
                  fontSize:FS.xs, fontWeight:700, padding:'1px 5px',
                  lineHeight:1, minWidth:14, textAlign:'center' }}>
                  {notifUnread>9?'9+':notifUnread}
                </span>
              )}
            </button>
            {/* Avatar */}
            <div style={{ width:32, height:32, borderRadius:'50%',
              background:DEPT_COLOR[user.dept_id]||T.gold,
              display:'flex', alignItems:'center', justifyContent:'center',
              color:'#fff', fontSize:11, fontWeight:700,
              boxShadow:'0 1px 3px rgba(0,0,0,0.15)' }}>{user.ini}</div>
          </div>
        )}
        <main style={{ flex:1, overflowY:'auto', paddingTop:4, minWidth:0,
          paddingBottom: mobile ? 68 : 0 }}>
          <PriorityAlertBanner user={user} onOpen={() => setPriorityAckOpen(true)}/>
          {validPage==='dashboard' && <Dashboard {...pp} checklist={checklist} tasks={tasks} attendance={attendance} leaveRequests={leaveRequests} otRequests={[]}/>}
          {validPage==='checklist'  && <Checklist {...pp} checklist={checklist} setChecklist={setChecklist} addLog={addLog}/>}
          {validPage==='tasks'      && <Tasks {...pp} tasks={tasks} setTasks={setTasks} addLog={addLog}/>}
          {validPage==='templates'  && <Templates {...pp} templates={templates} setTemplates={setTemplates}/>}
          {validPage==='attendance' && <Attendance {...pp} leaveRequests={leaveRequests} attendance={attendance} setAttendance={setAttendance}/>}
          {validPage==='overtime'   && <Overtime {...pp}/>}
          {validPage==='announce'   && <Announcements {...pp}/>}
          {validPage==='leave'      && <Leave {...pp} leaveRequests={leaveRequests} setLeaveRequests={setLeaveReqs}/>}
          {validPage==='orgchart'   && <OrgChart {...pp} positions={positions}/>}
          {validPage==='history'    && <History {...pp} history={history}/>}
          {validPage==='users'      && <UserManagement {...pp} setAllUsers={setAllUsers} departments={departments} positions={positions}/>}
          {validPage==='positions'  && <PositionsManagement user={user} positions={positions} setPositions={setPositions} mobile={mobile}/>}
          {validPage==='shortage'   && <ShortageItems {...pp} products={products} setProducts={setProducts}/>}
          {validPage==='inventory'  && <InventoryModule {...pp} products={products} invSessions={invSessions} setInvSessions={setInvSessions}/>}
          {validPage==='returns'    && <ReturnItems {...pp} products={products}/>}
          {validPage==='wrongord'   && <WrongOrders {...pp} wrongOrders={wrongOrders} setWrongOrders={setWrongOrders} allUsers={allUsers}/>}
          {validPage==='expiry'     && <ExpiryModule {...pp} products={products} batches={batches} setBatches={setBatches}/>}
          {validPage==='payment'    && <PaymentModule {...pp}/>}
          {validPage==='pricelist'  && <PriceModule {...pp} products={products} priceConfigs={priceConfigs} setPriceConfigs={setPriceConfigs} priceTiers={priceTiers} setPriceTiers={setPriceTiers} priceHistory={priceHistory} setPriceHistory={setPriceHistory} brandPrograms={brandPrograms} setBrandPrograms={setBrandPrograms}/>}
          {validPage==='notifications' && <NotificationPage {...pp} groups={notifGroups} totalUnread={notifUnread} totalItems={notifTotal} reads={notificationReads} setReads={setNotificationReads} setPage={setPage} overdueMeta={overdueMeta} overdueLoading={overdueLoading} overdueRefresh={() => fetchOverdueOrders(settings?.overdue_days_threshold ?? 7, true)}/>}
          {validPage==='picking'    && <PickingModule {...pp} products={products}/>}
          {validPage==='packing'    && <PackingModule {...pp} products={products}/>}
          {validPage==='trackorders' && <SaleOrderTrackingModule {...pp}/>}
          {validPage==='schedule'   && <WarehouseScheduleModule {...pp} leaveRequests={leaveRequests} attendance={attendance}/>}
          {validPage==='whstats'    && <WarehouseStatsModule {...pp}/>}
          {validPage==='priority'   && <PriorityRequestModule {...pp}/>}
          {validPage==='audit'      && <AuditLogModule {...pp}/>}
          {validPage==='settings'   && <Settings {...pp} setUser={setUser} settings={settings} setSettings={setSettings} onManualReset={manualReset}/>}
          {validPage==='notes'      && <PersonalNotesModule user={user} mobile={mobile}/>}
        </main>
        {mobile && <BottomNav user={user} page={validPage} setPage={setPage} pendingLeave={pendingLeave} pendingOT={pendingOT} notifUnread={notifUnread} onLogout={() => {
          localStorage.removeItem('la_user')
          localStorage.removeItem('la_app_version')
          setUser(null); setAllUsers([]); setChecklist([])
        }}/>}
        {/* Sticky Note — floating for all users */}
        {user && <StickyNote user={user}/>}
        {user && !taskNotiDismissed && <TaskNotifBanner user={user} tasks={tasks} allUsers={allUsers} setPage={setPage} onDismiss={() => setTaskNotiDismissed(true)}/>}
        {user && <SaturdayBanner user={user}/>}
        {priorityAckOpen && user && (
          <PriorityAckModal user={user} onClose={() => setPriorityAckOpen(false)}/>
        )}
      </div>
     )
}

// ══ KẾT THÚC PHẦN 6 — HOÀN THÀNH! ══
// ══ WRONG ORDERS (Đơn sai) ════════════════════════════
function WrongOrders({ user, allUsers, wrongOrders, setWrongOrders, mobile }: any) {
  const [showAdd,  setShowAdd]  = useState(false)
  const [showEdit, setShowEdit] = useState<any>(null)
  const [tab,      setTab]      = useState<'list'|'stats'>('list')
  const [sortBy,   setSortBy]   = useState<'created_at'|'date'>('created_at')
  const [monthFilter, setMonthFilter] = useState(() => {
    const n = new Date(); return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`
  })
  const [searchQ, setSearchQ] = useState('')
  const [expandedSlip, setExpandedSlip] = useState<any>(null)
  const p = mobile ? '16px' : '24px'
  const perm = getPerm(user)
  const isKho   = user.dept_id === 'kho'
  const isSale  = user.dept_id === 'sale'
  const canAdd  = isKho || perm.viewAllDashboard
  const canResolve = perm.resolveWrongOrder

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
  const fuzzy = (r: any, q: string) => !q.trim() || norm(q).split(/\s+/).every((t: string) =>
    norm([r.order_code,r.customer_name,r.detail,r.sale_name,r.violator_name].join(' ')).includes(t)
  )

  const emptyForm = { date:'', order_code:'', customer_name:'', sale_id:'', violator_id:'', detail:'' }
  const [form, setForm] = useState<any>(emptyForm)

  const [fy, fm] = monthFilter.split('-').map(Number)
  const filtered = wrongOrders.filter((r: any) => {
    if (!fuzzy(r, searchQ)) return false
    // Filter by created_at month primarily
    const ref = r.created_at || r.date || ''
    if (!ref) return true
    const d = new Date(ref)
    return d.getFullYear()===fy && d.getMonth()+1===fm
  }).sort((a: any, b: any) => {
    const aVal = sortBy==='date' ? (a.date||'') : (a.created_at||'')
    const bVal = sortBy==='date' ? (b.date||'') : (b.created_at||'')
    return bVal.localeCompare(aVal)  // mới nhất trước
  })

  // Stats
  const woStats = {
    total: filtered.length,
    pending:     filtered.filter((r: any) => r.status==='pending').length,
    sale_filled: filtered.filter((r: any) => r.status==='sale_filled').length,
    resolved:    filtered.filter((r: any) => r.status==='resolved').length,
    bySale: allUsers.filter((u: any) => filtered.some((r: any) => r.sale_id===u.id || r.violator_id===u.id)).map((u: any) => ({
      id:u.id, name:u.name,
      asResponsible: filtered.filter((r: any) => r.sale_id===u.id).length,
      asViolator:    filtered.filter((r: any) => r.violator_id===u.id).length,
    })).sort((a: any, b: any) => (b.asResponsible+b.asViolator)-(a.asResponsible+a.asViolator))
  }

  const STATUS_CFG_WO: any = {
    pending:     { label:'⏳ Chưa xử lý',    color:T.red,   bg:T.redBg   },
    sale_filled: { label:'📝 Chờ QM xác nhận', color:T.amber, bg:T.amberBg },
    resolved:    { label:'✅ Đã xử lý',       color:T.green, bg:T.greenBg  },
  }

  const submit = async () => {
    if (!form.order_code || !form.date) return
    const now = new Date().toISOString()
    const newItem = { id:'wo'+Date.now(), ...form, status:'pending',
      resolution_note:'', resolved_by:'', resolved_at:'',
      sale_filled_at:'', created_by:user.id, created_at:now }
    setWrongOrders((prev: any) => [newItem, ...prev])
    const { error } = await db.from('wrong_orders').insert(newItem)
    if (error) { setWrongOrders((prev: any) => prev.filter((i: any) => i.id!==newItem.id)); alert('❌ '+error.message); return }
    setShowAdd(false); setForm(emptyForm)
    // Auto-notify: create announcement for sale dept
    const saleUser = allUsers.find((u: any) => u.id===form.sale_id)
    if (saleUser) {
      await db.from('announcements').insert({
        id:'ann_wo_'+Date.now(), title:`⚠️ Đơn sai mới: ${form.order_code}`,
        content:`Đơn ${form.order_code} - KH: ${form.customer_name||'?'} có sai sót. Sale ${saleUser.name} cần vào điền thông tin xử lý.`,
        dept_id:'sale', created_by:user.id, created_at:now, priority:'high'
      })
    }
  }

  const saleFill = async (id: string, note: string) => {
    const upd = { status:'sale_filled', resolution_note:note, sale_filled_at:new Date().toISOString() }
    setWrongOrders((prev: any) => prev.map((r: any) => r.id===id ? {...r,...upd} : r))
    await db.from('wrong_orders').update(upd).eq('id', id)
    setShowEdit(null)
  }

  const resolve = async (id: string) => {
    if (!confirm('Xác nhận đơn này đã được xử lý xong?')) return
    const upd = { status:'resolved', resolved_by:user.id, resolved_at:new Date().toISOString() }
    setWrongOrders((prev: any) => prev.map((r: any) => r.id===id ? {...r,...upd} : r))
    await db.from('wrong_orders').update(upd).eq('id', id)
  }

  const del = async (id: string) => {
    if (!confirm('Xóa đơn sai này?')) return
    setWrongOrders((prev: any) => prev.filter((r: any) => r.id!==id))
    await db.from('wrong_orders').delete().eq('id', id)
  }

  const pendingMine = wrongOrders.filter((r: any) =>
    r.status==='pending' && (r.sale_id===user.id || isSale || perm.viewAllDashboard)
  ).length

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="⚠️ Báo cáo đơn sai"
        subtitle={`Tháng ${fm}/${fy} — ${filtered.length} đơn`}
        action={
          <div style={{ display:'flex', gap:8, alignItems:'center' }}>
            {pendingMine>0 && (
              <span style={{ fontSize:12, fontWeight:700, color:T.red, background:T.redBg,
                padding:'4px 10px', borderRadius:20 }}>⚠️ {pendingMine} chờ xử lý</span>
            )}
            {canAdd && <GoldBtn small onClick={() => { setForm({...emptyForm, date:new Date().toISOString().split('T')[0]}); setShowAdd(true) }}>+ Tạo đơn sai</GoldBtn>}
          </div>
        }/>

      {/* Tabs + Month + Sort + Search */}
      <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap', alignItems:'center' }}>
        {([['list','📋 Danh sách'],['stats','📊 Thống kê']] as [string,string][]).map(([id,label]) => (
          <button key={id} onClick={() => setTab(id as any)}
            style={{ padding:'6px 14px', borderRadius:8, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${tab===id?T.gold:T.border}`,
              background:tab===id?T.goldBg:'transparent',
              color:tab===id?T.goldText:T.med, fontWeight:tab===id?700:400 }}>{label}</button>
        ))}
        <div style={{ display:'flex', gap:6, alignItems:'center', flexShrink:0 }}>
          {(() => {
            const now = new Date()
            const thisM = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`
            const prevD = new Date(now.getFullYear(), now.getMonth()-1, 1)
            const prevM = `${prevD.getFullYear()}-${String(prevD.getMonth()+1).padStart(2,'0')}`
            return (<>
              {[{label:'Tháng này', val:thisM},{label:'Tháng trước', val:prevM}].map(opt => (
                <button key={opt.val} onClick={() => setMonthFilter(opt.val)}
                  style={{ padding:'5px 11px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:11,
                    border:`1.5px solid ${monthFilter===opt.val?T.gold:T.border}`,
                    background:monthFilter===opt.val?T.goldBg:'transparent',
                    color:monthFilter===opt.val?T.goldText:T.med, fontWeight:monthFilter===opt.val?700:400 }}>
                  {opt.label}
                </button>
              ))}
              <input type="month" value={monthFilter} onChange={e => setMonthFilter(e.target.value)}
                style={{ padding:'5px 9px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:11, fontFamily:'inherit', color:T.dark, background:'#fff', colorScheme:'light', cursor:'pointer' }}/>
            </>)
          })()}
        </div>
        {tab==='list' && (
          <select value={sortBy} onChange={e => setSortBy(e.target.value as any)}
            style={{ padding:'6px 10px', borderRadius:8, border:`1px solid ${T.border}`,
              fontSize:12, fontFamily:'inherit', color:T.dark, background:T.bg, cursor:'pointer' }}>
            <option value="created_at">📅 Sắp xếp: Ngày tạo phiếu</option>
            <option value="date">⚠️ Sắp xếp: Ngày sai</option>
          </select>
        )}
        <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
          placeholder="🔍 Tìm mã đơn, khách hàng, chi tiết..."
          style={{ flex:1, minWidth:160, padding:'6px 10px', border:`1px solid ${T.border}`,
            borderRadius:8, fontSize:12, fontFamily:'inherit', color:T.dark, background:T.bg,
            outline:'none' }}/>
      </div>

      {tab==='stats' ? (
        <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
          <div style={{ display:'grid', gridTemplateColumns:mobile?'1fr':'repeat(4,1fr)', gap:12 }}>
            {[
              ['📋 Tổng đơn sai', woStats.total, T.dark],
              ['⏳ Chờ xử lý', woStats.pending, T.red],
              ['📝 Chờ QM xác nhận', woStats.sale_filled, T.amber],
              ['✅ Đã xử lý', woStats.resolved, T.green],
            ].map(([label,val,color]) => (
              <Card key={label as string} style={{ textAlign:'center', padding:'14px 12px' }}>
                <div style={{ fontSize:22, fontWeight:800, color:color as string }}>{val}</div>
                <div style={{ fontSize:11, color:T.light, marginTop:4 }}>{label}</div>
              </Card>
            ))}
          </div>
          <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
            <div style={{ padding:'10px 14px', background:T.amberBg, borderBottom:`1px solid #fcd34d`,
              fontSize:13, fontWeight:700, color:T.amber }}>👤 Thống kê theo nhân viên</div>
            {/* Header */}
            <div style={{ display:'grid', gridTemplateColumns:'1fr 100px 100px',
              padding:'7px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
              fontSize:10, fontWeight:700, color:T.light, textTransform:'uppercase', letterSpacing:.5, gap:8 }}>
              <span>Nhân viên</span>
              <span style={{ textAlign:'center' }}>Sale phụ trách</span>
              <span style={{ textAlign:'center' }}>Vi phạm</span>
            </div>
            {woStats.bySale.length===0
              ? <div style={{ padding:'20px', textAlign:'center', color:T.light, fontSize:12 }}>Chưa có dữ liệu</div>
              : woStats.bySale.map((s: any, i: number) => (
                <div key={s.id} style={{ display:'grid',
                  gridTemplateColumns:'1fr 100px 100px',
                  padding:'9px 14px', gap:8, alignItems:'center',
                  borderBottom:`1px solid ${T.border}`,
                  background:i%2===0?'#fff':T.rowAlt }}>
                  <span style={{ fontSize:12, fontWeight:600, color:T.dark }}>{s.name}</span>
                  <span style={{ textAlign:'center', fontSize:14,
                    fontWeight:s.asResponsible>0?700:400,
                    color:s.asResponsible>0?T.blue:T.light }}>
                    {s.asResponsible>0?s.asResponsible:'—'}
                  </span>
                  <span style={{ textAlign:'center', fontSize:12,
                    fontWeight:s.asViolator>0?700:400,
                    color:s.asViolator>0?T.red:T.light }}>
                    {s.asViolator>0?`⚠️ ${s.asViolator}`:'—'}
                  </span>
                </div>
              ))
            }
          </div>
        </div>
      ) : (
      <>{filtered.length===0
        ? <EmptyState icon={Ico.alertTri} title="Không có đơn sai nào" description="Không có đơn sai nào trong tháng này."/>
        : <div style={{ background:T.card, borderRadius:RD.lg, border:`1px solid ${T.border}`,
            boxShadow:'0 1px 3px rgba(0,0,0,0.04)', overflow:'hidden' }}>

            {/* ── Header ── */}
            {!mobile && (
              <div style={{ display:'grid',
                gridTemplateColumns:'68px 68px 95px 120px 1fr 160px 90px 90px 110px 95px',
                padding:'8px 12px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                fontSize:10, fontWeight:700, color:T.light, textTransform:'uppercase',
                letterSpacing:.6, gap:8, alignItems:'center', position:'sticky', top:0, zIndex:2 }}>
                <span>Ngày tạo</span>
                <span>Ngày sai</span>
                <span>Mã đơn</span>
                <span>Khách hàng</span>
                <span>Chi tiết đơn sai</span>
                <span>Ghi chú xử lý</span>
                <span>Sale PT</span>
                <span>Vi phạm</span>
                <span>Tình trạng</span>
                <span style={{ textAlign:'right' }}>Thao tác</span>
              </div>
            )}

            {filtered.map((r: any, i: number) => {
              const sc          = STATUS_CFG_WO[r.status]||STATUS_CFG_WO.pending
              const saleUser    = allUsers.find((u: any) => u.id===r.sale_id)
              const violUser    = allUsers.find((u: any) => u.id===r.violator_id)
              const resolvedUser = allUsers.find((u: any) => u.id===r.resolved_by)
              const canSaleFill = (isSale || perm.viewAllDashboard) && (r.status==='pending' || perm.viewAllDashboard)
              const canRes      = canResolve && r.status==='sale_filled'
              const canDel      = (canAdd && r.status==='pending') || perm.viewAllDashboard
              const detailLong  = (r.detail||'').length > 100
              const isOpen      = expandedSlip === r.id
              const rowBg       = i%2===0 ? '#fff' : T.rowAlt

              return (
                <div key={r.id} style={{ borderBottom:`1px solid ${T.border}`,
                  background: isOpen ? T.goldBg : rowBg }}>

                  {mobile ? (
                    /* ── Mobile card ── */
                    <div style={{ padding:'10px 14px' }}>
                      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:8 }}>
                        <div style={{ flex:1 }}>
                          <div style={{ fontSize:12, fontWeight:700, color:T.gold }}>
                            {r.order_code||'—'}
                            <span style={{ fontSize:10, color:T.light, marginLeft:8, fontWeight:400 }}>
                              {r.date?new Date(r.date).toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}):''} 
                            </span>
                          </div>
                          {r.customer_name && <div style={{ fontSize:11, color:T.dark, marginTop:2 }}>{r.customer_name}</div>}
                          {r.detail && <div style={{ fontSize:11, color:T.med, marginTop:3, lineHeight:1.4 }}>{r.detail}</div>}
                          {r.resolution_note && <div style={{ fontSize:11, color:T.blue, marginTop:3 }}>📝 {r.resolution_note}</div>}
                        </div>
                        <div style={{ display:'flex',flexDirection:'column',gap:4,alignItems:'flex-end',flexShrink:0 }}>
                          <span style={{ fontSize:10, fontWeight:700, padding:'2px 7px', borderRadius:20,
                            color:sc.color, background:sc.bg, whiteSpace:'nowrap' }}>{sc.label}</span>
                          {canDel && (
                            <button onClick={() => del(r.id)}
                              style={{ padding:'2px 7px',borderRadius:20,border:`1px solid ${T.redBg}`,
                                background:T.redBg,cursor:'pointer',fontSize:9,fontFamily:'inherit',color:T.red }}>✕ Hủy</button>
                          )}
                        </div>
                      </div>
                      <div style={{ display:'flex', gap:6, marginTop:8, flexWrap:'wrap' }}>
                        {canSaleFill && <button onClick={() => setShowEdit(r)}
                          style={{ padding:'4px 10px', borderRadius:20, border:`1.5px solid ${T.gold}`,
                            background:T.goldBg, cursor:'pointer', fontSize:10, fontFamily:'inherit', color:T.goldText, fontWeight:700 }}>Điền xử lý</button>}
                        {canRes && <button onClick={() => resolve(r.id)}
                          style={{ padding:'4px 10px', borderRadius:20, border:`1.5px solid ${T.green}`,
                            background:T.greenBg, cursor:'pointer', fontSize:10, fontFamily:'inherit', color:T.green, fontWeight:700 }}>✅ Xác nhận</button>}
                      </div>
                    </div>
                  ) : (
                    /* ── Desktop table row ── */
                    <div style={{ display:'grid',
                      gridTemplateColumns:'68px 68px 95px 120px 1fr 160px 90px 90px 110px 95px',
                      padding:'9px 12px', gap:8, alignItems:'start' }}
                      onClick={() => detailLong && setExpandedSlip((prev: any) => prev===r.id?null:r.id)}>

                      {/* Ngày tạo */}
                      <span style={{ fontSize:11, color:T.light }}>
                        {r.created_at?new Date(r.created_at).toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}):'—'}
                      </span>

                      {/* Ngày sai */}
                      <span style={{ fontSize:11, color:T.med, fontWeight:500 }}>
                        {r.date?new Date(r.date).toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}):'—'}
                      </span>

                      {/* Mã đơn */}
                      <span style={{ fontSize:12, fontWeight:700, color:T.gold,
                        overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                        {r.order_code||'—'}
                      </span>

                      {/* Khách hàng */}
                      <span style={{ fontSize:11, color:T.dark, lineHeight:1.4 }}>
                        {r.customer_name||'—'}
                      </span>

                      {/* Chi tiết — wrap, truncate nếu dài */}
                      <div style={{ fontSize:11, color:T.med, lineHeight:1.4 }}>
                        {detailLong && !isOpen
                          ? <>{r.detail.slice(0,100)}<span style={{ color:T.light, cursor:'pointer' }}
                              onClick={e => { e.stopPropagation(); setExpandedSlip((p: any) => p===r.id?null:r.id) }}>
                              ... <span style={{ color:T.blue, textDecoration:'underline' }}>xem thêm</span>
                            </span></>
                          : r.detail||'—'
                        }
                        {isOpen && detailLong && (
                          <span style={{ color:T.blue, cursor:'pointer', marginLeft:6, fontSize:10 }}
                            onClick={e => { e.stopPropagation(); setExpandedSlip(null) }}>thu gọn ▲</span>
                        )}
                      </div>

                      {/* Ghi chú xử lý */}
                      <div style={{ fontSize:11, lineHeight:1.4 }}>
                        {r.resolution_note
                          ? <><span style={{ color:T.blue }}>{r.resolution_note}</span>
                              {resolvedUser && <div style={{ fontSize:10, color:T.green, marginTop:2 }}>✅ {resolvedUser.name}</div>}</>
                          : <span style={{ color:T.light, fontStyle:'italic' }}>Chưa có</span>
                        }
                      </div>

                      {/* Sale PT */}
                      <span style={{ fontSize:11, color:saleUser?T.gold:T.light,
                        lineHeight:1.4 }}>
                        {saleUser?.name||'—'}
                      </span>

                      {/* Vi phạm */}
                      <span style={{ fontSize:11, color:violUser?T.red:T.light,
                        lineHeight:1.4 }}>
                        {violUser?'⚠️ '+violUser.name:'—'}
                      </span>

                      {/* Tình trạng */}
                      <span style={{ fontSize:10, fontWeight:700, padding:'2px 8px', borderRadius:20,
                        color:sc.color, background:sc.bg, whiteSpace:'nowrap',
                        display:'inline-block', textAlign:'center' }}>{sc.label}</span>

                      {/* Thao tác */}
                      <div style={{ display:'flex', gap:5, justifyContent:'flex-end', flexWrap:'wrap' }}
                        onClick={e => e.stopPropagation()}>
                        {canSaleFill && (
                          <button onClick={() => setShowEdit(r)}
                            style={{ padding:'3px 9px', borderRadius:20, border:`1.5px solid ${T.gold}`,
                              background:T.goldBg, cursor:'pointer', fontSize:10, fontFamily:'inherit',
                              color:T.goldText, fontWeight:700, whiteSpace:'nowrap' }}>Điền</button>
                        )}
                        {canRes && (
                          <button onClick={() => resolve(r.id)}
                            style={{ padding:'3px 9px', borderRadius:20, border:`1.5px solid ${T.green}`,
                              background:T.greenBg, cursor:'pointer', fontSize:10, fontFamily:'inherit',
                              color:T.green, fontWeight:700 }}>✅</button>
                        )}
                        {canDel && (
                          <button onClick={() => del(r.id)}
                            style={{ padding:'3px 7px', borderRadius:20, border:`1px solid ${T.redBg}`,
                              background:T.redBg, cursor:'pointer', fontSize:10, fontFamily:'inherit', color:T.red }}>✕</button>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              )
            })}
          </div>
      }</> )}

      {/* Modal tạo đơn sai */}
      <Modal open={showAdd} onClose={() => setShowAdd(false)} title="⚠️ Tạo đơn sai mới" wide>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <Inp label="Ngày sai *" type="date" value={form.date} onChange={(v) => setForm((f: any) => ({...f,date:v}))}/>
          <Inp label="Mã đơn hàng *" value={form.order_code} onChange={(v) => setForm((f: any) => ({...f,order_code:v}))} placeholder="VD: DH006994"/>
        </div>
        <Inp label="Tên khách hàng" value={form.customer_name} onChange={(v) => setForm((f: any) => ({...f,customer_name:v}))} placeholder="Tên KH..."/>
        <Sel label="Sale phụ trách" value={form.sale_id} onChange={(v) => setForm((f: any) => ({...f,sale_id:v}))}
          options={[{value:'',label:'— Chọn sale —'},...allUsers.filter((u: any)=>u.dept_id==='sale').map((u: any)=>({value:u.id,label:u.name}))]}/>
        <Sel label="Nhân viên vi phạm (Kho/Sale)" value={form.violator_id} onChange={(v) => setForm((f: any) => ({...f,violator_id:v}))}
          options={[{value:'',label:'— Chọn NV —'},...allUsers.filter((u: any)=>u.dept_id==='kho'||u.dept_id==='sale').map((u: any)=>({value:u.id,label:`${u.name} (${u.dept_name||u.dept_id})`}))]}/>
        <div style={{ marginBottom:13 }}>
          <div style={{ fontSize:12, fontWeight:500, color:T.med, marginBottom:5 }}>Chi tiết đơn sai *</div>
          <textarea value={form.detail} onChange={e => setForm((f: any) => ({...f,detail:e.target.value}))}
            placeholder="VD: Đóng 2 JA serum folic acid b9 55ml => 2 serum vicderma folic acid b9..."
            rows={3} style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
              fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff',
              resize:'vertical', boxSizing:'border-box' as any, outline:'none' }}/>
        </div>
        <div style={{ display:'flex', justifyContent:'flex-end', gap:10 }}>
          <GoldBtn outline small onClick={() => setShowAdd(false)}>Hủy</GoldBtn>
          <GoldBtn small onClick={submit} disabled={!form.order_code||!form.date||!form.detail}>Tạo đơn sai</GoldBtn>
        </div>
      </Modal>

      {/* Modal sale điền tình trạng */}
      {showEdit && <SaleFillModal item={showEdit} onSave={saleFill} onClose={() => setShowEdit(null)}/>}
    </div>
  )
}

function SaleFillModal({ item, onSave, onClose }: any) {
  const [note, setNote] = useState(item.resolution_note||'')
  return (
    <Modal open={true} onClose={onClose} title="📝 Điền ghi chú tình trạng xử lý">
      <div style={{ padding:'8px 12px', background:T.amberBg, borderRadius:8, marginBottom:14, fontSize:12, color:T.amber }}>
        ⚠️ Đơn {item.order_code} — {item.customer_name||'?'}<br/>
        <span style={{ fontSize:11, marginTop:4, display:'block' }}>{item.detail}</span>
      </div>
      <div style={{ marginBottom:13 }}>
        <div style={{ fontSize:12, fontWeight:500, color:T.med, marginBottom:5 }}>Ghi chú tình trạng xử lý *</div>
        <textarea value={note} onChange={e => setNote(e.target.value)}
          placeholder="VD: Đã liên hệ KH đổi hàng, dự kiến xử lý ngày 15/04..."
          rows={4} style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff',
            resize:'vertical', boxSizing:'border-box' as any, outline:'none' }}/>
      </div>
      <div style={{ display:'flex', justifyContent:'flex-end', gap:10 }}>
        <GoldBtn outline small onClick={onClose}>Hủy</GoldBtn>
        <GoldBtn small onClick={() => onSave(item.id, note)} disabled={!note.trim()}>Gửi lên QM xác nhận</GoldBtn>
      </div>
    </Modal>
  )
}

// ════════════════════════════════════════════════════════
// 📦 MODULE KIỂM KÊ KHO
// ════════════════════════════════════════════════════════

// ── Saturday Banner ─────────────────────────────────────
function SaturdayBanner({ user }: any) {
  const [dismissed, setDismissed] = useState(false)
  const [confirmed, setConfirmed] = useState(false)
  const [loaded, setLoaded] = useState(false)
  const perm = getPerm(user)
  const isSale = user.dept_id === 'sale'
  const isManager = perm.approveLeave || perm.viewAllDashboard
  const now = new Date()
  const isSat = now.getDay() === 6
  const hour = now.getHours()
  const todayStr = now.toISOString().split('T')[0]
  const showBanner = isSale && !isManager && isSat && hour >= 12

  useEffect(() => {
    if (!showBanner) { setLoaded(true); return }
    db.from('saturday_checkins').select('id').eq('user_id', user.id).eq('date', todayStr)
      .maybeSingle().then(({ data }) => { if (data) setConfirmed(true); setLoaded(true) })
  }, [])

  const handleConfirm = async () => {
    await db.from('saturday_checkins').upsert({ id:`sat_${user.id}_${todayStr}`, user_id:user.id, date:todayStr, confirmed_at:now.toISOString() })
    setConfirmed(true)
  }

  if (!loaded || !showBanner || confirmed || dismissed) return null

  return (
    <div style={{ position:'fixed', top:16, left:'50%', transform:'translateX(-50%)',
      zIndex:10000, background:'#fff', border:`2px solid ${T.amber}`,
      borderRadius:14, boxShadow:'0 8px 32px rgba(180,83,9,0.2)',
      padding:'14px 18px', maxWidth:400, width:'calc(100vw - 32px)' }}>
      <div style={{ display:'flex', alignItems:'flex-start', gap:12 }}>
        <span style={{ fontSize:22, flexShrink:0 }}>⚠️</span>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:13, fontWeight:800, color:T.amber, marginBottom:4, letterSpacing:.3 }}>
            HOÀN THÀNH HÓA ĐƠN ĐỂ KIỂM KÊ KHO
          </div>
          <div style={{ fontSize:11, color:T.med, marginBottom:10, lineHeight:1.5 }}>
            Kho sẽ kiểm kê vào sáng Chủ Nhật. Sale vui lòng hoàn thành tất cả đơn hàng hôm nay.
          </div>
          <div style={{ display:'flex', gap:8 }}>
            {hour >= 18 && (
              <button onClick={handleConfirm}
                style={{ padding:'6px 14px', borderRadius:20, border:'none', background:T.green,
                  color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:11, fontWeight:700 }}>
                ✅ Đã hoàn thành
              </button>
            )}
            <button onClick={() => setDismissed(true)}
              style={{ padding:'6px 12px', borderRadius:20, border:`1px solid ${T.border}`,
                background:'transparent', color:T.light, cursor:'pointer', fontFamily:'inherit', fontSize:11 }}>
              Nhắc lại sau
            </button>
          </div>
        </div>
        <button onClick={() => setDismissed(true)}
          style={{ background:'none', border:'none', cursor:'pointer', color:T.light, fontSize:18, padding:0 }}>✕</button>
      </div>
    </div>
  )
}

// ── Inventory Check Row subcomponent (avoid hooks in .map) ─
function InvCheckRow({ check, products, allUsers, canEdit, onUpdate, idx, total }: any) {
  const [editing, setEditing] = useState(false)
  const [val, setVal] = useState(check.actual_qty != null ? String(check.actual_qty) : '')
  const prod = products.find((p: any) => p.code === check.product_code)
  const checker = allUsers.find((u: any) => u.id === check.assigned_to)
  const diff = check.diff
  const hasDiff = diff != null && diff !== 0

  const save = async () => {
    const actual = Number(val)
    const newDiff = actual - (check.system_qty || 0)
    const upd = { actual_qty: actual, diff: newDiff,
      status: newDiff !== 0 ? 'discrepancy' : 'checked', checked_at: new Date().toISOString() }
    await db.from('inventory_checks').update(upd).eq('id', check.id)
    onUpdate(check.id, upd)
    setEditing(false)
  }

  return (
    <div style={{ display:'grid', gridTemplateColumns:'1fr 70px 70px 80px 100px 80px',
      padding:'8px 12px', gap:8, alignItems:'center',
      borderBottom: idx < total-1 ? `1px solid ${T.border}` : 'none',
      background: hasDiff ? '#FFF5F5' : idx%2===0 ? '#fff' : T.rowAlt }}>
      <div>
        <div style={{ fontSize:12, fontWeight:500, color:T.dark }}>{check.product_name}</div>
        <div style={{ fontSize:10, color:T.light }}>{check.product_code}
          {checker && <span style={{ marginLeft:6, color:T.blue }}>· {checker.name}</span>}
        </div>
      </div>
      <span style={{ fontSize:12, textAlign:'center', color:T.med }}>{check.system_qty ?? '—'}</span>
      {editing ? (
        <input type="number" value={val} onChange={e => setVal(e.target.value)}
          autoFocus style={{ width:'100%', padding:'4px 6px', border:`1.5px solid ${T.gold}`,
            borderRadius:6, fontSize:12, fontFamily:'inherit', textAlign:'center' }}
          onKeyDown={e => e.key==='Enter' && save()}/>
      ) : (
        <span style={{ fontSize:12, textAlign:'center', fontWeight:check.actual_qty!=null?700:400,
          color:check.actual_qty!=null?T.dark:T.light }}>
          {check.actual_qty ?? '—'}
        </span>
      )}
      <span style={{ fontSize:12, textAlign:'center', fontWeight:700,
        color:!hasDiff?T.green:diff>0?T.blue:T.red }}>
        {diff==null?'—':diff>0?'+'+diff:diff}
      </span>
      <span style={{ fontSize:10, padding:'2px 7px', borderRadius:20, textAlign:'center',
        background:check.status==='checked'||check.status==='confirmed'?T.greenBg:check.status==='discrepancy'?T.redBg:T.bg,
        color:check.status==='checked'||check.status==='confirmed'?T.green:check.status==='discrepancy'?T.red:T.light }}>
        {check.status==='checked'?'✓ OK':check.status==='discrepancy'?'⚠️ Lệch':check.status==='confirmed'?'✅':check.status==='pending'?'Chờ':'—'}
      </span>
      <div style={{ display:'flex', gap:4, justifyContent:'flex-end' }}>
        {canEdit && !editing && (
          <button onClick={() => setEditing(true)}
            style={{ padding:'3px 9px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', cursor:'pointer', fontSize:10, fontFamily:'inherit', color:T.med }}>
            {check.actual_qty!=null?'Sửa':'Nhập'}
          </button>
        )}
        {editing && <>
          <button onClick={save}
            style={{ padding:'3px 9px', borderRadius:20, border:'none', background:T.green,
              cursor:'pointer', fontSize:10, fontFamily:'inherit', color:'#fff', fontWeight:700 }}>✓</button>
          <button onClick={() => { setEditing(false); setVal(check.actual_qty!=null?String(check.actual_qty):'') }}
            style={{ padding:'3px 8px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', cursor:'pointer', fontSize:10, fontFamily:'inherit', color:T.light }}>✕</button>
        </>}
      </div>
    </div>
  )
}

// ── Mobile Check Input (NV dùng điện thoại) ──────────────
// ── CheckListRow — 1 dòng trong list KK của NV ─────────────
function CheckListRow({ check, isActive, onSelect, onConfirm, onSkip, idx, total }: any) {
  const [val, setVal] = useState(check.actual_qty != null ? String(check.actual_qty) : '')
  const inputRef = React.useRef<HTMLInputElement>(null)
  const done = check.actual_qty != null
  const [editDone, setEditDone] = useState(false)
  const isEditable = done && editDone
  const diff = val !== '' ? Number(val) - (check.system_qty || 0) : null

  // Auto-focus input when row becomes active
  useEffect(() => {
    if (isActive && inputRef.current) {
      setTimeout(() => inputRef.current?.focus(), 100)
    }
  }, [isActive])

  const handleConfirm = async () => {
    if (val === '') return
    const actual = Number(val)
    const newDiff = actual - (check.system_qty || 0)
    const upd = { actual_qty: actual, diff: newDiff,
      status: newDiff !== 0 ? 'discrepancy' : 'checked',
      checked_at: new Date().toISOString() }
    await db.from('inventory_checks').update(upd).eq('id', check.id)
    onConfirm(check.id, upd)
  }

  const effectiveActive = isActive || isEditable
  const statusIcon = done && !isEditable
    ? (check.diff !== 0 ? '⚠️' : '✅')
    : (effectiveActive ? '▶' : '○')
  const statusColor = done && !isEditable
    ? (check.diff !== 0 ? T.red : T.green)
    : (effectiveActive ? T.gold : T.border)

  return (
    <div style={{
      borderBottom: idx < total - 1 ? `1px solid ${T.border}` : 'none',
      background: isActive ? '#FFFDF5' : done ? (check.diff !== 0 ? '#FFF5F5' : '#F5FFF5') : (idx%2===0?'#fff':T.rowAlt),
      transition: 'all .15s',
    }}>
      {/* Compact row — always visible */}
      <div onClick={() => done ? setEditDone(v => !v) : onSelect(check.id)}
        style={{ display:'grid', gridTemplateColumns:'36px 1fr 60px 36px',
          padding: effectiveActive ? '12px 14px 0' : '10px 14px',
          gap:10, alignItems:'center',
          cursor: 'pointer' }}>
        {/* Status icon */}
        <span style={{ fontSize:18, textAlign:'center', color:statusColor,
          transition:'all .2s' }}>{statusIcon}</span>
        {/* Product info */}
        <div>
          <div style={{ fontSize:12, fontWeight:isActive?700:500, color:T.dark,
            lineHeight:1.3 }}>{check.product_name}</div>
          <div style={{ fontSize:10, color:T.light }}>{check.product_code}</div>
        </div>
        {/* System qty */}
        <div style={{ textAlign:'right' }}>
          <div style={{ fontSize:10, color:T.light }}>Tồn HT</div>
          <div style={{ fontSize:14, fontWeight:700, color:T.blue }}>{check.system_qty ?? '—'}</div>
        </div>
        {/* Done badge */}
        {done && (
          <div style={{ textAlign:'center' }}>
            <div style={{ fontSize:12, fontWeight:800,
              color:check.diff===0?T.green:check.diff>0?T.blue:T.red }}>
              {check.diff===0?'✓':check.diff>0?`+${check.diff}`:check.diff}
            </div>
          </div>
        )}
        {!done && !isActive && (
          <div style={{ width:24, height:24, borderRadius:'50%',
            border:`1.5px solid ${T.border}`, flexShrink:0 }}/>
        )}
      </div>

      {/* Expanded input — only when active */}
      {effectiveActive && (
        <div style={{ padding:'12px 14px 16px' }}>
          {/* 3-number display */}
          <div style={{ display:'flex', justifyContent:'space-around',
            background:'#fff', borderRadius:12, padding:'12px',
            border:`1.5px solid ${T.gold}`, marginBottom:12 }}>
            <div style={{ textAlign:'center' }}>
              <div style={{ fontSize:10, color:T.light, marginBottom:2 }}>Tồn hệ thống</div>
              <div style={{ fontSize:24, fontWeight:800, color:T.blue }}>{check.system_qty ?? '—'}</div>
            </div>
            <div style={{ display:'flex', alignItems:'center', color:T.border, fontSize:18 }}>→</div>
            <div style={{ textAlign:'center' }}>
              <div style={{ fontSize:10, color:T.light, marginBottom:2 }}>Tồn thực tế</div>
              <div style={{ fontSize:24, fontWeight:800,
                color:diff==null?T.light:diff===0?T.green:diff>0?T.blue:T.red }}>
                {val||'—'}
              </div>
            </div>
            {diff != null && (
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:10, color:T.light, marginBottom:2 }}>Chênh lệch</div>
                <div style={{ fontSize:24, fontWeight:800,
                  color:diff===0?T.green:diff>0?T.blue:T.red }}>
                  {diff>0?'+':''}{diff}
                </div>
              </div>
            )}
          </div>
          {/* Input */}
          <input ref={inputRef} type="number" value={val}
            onChange={e => setVal(e.target.value)}
            placeholder="Nhập tồn thực tế..."
            onKeyDown={e => e.key==='Enter' && handleConfirm()}
            style={{ width:'100%', padding:'13px', border:`2px solid ${val?T.gold:T.border}`,
              borderRadius:12, fontSize:20, fontFamily:'inherit', textAlign:'center',
              fontWeight:700, color:T.dark, background:'#fff',
              boxSizing:'border-box' as any, outline:'none', marginBottom:10 }}/>
          {/* Buttons */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 2fr', gap:8 }}>
            <button onClick={() => onSkip(check.id)}
              style={{ padding:'12px', borderRadius:12, border:`1.5px solid ${T.border}`,
                background:'transparent', cursor:'pointer', fontFamily:'inherit',
                fontSize:13, color:T.med, fontWeight:600 }}>Bỏ qua</button>
            <button onClick={handleConfirm} disabled={val===''}
              style={{ padding:'12px', borderRadius:12, border:'none',
                background:val?T.green:'#ccc', cursor:val?'pointer':'default',
                fontFamily:'inherit', fontSize:14, color:'#fff', fontWeight:700 }}>
              ✓ Xác nhận
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

function MobileCheckInput({ session, myChecks, allChecks, user, allUsers, products, onUpdate, onBack }: any) {
  const [activeId, setActiveId] = useState<string|null>(null)
  const [sortBy, setSortBy] = useState<'alpha'|'stock'>('alpha')
  const [showDC, setShowDC] = useState(true)

  // Double-check items: mã được giao DC cho user này, chưa nhập
  const dcItems = (allChecks||[]).filter((c: any) =>
    c.session_id === session.id &&
    c.double_check_by === user.id &&
    c.double_actual_qty == null
  )

  const done    = myChecks.filter((c: any) => c.actual_qty != null).length
  const pending = myChecks.filter((c: any) => c.actual_qty == null).length

  const sorted = [...myChecks].sort((a: any, b: any) => {
    if (sortBy === 'stock') return (b.system_qty||0) - (a.system_qty||0)
    return (a.product_name||'').localeCompare(b.product_name||'')
  })

  const handleConfirm = (id: string, upd: any) => {
    onUpdate(id, upd)
    const nextPending = sorted.find((c: any) => c.id !== id && c.actual_qty == null && c.id !== activeId)
    setActiveId(nextPending?.id || null)
  }

  const handleDCConfirm = async (check: any, val: string) => {
    const actual = Number(val)
    const upd = { double_actual_qty: actual, double_checked_at: new Date().toISOString() }
    await db.from('inventory_checks').update(upd).eq('id', check.id)
    onUpdate(check.id, upd)
  }

  return (
    <div style={{ display:'flex', flexDirection:'column', height:'100vh', background:T.bg }}>
      {/* Fixed header */}
      <div style={{ padding:'10px 14px', background:'#fff', borderBottom:`1px solid ${T.border}`,
        flexShrink:0, position:'sticky', top:0, zIndex:10 }}>
        <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:8 }}>
          <button onClick={onBack}
            style={{ padding:'5px 12px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', cursor:'pointer', fontSize:12, fontFamily:'inherit', color:T.med }}>
            ← Về
          </button>
          <div style={{ flex:1 }}>
            <div style={{ height:6, background:T.border, borderRadius:3 }}>
              <div style={{ height:'100%', borderRadius:3, background:T.green,
                width:`${myChecks.length>0?done*100/myChecks.length:0}%`, transition:'width .4s' }}/>
            </div>
          </div>
          <span style={{ fontSize:12, fontWeight:700, color:T.dark, flexShrink:0 }}>
            {done}/{myChecks.length}
          </span>
        </div>
        <div style={{ display:'flex', gap:6, alignItems:'center' }}>
          <span style={{ fontSize:11, color:T.light }}>Sắp xếp:</span>
          {([['alpha','A → Z'],['stock','Tồn kho']] as [string,string][]).map(([val,label]) => (
            <button key={val} onClick={() => setSortBy(val as any)}
              style={{ padding:'4px 12px', borderRadius:20, cursor:'pointer',
                fontFamily:'inherit', fontSize:11,
                border:`1.5px solid ${sortBy===val?T.gold:T.border}`,
                background:sortBy===val?T.goldBg:'transparent',
                color:sortBy===val?T.goldText:T.med, fontWeight:sortBy===val?700:400 }}>
              {label}
            </button>
          ))}
          {pending > 0 && (
            <span style={{ marginLeft:'auto', fontSize:11, color:T.amber }}>⏳ {pending} chưa KK</span>
          )}
        </div>
      </div>

      {/* Scrollable list */}
      <div style={{ flex:1, overflowY:'auto', background:'#fff', paddingBottom:80 }}>

        {/* ── Double-check section ── */}
        {dcItems.length > 0 && (
          <div style={{ margin:'12px 12px 0', padding:'12px 14px',
            background:'#EDE9FE', border:`1.5px solid ${T.purple}`, borderRadius:12 }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:8 }}>
              <div style={{ fontSize:12, fontWeight:700, color:T.purple }}>
                🔁 Double-check — {dcItems.length} mã cần xác nhận lại
              </div>
              <button onClick={() => setShowDC(v => !v)}
                style={{ background:'none', border:'none', cursor:'pointer', fontSize:11, color:T.purple }}>
                {showDC ? 'Thu gọn ▲' : 'Mở rộng ▼'}
              </button>
            </div>
            <div style={{ fontSize:11, color:'#7C3AED', marginBottom: showDC ? 10 : 0 }}>
              Những mã này được giao để kiểm lại do lệch kho — nhập số tồn thực tế của bạn.
            </div>
            {showDC && dcItems.map((c: any) => (
              <DCInputRow key={c.id} check={c} onConfirm={handleDCConfirm}/>
            ))}
          </div>
        )}

        {done === myChecks.length && dcItems.length === 0 && (
          <div style={{ padding:'40px 24px', textAlign:'center' }}>
            <div style={{ fontSize:44, marginBottom:12 }}>🎉</div>
            <div style={{ fontSize:16, fontWeight:700, color:T.green, marginBottom:6 }}>Hoàn thành!</div>
            <div style={{ fontSize:13, color:T.med, marginBottom:20 }}>Đã kiểm kê {done} mã hàng</div>
            <button onClick={onBack}
              style={{ padding:'10px 24px', borderRadius:20, border:'none', background:T.gold,
                color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              ← Quay lại danh sách
            </button>
          </div>
        )}
        {sorted.map((c: any, i: number) => (
          <CheckListRow key={c.id} check={c} idx={i} total={sorted.length}
            isActive={activeId === c.id}
            onSelect={(id: string) => setActiveId(prev => prev===id ? null : id)}
            onConfirm={handleConfirm}
            onSkip={(id: string) => {
              const next = sorted.find((x: any) => x.id !== id && x.actual_qty == null && x.id !== activeId)
              setActiveId(next?.id || null)
            }}/>
        ))}
      </div>
    </div>
  )
}

// ── DCInputRow — 1 dòng nhập double-check ─────────────────
function DCInputRow({ check, onConfirm }: any) {
  const [val, setVal] = useState('')
  const [done, setDone] = useState(check.double_actual_qty != null)
  const diff = val !== '' ? Number(val) - (check.actual_qty || 0) : null

  if (done) return (
    <div style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0',
      borderBottom:`1px solid #DDD8FF` }}>
      <div style={{ flex:1 }}>
        <div style={{ fontSize:12, fontWeight:600, color:'#4C1D95' }}>{check.product_name}</div>
        <div style={{ fontSize:10, color:'#7C3AED' }}>{check.product_code}</div>
      </div>
      <div style={{ fontSize:11, color:T.green, fontWeight:700 }}>✅ Đã nhập: {check.double_actual_qty}</div>
    </div>
  )

  return (
    <div style={{ padding:'10px 0', borderBottom:`1px solid #DDD8FF` }}>
      <div style={{ fontSize:12, fontWeight:700, color:'#4C1D95', marginBottom:4 }}>{check.product_name}</div>
      <div style={{ display:'flex', gap:8, alignItems:'center', fontSize:11, color:T.med, marginBottom:8 }}>
        <span>KK lần 1: <b>{check.actual_qty}</b></span>
        <span>Tồn HT: <b>{check.system_qty}</b></span>
        <span style={{ color:check.diff!==0?T.red:T.green }}>Lệch: {check.diff>0?'+':''}{check.diff}</span>
      </div>
      <div style={{ display:'flex', gap:8, alignItems:'center' }}>
        <input type="number" value={val} onChange={e => setVal(e.target.value)}
          placeholder="Nhập tồn thực tế..."
          style={{ flex:1, padding:'8px 11px', border:`1.5px solid ${T.purple}`,
            borderRadius:8, fontSize:13, fontFamily:'inherit', outline:'none',
            color:'#4C1D95', background:'#F5F3FF' }}/>
        {diff !== null && (
          <span style={{ fontSize:13, fontWeight:700, color:diff===0?T.green:T.red, flexShrink:0 }}>
            {diff===0?'✅ Khớp':diff>0?`+${diff}`:diff}
          </span>
        )}
        <button onClick={async () => {
          if (val==='') return
          await onConfirm(check, val)
          setDone(true)
        }}
          style={{ padding:'8px 14px', borderRadius:8, border:'none', background:T.purple,
            color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:12, fontWeight:700 }}>
          ✓ Xác nhận
        </button>
      </div>
    </div>
  )
}

// ── Main InventoryModule ─────────────────────────────────
function InventoryModule({ user, allUsers, products, invSessions, setInvSessions, mobile }: any) {
  const [tab, setTab] = useState<'overview'|'sessions'|'check'|'discrepancy'>('overview')
  const [checks, setChecks] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)
  const [showAssign, setShowAssign] = useState(false)
  const [showWizard, setShowWizard] = useState(false)
  const [showExcluded, setShowExcluded] = useState(false)
  const [expandedSession, setExpandedSession] = useState<string|null>(null)
  const [searchSP, setSearchSP] = useState('')
  const [mobileCheck, setMobileCheck] = useState(false)
  const [excludedCodes, setExcludedCodes] = useState<Set<string>>(new Set())
  const [lastKvSync, setLastKvSync] = useState<string>('')
  const [kvSyncing, setKvSyncing] = useState(false)
  const [newDate, setNewDate] = useState(new Date().toISOString().split('T')[0])
  const [newNote, setNewNote] = useState('')
  const [importing, setImporting] = useState(false)
  const [diffFilter, setDiffFilter] = useState<'all'|'neg'|'pos'>('all')
  const [selectedChecks, setSelectedChecks] = useState<Set<string>>(new Set())
  const [monthFilter, setMonthFilter] = useState(() => {
    const n = new Date(); return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`
  })
  // Modal xác nhận xóa (yêu cầu gõ "XÓA")
  const [confirmDelete, setConfirmDelete] = useState<any>(null)
  const p = mobile ? '16px' : '24px'
  const perm = getPerm(user)
  const canManage = perm.viewAllDashboard || (perm as any).manageInventory
  const isKhoNV   = user.dept_id === 'kho' && !canManage  // NV kho thường
  const canCheck  = user.dept_id === 'kho' || canManage

  const openSession = invSessions.find((s: any) => s.status === 'open')

  const [lastSync, setLastSync] = useState<Date|null>(null)
  const [syncing, setSyncing] = useState(false)

  const fetchData = async (quiet=false) => {
    if (!quiet) setSyncing(true)
    const [{data:s},{data:c}] = await Promise.all([
      db.from('inventory_sessions').select('*').order('date',{ascending:false}).limit(100),
      db.from('inventory_checks').select('*').order('created_at',{ascending:false}).limit(5000)
    ])
    setInvSessions(s||[])
    setChecks(c||[])
    setLastSync(new Date())
    // Load excluded + last sync
    db.from('kk_excluded_products').select('product_code')
      .then(({data:ex}) => { if(ex) setExcludedCodes(new Set(ex.map((x: any) => x.product_code))) })
    db.from('settings').select('last_kv_sync').eq('id','main').maybeSingle()
      .then(({data:st}) => { if(st?.last_kv_sync) setLastKvSync(st.last_kv_sync) })
    if (!quiet) { setSyncing(false); setLoading(false) }
    else setLoading(false)
  }

  useEffect(() => {
    fetchData()
    // Poll mỗi 10 giây khi có phiên đang mở
    const interval = setInterval(() => {
      const hasOpen = invSessions.some((s: any) => s.status==='open')
      if (hasOpen || tab==='check') fetchData(true)
    }, 10000)
    return () => clearInterval(interval)
  }, [invSessions.length, tab])

  const updateCheck = (id: string, upd: any) =>
    setChecks(prev => prev.map((c: any) => c.id===id ? {...c,...upd} : c))

  const syncKiotViet = async () => {
    setKvSyncing(true)
    try {
      const res = await fetch('https://uzloxzrqtzuucxlokqfm.supabase.co/functions/v1/kiotviet-sync', {
        method:'POST', headers:{'Authorization':`Bearer ${SUPABASE_ANON}`}
      })
      const now = new Date().toISOString()
      await db.from('settings').update({last_kv_sync:now}).eq('id','main')
      setLastKvSync(now)
      // Reload products
      fetchData(true)
    } catch(e: any) { alert('Sync lỗi: ' + e.message) }
    setKvSyncing(false)
  }

  const createSession = async () => {
    if (!newDate) return
    const newS = { id:'sess_'+Date.now(), date:newDate, note:newNote, status:'open',
      total_assigned:0, total_checked:0, created_by:user.id, created_at:new Date().toISOString() }
    setInvSessions(prev => [newS, ...prev])
    await db.from('inventory_sessions').insert(newS)
    setShowCreate(false); setNewNote('')
  }

  const closeSession = async (sid: string) => {
    if (!confirm('Chốt phiên kiểm kê này? Sau khi chốt sẽ không thể nhập liệu thêm.')) return
    const upd = { status:'closed', closed_by:user.id, closed_at:new Date().toISOString() }
    setInvSessions(prev => prev.map((s: any) => s.id===sid ? {...s,...upd} : s))
    await db.from('inventory_sessions').update(upd).eq('id', sid)
  }

  // Import Excel (LichSu_KK format)
  const importExcel = async (file: File) => {
    setImporting(true)
    try {
      const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
      const buf  = await file.arrayBuffer()
      const wb   = xlsx.read(buf, {type:'array'})
      const ws   = wb.Sheets['LichSu_KK'] || wb.Sheets[wb.SheetNames[0]]
      const rows: any[] = xlsx.utils.sheet_to_json(ws, {header:1, defval:''})
      // Find header row
      const hIdx = rows.findIndex((r: any[]) => r.some((c: any) => String(c).includes('Ngày KK')))
      if (hIdx<0) { alert('Không tìm thấy sheet LichSu_KK đúng format'); setImporting(false); return }
      const headers = rows[hIdx].map((h: any) => String(h).trim())
      const colNgay  = headers.findIndex((h: string) => h.includes('Ngày KK'))
      const colMa    = headers.findIndex((h: string) => h.includes('Mã SP'))
      const colTen   = headers.findIndex((h: string) => h.includes('Tên SP'))
      const colHT    = headers.findIndex((h: string) => h.includes('Hệ Thống'))
      const colTT    = headers.findIndex((h: string) => h.includes('Thực Tế'))
      const colCL    = headers.findIndex((h: string) => h.includes('Chênh'))
      const colNV    = headers.findIndex((h: string) => h.includes('Người'))
      // Group by date
      const byDate: Record<string, any[]> = {}
      rows.slice(hIdx+1).forEach((r: any[]) => {
        const ma = String(r[colMa]||'').trim()
        if (!ma) return
        const rawDate = r[colNgay]
        let dateStr = ''
        if (rawDate instanceof Date) dateStr = rawDate.toISOString().split('T')[0]
        else if (typeof rawDate === 'number') {
          const d = new Date(Math.round((rawDate - 25569) * 86400 * 1000))
          dateStr = d.toISOString().split('T')[0]
        } else dateStr = String(rawDate).split('T')[0] || String(rawDate).split(' ')[0]
        if (!byDate[dateStr]) byDate[dateStr] = []
        byDate[dateStr].push({
          product_code: ma, product_name: String(r[colTen]||'').trim(),
          system_qty:   Number(r[colHT])||0, actual_qty: Number(r[colTT])||0,
          diff:         Number(r[colCL])||0,
          checked_by_name: String(r[colNV]||'Admin').trim()
        })
      })
      // Create sessions + checks
      let created = 0
      for (const [dateStr, items] of Object.entries(byDate)) {
        const existing = invSessions.find((s: any) => s.date===dateStr)
        let sessId = existing?.id
        if (!sessId) {
          sessId = 'sess_import_'+dateStr.replace(/-/g,'')
          const newS = { id:sessId, date:dateStr, note:'Import từ Excel', status:'closed',
            total_assigned:items.length, total_checked:items.length,
            created_by:user.id, created_at:new Date().toISOString(),
            closed_at:new Date().toISOString() }
          await db.from('inventory_sessions').upsert(newS)
          setInvSessions(prev => [...prev.filter((s: any) => s.id!==sessId), newS])
        }
        const newChecks = items.map((item: any, i: number) => ({
          id: `chk_${sessId}_${i}_${Date.now()}`,
          session_id: sessId, product_code: item.product_code,
          product_name: item.product_name, system_qty: item.system_qty,
          actual_qty: item.actual_qty, diff: item.diff,
          base_price: products.find((p: any) => p.code===item.product_code)?.base_price || 0,
          assigned_to: user.id, status: item.diff!==0?'discrepancy':'checked',
          diff_status: '', diff_note: '', checked_at: dateStr, created_at: new Date().toISOString()
        }))
        await db.from('inventory_checks').upsert(newChecks)
        setChecks(prev => [...prev.filter((c: any) => c.session_id!==sessId), ...newChecks])
        created += items.length
      }
      alert(`✅ Import thành công ${created} bản ghi từ ${Object.keys(byDate).length} đợt kiểm kê`)
    } catch(e: any) { alert('❌ Lỗi import: ' + e.message) }
    setImporting(false)
  }

  // Stats
  const totalProducts = products.length
  const checkedCodes  = new Set(checks.map((c: any) => c.product_code)).size
  const discrepancies = checks.filter((c: any) => c.status==='discrepancy' && c.diff_status==='')
  const myChecks      = openSession ? checks.filter((c: any) => c.session_id===openSession.id && c.assigned_to===user.id) : []

  const [fy, fm] = monthFilter.split('-').map(Number)
  const monthChecks = checks.filter((c: any) => {
    const sid = invSessions.find((s: any) => s.id===c.session_id)
    if (!sid) return false
    const d = new Date(sid.date)
    return d.getFullYear()===fy && d.getMonth()+1===fm
  })

  const exportKKForm = async (items: any[]) => {
    try {
      const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
      const wb = xlsx.utils.book_new()
      const rows = [
        ['STT','Mã SP','Tên Sản Phẩm','ĐVT','Tồn Hệ Thống','Tồn Thực Tế','Chênh Lệch','Người Kiểm Kê','Ghi Chú'],
        ...items.map((p: any, i: number) => [i+1, p.code, p.name, p.unit||'', p.stock, '', '', '', ''])
      ]
      const ws = xlsx.utils.aoa_to_sheet(rows)
      ws['!cols'] = [{wch:5},{wch:14},{wch:50},{wch:8},{wch:14},{wch:14},{wch:12},{wch:16},{wch:20}]
      xlsx.utils.book_append_sheet(wb, ws, 'Phieu_KiemKe')
      xlsx.writeFile(wb, `PhieuKiemKe_${new Date().toISOString().split('T')[0]}.xlsx`)
    } catch(e: any) { alert('❌ Lỗi export: ' + e.message) }
  }

  // NV kho mặc định vào tab Nhập liệu
  useEffect(() => {
    if (!canManage && tab === 'overview') setTab('check')
  }, [canManage])

  if (loading) return <div style={{padding:p,textAlign:'center',color:T.light,paddingTop:40}}>⏳ Đang tải dữ liệu...</div>

  // Mobile check mode
  if (mobileCheck && openSession && myChecks.length > 0) return (
    <MobileCheckInput session={openSession} myChecks={myChecks} allChecks={checks} user={user}
      allUsers={allUsers} products={products}
      onUpdate={updateCheck} onBack={() => setMobileCheck(false)}/>
  )

  const TABS = [
    ...(canManage ? [
      {id:'overview',    label:'📊 Tổng quan'},
      {id:'sessions',    label:'📋 Phiên KK'},
    ] : []),
    {id:'check',         label:`✅ Nhập liệu${openSession?` (${myChecks.filter((c: any)=>c.actual_qty==null).length + checks.filter((c: any)=>c.session_id===openSession?.id&&c.double_check_by===user.id&&c.double_actual_qty==null).length})`:''}`},
    {id:'discrepancy',   label:`⚠️ Lệch kho${discrepancies.length?` (${discrepancies.length})`:''}`},
    {id:'monthly',       label:'📈 Cuối tháng'},
    ...(canManage ? [{id:'excluded', label:`🚫 Mã không KK${excludedCodes.size?` (${excludedCodes.size})`:''}`}] : []),
  ]

  return (
    <div style={{padding:`0 ${p} ${mobile?'80px':p}`}}>
      <Topbar mobile={mobile} title="📦 Kiểm kê kho"
        subtitle={openSession ? `📂 Phiên ${openSession.date} đang mở` : 'Quản lý kiểm kê hàng hóa'}
        action={
          <div style={{display:'flex',gap:8,alignItems:'center'}}>
            {lastSync && (
              <span style={{fontSize:10,color:T.light}}>
                {syncing?'🔄 Đang sync...':'✓ '+lastSync.toLocaleTimeString('vi-VN',{hour:'2-digit',minute:'2-digit',second:'2-digit'})}
              </span>
            )}
            <button onClick={() => fetchData()}
              style={{padding:'5px 12px',borderRadius:20,border:`1px solid ${T.border}`,
                background:'transparent',cursor:'pointer',fontSize:11,fontFamily:'inherit',color:T.med}}>
              🔄 Refresh
            </button>
            {canManage && (
              <div style={{display:'flex',flexDirection:'column',alignItems:'center',gap:1}}>
                <button onClick={syncKiotViet} disabled={kvSyncing}
                  style={{padding:'5px 12px',borderRadius:20,border:`1.5px solid ${T.green}`,
                    background:T.greenBg,cursor:'pointer',fontSize:11,fontFamily:'inherit',
                    color:T.green,fontWeight:600}}>
                  {kvSyncing?'⏳ Syncing...':'🔄 Sync KiotViet'}
                </button>
                {lastKvSync && <span style={{fontSize:9,color:T.light}}>
                  {new Date(lastKvSync).toLocaleString('vi-VN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit'})}
                </span>}
              </div>
            )}
            {canManage && <GoldBtn small onClick={() => setShowWizard(true)}>+ Tạo phiên KK</GoldBtn>}
          </div>
        }/>

      {/* Tabs */}
      <div style={{display:'flex',gap:6,marginBottom:14,flexWrap:'wrap'}}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id as any)}
            style={{padding:'6px 14px',borderRadius:8,cursor:'pointer',fontFamily:'inherit',fontSize:12,
              border:`1.5px solid ${tab===t.id?T.gold:T.border}`,
              background:tab===t.id?T.goldBg:'transparent',
              color:tab===t.id?T.goldText:T.med,fontWeight:tab===t.id?700:400}}>{t.label}</button>
        ))}
      </div>

      {/* ── TAB: TỔNG QUAN ── */}
      {tab==='overview' && (
        <div style={{display:'flex',flexDirection:'column',gap:14}}>
          {/* 4 cards */}
          <div style={{display:'grid',gridTemplateColumns:mobile?'1fr 1fr':'repeat(4,1fr)',gap:12}}>
            {[
              ['📦 Tổng SP',        totalProducts,                    T.dark],
              ['✅ Đã kiểm kê',     checkedCodes,                     T.green],
              ['❌ Chưa kiểm kê',   totalProducts-checkedCodes,       T.amber],
              ['⚠️ Đang lệch',      discrepancies.length,             T.red],
            ].map(([label,val,color]) => (
              <Card key={label as string} style={{textAlign:'center',padding:'14px 12px'}}>
                <div style={{fontSize:26,fontWeight:800,color:color as string}}>{val as number}</div>
                <div style={{fontSize:11,color:T.light,marginTop:4}}>{label}</div>
              </Card>
            ))}
          </div>
          {/* Progress */}
          <Card>
            <div style={{fontSize:13,fontWeight:700,color:T.dark,marginBottom:10}}>
              Tiến độ kiểm kê tổng thể
            </div>
            <div style={{height:10,background:T.border,borderRadius:5,marginBottom:8}}>
              <div style={{height:'100%',borderRadius:5,background:`linear-gradient(90deg,${T.green},${T.teal})`,
                width:`${totalProducts>0?checkedCodes*100/totalProducts:0}%`,transition:'width .5s'}}/>
            </div>
            <div style={{fontSize:12,color:T.light}}>
              {checkedCodes}/{totalProducts} mã ({totalProducts>0?Math.round(checkedCodes*100/totalProducts):0}%)
            </div>
          </Card>
          {/* Recent sessions */}
          <Card>
            <div style={{fontSize:13,fontWeight:700,color:T.dark,marginBottom:12}}>Các đợt KK gần đây</div>
            {invSessions.slice(0,5).map((s: any, i: number) => {
              const sChecks = checks.filter((c: any) => c.session_id===s.id)
              const sLech   = sChecks.filter((c: any) => c.diff!=null && c.diff!==0).length
              return (
                <div key={s.id} style={{display:'flex',alignItems:'center',gap:12,
                  padding:'8px 0',borderBottom:i<4?`1px solid ${T.border}`:'none'}}>
                  <div style={{flex:1}}>
                    <span style={{fontSize:12,fontWeight:600,color:T.dark}}>{s.date}</span>
                    {s.note && <span style={{fontSize:11,color:T.light,marginLeft:8}}>{s.note}</span>}
                  </div>
                  <span style={{fontSize:11,color:T.blue}}>{sChecks.length} SP</span>
                  {sLech>0 && <span style={{fontSize:11,color:T.red}}>⚠️ {sLech} lệch</span>}
                  <span style={{fontSize:10,padding:'2px 8px',borderRadius:20,
                    background:s.status==='open'?T.greenBg:T.grayBg,
                    color:s.status==='open'?T.green:T.gray}}>{s.status==='open'?'Đang mở':'Đã chốt'}</span>
                </div>
              )
            })}
          </Card>
          {/* Top discrepancies */}
          {discrepancies.length>0 && (
            <Card>
              <div style={{fontSize:13,fontWeight:700,color:T.red,marginBottom:12}}>
                ⚠️ Mã lệch kho chưa xử lý (top {Math.min(10,discrepancies.length)})
              </div>
              {discrepancies.slice(0,10).sort((a: any,b: any)=>Math.abs(b.diff)-Math.abs(a.diff)).map((c: any,i: number) => (
                <div key={c.id} style={{display:'flex',alignItems:'center',gap:12,
                  padding:'7px 0',borderBottom:i<9?`1px solid ${T.border}`:'none'}}>
                  <div style={{flex:1,fontSize:12,color:T.dark}}>{c.product_name}</div>
                  <span style={{fontSize:11,color:T.light}}>{c.product_code}</span>
                  <span style={{fontSize:13,fontWeight:700,color:c.diff>0?T.blue:T.red}}>
                    {c.diff>0?'+':''}{c.diff}
                  </span>
                </div>
              ))}
            </Card>
          )}
        </div>
      )}

      {/* ── TAB: PHIÊN KK ── */}
      {tab==='sessions' && (
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
{/* Assign/Export buttons removed — handled inside wizard */}

          {/* Import Excel */}
          <Card>
            <div style={{fontSize:13,fontWeight:700,color:T.dark,marginBottom:8}}>📥 Import từ Excel</div>
            <div style={{fontSize:11,color:T.med,marginBottom:10}}>
              Chọn file Excel (sheet LichSu_KK) để import lịch sử kiểm kê. Hệ thống sẽ tự tạo phiên theo ngày.
            </div>
            <label style={{display:'inline-block',padding:'8px 16px',borderRadius:20,
              border:`2px dashed ${T.border}`,cursor:'pointer',fontSize:12,color:T.med,
              background:T.bg,transition:'all .2s'}}
              onMouseEnter={e => (e.currentTarget as any).style.borderColor=T.gold}
              onMouseLeave={e => (e.currentTarget as any).style.borderColor=T.border}>
              {importing ? '⏳ Đang import...' : '📂 Chọn file Excel (.xlsx)'}
              <input type="file" accept=".xlsx,.xls" style={{display:'none'}}
                onChange={e => e.target.files?.[0] && importExcel(e.target.files[0])}
                disabled={importing}/>
            </label>
          </Card>

          {/* Session list */}
          <div style={{background:T.card,borderRadius:12,border:`1px solid ${T.border}`,overflow:'hidden',boxShadow:'0 1px 4px rgba(0,0,0,0.06)'}}>
            {!mobile && (
              <div style={{display:'grid',gridTemplateColumns:'100px 1fr 70px 70px 80px 110px 120px',
                padding:'8px 12px',background:T.bg,borderBottom:`2px solid ${T.border}`,
                fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8}}>
                <span>Ngày KK</span><span>Ghi chú</span>
                <span style={{textAlign:'center'}}>SP KK</span>
                <span style={{textAlign:'center'}}>SP lệch</span>
                <span>Trạng thái</span>
                <span>Người tạo</span>
                <span style={{textAlign:'right'}}>Thao tác</span>
              </div>
            )}
            {/* Search SP across sessions */}
            <div style={{padding:'8px 12px',background:T.bg,borderBottom:`1px solid ${T.border}`}}>
              <input value={searchSP} onChange={e => setSearchSP(e.target.value)}
                placeholder="🔍 Tìm sản phẩm để xem lịch sử các phiên KK..."
                style={{width:'100%',padding:'7px 12px',border:`1px solid ${T.border}`,borderRadius:20,
                  fontSize:12,fontFamily:'inherit',color:T.dark,background:'#fff',
                  boxSizing:'border-box' as any,outline:'none'}}/>
            </div>

            {/* Search results */}
            {searchSP.trim() && (() => {
              const norm2 = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/đ/g,'d')
              const q = norm2(searchSP)
              const matched = checks.filter((c: any) => norm2(c.product_name+' '+c.product_code).includes(q))
              const bySess = invSessions.map(s => {
                const sc = matched.filter((c: any) => c.session_id===s.id)
                return sc.length>0 ? {s, sc} : null
              }).filter(Boolean)
              if (bySess.length===0) return (
                <div style={{padding:'20px',textAlign:'center',color:T.light,fontSize:12}}>
                  Không tìm thấy sản phẩm này trong lịch sử kiểm kê
                </div>
              )
              return (
                <div style={{padding:'8px 12px'}}>
                  <div style={{fontSize:11,color:T.med,marginBottom:8}}>
                    Tìm thấy trong <b>{bySess.length}</b> phiên:
                  </div>
                  {bySess.map(({s,sc}: any) => (
                    <div key={s.id} style={{padding:'8px 12px',borderRadius:8,border:`1px solid ${T.border}`,
                      marginBottom:6,background:'#fff'}}>
                      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',gap:8,marginBottom:4}}>
                        <span style={{fontSize:12,fontWeight:700,color:T.dark}}>📅 {s.date}</span>
                        <span style={{fontSize:10,color:T.light}}>{s.note||''}</span>
                      </div>
                      {sc.map((c: any) => (
                        <div key={c.id} style={{display:'grid',gridTemplateColumns:'1fr 70px 70px 70px',
                          gap:8,fontSize:11,padding:'4px 0',borderTop:`1px solid ${T.border}`}}>
                          <span style={{color:T.dark}}>{c.product_name}</span>
                          <span style={{textAlign:'center',color:T.blue}}>HT: {c.system_qty??'—'}</span>
                          <span style={{textAlign:'center',color:T.dark}}>TT: {c.actual_qty??'—'}</span>
                          <span style={{textAlign:'center',fontWeight:700,
                            color:c.diff===0||c.diff==null?T.green:c.diff>0?T.blue:T.red}}>
                            {c.diff==null?'—':c.diff===0?'✓':c.diff>0?'+'+c.diff:c.diff}
                          </span>
                        </div>
                      ))}
                    </div>
                  ))}
                </div>
              )
            })()}

            {!searchSP.trim() && (invSessions.length===0
              ? <div style={{padding:'32px',textAlign:'center',color:T.light}}>Chưa có phiên kiểm kê nào</div>
              : invSessions.map((s: any, i: number) => {
                  const sChecks = checks.filter((c: any) => c.session_id===s.id)
                  const sLech   = sChecks.filter((c: any) => c.diff!=null && c.diff!==0).length
                  const creator = allUsers.find((u: any) => u.id===s.created_by)
                  const isExp   = expandedSession === s.id
                  // Group by NV
                  const nvIds   = [...new Set(sChecks.map((c: any) => c.assigned_to))].filter(Boolean)
                  return (
                    <div key={s.id} style={{borderBottom:i<invSessions.length-1?`1px solid ${T.border}`:'none',background:'transparent'}}>
                      {/* ── Session row ── */}
                      <div style={{display:'grid',
                        gridTemplateColumns:'100px 1fr 70px 70px 80px 110px 120px',
                        padding:'10px 12px',gap:8,alignItems:'center',cursor:'pointer',
                        background:isExp?T.goldBg:i%2===0?'#fff':T.rowAlt}}
                        onClick={() => setExpandedSession(isExp?null:s.id)}>
                        <span style={{fontSize:12,fontWeight:700,color:T.dark}}>{s.date}</span>
                        <span style={{fontSize:11,color:T.med}}>{s.note||'—'}</span>
                        <span style={{fontSize:12,textAlign:'center',color:T.blue}}>{sChecks.length}</span>
                        <span style={{fontSize:12,textAlign:'center',color:sLech>0?T.red:T.green,fontWeight:sLech>0?700:400}}>
                          {sLech>0?sLech:'✓'}
                        </span>
                        <span style={{fontSize:10,padding:'2px 8px',borderRadius:20,
                          background:s.status==='open'?T.greenBg:T.grayBg,
                          color:s.status==='open'?T.green:T.gray}}>
                          {s.status==='open'?'🟢 Đang mở':'⚫ Đã chốt'}
                        </span>
                        <span style={{fontSize:11,color:T.med}}>{creator?.name||'Admin'}</span>
                        <div style={{display:'flex',gap:5,justifyContent:'flex-end',alignItems:'center'}}
                          onClick={e => e.stopPropagation()}>
                          {s.status==='open' && canManage && (
                            <button onClick={() => closeSession(s.id)}
                              style={{padding:'3px 10px',borderRadius:20,border:`1.5px solid ${T.amber}`,
                                background:T.amberBg,cursor:'pointer',fontSize:10,fontFamily:'inherit',
                                color:T.amber,fontWeight:700}}>Chốt</button>
                          )}
                          {perm.deleteInvSession && (
                            <button onClick={() => {
                              const sessChecks = checks.filter((c: any) => c.session_id === s.id)
                              setConfirmDelete({
                                title: 'Xóa phiên kiểm kê',
                                message: `Bạn sắp xóa phiên kiểm kê ngày ${s.date}.`,
                                detail: `Phiên này có ${sessChecks.length} bản ghi kiểm kê.\nToàn bộ dữ liệu kiểm kê chi tiết sẽ bị xóa vĩnh viễn.`,
                                action: async () => {
                                  // Snapshot trước khi xóa (để rescue nếu cần)
                                  await logAudit({
                                    user,
                                    action: 'bulk_delete',
                                    table: 'inventory_sessions',
                                    recordId: s.id,
                                    snapshot: { session: s, checks: sessChecks },
                                    note: `Xóa phiên KK ngày ${s.date} kèm ${sessChecks.length} bản ghi`,
                                  })
                                  await db.from('inventory_checks').delete().eq('session_id', s.id)
                                  await db.from('inventory_sessions').delete().eq('id', s.id)
                                  setInvSessions((prev: any) => prev.filter((x: any) => x.id!==s.id))
                                  setChecks((prev: any) => prev.filter((c: any) => c.session_id!==s.id))
                                  setConfirmDelete(null)
                                }
                              })
                            }}
                              style={{padding:'3px 8px',borderRadius:20,border:`1px solid ${T.redBg}`,
                                background:T.redBg,cursor:'pointer',fontSize:10,fontFamily:'inherit',color:T.red}}>✕</button>
                          )}
                          <span style={{fontSize:10,color:T.light}}>{isExp?'▲':'▼'}</span>
                        </div>
                      </div>

                      {/* ── Expanded: NV + mã ── */}
                      {isExp && (
                        <div style={{background:T.bg,borderTop:`1px dashed ${T.border}`,padding:'10px 14px'}}>
                          {nvIds.length===0 ? (
                            <div style={{fontSize:12,color:T.light}}>Chưa phân chia mã cho nhân viên</div>
                          ) : nvIds.map((nvId: any) => {
                            const nv = allUsers.find((u: any) => u.id===nvId)
                            const nvChecks = sChecks.filter((c: any) => c.assigned_to===nvId)
                            const nvDone   = nvChecks.filter((c: any) => c.actual_qty!=null).length
                            return (
                              <NVCheckGroup key={nvId} nv={nv} nvChecks={nvChecks} nvDone={nvDone}/>
                            )
                          })}
                        </div>
                      )}
                    </div>
                  )
              })
            )}
          </div>
        </div>
      )}

      {/* ── TAB: NHẬP LIỆU ── */}
      {tab==='check' && (
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
          {!openSession ? (
            <EmptyState icon={Ico.clipboard}
              title="Không có phiên kiểm kê nào đang mở"
              action={canManage && <Btn onClick={() => setShowCreate(true)} icon={Ico.plus(14)}>Tạo phiên KK mới</Btn>}/>
          ) : (
            <>
              {/* QM Monitor View OR NV own list */}
              {canManage ? (
                <InvMonitorView session={openSession} checks={checks}
                  allUsers={allUsers} user={user} products={products}
                  onStartMobile={() => setMobileCheck(true)} myChecks={myChecks}/>
              ) : (
                <Card style={{display:'flex',alignItems:'center',justifyContent:'space-between',flexWrap:'wrap',gap:12}}>
                  <div>
                    <div style={{fontSize:13,fontWeight:700,color:T.dark}}>Phiên {openSession.date}</div>
                    <div style={{fontSize:11,color:T.light}}>
                      {myChecks.length} mã · {myChecks.filter((c: any)=>c.actual_qty!=null).length} đã KK
                    </div>
                  </div>
                  {myChecks.filter((c: any)=>c.actual_qty==null).length > 0 && (
                    <GoldBtn small onClick={() => setMobileCheck(true)}>
                      📱 Bắt đầu KK ({myChecks.filter((c: any)=>c.actual_qty==null).length} mã)
                    </GoldBtn>
                  )}
                </Card>
              )}

              {/* Check table */}
              {myChecks.length === 0 ? (
                <Card style={{textAlign:'center',padding:'32px',color:T.light}}>
                  Chưa có mã nào được phân cho bạn trong phiên này
                </Card>
              ) : (
                <div style={{background:T.card,borderRadius:12,border:`1px solid ${T.border}`,overflow:'hidden',boxShadow:'0 1px 4px rgba(0,0,0,0.06)'}}>
                  {!mobile && (
                    <div style={{display:'grid',gridTemplateColumns:'1fr 70px 70px 80px 100px 80px',
                      padding:'8px 12px',background:T.bg,borderBottom:`2px solid ${T.border}`,
                      fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8}}>
                      <span>Sản phẩm</span>
                      <span style={{textAlign:'center'}}>Tồn HT</span>
                      <span style={{textAlign:'center'}}>Tồn TT</span>
                      <span style={{textAlign:'center'}}>Chênh lệch</span>
                      <span style={{textAlign:'center'}}>Trạng thái</span>
                      <span style={{textAlign:'right'}}>Thao tác</span>
                    </div>
                  )}
                  {myChecks.map((c: any, i: number) => (
                    <InvCheckRow key={c.id} check={c} products={products} allUsers={allUsers}
                      canEdit={canCheck} onUpdate={updateCheck} idx={i} total={myChecks.length}/>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      )}

      {/* ── TAB: LỆCH KHO ── */}
      {tab==='discrepancy' && (
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
          {/* Bulk action bar */}
          {selectedChecks.size > 0 && canManage && (
            <div style={{display:'flex',gap:8,alignItems:'center',padding:'10px 14px',
              background:T.goldBg,borderRadius:10,border:`1.5px solid ${T.gold}`,flexWrap:'wrap'}}>
              <span style={{fontSize:12,fontWeight:700,color:T.goldText,flexShrink:0}}>
                Đã chọn {selectedChecks.size} mã
              </span>
              <span style={{fontSize:11,color:T.light}}>→</span>
              {[
                {val:'found',    label:'✅ Tìm được hàng',  color:T.green,   bg:T.greenBg},
                {val:'reason',   label:'🔍 Tìm được NN',    color:T.blue,    bg:T.blueBg},
                {val:'no_reason',label:'❌ Không tìm được', color:T.red,     bg:T.redBg},
                {val:'resolved', label:'✔️ Đã xử lý',       color:'#7C3AED', bg:'#EDE9FE'},
              ].map(opt => (
                <button key={opt.val} onClick={async () => {
                  const now = new Date().toISOString()
                  const ids = [...selectedChecks]
                  const upd: any = {diff_status:opt.val, resolved_by:user.id, resolved_at:now}
                  await db.from('inventory_checks').update(upd).in('id', ids)
                  ids.forEach((id: string) => updateCheck(id, upd))
                  setSelectedChecks(new Set())
                }}
                  style={{padding:'4px 12px',borderRadius:20,border:`1.5px solid ${opt.color}`,
                    background:opt.bg,cursor:'pointer',fontSize:11,fontFamily:'inherit',
                    color:opt.color,fontWeight:700}}>
                  {opt.label}
                </button>
              ))}
              <button onClick={() => setSelectedChecks(new Set())}
                style={{padding:'4px 10px',borderRadius:20,border:`1px solid ${T.border}`,
                  background:'transparent',cursor:'pointer',fontSize:11,fontFamily:'inherit',
                  color:T.light,marginLeft:'auto'}}>Bỏ chọn</button>
            </div>
          )}
          {/* Filter bar */}
          {/* Time range filter */}
          {(() => {
            const now = new Date()
            const thisMonth = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`
            const lastMonthDate = new Date(now.getFullYear(), now.getMonth()-1, 1)
            const lastMonth = `${lastMonthDate.getFullYear()}-${String(lastMonthDate.getMonth()+1).padStart(2,'0')}`
            return (
              <div style={{display:'flex',gap:8,alignItems:'center',flexWrap:'wrap'}}>
                {[
                  {label:'Tháng này', val:thisMonth},
                  {label:'Tháng trước', val:lastMonth},
                ].map(opt => (
                  <button key={opt.val} onClick={() => setMonthFilter(opt.val)}
                    style={{padding:'6px 14px',borderRadius:20,cursor:'pointer',fontFamily:'inherit',fontSize:12,
                      border:`1.5px solid ${monthFilter===opt.val?T.gold:T.border}`,
                      background:monthFilter===opt.val?T.goldBg:'transparent',
                      color:monthFilter===opt.val?T.goldText:T.med,fontWeight:monthFilter===opt.val?700:400}}>
                    {opt.label}
                  </button>
                ))}
                <div style={{display:'flex',alignItems:'center',gap:6}}>
                  <span style={{fontSize:11,color:T.light}}>Tùy chọn:</span>
                  <input type="month" value={monthFilter} onChange={e => setMonthFilter(e.target.value)}
                    style={{padding:'5px 9px',border:`1px solid ${T.border}`,borderRadius:8,
                      fontSize:12,fontFamily:'inherit',color:T.dark,background:'#fff',
                      colorScheme:'light'}}/>
                </div>
                <div style={{marginLeft:'auto',display:'flex',gap:6}}>
                  {(['all','neg','pos'] as const).map(f => (
                    <button key={f} onClick={() => setDiffFilter(f)}
                      style={{padding:'5px 12px',borderRadius:20,cursor:'pointer',fontFamily:'inherit',fontSize:11,
                        border:`1.5px solid ${diffFilter===f?T.gold:T.border}`,
                        background:diffFilter===f?T.goldBg:'transparent',
                        color:diffFilter===f?T.goldText:T.med}}>
                      {f==='all'?'Tất cả':f==='neg'?'Lệch âm':'Lệch dương'}
                    </button>
                  ))}
                </div>
              </div>
            )
          })()}

          {/* Discrepancy table */}
          <div style={{background:T.card,borderRadius:12,border:`1px solid ${T.border}`,overflow:'hidden',boxShadow:'0 1px 4px rgba(0,0,0,0.06)'}}>
            {!mobile && (
              <div style={{display:'grid',gridTemplateColumns: canManage ? '28px 1fr 90px 60px 60px 60px 150px 120px' : '1fr 90px 60px 60px 60px 150px 120px',
                padding:'8px 12px',background:T.bg,borderBottom:`2px solid ${T.border}`,
                fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8,
                alignItems:'center'}}>
                {canManage && <span></span>}
                <span>Sản phẩm</span>
                <span style={{textAlign:'center'}}>Tồn HT</span>
                <span style={{textAlign:'center'}}>Tồn TT</span>
                <span style={{textAlign:'center'}}>Lệch</span>
                <span></span>
                <span>Trạng thái</span>
                <span style={{textAlign:'right'}}>Thao tác</span>
              </div>
            )}
            {/* filtered computed outside for checkbox header access */}
            {(()=>{
              const filtered=monthChecks.filter((c: any)=>{
                if (c.diff==null || c.diff===0) return false
                if (diffFilter==='neg' && c.diff>=0) return false
                if (diffFilter==='pos' && c.diff<=0) return false
                return true
              }).sort((a: any,b: any) => {
                const da = invSessions.find((s: any)=>s.id===a.session_id)?.date||''
                const db2 = invSessions.find((s: any)=>s.id===b.session_id)?.date||''
                return db2.localeCompare(da) || Math.abs(b.diff)-Math.abs(a.diff)
              })
              // Group by date
              const byDate: Record<string,any[]> = {}
              filtered.forEach((c: any) => {
                const d = invSessions.find((s: any)=>s.id===c.session_id)?.date||'—'
                if (!byDate[d]) byDate[d] = []
                byDate[d].push(c)
              })
              const dates = Object.keys(byDate).sort((a,b)=>b.localeCompare(a))

              if (filtered.length===0) return (
                <div style={{padding:'32px',textAlign:'center',color:T.light}}>
                  <div style={{fontSize:28,marginBottom:8}}>✅</div>
                  <div style={{fontSize:13}}>Không có mã nào lệch trong tháng này</div>
                </div>
              )

              const DIFF_CFG: any = {
                '':          {label:'⏳ Chưa xử lý',    color:T.red,    bg:T.redBg  },
                'found':     {label:'✅ Tìm được hàng',  color:T.green,  bg:T.greenBg},
                'reason':    {label:'🔍 Tìm được NN',    color:T.blue,   bg:T.blueBg },
                'no_reason': {label:'❌ Không tìm được', color:T.red,    bg:T.redBg  },
                'resolved':  {label:'✔️ Đã xử lý',       color:'#7C3AED',bg:'#EDE9FE'},
              }

              return dates.map((date: string) => {
                const dateItems = byDate[date]
                const dateIds   = dateItems.map((c: any) => c.id)
                const allDateSel = dateIds.every((id: string) => selectedChecks.has(id))
                const lech = dateItems.filter((c: any) => c.diff!==0).length
                return (
                  <div key={date}>
                    {/* ── Date group header ── */}
                    <div style={{display:'flex',alignItems:'center',gap:10,
                      padding:'8px 12px',background:T.bg,borderBottom:`1px solid ${T.border}`,
                      borderTop:`2px solid ${T.border}`,position:'sticky',top: mobile ? 48 : 0,zIndex:1}}>
                      {canManage && (
                        <input type="checkbox"
                          checked={allDateSel && dateIds.length>0}
                          onChange={() => setSelectedChecks(prev => {
                            const n = new Set(prev)
                            allDateSel ? dateIds.forEach((id: string) => n.delete(id))
                                       : dateIds.forEach((id: string) => n.add(id))
                            return n
                          })} style={{cursor:'pointer'}}/>
                      )}
                      <span style={{fontSize:12,fontWeight:700,color:T.dark}}>📅 {date}</span>
                      <span style={{fontSize:11,color:T.blue}}>{dateItems.length} mã lệch</span>
                      {lech>0 && <span style={{fontSize:11,color:T.red}}>⚠️ {lech} chưa xử lý</span>}
                    </div>
                    {/* ── Rows ── */}
                    {dateItems.map((c: any, i: number) => {
                      const dsc = DIFF_CFG[c.diff_status||''] || DIFF_CFG['']
                      const isSel = selectedChecks.has(c.id)
                      return (
                        <div key={c.id} style={{display:'grid',
                          gridTemplateColumns: canManage ? '28px 1fr 90px 60px 60px 60px 150px 120px' : '1fr 90px 60px 60px 60px 150px 120px',
                          padding:'8px 12px 8px 28px',gap:8,alignItems:'center',
                          borderBottom:i<dateItems.length-1?`1px solid ${T.border}`:'none',
                          borderLeft:`3px solid ${isSel?T.gold:T.border}`,
                          marginLeft:16,
                          background:isSel?T.goldBg:c.diff_status===''?(i%2===0?'#FFF5F5':'#FFF0F0'):(i%2===0?'#fff':T.rowAlt)}}>
                          {canManage && (
                            <input type="checkbox" checked={isSel}
                              onChange={() => setSelectedChecks(prev => {
                                const n = new Set(prev)
                                isSel ? n.delete(c.id) : n.add(c.id)
                                return n
                              })} style={{cursor:'pointer'}}/>
                          )}
                          <div>
                            <div style={{fontSize:12,fontWeight:500,color:T.dark,lineHeight:1.3}}>{c.product_name}</div>
                            <div style={{fontSize:10,color:T.light}}>{c.product_code}</div>
                          </div>
                          <span style={{fontSize:11,textAlign:'center',color:T.med}}>{c.system_qty}</span>
                          <span style={{fontSize:11,textAlign:'center',color:T.dark,fontWeight:600}}>{c.actual_qty}</span>
                          <span style={{fontSize:13,textAlign:'center',fontWeight:800,
                            color:c.diff>0?T.blue:T.red}}>{c.diff>0?'+':''}{c.diff}</span>
                          <div/>
                          <span style={{fontSize:10,padding:'2px 7px',borderRadius:20,
                            color:dsc.color,background:dsc.bg,whiteSpace:'nowrap'}}>{dsc.label}</span>
                          <div style={{display:'flex',flexDirection:'column',gap:3,alignItems:'flex-end'}}>
                            {canManage ? (
                              <>
                                <select value={c.diff_status||''} onChange={async e => {
                                  const val = e.target.value
                                  const now = new Date().toISOString()
                                  const upd: any = {diff_status:val}
                                  if (val) { upd.resolved_by = user.id; upd.resolved_at = now }
                                  await db.from('inventory_checks').update(upd).eq('id',c.id)
                                  updateCheck(c.id, upd)
                                }}
                                  style={{padding:'3px 6px',borderRadius:8,border:`1px solid ${T.border}`,
                                    fontSize:10,fontFamily:'inherit',color:T.dark,background:T.bg,cursor:'pointer'}}>
                                  <option value="">⏳ Chưa XL</option>
                                  <option value="found">✅ Tìm được hàng</option>
                                  <option value="reason">🔍 Tìm được NN</option>
                                  <option value="no_reason">❌ Không tìm được</option>
                                  <option value="resolved">✔️ Đã xử lý</option>
                                </select>
                                {/* Nút giao double-check */}
                                {c.diff_status === '' && (
                                  <DoubleCheckAssign
                                    check={c} allUsers={allUsers}
                                    onAssign={async (nvId: string) => {
                                      const upd = { double_check_by: nvId }
                                      await db.from('inventory_checks').update(upd).eq('id', c.id)
                                      updateCheck(c.id, upd)
                                    }}/>
                                )}
                                {c.double_check_by && (
                                  <div style={{fontSize:9,color:T.purple,textAlign:'right'}}>
                                    🔁 DC: {allUsers.find((u: any)=>u.id===c.double_check_by)?.name||'?'}
                                    {c.double_actual_qty!=null && ` → ${c.double_actual_qty}`}
                                  </div>
                                )}
                              </>
                            ) : (
                              <span style={{fontSize:10,padding:'2px 7px',borderRadius:20,
                                color:dsc.color,background:dsc.bg,whiteSpace:'nowrap'}}>{dsc.label}</span>
                            )}
                            {c.diff_status && c.resolved_by && (
                              <div style={{fontSize:9,color:T.light,textAlign:'right'}}>
                                {allUsers.find((u: any)=>u.id===c.resolved_by)?.name||'?'}
                              </div>
                            )}
                          </div>
                        </div>
                      )
                    })}
                  </div>
                )
              })
            })()}
          </div>
        </div>
      )}

      {/* ── TAB: CUỐI THÁNG ── */}
      {tab==='monthly' && (
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
          <div style={{display:'flex',gap:8,alignItems:'center',flexWrap:'wrap',marginBottom:4}}>
            <input type="month" value={monthFilter} onChange={e => setMonthFilter(e.target.value)}
              style={{padding:'6px 10px',border:`1px solid ${T.border}`,borderRadius:8,
                fontSize:12,fontFamily:'inherit',color:T.dark,background:'#fff', colorScheme:'light'}}/>
            <span style={{fontSize:12,color:T.light}}>Chỉ tính mã có trạng thái "Không tìm được nguyên nhân"</span>
          </div>
          {(() => {
            const noReason = monthChecks.filter((c: any) => c.diff_status==='no_reason' && c.diff!=null && c.diff!==0)
            const totalCost = noReason.reduce((s: number, c: any) => {
              const price = c.price_override ?? c.base_price ?? 0
              return s + Math.abs(c.diff||0) * price
            }, 0)
            return (
              <>
                {/* Summary cards */}
                <div style={{display:'grid',gridTemplateColumns:mobile?'1fr 1fr':'repeat(3,1fr)',gap:12}}>
                  {[
                    ['📦 SP không tìm được NN', noReason.length, T.red],
                    ['💰 Tổng tiền mất ước tính', totalCost.toLocaleString('vi-VN')+'đ', T.amber],
                    ['👥 Số NV phòng Kho', allUsers.filter((u: any)=>u.dept_id==='kho').length, T.blue],
                  ].map(([label,val,color]) => (
                    <Card key={label as string} style={{textAlign:'center',padding:'14px 12px'}}>
                      <div style={{fontSize:20,fontWeight:800,color:color as string}}>{val}</div>
                      <div style={{fontSize:11,color:T.light,marginTop:4}}>{label}</div>
                    </Card>
                  ))}
                </div>
                {/* Per-person cost */}
                {noReason.length>0 && (
                  <Card style={{padding:'12px 16px'}}>
                    <div style={{fontSize:12,fontWeight:700,color:T.dark,marginBottom:6}}>
                      💸 Mỗi NV Kho chịu trách nhiệm (chia đều):
                    </div>
                    <div style={{fontSize:22,fontWeight:800,color:T.red}}>
                      {allUsers.filter((u: any)=>u.dept_id==='kho').length>0
                        ? Math.round(totalCost/allUsers.filter((u: any)=>u.dept_id==='kho').length).toLocaleString('vi-VN')+'đ'
                        : '—'}
                    </div>
                  </Card>
                )}
                {/* Detail table */}
                <div style={{background:T.card,borderRadius:12,border:`1px solid ${T.border}`,overflow:'hidden',boxShadow:'0 1px 4px rgba(0,0,0,0.06)'}}>
                  {!mobile && (
                    <div style={{display:'grid',gridTemplateColumns:'100px 1fr 90px 60px 60px 80px 110px 120px',
                      padding:'8px 12px',background:T.bg,borderBottom:`2px solid ${T.border}`,
                      fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8}}>
                      <span>Ngày KK</span><span>Sản phẩm</span><span>Mã SP</span>
                      <span style={{textAlign:'center'}}>Lệch</span>
                      <span style={{textAlign:'center'}}>Giá vốn</span>
                      <span style={{textAlign:'right'}}>Tiền mất</span>
                      <span>Override giá</span>
                      <span style={{textAlign:'center'}}>Người KK</span>
                    </div>
                  )}
                  {noReason.length===0
                    ? <div style={{padding:'32px',textAlign:'center',color:T.green,fontSize:13}}>
                        ✅ Không có mã nào ở trạng thái "Không tìm được nguyên nhân"
                      </div>
                    : noReason.map((c: any, i: number) => {
                        const sess     = invSessions.find((s: any) => s.id===c.session_id)
                        const price    = c.price_override ?? c.base_price ?? 0
                        const lostVal  = Math.abs(c.diff||0) * price
                        const checker  = allUsers.find((u: any) => u.id===c.assigned_to)
                        return (
                          <div key={c.id} style={{display:mobile?'block':'grid',
                            gridTemplateColumns:'100px 1fr 90px 60px 60px 80px 110px 120px',
                            padding:'9px 12px',gap:8,alignItems:'center',
                            borderBottom:i<noReason.length-1?`1px solid ${T.border}`:'none',
                            background:i%2===0?'#fff':T.rowAlt}}>
                            <span style={{fontSize:11,color:T.light}}>{sess?.date||'—'}</span>
                            <span style={{fontSize:12,fontWeight:500,color:T.dark}}>{c.product_name}</span>
                            <span style={{fontSize:10,color:T.light}}>{c.product_code}</span>
                            <span style={{fontSize:13,fontWeight:800,textAlign:'center',
                              color:c.diff>0?T.blue:T.red}}>{c.diff>0?'+':''}{c.diff}</span>
                            <span style={{fontSize:11,textAlign:'center',color:T.med}}>
                              {(c.base_price||0).toLocaleString()}đ
                            </span>
                            <span style={{fontSize:12,fontWeight:700,textAlign:'right',color:T.red}}>
                              {lostVal>0?lostVal.toLocaleString('vi-VN')+'đ':'—'}
                            </span>
                            {/* Override giá — admin only */}
                            <div>
                              {perm.viewAllDashboard ? (
                                <input type="number" defaultValue={c.price_override||''}
                                  placeholder={String(c.base_price||0)}
                                  onBlur={async e => {
                                    const v = e.target.value ? Number(e.target.value) : null
                                    await db.from('inventory_checks').update({price_override:v}).eq('id',c.id)
                                    updateCheck(c.id, {price_override:v})
                                  }}
                                  style={{width:'100%',padding:'4px 7px',border:`1px solid ${T.border}`,
                                    borderRadius:7,fontSize:11,fontFamily:'inherit',color:T.dark,background:'#fff'}}/>
                              ) : (
                                <span style={{fontSize:11,color:c.price_override?T.blue:T.light}}>
                                  {c.price_override?c.price_override.toLocaleString()+'đ':'—'}
                                </span>
                              )}
                            </div>
                            <span style={{fontSize:11,textAlign:'center',color:T.med}}>{checker?.name||'—'}</span>
                          </div>
                        )
                      })
                  }
                  {noReason.length>0 && (
                    <div style={{padding:'10px 12px',background:T.redBg,borderTop:`2px solid ${T.red}`,
                      display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                      <span style={{fontSize:13,fontWeight:700,color:T.red}}>TỔNG TIỀN MẤT THÁNG {fm}/{fy}</span>
                      <span style={{fontSize:16,fontWeight:800,color:T.red}}>
                        {totalCost.toLocaleString('vi-VN')}đ
                      </span>
                    </div>
                  )}
                </div>
              </>
            )
          })()}
        </div>
      )}

      {/* ── TAB: MÃ KHÔNG KK ── */}
      {tab==='excluded' && (
        <ExcludedTab products={products} excludedCodes={excludedCodes}
          user={user} mobile={mobile}
          onAdd={(code: string) => setExcludedCodes(prev => new Set([...prev, code]))}
          onRemove={(code: string) => setExcludedCodes(prev => {const n=new Set(prev);n.delete(code);return n})}/>
      )}

      {/* ── Modal phân chia mã ── */}
      {showAssign && openSession && (
        <AssignModal session={openSession} products={products} allUsers={allUsers}
          user={user} checks={checks} onAssigned={(newChecks: any[]) => {
            setChecks(prev => [...prev, ...newChecks])
            setInvSessions(prev => prev.map((s: any) => s.id===openSession.id
              ? {...s, total_assigned:(s.total_assigned||0)+newChecks.length} : s))
          }} onClose={() => setShowAssign(false)}/>
      )}

      {/* ── Wizard tạo phiên ── */}
      {showWizard && (
        <SessionCreateWizard products={products} checks={checks} allUsers={allUsers}
          user={user} excludedCodes={excludedCodes}
          lastKvSync={lastKvSync}
          onSyncNow={syncKiotViet}
          kvSyncing={kvSyncing}
          onCreated={(newS: any, newChecks: any[]) => {
            setInvSessions(prev => [newS, ...prev])
            setChecks(prev => [...prev, ...newChecks])
            setShowWizard(false)
          }}
          onClose={() => setShowWizard(false)}/>
      )}

      {/* Confirm delete modal — yêu cầu gõ "XÓA" + ghi audit log */}
      {confirmDelete && (
        <ConfirmDeleteModal
          title={confirmDelete.title}
          message={confirmDelete.message}
          detail={confirmDelete.detail}
          onConfirm={confirmDelete.action}
          onCancel={() => setConfirmDelete(null)}
        />
      )}
    </div>
  )
}

// ── AssignModal — phân chia mã KK cho NV ────────────────
function AssignModal({ session, products, allUsers, user, checks, onAssigned, onClose }: any) {
  const khoUsers = allUsers.filter((u: any) => u.dept_id==='kho')
  const [selectedNVs, setSelectedNVs] = useState<string[]>([])
  const [targetCount, setTargetCount] = useState(150)
  const [step, setStep] = useState<'select_nv'|'preview'>('select_nv')

  const existingCodes = new Set(
    checks.filter((c: any) => c.session_id===session.id).map((c: any) => c.product_code)
  )
  const checkedHistory = new Set(checks.map((c: any) => c.product_code))

  // Generate suggested product list: ưu tiên chưa KK, chia 3 nhóm tồn
  const available = products.filter((p: any) =>
    p.stock > 0 && p.active && !existingCodes.has(p.code)
  ).sort((a: any, b: any) => {
    const aNew = !checkedHistory.has(a.code)
    const bNew = !checkedHistory.has(b.code)
    if (aNew && !bNew) return -1
    if (!aNew && bNew) return 1
    return 0
  })

  const highStock = available.filter((p: any) => p.stock >= 100)
  const midStock  = available.filter((p: any) => p.stock >= 20 && p.stock < 100)
  const lowStock  = available.filter((p: any) => p.stock > 0 && p.stock < 20)

  const each = Math.floor(targetCount / 3)
  const selected3 = [
    ...highStock.slice(0, each).map((p: any) => ({...p, _group:'Tồn nhiều (≥100)'})),
    ...midStock.slice(0,  each).map((p: any) => ({...p, _group:'Tồn vừa (20-99)'})),
    ...lowStock.slice(0, targetCount - each*2).map((p: any) => ({...p, _group:'Tồn ít (<20)'})),
  ]

  // Assign algorithm: interleave across NVs
  const buildAssignment = () => {
    if (selectedNVs.length === 0) return []
    const shuffled = [...selected3]
    // Distribute round-robin across NVs
    return shuffled.map((prod, idx) => {
      const nvId = selectedNVs[idx % selectedNVs.length]
      return {
        id: `chk_${session.id}_${prod.code}_${Date.now()}_${idx}`,
        session_id: session.id, product_code: prod.code,
        product_name: prod.name, system_qty: prod.stock,
        actual_qty: null, diff: null,
        base_price: prod.base_price || 0,
        assigned_to: nvId, status:'pending',
        diff_status:'', diff_note:'',
        checked_at:'', created_at: new Date().toISOString()
      }
    })
  }

  const preview = step==='preview' ? buildAssignment() : []
  const perNV   = selectedNVs.map(id => ({
    nv: allUsers.find((u: any) => u.id===id),
    count: preview.filter((c: any) => c.assigned_to===id).length,
    high: preview.filter((c: any) => c.assigned_to===id && (products.find((p: any)=>p.code===c.product_code)?.stock||0)>=100).length,
    mid:  preview.filter((c: any) => c.assigned_to===id && (products.find((p: any)=>p.code===c.product_code)?.stock||0)>=20 && (products.find((p: any)=>p.code===c.product_code)?.stock||0)<100).length,
    low:  preview.filter((c: any) => c.assigned_to===id && (products.find((p: any)=>p.code===c.product_code)?.stock||0)<20).length,
  }))

  const doAssign = async () => {
    const newChecks = buildAssignment()
    await db.from('inventory_checks').insert(newChecks)
    onAssigned(newChecks)
    onClose()
  }

  return (
    <Modal open={true} onClose={onClose} title="👥 Phân chia mã kiểm kê" wide>
      {step==='select_nv' ? (
        <>
          {/* Target count */}
          <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:12,alignItems:'end',marginBottom:16}}>
            <Inp label="Số mã kiểm kê (chia theo 3 nhóm tồn)"
              type="number" value={String(targetCount)}
              onChange={(v) => setTargetCount(Math.min(Number(v)||150, available.length))}/>
            <div style={{fontSize:11,color:T.light,paddingBottom:12}}>
              Còn: {available.length} SP hợp lệ
            </div>
          </div>

          {/* Preview 3 groups */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:8,marginBottom:16}}>
            {[
              {label:'🔴 Tồn nhiều (≥100)',   count:Math.min(each, highStock.length),   total:highStock.length,  color:T.red},
              {label:'🟡 Tồn vừa (20-99)',    count:Math.min(each, midStock.length),    total:midStock.length,   color:T.amber},
              {label:'🟢 Tồn ít (<20)',       count:Math.min(targetCount-each*2, lowStock.length), total:lowStock.length, color:T.green},
            ].map(g => (
              <div key={g.label} style={{padding:'10px',background:T.bg,borderRadius:10,
                border:`1px solid ${T.border}`,textAlign:'center'}}>
                <div style={{fontSize:11,color:T.med,marginBottom:4}}>{g.label}</div>
                <div style={{fontSize:18,fontWeight:800,color:g.color}}>{g.count}</div>
                <div style={{fontSize:10,color:T.light}}>/ {g.total} có thể</div>
              </div>
            ))}
          </div>

          {/* Select NVs */}
          <div style={{marginBottom:14}}>
            <div style={{fontSize:12,fontWeight:600,color:T.dark,marginBottom:8}}>Chọn nhân viên kiểm kê:</div>
            <div style={{display:'flex',flexDirection:'column',gap:6}}>
              {khoUsers.map((u: any) => {
                const sel = selectedNVs.includes(u.id)
                return (
                  <label key={u.id} style={{display:'flex',alignItems:'center',gap:10,
                    padding:'8px 12px',borderRadius:10,cursor:'pointer',
                    background:sel?T.goldBg:T.bg,border:`1px solid ${sel?T.gold:T.border}`}}>
                    <input type="checkbox" checked={sel}
                      onChange={() => setSelectedNVs(prev =>
                        sel ? prev.filter(id => id!==u.id) : [...prev,u.id]
                      )}/>
                    <span style={{fontSize:13,fontWeight:sel?700:400,color:sel?T.goldText:T.dark}}>
                      {u.name}
                    </span>
                    <span style={{fontSize:11,color:T.light}}>{u.position_name||''}</span>
                  </label>
                )
              })}
            </div>
          </div>

          {selectedNVs.length>0 && (
            <div style={{padding:'8px 12px',background:T.blueBg,borderRadius:8,
              fontSize:12,color:T.blue,marginBottom:14}}>
              💡 {selected3.length} mã sẽ chia cho {selectedNVs.length} NV — mỗi người ~{Math.ceil(selected3.length/selectedNVs.length)} mã (mix đều 3 nhóm)
            </div>
          )}

          <div style={{display:'flex',justifyContent:'flex-end',gap:10}}>
            <GoldBtn outline small onClick={onClose}>Hủy</GoldBtn>
            <GoldBtn small disabled={selectedNVs.length===0||selected3.length===0}
              onClick={() => setStep('preview')}>Xem trước →</GoldBtn>
          </div>
        </>
      ) : (
        <>
          {/* Preview assignment */}
          <div style={{marginBottom:14}}>
            <div style={{fontSize:13,fontWeight:700,color:T.dark,marginBottom:10}}>
              Phân chia {selected3.length} mã cho {selectedNVs.length} nhân viên:
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:8}}>
              {perNV.map(({nv,count,high,mid,low}) => (
                <div key={nv?.id} style={{display:'flex',alignItems:'center',gap:12,
                  padding:'10px 14px',background:T.bg,borderRadius:10,border:`1px solid ${T.border}`}}>
                  <div style={{width:32,height:32,borderRadius:'50%',background:T.gold,
                    display:'flex',alignItems:'center',justifyContent:'center',
                    color:'#fff',fontSize:11,fontWeight:700,flexShrink:0}}>{nv?.ini||'?'}</div>
                  <div style={{flex:1}}>
                    <div style={{fontSize:13,fontWeight:700,color:T.dark}}>{nv?.name||'?'}</div>
                    <div style={{fontSize:11,color:T.light}}>
                      🔴 {high} mã tồn nhiều · 🟡 {mid} mã tồn vừa · 🟢 {low} mã tồn ít
                    </div>
                  </div>
                  <div style={{fontSize:18,fontWeight:800,color:T.blue}}>{count}</div>
                </div>
              ))}
            </div>
          </div>

          <div style={{display:'flex',justifyContent:'space-between',gap:10}}>
            <GoldBtn outline small onClick={() => setStep('select_nv')}>← Quay lại</GoldBtn>
            <GoldBtn small onClick={doAssign}>✅ Xác nhận phân chia</GoldBtn>
          </div>
        </>
      )}
    </Modal>
  )
}

// ── DoubleCheckAssign — nút giao KK lại cho NV khác ─────────
function DoubleCheckAssign({ check, allUsers, onAssign }: any) {
  const [open, setOpen] = useState(false)
  const khoUsers = allUsers.filter((u: any) => u.dept_id === 'kho' && u.id !== check.assigned_to && u.active !== false)

  if (khoUsers.length === 0) return null

  return (
    <div style={{ position:'relative' }}>
      <button onClick={() => setOpen(v => !v)}
        style={{ padding:'2px 8px', borderRadius:8, border:`1px solid ${T.purple}`,
          background: check.double_check_by ? '#EDE9FE' : 'transparent',
          color:T.purple, cursor:'pointer', fontSize:9, fontFamily:'inherit',
          whiteSpace:'nowrap' }}>
        {check.double_check_by ? '🔁 Đổi DC' : '🔁 Giao DC'}
      </button>
      {open && (
        <div style={{ position:'absolute', right:0, top:'100%', marginTop:4,
          background:'#fff', border:`1px solid ${T.border}`, borderRadius:10,
          boxShadow:'0 4px 16px rgba(0,0,0,0.12)', zIndex:100, minWidth:160, overflow:'hidden' }}>
          <div style={{ padding:'6px 10px', fontSize:9, fontWeight:700, color:T.light,
            textTransform:'uppercase', letterSpacing:.5, background:T.bg,
            borderBottom:`1px solid ${T.border}` }}>
            Giao KK lại cho:
          </div>
          {khoUsers.map((u: any) => (
            <div key={u.id} onClick={() => { onAssign(u.id); setOpen(false) }}
              style={{ padding:'8px 12px', cursor:'pointer', fontSize:12, color:T.dark,
                borderBottom:`1px solid ${T.border}`,
                background: check.double_check_by === u.id ? '#EDE9FE' : '#fff' }}
              onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
              onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = check.double_check_by === u.id ? '#EDE9FE' : '#fff' }}>
              {u.name}
              {check.double_check_by === u.id && <span style={{ fontSize:9, color:T.purple, marginLeft:4 }}>✓ Đang DC</span>}
            </div>
          ))}
          <div onClick={() => { onAssign(''); setOpen(false) }}
            style={{ padding:'6px 12px', cursor:'pointer', fontSize:11, color:T.light,
              borderTop:`1px solid ${T.border}` }}>
            ✕ Hủy giao DC
          </div>
        </div>
      )}
    </div>
  )
}

// ── DoubleCheckNotice — hiện trong MobileCheckInput khi có mã cần double-check ──
function DoubleCheckNotice({ checks, sessionId, userId }: any) {
  const mine = checks.filter((c: any) =>
    c.session_id===sessionId && c.double_check_by===userId && c.double_actual_qty==null
  )
  if (mine.length===0) return null
  return (
    <div style={{padding:'10px 14px',background:T.amberBg,borderRadius:10,
      border:`1.5px solid ${T.amber}`,marginBottom:12}}>
      <div style={{fontSize:12,fontWeight:700,color:T.amber,marginBottom:4}}>
        ⚡ Bạn có {mine.length} mã cần kiểm kê lại (double-check)
      </div>
      <div style={{fontSize:11,color:T.med}}>
        Các mã này đã được người khác kiểm kê nhưng phát hiện lệch — cần bạn xác nhận lại.
      </div>
    </div>
  )
}

// ── InvMonitorView — QM xem tiến độ real-time ─────────────
function InvMonitorView({ session, checks, allUsers, user, products, onStartMobile, myChecks }: any) {
  const sessChecks = checks.filter((c: any) => c.session_id === session.id)
  const total      = sessChecks.length
  const done       = sessChecks.filter((c: any) => c.actual_qty != null).length
  const lech       = sessChecks.filter((c: any) => c.diff != null && c.diff !== 0).length

  // Per-NV stats
  const nvIds = [...new Set(sessChecks.map((c: any) => c.assigned_to))].filter(Boolean)
  const perNV = nvIds.map((id: any) => {
    const nvChecks = sessChecks.filter((c: any) => c.assigned_to === id)
    const nv = allUsers.find((u: any) => u.id === id)
    return {
      nv, id,
      total:  nvChecks.length,
      done:   nvChecks.filter((c: any) => c.actual_qty != null).length,
      lech:   nvChecks.filter((c: any) => c.diff != null && c.diff !== 0).length,
    }
  }).sort((a: any, b: any) => b.done/Math.max(b.total,1) - a.done/Math.max(a.total,1))

  // My checks (if manager is also a checker)
  const myPending = myChecks.filter((c: any) => c.actual_qty == null).length

  return (
    <div style={{display:'flex',flexDirection:'column',gap:12}}>
      {/* Overall progress */}
      <Card>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10,flexWrap:'wrap',gap:8}}>
          <div style={{fontSize:13,fontWeight:700,color:T.dark}}>
            📋 Phiên {session.date} {session.note&&`· ${session.note}`}
          </div>
          <div style={{display:'flex',gap:12}}>
            <span style={{fontSize:12,color:T.blue}}>✅ {done}/{total} mã</span>
            {lech>0 && <span style={{fontSize:12,color:T.red,fontWeight:700}}>⚠️ {lech} lệch</span>}
          </div>
        </div>
        <div style={{height:10,background:T.border,borderRadius:5,marginBottom:6}}>
          <div style={{height:'100%',borderRadius:5,
            background:`linear-gradient(90deg,${T.green},${T.teal})`,
            width:`${total>0?done*100/total:0}%`,transition:'width .5s'}}/>
        </div>
        <div style={{fontSize:11,color:T.light}}>{total>0?Math.round(done*100/total):0}% hoàn thành</div>
      </Card>

      {/* Per-NV table */}
      <Card style={{padding:0,overflow:'hidden'}}>
        <div style={{padding:'10px 14px',background:T.goldBg,borderBottom:`1px solid ${T.goldBorder}`,
          fontSize:12,fontWeight:700,color:T.goldText}}>👥 Tiến độ từng nhân viên</div>
        {perNV.length===0
          ? <div style={{padding:'20px',textAlign:'center',color:T.light,fontSize:12}}>
              Chưa phân chia mã cho nhân viên
            </div>
          : perNV.map(({nv,id,total:t,done:d,lech:l}: any) => {
              const pct = t>0?Math.round(d*100/t):0
              const statusColor = pct===100?T.green:pct>50?T.amber:T.red
              return (
                <div key={id} style={{padding:'10px 14px',borderBottom:`1px solid ${T.border}`,
                  display:'flex',alignItems:'center',gap:12}}>
                  <div style={{width:32,height:32,borderRadius:'50%',
                    background:DEPT_COLOR['kho'],flexShrink:0,
                    display:'flex',alignItems:'center',justifyContent:'center',
                    color:'#fff',fontSize:10,fontWeight:700}}>{nv?.ini||'?'}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12,fontWeight:600,color:T.dark,marginBottom:4}}>
                      {nv?.name||'NV không xác định'}
                    </div>
                    <div style={{height:6,background:T.border,borderRadius:3}}>
                      <div style={{height:'100%',borderRadius:3,background:statusColor,
                        width:`${pct}%`,transition:'width .3s'}}/>
                    </div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    <div style={{fontSize:13,fontWeight:700,color:statusColor}}>{d}/{t}</div>
                    {l>0 && <div style={{fontSize:10,color:T.red}}>⚠️ {l} lệch</div>}
                  </div>
                </div>
              )
            })
        }
      </Card>

      {/* Recent checks live feed */}
      <Card style={{padding:0,overflow:'hidden'}}>
        <div style={{padding:'10px 14px',background:T.bg,borderBottom:`1px solid ${T.border}`,
          fontSize:12,fontWeight:700,color:T.dark}}>🔴 Live — Mã vừa kiểm kê</div>
        {sessChecks.filter((c: any)=>c.actual_qty!=null)
          .sort((a: any,b: any)=>(b.checked_at||'').localeCompare(a.checked_at||''))
          .slice(0,15)
          .map((c: any, i: number) => {
            const nv = allUsers.find((u: any) => u.id===c.assigned_to)
            const hasDiff = c.diff!=null && c.diff!==0
            return (
              <div key={c.id} style={{display:'flex',alignItems:'center',gap:10,
                padding:'8px 14px',borderBottom:i<14?`1px solid ${T.border}`:'none',
                background:hasDiff?'#FFF5F5':i%2===0?'#fff':T.rowAlt}}>
                <span style={{fontSize:10,color:T.light,flexShrink:0,width:45}}>
                  {c.checked_at?new Date(c.checked_at).toLocaleTimeString('vi-VN',{hour:'2-digit',minute:'2-digit'}):'—'}
                </span>
                <span style={{fontSize:11,color:T.light,flexShrink:0,width:80,
                  overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                  {nv?.name||'?'}
                </span>
                <span style={{flex:1,fontSize:11,color:T.dark,
                  overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                  {c.product_name}
                </span>
                <span style={{fontSize:12,fontWeight:700,flexShrink:0,
                  color:!hasDiff?T.green:c.diff>0?T.blue:T.red}}>
                  {!hasDiff?'✓ OK':c.diff>0?`+${c.diff}`:c.diff}
                </span>
              </div>
            )
          })
        }
        {sessChecks.filter((c: any)=>c.actual_qty!=null).length===0 && (
          <div style={{padding:'24px',textAlign:'center',color:T.light,fontSize:12}}>
            Chưa có mã nào được kiểm kê
          </div>
        )}
      </Card>

      {/* If manager also has checks */}
      {myPending > 0 && (
        <button onClick={onStartMobile}
          style={{padding:'12px',borderRadius:12,border:'none',
            background:`linear-gradient(135deg,${T.green},${T.teal})`,
            color:'#fff',cursor:'pointer',fontFamily:'inherit',fontSize:13,fontWeight:700}}>
          📱 Bắt đầu KK phần của bạn ({myPending} mã)
        </button>
      )}
    </div>
  )
}

// ── SessionCreateWizard — 3-step wizard ──────────────────
// ── Helper: kiểm tra sync có quá cũ không (> 4 giờ) ──
function isSyncTooOld(lastKvSync: string): boolean {
  if (!lastKvSync) return true  // chưa sync lần nào → chặn
  const ageMs = Date.now() - new Date(lastKvSync).getTime()
  return ageMs > 4 * 3600 * 1000  // 4 giờ
}

// ── Banner cảnh báo tuổi sync ──
function SyncAgeBanner({ lastKvSync, onSyncNow, kvSyncing }: any) {
  if (!lastKvSync) {
    return (
      <div style={{ padding:'12px 14px', marginBottom:12, borderRadius:10,
        background:T.redBg, border:`2px solid ${T.red}` }}>
        <div style={{ fontSize:13, fontWeight:800, color:T.red, marginBottom:6 }}>
          🚨 CHƯA SYNC DỮ LIỆU TỪ KIOTVIET
        </div>
        <div style={{ fontSize:11, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
          Bắt buộc phải sync trước khi tạo phiên kiểm kê.
        </div>
        <button onClick={onSyncNow} disabled={kvSyncing}
          style={{ padding:'7px 14px', borderRadius:8, border:'none',
            background:T.red, color:'#fff', cursor:kvSyncing?'wait':'pointer',
            fontFamily:'inherit', fontSize:12, fontWeight:700 }}>
          {kvSyncing ? '⏳ Đang sync...' : '🔄 Sync ngay từ KiotViet'}
        </button>
      </div>
    )
  }

  const ageMs  = Date.now() - new Date(lastKvSync).getTime()
  const ageMin = Math.floor(ageMs / 60000)
  const ageHr  = Math.floor(ageMs / 3600000)
  const ageTxt = ageHr >= 1 ? `${ageHr}h ${ageMin % 60}p` : `${ageMin} phút`
  const syncedAt = new Date(lastKvSync).toLocaleString('vi-VN', {
    day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit'
  })

  // < 30 phút → xanh, OK
  if (ageMs < 30 * 60 * 1000) {
    return (
      <div style={{ padding:'10px 14px', marginBottom:12, borderRadius:10,
        background:T.greenBg, border:`1px solid ${T.green}`, fontSize:12, color:T.green }}>
        ✓ Data KiotViet mới — sync cách đây {ageTxt} ({syncedAt})
      </div>
    )
  }

  // 30 phút - 4 giờ → vàng, nên sync
  if (ageMs < 4 * 3600 * 1000) {
    return (
      <div style={{ padding:'12px 14px', marginBottom:12, borderRadius:10,
        background:T.amberBg, border:`2px solid ${T.amber}` }}>
        <div style={{ fontSize:13, fontWeight:700, color:T.amber, marginBottom:4 }}>
          ⚠️ Data sync cách đây {ageTxt}
        </div>
        <div style={{ fontSize:11, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
          Nên sync lại trước khi tạo phiên để đảm bảo số tồn chính xác. Lần sync cuối: {syncedAt}.
        </div>
        <button onClick={onSyncNow} disabled={kvSyncing}
          style={{ padding:'6px 14px', borderRadius:8, border:`1px solid ${T.amber}`,
            background:'#fff', color:T.amber, cursor:kvSyncing?'wait':'pointer',
            fontFamily:'inherit', fontSize:12, fontWeight:700 }}>
          {kvSyncing ? '⏳ Đang sync...' : '🔄 Sync lại'}
        </button>
      </div>
    )
  }

  // > 4 giờ → đỏ, BẮT BUỘC sync
  return (
    <div style={{ padding:'12px 14px', marginBottom:12, borderRadius:10,
      background:T.redBg, border:`2px solid ${T.red}` }}>
      <div style={{ fontSize:13, fontWeight:800, color:T.red, marginBottom:4 }}>
        🚨 DATA QUÁ CŨ — Sync cách đây {ageTxt}
      </div>
      <div style={{ fontSize:11, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
        Bắt buộc phải sync trước khi tạo phiên (nút "Tiếp theo" đã bị khóa). Lần sync cuối: {syncedAt}.
      </div>
      <button onClick={onSyncNow} disabled={kvSyncing}
        style={{ padding:'7px 14px', borderRadius:8, border:'none',
          background:T.red, color:'#fff', cursor:kvSyncing?'wait':'pointer',
          fontFamily:'inherit', fontSize:12, fontWeight:700 }}>
        {kvSyncing ? '⏳ Đang sync...' : '🔄 Sync ngay từ KiotViet'}
      </button>
    </div>
  )
}

function SessionCreateWizard({ products, checks, allUsers, user, excludedCodes, onCreated, onClose, lastKvSync, onSyncNow, kvSyncing }: any) {
  const [step, setStep] = useState(1)
  const [date, setDate] = useState(new Date().toISOString().split('T')[0])
  const [note, setNote] = useState('')
  const [selected, setSelected] = useState<Set<string>>(new Set())
  const [sortBy, setSortBy] = useState<'priority'|'stock_desc'|'stock_asc'|'alpha'>('priority')
  const [showFilter, setShowFilter] = useState<'all'|'selected'|'unselected'>('all')
  const [searchQ, setSearchQ] = useState('')
  const [selectedNVs, setSelectedNVs] = useState<string[]>([])
  const [page, setPage] = useState(0)
  const [kkImportErrors, setKkImportErrors] = useState<string[]>([])
  const PAGE_SIZE = 80

  const khoUsers = allUsers.filter((u: any) => u.dept_id==='kho')
  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
  const checkedHistory = new Set(checks.map((c: any) => c.product_code))
  const lastChecked: Record<string,string> = {}
  checks.forEach((c: any) => {
    if (!lastChecked[c.product_code] || c.checked_at > lastChecked[c.product_code])
      lastChecked[c.product_code] = c.checked_at
  })
  const checkCount: Record<string,number> = {}
  checks.forEach((c: any) => { checkCount[c.product_code] = (checkCount[c.product_code]||0)+1 })

  // Generate initial suggestions on step change to 2
  useEffect(() => {
    if (step !== 2 || selected.size > 0) return
    const avail = products.filter((p: any) => p.stock > 0 && p.active && !excludedCodes.has(p.code))
    const highS = avail.filter((p: any) => p.stock >= 100 && !checkedHistory.has(p.code)).slice(0,50)
    const midS  = avail.filter((p: any) => p.stock >= 20 && p.stock < 100 && !checkedHistory.has(p.code)).slice(0,50)
    const lowS  = avail.filter((p: any) => p.stock > 0 && p.stock < 20 && !checkedHistory.has(p.code)).slice(0,50)
    const extras = avail.filter((p: any) => checkedHistory.has(p.code))
      .sort((a: any,b: any) => (lastChecked[a.code]||'').localeCompare(lastChecked[b.code]||''))
    const total150 = [...highS, ...midS, ...lowS]
    const remaining = 150 - total150.length
    if (remaining > 0) total150.push(...extras.slice(0, remaining))
    setSelected(new Set(total150.map((p: any) => p.code).slice(0,150)))
  }, [step])

  // Import Excel for product selection — validate Mã SP vs products
  const importExcelCodes = async (file: File) => {
    const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
    const buf  = await file.arrayBuffer()
    const wb   = xlsx.read(buf, {type:'array'})
    const ws   = wb.Sheets[wb.SheetNames[0]]
    const rows: any[] = xlsx.utils.sheet_to_json(ws, {header:1, defval:''})
    const dataRows = rows.slice(1).filter((r: any[]) => r[0] || r[1])
    const errors: string[] = []
    const validCodes = new Set<string>()
    dataRows.forEach((r: any[], i: number) => {
      const codeRaw = String(r[0]||'').trim()
      const nameRaw = String(r[1]||'').trim()
      const lineNum = i + 2
      if (!codeRaw && !nameRaw) return
      const prod = products.find((p: any) =>
        (codeRaw && p.code.toUpperCase() === codeRaw.toUpperCase()) ||
        (nameRaw && p.name.toLowerCase() === nameRaw.toLowerCase())
      )
      if (!prod) {
        errors.push(`Dòng ${lineNum}: Mã "${codeRaw||'?'}" / Tên "${nameRaw||'?'}" không tồn tại. Vui lòng nhập đúng Mã SP hoặc Tên SP theo KiotViet.`)
        return
      }
      validCodes.add(prod.code)
    })
    setKkImportErrors(errors)
    if (errors.length === 0) setSelected(prev => new Set([...prev, ...validCodes]))
  }

  // Download file mẫu KK (Mã SP + Tên SP)
  const downloadKKTemplate = async () => {
    const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
    const rows: any[][] = [['Mã SP *', 'Tên SP']]
    if (selected.size > 0) {
      products.filter((p: any) => selected.has(p.code)).forEach((p: any) => rows.push([p.code, p.name]))
    } else {
      rows.push(['(Nhập Mã SP hoặc Tên SP theo đúng KiotViet)', ''])
    }
    const ws = xlsx.utils.aoa_to_sheet(rows)
    ws['!cols'] = [{wch:20},{wch:50}]
    const wb = xlsx.utils.book_new()
    xlsx.utils.book_append_sheet(wb, ws, 'Danh Sach KK')
    xlsx.writeFile(wb, 'mau_danh_sach_KK.xlsx')
  }

  // Filtered + sorted product list
  const filteredProds = products.filter((p: any) => {
    if (excludedCodes.has(p.code)) return showFilter === 'all' ? false : false
    if (showFilter === 'selected' && !selected.has(p.code)) return false
    if (showFilter === 'unselected' && selected.has(p.code)) return false
    if (searchQ) {
      const q = norm(searchQ)
      return norm(p.name+' '+p.code).includes(q)
    }
    return p.stock >= 0
  }).sort((a: any, b: any) => {
    if (sortBy === 'stock_desc') return (b.stock||0) - (a.stock||0)
    if (sortBy === 'stock_asc')  return (a.stock||0) - (b.stock||0)
    if (sortBy === 'alpha')      return (a.name||'').localeCompare(b.name||'')
    // priority: never checked first, then least recently checked, then by stock
    const aNew = !checkedHistory.has(a.code), bNew = !checkedHistory.has(b.code)
    if (aNew && !bNew) return -1
    if (!aNew && bNew) return 1
    return (lastChecked[a.code]||'').localeCompare(lastChecked[b.code]||'')
  })
  const pagedProds = filteredProds.slice(page*PAGE_SIZE, (page+1)*PAGE_SIZE)
  const totalPages = Math.ceil(filteredProds.length / PAGE_SIZE)

  // Build assignment for preview
  const selectedArr = products.filter((p: any) => selected.has(p.code))
  const each = Math.floor(selectedArr.length / Math.max(selectedNVs.length,1))
  const perNVPreview = selectedNVs.map((id, idx) => {
    const nv = allUsers.find((u: any) => u.id===id)
    return { nv, count: idx < selectedArr.length % selectedNVs.length ? each+1 : each }
  })

  const doCreate = async () => {
    const sid = 'sess_'+Date.now()
    const now = new Date().toISOString()
    const newS = { id:sid, date, note, status:'open',
      total_assigned:selectedArr.length, total_checked:0,
      created_by:user.id, created_at:now }
    await db.from('inventory_sessions').insert(newS)
    // Build checks with assignment
    const newChecks: any[] = []
    selectedArr.forEach((prod: any, idx: number) => {
      const nvId = selectedNVs.length > 0 ? selectedNVs[idx % selectedNVs.length] : user.id
      newChecks.push({
        id:`chk_${sid}_${prod.code}_${idx}`,
        session_id:sid, product_code:prod.code, product_name:prod.name,
        system_qty:prod.stock, actual_qty:null, diff:null,
        base_price:prod.base_price||0, assigned_to:nvId,
        status:'pending', diff_status:'', diff_note:'',
        checked_at:'', created_at:now
      })
    })
    if (newChecks.length > 0) await db.from('inventory_checks').insert(newChecks)
    onCreated(newS, newChecks)
  }

  // Full screen overlay
  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.6)',zIndex:2000,
      display:'flex',alignItems:'stretch',justifyContent:'center',padding:'20px'}}>
      <div style={{background:'#fff',borderRadius:16,width:'100%',maxWidth:900,
        display:'flex',flexDirection:'column',maxHeight:'100%',overflow:'hidden'}}>

        {/* Header */}
        <div style={{padding:'16px 20px',borderBottom:`1px solid ${T.border}`,
          display:'flex',alignItems:'center',gap:12,flexShrink:0}}>
          <div style={{flex:1}}>
            <div style={{fontSize:14,fontWeight:700,color:T.dark}}>
              {step===1?'📋 Tạo phiên kiểm kê mới':step===2?`📦 Chọn sản phẩm (${selected.size} đã chọn)`:'👥 Phân chia & Xác nhận'}
            </div>
            <div style={{display:'flex',gap:8,marginTop:6}}>
              {[1,2,3].map(s => (
                <span key={s} style={{width:24,height:24,borderRadius:'50%',
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize:11,fontWeight:700,
                  background:step===s?T.gold:step>s?T.green:T.border,
                  color:step>=s?'#fff':T.light}}>{step>s?'✓':s}</span>
              ))}
            </div>
          </div>
          <button onClick={onClose}
            style={{background:'none',border:'none',fontSize:20,cursor:'pointer',color:T.light}}>✕</button>
        </div>

        {/* Body */}
        <div style={{flex:1,overflowY:'auto',padding:'16px 20px'}}>

          {/* Step 1 */}
          {step===1 && (
            <div style={{maxWidth:480}}>
              {/* Sync timestamp warning */}
              <SyncAgeBanner lastKvSync={lastKvSync} onSyncNow={onSyncNow} kvSyncing={kvSyncing}/>
              <Inp label="Ngày kiểm kê *" type="date" value={date} onChange={(v) => setDate(v)}/>
              <Inp label="Ghi chú (tùy chọn)" value={note} onChange={(v) => setNote(v)}
                placeholder="VD: Kiểm kê tuần 15 — nhóm A"/>
              <div style={{padding:'12px',background:T.goldBg,borderRadius:10,fontSize:12,color:T.goldText,marginTop:8}}>
                💡 Bước tiếp theo hệ thống sẽ gợi ý 150 SP ưu tiên. Bạn có thể thêm/bớt trước khi xác nhận.
              </div>
            </div>
          )}

          {/* Step 2 — Product selection */}
          {step===2 && (
            <div style={{display:'flex',flexDirection:'column',gap:10}}>
              {/* Controls */}
              <div style={{display:'flex',gap:8,flexWrap:'wrap',alignItems:'center'}}>
                <input value={searchQ} onChange={e => {setSearchQ(e.target.value); setPage(0)}}
                  placeholder="🔍 Tìm mã SP hoặc tên..."
                  style={{flex:1,minWidth:200,padding:'7px 11px',border:`1px solid ${T.border}`,
                    borderRadius:20,fontSize:12,fontFamily:'inherit',color:T.dark,background:'#fff',outline:'none'}}/>
                <select value={sortBy} onChange={e => setSortBy(e.target.value as any)}
                  style={{padding:'7px 11px',border:`1px solid ${T.border}`,borderRadius:20,
                    fontSize:12,fontFamily:'inherit',color:T.dark,background:'#fff',cursor:'pointer'}}>
                  <option value="priority">⭐ Ưu tiên</option>
                  <option value="stock_desc">📦 Tồn nhiều → ít</option>
                  <option value="stock_asc">📦 Tồn ít → nhiều</option>
                  <option value="alpha">🔤 A → Z</option>
                </select>
                {(['all','selected','unselected'] as const).map(f => (
                  <button key={f} onClick={() => {setShowFilter(f);setPage(0)}}
                    style={{padding:'5px 12px',borderRadius:20,cursor:'pointer',fontFamily:'inherit',fontSize:11,
                      border:`1.5px solid ${showFilter===f?T.gold:T.border}`,
                      background:showFilter===f?T.goldBg:'transparent',
                      color:showFilter===f?T.goldText:T.med}}>
                    {f==='all'?`Tất cả (${products.filter((p: any)=>!excludedCodes.has(p.code)).length})`:f==='selected'?`Đã chọn (${selected.size})`:`Chưa chọn`}
                  </button>
                ))}
                <label style={{padding:'5px 12px',borderRadius:20,border:`1px solid ${T.border}`,
                  cursor:'pointer',fontSize:11,color:T.med,background:T.bg,whiteSpace:'nowrap'}}>
                  📥 Import danh sách KK
                  <input type="file" accept=".xlsx,.xls" style={{display:'none'}}
                    onChange={e => e.target.files?.[0] && importExcelCodes(e.target.files[0])}/>
                </label>
                <button onClick={downloadKKTemplate}
                  style={{padding:'5px 12px',borderRadius:20,border:`1px solid ${T.border}`,
                    cursor:'pointer',fontFamily:'inherit',fontSize:11,color:T.med,background:T.bg,whiteSpace:'nowrap'}}>
                  📄 Tải file mẫu KK
                </button>
              </div>

              {/* Quick actions */}
              <div style={{display:'flex',gap:8,alignItems:'center',fontSize:11}}>
                <button onClick={() => setSelected(new Set(filteredProds.map((p: any)=>p.code)))}
                  style={{padding:'3px 10px',borderRadius:20,border:`1px solid ${T.border}`,
                    background:'transparent',cursor:'pointer',fontFamily:'inherit',color:T.blue}}>
                  Chọn tất cả trang này
                </button>
                <button onClick={() => setSelected(new Set())}
                  style={{padding:'3px 10px',borderRadius:20,border:`1px solid ${T.border}`,
                    background:'transparent',cursor:'pointer',fontFamily:'inherit',color:T.red}}>
                  Bỏ chọn tất cả
                </button>
                <span style={{color:T.light,marginLeft:'auto'}}>
                  Hiện {filteredProds.length} SP · Trang {page+1}/{totalPages}
                </span>
              </div>

              {/* KK Import error panel */}
              {kkImportErrors.length > 0 && (
                <div style={{padding:'10px 14px',background:T.redBg,border:`1px solid ${T.red}`,borderRadius:10,fontSize:11}}>
                  <div style={{fontWeight:700,color:T.red,marginBottom:6}}>
                    ❌ {kkImportErrors.length} mã không tìm thấy — cần sửa lại file Excel:
                  </div>
                  {kkImportErrors.slice(0,5).map((e,i) => (
                    <div key={i} style={{color:T.red,marginBottom:3}}>• {e}</div>
                  ))}
                  {kkImportErrors.length > 5 && (
                    <div style={{color:T.light}}>...+{kkImportErrors.length-5} lỗi nữa</div>
                  )}
                  <div style={{marginTop:8,fontStyle:'italic',color:T.med}}>
                    💡 Tải file mẫu KK để xem đúng định dạng Mã SP / Tên SP
                  </div>
                  <button onClick={() => setKkImportErrors([])}
                    style={{marginTop:8,padding:'3px 12px',borderRadius:20,border:`1px solid ${T.red}`,
                      background:'transparent',color:T.red,cursor:'pointer',fontFamily:'inherit',fontSize:11}}>
                    Đóng
                  </button>
                </div>
              )}

              {/* Table */}
              <div style={{border:`1px solid ${T.border}`,borderRadius:10,overflow:'hidden'}}>
                <div style={{display:'grid',
                  gridTemplateColumns:'36px 90px 1fr 70px 70px 70px 110px',
                  padding:'7px 12px',background:T.bg,borderBottom:`2px solid ${T.border}`,
                  fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8}}>
                  <span>✓</span><span>Mã SP</span><span>Tên SP</span>
                  <span style={{textAlign:'right'}}>Tồn</span>
                  <span style={{textAlign:'right'}}>KH đặt</span>
                  <span style={{textAlign:'center'}}>Lần KK</span>
                  <span>KK cuối</span>
                </div>
                {pagedProds.map((p: any, i: number) => {
                  const isSel = selected.has(p.code)
                  const nKK   = checkCount[p.code]||0
                  const lastKK = lastChecked[p.code]
                  return (
                    <div key={p.code} onClick={() => setSelected(prev => {
                      const n = new Set(prev)
                      isSel ? n.delete(p.code) : n.add(p.code)
                      return n
                    })}
                      style={{display:'grid',
                        gridTemplateColumns:'36px 90px 1fr 70px 70px 70px 110px',
                        padding:'8px 12px',gap:8,alignItems:'center',cursor:'pointer',
                        borderBottom:i<pagedProds.length-1?`1px solid ${T.border}`:'none',
                        background:isSel?T.goldBg:i%2===0?'#fff':T.rowAlt}}
                      onMouseEnter={e => { if(!isSel)(e.currentTarget as any).style.background=T.bg }}
                      onMouseLeave={e => { if(!isSel)(e.currentTarget as any).style.background=i%2===0?'#fff':T.rowAlt }}>
                      <span style={{fontSize:16,color:isSel?T.green:T.border,textAlign:'center'}}>
                        {isSel?'✓':'○'}
                      </span>
                      <span style={{fontSize:10,color:T.light,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{p.code}</span>
                      <span style={{fontSize:12,color:T.dark,fontWeight:isSel?500:400,lineHeight:1.3}}>{p.name}</span>
                      <span style={{fontSize:12,textAlign:'right',fontWeight:700,
                        color:p.stock===0?T.light:p.stock<10?T.red:p.stock<50?T.amber:T.green}}>
                        {p.stock??'—'}
                      </span>
                      <span style={{fontSize:12,textAlign:'right',
                        color:(p.ordered_qty||p.reserved||0)>0?T.blue:T.light}}>
                        {p.ordered_qty||p.reserved||0||'—'}
                      </span>
                      <span style={{fontSize:11,textAlign:'center',color:nKK>0?T.green:T.red}}>
                        {nKK>0?nKK:'Chưa KK'}
                      </span>
                      <span style={{fontSize:10,color:T.light}}>
                        {lastKK?new Date(lastKK).toLocaleDateString('vi-VN',{day:'2-digit',month:'2-digit'}):'—'}
                      </span>
                    </div>
                  )
                })}
              </div>

              {/* Pagination */}
              {totalPages > 1 && (
                <div style={{display:'flex',gap:6,justifyContent:'center',flexWrap:'wrap'}}>
                  {Array.from({length:Math.min(totalPages,10)},(_,i)=>(
                    <button key={i} onClick={()=>setPage(i)}
                      style={{width:28,height:28,borderRadius:'50%',border:`1px solid ${T.border}`,
                        cursor:'pointer',fontFamily:'inherit',fontSize:11,
                        background:page===i?T.gold:'transparent',
                        color:page===i?'#fff':T.med}}>
                      {i+1}
                    </button>
                  ))}
                  {totalPages>10 && <span style={{padding:'4px 8px',color:T.light}}>...{totalPages} trang</span>}
                </div>
              )}
            </div>
          )}

          {/* Step 3 — NV + preview */}
          {step===3 && (
            <div style={{display:'flex',flexDirection:'column',gap:14}}>
              <div style={{padding:'10px 14px',background:T.goldBg,borderRadius:10,
                fontSize:12,color:T.goldText,fontWeight:600}}>
                📦 {selected.size} mã sẽ được kiểm kê trong phiên {date}
              </div>
              <div>
                <div style={{fontSize:12,fontWeight:600,color:T.dark,marginBottom:8}}>Chọn nhân viên kiểm kê:</div>
                <div style={{display:'flex',flexDirection:'column',gap:6}}>
                  {khoUsers.map((u: any) => {
                    const sel = selectedNVs.includes(u.id)
                    return (
                      <label key={u.id} style={{display:'flex',alignItems:'center',gap:10,
                        padding:'9px 14px',borderRadius:10,cursor:'pointer',
                        background:sel?T.goldBg:T.bg,border:`1px solid ${sel?T.gold:T.border}`}}>
                        <input type="checkbox" checked={sel}
                          onChange={() => setSelectedNVs(prev =>
                            sel ? prev.filter(id=>id!==u.id) : [...prev,u.id]
                          )}/>
                        <span style={{fontSize:13,fontWeight:sel?700:400,color:sel?T.goldText:T.dark}}>
                          {u.name}
                        </span>
                        <span style={{fontSize:11,color:T.light}}>{u.position_name||''}</span>
                      </label>
                    )
                  })}
                </div>
              </div>
              {selectedNVs.length > 0 && (
                <div>
                  <div style={{fontSize:12,fontWeight:600,color:T.dark,marginBottom:8}}>Preview phân chia:</div>
                  <div style={{display:'flex',flexDirection:'column',gap:6}}>
                    {perNVPreview.map(({nv,count}: any) => (
                      <div key={nv?.id} style={{display:'flex',alignItems:'center',gap:10,
                        padding:'10px 14px',background:T.bg,borderRadius:10,border:`1px solid ${T.border}`}}>
                        <div style={{width:32,height:32,borderRadius:'50%',background:T.gold,
                          display:'flex',alignItems:'center',justifyContent:'center',
                          color:'#fff',fontSize:11,fontWeight:700}}>{nv?.ini||'?'}</div>
                        <span style={{flex:1,fontSize:13,fontWeight:600,color:T.dark}}>{nv?.name||'?'}</span>
                        <span style={{fontSize:18,fontWeight:800,color:T.blue}}>{count} mã</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
              {selectedNVs.length===0 && (
                <div style={{padding:'12px',background:T.amberBg,borderRadius:8,fontSize:12,color:T.amber}}>
                  ⚠️ Chưa chọn nhân viên. Tất cả mã sẽ được assign cho bạn.
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{padding:'14px 20px',borderTop:`1px solid ${T.border}`,flexShrink:0,
          display:'flex',justifyContent:'space-between',alignItems:'center',background:T.bg}}>
          <div>
            {step===2 && <span style={{fontSize:12,color:T.med}}>Đã chọn: <b>{selected.size}</b> mã</span>}
          </div>
          <div style={{display:'flex',gap:10}}>
            {step>1 && (
              <button onClick={() => setStep(s => s-1)}
                style={{padding:'8px 18px',borderRadius:20,border:`1.5px solid ${T.border}`,
                  background:'transparent',cursor:'pointer',fontFamily:'inherit',fontSize:12,color:T.med}}>
                ← Quay lại
              </button>
            )}
            <button onClick={() => onClose()}
              style={{padding:'8px 18px',borderRadius:20,border:`1px solid ${T.border}`,
                background:'transparent',cursor:'pointer',fontFamily:'inherit',fontSize:12,color:T.light}}>
              Hủy
            </button>
            {step < 3 ? (
              <GoldBtn small onClick={() => setStep(s => s+1)}
                disabled={step===1?(!date || isSyncTooOld(lastKvSync)):step===2?selected.size===0:false}>
                Tiếp theo →
              </GoldBtn>
            ) : (
              <GoldBtn small onClick={doCreate}>
                ✅ Xác nhận tạo phiên
              </GoldBtn>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

// ── NVCheckGroup subcomponent (avoid useState in map) ─────
function NVCheckGroup({ nv, nvChecks, nvDone }: any) {
  const [expNV, setExpNV] = useState(false)
  const [notes, setNotes] = useState<Record<string,string>>({})
  const [savingNote, setSavingNote] = useState<string|null>(null)

  const saveNote = async (checkId: string, note: string) => {
    setSavingNote(checkId)
    await db.from('inventory_checks').update({ diff_note: note }).eq('id', checkId)
    setSavingNote(null)
  }

  // Mã lệch lên trước, sau đó chưa KK, sau đó OK
  const sorted = [...nvChecks].sort((a: any, b: any) => {
    const rank = (c: any) => {
      if (c.diff != null && c.diff !== 0) return 0   // lệch → lên đầu
      if (c.actual_qty == null) return 1              // chưa KK
      return 2                                        // OK
    }
    return rank(a) - rank(b)
  })

  const lechs = nvChecks.filter((c: any) => c.diff != null && c.diff !== 0).length

  return (
    <div style={{marginBottom:8,borderRadius:8,border:`1px solid ${T.border}`,overflow:'hidden'}}>
      <div onClick={() => setExpNV(v=>!v)}
        style={{display:'flex',alignItems:'center',gap:10,padding:'8px 12px',
          background:'#fff',cursor:'pointer'}}>
        <div style={{width:28,height:28,borderRadius:'50%',background:T.gold,
          display:'flex',alignItems:'center',justifyContent:'center',
          color:'#fff',fontSize:10,fontWeight:700,flexShrink:0}}>
          {nv?.ini||'?'}
        </div>
        <span style={{flex:1,fontSize:12,fontWeight:600,color:T.dark}}>{nv?.name||'NV không xác định'}</span>
        {lechs > 0 && (
          <span style={{fontSize:10,padding:'2px 7px',borderRadius:10,
            background:T.redBg,color:T.red,fontWeight:700}}>⚠️ {lechs} lệch</span>
        )}
        <span style={{fontSize:11,color:T.blue}}>{nvDone}/{nvChecks.length} mã</span>
        <div style={{height:6,width:80,background:T.border,borderRadius:3}}>
          <div style={{height:'100%',borderRadius:3,
            background:nvDone===nvChecks.length?T.green:T.amber,
            width:`${nvChecks.length>0?nvDone*100/nvChecks.length:0}%`}}/>
        </div>
        <span style={{fontSize:10,color:T.light}}>{expNV?'▲':'▼'}</span>
      </div>
      {expNV && (
        <div style={{borderTop:`1px solid ${T.border}`}}>
          {lechs > 0 && (
            <div style={{padding:'4px 12px',background:'#FFF7ED',borderBottom:`1px solid ${T.border}`,
              fontSize:10,color:T.amber,fontWeight:700}}>
              ⚠️ {lechs} mã lệch kho — hiển thị ở trên cùng
            </div>
          )}
          <div style={{display:'grid',gridTemplateColumns:'1fr 60px 60px 55px 1fr',
            padding:'5px 12px',background:T.bg,fontSize:9,fontWeight:700,
            color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:6}}>
            <span>Sản phẩm</span>
            <span style={{textAlign:'center'}}>Tồn HT</span>
            <span style={{textAlign:'center'}}>Tồn TT</span>
            <span style={{textAlign:'center'}}>Lệch</span>
            <span>Ghi chú</span>
          </div>
          {sorted.map((c: any, ci: number) => {
            const isLech = c.diff != null && c.diff !== 0
            const noteVal = notes[c.id] !== undefined ? notes[c.id] : (c.diff_note || '')
            return (
              <div key={c.id} style={{display:'grid',
                gridTemplateColumns:'1fr 60px 60px 55px 1fr',
                padding:'6px 12px',gap:6,alignItems:'center',
                borderTop:`1px solid ${T.border}`,
                background: isLech ? '#FFF7ED' : ci%2===0?'#fff':T.rowAlt}}>
                <div>
                  <div style={{fontSize:11,color:isLech?T.amber:T.dark,lineHeight:1.3,fontWeight:isLech?700:400}}>
                    {isLech && '⚠️ '}{c.product_name}
                  </div>
                  <div style={{fontSize:9,color:T.light}}>{c.product_code}</div>
                </div>
                <span style={{textAlign:'center',fontSize:11,color:T.med}}>{c.system_qty??'—'}</span>
                <span style={{textAlign:'center',fontSize:11,
                  fontWeight:c.actual_qty!=null?700:400,
                  color:c.actual_qty!=null?T.dark:T.light}}>
                  {c.actual_qty??'Chưa KK'}
                </span>
                <span style={{textAlign:'center',fontSize:12,fontWeight:700,
                  color:c.diff==null?T.light:c.diff===0?T.green:c.diff>0?T.blue:T.red}}>
                  {c.diff==null?'—':c.diff===0?'✓':c.diff>0?'+'+c.diff:c.diff}
                </span>
                <div style={{display:'flex',gap:4,alignItems:'center'}}>
                  <input
                    value={noteVal}
                    onChange={e => setNotes(prev => ({...prev, [c.id]: e.target.value}))}
                    onBlur={e => saveNote(c.id, e.target.value)}
                    placeholder="Ghi chú..."
                    style={{flex:1,fontSize:10,padding:'3px 6px',border:`1px solid ${T.border}`,
                      borderRadius:5,fontFamily:'inherit',color:T.dark,background:'#fff',outline:'none',
                      minWidth:0}}/>
                  {savingNote===c.id && <span style={{fontSize:9,color:T.light}}>💾</span>}
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

// ── ExcludedSearchBox — standalone component (no hook in IIFE) ─────
function ExcludedSearchBox({ products, excludedCodes, user, onAdd }: any) {
  const [excSearch, setExcSearch] = useState('')
  const norm3 = (s: string) => (s||'').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
  const excResults = excSearch.length >= 2
    ? (products||[]).filter((p: any) =>
        !excludedCodes.has(p.code) &&
        norm3(p.name+' '+p.code).includes(norm3(excSearch))
      ).slice(0,8)
    : []
  return (
    <div style={{marginBottom:12, position:'relative'}}>
      <input value={excSearch} onChange={e => setExcSearch(e.target.value)}
        placeholder="🔍 Tìm mã SP để thêm vào danh sách không KK..."
        style={{width:'100%',padding:'8px 12px',border:`1px solid ${T.border}`,
          borderRadius:8,fontSize:12,fontFamily:'inherit',color:T.dark,
          background:'#fff',boxSizing:'border-box' as any,outline:'none'}}/>
      {excResults.length > 0 && (
        <div style={{position:'absolute',top:'100%',left:0,right:0,zIndex:200,
          background:'#fff',border:`1px solid ${T.border}`,borderRadius:8,
          boxShadow:'0 4px 12px rgba(0,0,0,0.12)',maxHeight:240,overflowY:'auto'}}>
          {excResults.map((p: any) => (
            <div key={p.code} onClick={async () => {
              const row = {product_code:p.code, excluded_by:user.id,
                excluded_at:new Date().toISOString(), reason:'Không cần KK'}
              await db.from('kk_excluded_products').upsert(row)
              onAdd(p.code)
              setExcSearch('')
            }}
              style={{padding:'8px 12px',cursor:'pointer',borderBottom:`1px solid ${T.border}`,
                display:'flex',justifyContent:'space-between',alignItems:'center'}}
              onMouseEnter={e=>(e.currentTarget as any).style.background=T.bg}
              onMouseLeave={e=>(e.currentTarget as any).style.background='#fff'}>
              <div>
                <div style={{fontSize:12,color:T.dark}}>{p.name}</div>
                <div style={{fontSize:10,color:T.light}}>{p.code}</div>
              </div>
              <span style={{fontSize:11,color:T.green,fontWeight:600}}>+ Thêm</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// ── ExcludedTab — full product table with multi-select ────────
function ExcludedTab({ products, excludedCodes, user, mobile, onAdd, onRemove }: any) {
  const [search, setSearch] = useState('')
  const [selected, setSelected] = useState<Set<string>>(new Set())
  const [viewMode, setViewMode] = useState<'all'|'excluded'>('excluded')
  const norm_ = (s: string) => (s||'').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')

  const filtered = products.filter((p: any) => {
    if (viewMode==='excluded' && !excludedCodes.has(p.code)) return false
    if (search.length>=1 && !norm_(p.name+' '+p.code).includes(norm_(search))) return false
    return true
  }).slice(0, 200)

  const selAll = filtered.length>0 && filtered.every((p: any)=>selected.has(p.code))

  const addSelected = async () => {
    const toAdd = [...selected].filter((c: string)=>!excludedCodes.has(c))
    for (const code of toAdd) {
      await db.from('kk_excluded_products').upsert({
        product_code:code, excluded_by:user.id,
        excluded_at:new Date().toISOString(), reason:'Không cần KK'
      })
      onAdd(code)
    }
    setSelected(new Set())
  }

  const removeSelected = async () => {
    const toRm = [...selected].filter((c: string)=>excludedCodes.has(c))
    for (const code of toRm) {
      await db.from('kk_excluded_products').delete().eq('product_code',code)
      onRemove(code)
    }
    setSelected(new Set())
  }

  return (
    <div style={{display:'flex',flexDirection:'column',gap:10}}>
      {/* Header card */}
      <Card style={{padding:'12px 14px'}}>
        <div style={{fontSize:13,fontWeight:700,color:T.dark,marginBottom:4}}>🚫 Mã không kiểm kê</div>
        <div style={{fontSize:11,color:T.med}}>
          Mã trong danh sách này sẽ bị loại khỏi gợi ý khi tạo phiên KK.
          Thường là: tiền ship, túi, hộp giấy, phụ kiện...
        </div>
      </Card>

      {/* Controls */}
      <div style={{display:'flex',gap:8,flexWrap:'wrap',alignItems:'center'}}>
        <input value={search} onChange={e => setSearch(e.target.value)}
          placeholder="🔍 Tìm mã SP hoặc tên..."
          style={{flex:1,minWidth:180,padding:'7px 12px',border:`1px solid ${T.border}`,
            borderRadius:20,fontSize:12,fontFamily:'inherit',color:T.dark,
            background:'#fff',outline:'none'}}/>
        {[{id:'excluded',label:`🚫 Đang loại (${excludedCodes.size})`},{id:'all',label:'📦 Tất cả SP'}].map(v => (
          <button key={v.id} onClick={() => setViewMode(v.id as any)}
            style={{padding:'6px 13px',borderRadius:20,cursor:'pointer',fontFamily:'inherit',fontSize:11,
              border:`1.5px solid ${viewMode===v.id?T.gold:T.border}`,
              background:viewMode===v.id?T.goldBg:'transparent',
              color:viewMode===v.id?T.goldText:T.med,fontWeight:viewMode===v.id?700:400}}>
            {v.label}
          </button>
        ))}
      </div>

      {/* Bulk action bar */}
      {selected.size > 0 && (
        <div style={{display:'flex',gap:8,alignItems:'center',padding:'9px 14px',
          background:T.goldBg,borderRadius:10,border:`1.5px solid ${T.gold}`,flexWrap:'wrap'}}>
          <span style={{fontSize:12,fontWeight:700,color:T.goldText}}>Đã chọn {selected.size} mã</span>
          <button onClick={addSelected}
            style={{padding:'5px 14px',borderRadius:20,border:'none',background:T.red,
              cursor:'pointer',fontFamily:'inherit',fontSize:11,color:'#fff',fontWeight:700}}>
            🚫 Thêm vào danh sách không KK
          </button>
          <button onClick={removeSelected}
            style={{padding:'5px 14px',borderRadius:20,border:`1.5px solid ${T.green}`,
              background:T.greenBg,cursor:'pointer',fontFamily:'inherit',fontSize:11,
              color:T.green,fontWeight:700}}>
            ✅ Bỏ khỏi danh sách không KK
          </button>
          <button onClick={() => setSelected(new Set())}
            style={{padding:'5px 10px',borderRadius:20,border:`1px solid ${T.border}`,
              background:'transparent',cursor:'pointer',fontFamily:'inherit',fontSize:11,color:T.light}}>
            Bỏ chọn
          </button>
        </div>
      )}

      {/* Table */}
      <div style={{background:T.card,borderRadius:12,border:`1px solid ${T.border}`,overflow:'hidden',boxShadow:'0 1px 4px rgba(0,0,0,0.06)'}}>
        {/* Header */}
        <div style={{display:'grid',gridTemplateColumns:'36px 1fr 100px 70px',
          padding:'8px 14px',background:T.bg,borderBottom:`2px solid ${T.border}`,
          fontSize:10,fontWeight:700,color:T.light,textTransform:'uppercase',letterSpacing:.5,gap:8,
          alignItems:'center'}}>
          <input type="checkbox" checked={selAll}
            onChange={() => setSelected(selAll
              ? new Set()
              : new Set(filtered.map((p: any)=>p.code))
            )} style={{cursor:'pointer'}}/>
          <span>Sản phẩm</span>
          <span>Mã SP</span>
          <span style={{textAlign:'center'}}>Trạng thái</span>
        </div>
        {filtered.length===0
          ? <div style={{padding:'32px',textAlign:'center',color:T.light,fontSize:12}}>
              {viewMode==='excluded'?'Chưa có mã nào trong danh sách':'Không tìm thấy sản phẩm'}
            </div>
          : filtered.map((p: any, i: number) => {
              const isSel   = selected.has(p.code)
              const isExcl  = excludedCodes.has(p.code)
              return (
                <div key={p.code} onClick={() => setSelected(prev => {
                  const n = new Set(prev)
                  isSel ? n.delete(p.code) : n.add(p.code)
                  return n
                })}
                  style={{display:'grid',gridTemplateColumns:'36px 1fr 100px 70px',
                    padding:'8px 14px',gap:8,alignItems:'center',cursor:'pointer',
                    borderBottom:i<filtered.length-1?`1px solid ${T.border}`:'none',
                    background:isSel?T.goldBg:i%2===0?'#fff':T.rowAlt}}>
                  <input type="checkbox" checked={isSel}
                    onChange={() => {}} style={{cursor:'pointer',pointerEvents:'none'}}/>
                  <div>
                    <div style={{fontSize:12,color:T.dark,fontWeight:500,lineHeight:1.4}}>{p.name}</div>
                  </div>
                  <span style={{fontSize:11,color:T.light}}>{p.code}</span>
                  <div style={{textAlign:'center'}}>
                    {isExcl
                      ? <span style={{fontSize:10,padding:'2px 7px',borderRadius:20,
                          background:T.redBg,color:T.red,fontWeight:700}}>🚫 Loại</span>
                      : <span style={{fontSize:10,color:T.light}}>—</span>
                    }
                  </div>
                </div>
              )
            })
        }
        {filtered.length>=200 && (
          <div style={{padding:'8px',textAlign:'center',fontSize:11,color:T.light,borderTop:`1px solid ${T.border}`}}>
            Đang hiển thị 200 kết quả đầu. Dùng tìm kiếm để thu hẹp.
          </div>
        )}
      </div>
    </div>
  )
}

// ══ BATCH FORM ════════════════════════════════════════════════
function BatchForm({ edit, products, onSave, onClose, saving, mobile }: any) {
  const [form, setForm] = useState<any>(() => {
    if (edit) {
      const parts = (edit.expiry_date || '').split('-')
      const mm   = parts[1] || '01'
      const yyyy = parts[0] || new Date().getFullYear().toString()
      return {
        product_code:  edit.product_code  || '',
        product_name:  edit.product_name  || '',
        unit:          edit.unit          || '',
        expiry_mmyyyy: `${mm}/${yyyy}`,
        qty_remaining: String(edit.qty_remaining ?? 0),
        note:          edit.note          || '',
      }
    }
    return { product_code:'', product_name:'', unit:'', expiry_mmyyyy:'', qty_remaining:'0', note:'' }
  })
  const [searchProd, setSearchProd] = useState('')

  const normBF = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
  const filteredProds = products.filter((p: any) => {
    if (!searchProd) return true
    return normBF(p.code + ' ' + p.name).includes(normBF(searchProd))
  }).slice(0, 20)

  const selectProd = (p: any) => {
    setForm((f: any) => ({ ...f, product_code: p.code, product_name: p.name, unit: p.unit || '' }))
    setSearchProd('')
  }

  const validExpiry = /^\d{1,2}\/\d{4}$/.test(form.expiry_mmyyyy)
  const isValid = form.product_code && validExpiry && Number(form.qty_remaining) >= 0

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:3000,
      display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}>
      <div style={{ background:'#fff', borderRadius:16, width:'100%', maxWidth:480,
        maxHeight:'90vh', overflowY:'auto', padding:'20px 24px', boxSizing:'border-box' }}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:18 }}>
          <div style={{ fontSize:15, fontWeight:700, color:T.dark }}>
            {edit ? '✏️ Sửa lô hàng' : '➕ Thêm lô hàng mới'}
          </div>
          <button onClick={onClose}
            style={{ background:'none', border:'none', fontSize:20, cursor:'pointer', color:T.light }}>✕</button>
        </div>

        {/* Product picker */}
        <div style={{ marginBottom:14 }}>
          <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
            letterSpacing:.5, display:'block', marginBottom:6 }}>Sản phẩm *</label>
          {form.product_code ? (
            <div style={{ display:'flex', alignItems:'center', gap:8, padding:'10px 14px',
              background:T.goldBg, borderRadius:10, border:`1px solid ${T.goldBorder}` }}>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>{form.product_name}</div>
                <div style={{ fontSize:10, color:T.goldText }}>{form.product_code} · {form.unit}</div>
              </div>
              {!edit && (
                <button onClick={() => setForm((f: any) => ({ ...f, product_code:'', product_name:'', unit:'' }))}
                  style={{ background:'none', border:'none', cursor:'pointer', color:T.light, fontSize:18 }}>✕</button>
              )}
            </div>
          ) : (
            <div>
              <input value={searchProd} onChange={e => setSearchProd(e.target.value)}
                placeholder="Gõ mã hoặc tên SP để tìm..."
                style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`,
                  borderRadius:8, fontSize:13, fontFamily:'inherit', outline:'none',
                  color:T.dark, background:'#fff', boxSizing:'border-box' }}/>
              {searchProd && (
                <div style={{ border:`1px solid ${T.border}`, borderRadius:8, marginTop:4,
                  maxHeight:200, overflowY:'auto', background:'#fff',
                  boxShadow:'0 4px 12px rgba(0,0,0,0.08)' }}>
                  {filteredProds.map((p: any) => (
                    <div key={p.code} onClick={() => selectProd(p)}
                      style={{ padding:'9px 12px', cursor:'pointer',
                        borderBottom:`1px solid ${T.border}`,
                        display:'flex', justifyContent:'space-between', alignItems:'center',
                        background:'#fff' }}
                      onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
                      onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = '#fff' }}>
                      <span style={{ fontSize:13, color:T.dark }}>{p.name}</span>
                      <span style={{ fontSize:11, color:T.light, flexShrink:0, marginLeft:8 }}>{p.code}</span>
                    </div>
                  ))}
                  {filteredProds.length === 0 && (
                    <div style={{ padding:'12px', fontSize:12, color:T.light, textAlign:'center' }}>
                      Không tìm thấy SP
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        <Inp label="Ngày HSD * — định dạng MM/YYYY (VD: 06/2026)"
          value={form.expiry_mmyyyy}
          onChange={(v: string) => setForm((f: any) => ({ ...f, expiry_mmyyyy: v }))}
          placeholder="06/2026"/>
        {form.expiry_mmyyyy && !validExpiry && (
          <div style={{ fontSize:11, color:T.red, marginTop:-10, marginBottom:10 }}>
            ⚠️ Định dạng sai — nhập MM/YYYY, VD: 06/2026
          </div>
        )}

        <Inp label="SL tồn thực tế"
          type="number"
          value={form.qty_remaining}
          onChange={(v: string) => setForm((f: any) => ({ ...f, qty_remaining: v }))}/>

        <Inp label="Ghi chú (tùy chọn)"
          value={form.note}
          onChange={(v: string) => setForm((f: any) => ({ ...f, note: v }))}
          placeholder="VD: Lô tháng 1, nhập từ NCC A"/>

        <div style={{ display:'flex', gap:10, marginTop:20 }}>
          <GoldBtn onClick={() => isValid && onSave(form)} disabled={!isValid || saving}>
            {saving ? 'Đang lưu...' : edit ? 'Cập nhật lô' : 'Thêm lô'}
          </GoldBtn>
          <button onClick={onClose}
            style={{ padding:'9px 20px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
            Hủy
          </button>
        </div>
      </div>
    </div>
  )
}

// ══ PRICE MODULE — Báo giá & Chương trình nhãn hàng ═══════════
function PriceModule({ user, mobile, products, allUsers,
  priceConfigs, setPriceConfigs, priceTiers, setPriceTiers,
  priceHistory, setPriceHistory, brandPrograms, setBrandPrograms }: any) {
  const [tab, setTab] = useState<'price'|'programs'>('price')
  const perm = getPerm(user)
  const canEditPrice    = perm.editPrice || perm.viewAllDashboard
  const canEditPrograms = perm.managePrograms || perm.viewAllDashboard
  const p = mobile ? '12px' : '24px'

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="Báo giá & Chương trình nhãn hàng"
        subtitle="Bảng giá sản phẩm và theo dõi CTKM từng nhãn hàng"/>

      {/* Tab switcher */}
      <div style={{ display:'flex', gap:0, marginBottom:16, border:`1px solid ${T.border}`,
        borderRadius:10, overflow:'hidden', background:'#fff', width:'fit-content' }}>
        {([['price','💰 Báo giá'],['programs','🎯 Chương trình nhãn hàng']] as [string,string][]).map(([id,label]) => (
          <button key={id} onClick={() => setTab(id as any)}
            style={{ padding:'9px 20px', border:'none', cursor:'pointer', fontFamily:'inherit',
              fontSize:13, fontWeight:tab===id?700:400,
              background:tab===id?T.gold:'transparent',
              color:tab===id?'#fff':T.med, transition:'all .15s' }}>
            {label}
          </button>
        ))}
      </div>

      {tab==='price' && (
        <PriceListTab user={user} mobile={mobile} products={products} allUsers={allUsers}
          priceConfigs={priceConfigs} setPriceConfigs={setPriceConfigs}
          priceTiers={priceTiers} setPriceTiers={setPriceTiers}
          priceHistory={priceHistory} setPriceHistory={setPriceHistory}
          canEdit={canEditPrice}/>
      )}
      {tab==='programs' && (
        <BrandProgramsTab user={user} mobile={mobile} products={products} allUsers={allUsers}
          brandPrograms={brandPrograms} setBrandPrograms={setBrandPrograms}
          canEdit={canEditPrograms}/>
      )}
    </div>
  )
}

// ── PART 1: Price List Tab ─────────────────────────────────────
function PriceListTab({ user, mobile, products, allUsers,
  priceConfigs, setPriceConfigs, priceTiers, setPriceTiers,
  priceHistory, setPriceHistory, canEdit }: any) {

  const [search, setSearch]       = useState('')
  const [editCode, setEditCode]   = useState<string|null>(null)
  const [expandCode, setExpandCode] = useState<string|null>(null)
  const [saving, setSaving]       = useState(false)
  const [showConfirmAll, setShowConfirmAll] = useState<any>(null)

  // Edit form state
  const [editForm, setEditForm]   = useState<any>({
    pricing_type:'fixed', fixed_price:'', discount_pct:'', list_price:''
  })
  // Tiers edit
  const [tiersForm, setTiersForm] = useState<any[]>([])

  // Lấy nhãn hàng từ field trademark (KiotViet Brand)
  const getBrand = (prod: any) => prod.trademark || prod.brand || 'Chưa phân nhãn'

  // KiotViet lưu giá / 1000 → nhân lại để hiển thị đúng
  const realPrice = (p: number) => (p || 0) * 1000

  // Get config for a product
  const getCfg = (code: string) => priceConfigs.find((c: any) => c.product_code === code)

  // Computed sell price
  const getSellPrice = (prod: any) => {
    const cfg = getCfg(prod.code)
    const listP = realPrice(prod.base_price)
    if (!cfg) return listP
    if (cfg.pricing_type === 'discount') {
      return Math.round(listP * (1 - cfg.discount_pct / 100))
    }
    return cfg.fixed_price || listP
  }

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')

  const filtered = products.filter((p: any) =>
    !search.trim() || norm(p.name+' '+p.code).includes(norm(search))
  )

  // Group by brand
  const groups: Record<string,any[]> = {}
  filtered.forEach((p: any) => {
    const brand = getBrand(p)
    if (!groups[brand]) groups[brand] = []
    groups[brand].push(p)
  })

  const openEdit = (prod: any) => {
    const cfg = getCfg(prod.code)
    setEditForm({
      pricing_type: cfg?.pricing_type || 'fixed',
      fixed_price:  String(cfg?.fixed_price || realPrice(prod.base_price) || ''),
      discount_pct: String(cfg?.discount_pct || ''),
      list_price:   String(realPrice(prod.base_price) || '')
    })
    const myTiers = priceTiers.filter((t: any) => t.product_code === prod.code)
    setTiersForm(myTiers.length > 0 ? myTiers.map((t: any) => ({...t}))
      : [{ id:'', product_code: prod.code, min_qty:1, price: realPrice(prod.base_price)||0, note:'' }])
    setEditCode(prod.code)
  }

  const savePrice = async (prod: any, applyAll = false) => {
    setSaving(true)
    const now = new Date().toISOString()
    const oldCfg = getCfg(prod.code)
    const oldPrice = oldCfg?.fixed_price || oldCfg?.discount_pct || prod.base_price

    const newCfg = {
      id: oldCfg?.id || 'pc_'+prod.code,
      product_code: prod.code, product_name: prod.name,
      brand: getBrand(prod),
      list_price: Number(editForm.list_price) || realPrice(prod.base_price) || 0,
      pricing_type: editForm.pricing_type,
      fixed_price: editForm.pricing_type==='fixed' ? Number(editForm.fixed_price)||0 : 0,
      discount_pct: editForm.pricing_type==='discount' ? Number(editForm.discount_pct)||0 : 0,
      updated_at: now, updated_by: user.id
    }

    // Save history
    const hist = {
      id: 'ph_'+Date.now()+'_'+Math.random().toString(36).slice(2,5),
      product_code: prod.code, product_name: prod.name,
      old_price: oldCfg?.fixed_price || realPrice(prod.base_price) || 0,
      new_price: newCfg.pricing_type==='fixed' ? newCfg.fixed_price : Math.round(realPrice(prod.base_price)*(1-newCfg.discount_pct/100)),
      pricing_type: newCfg.pricing_type, discount_pct: newCfg.discount_pct,
      changed_at: now, changed_by: user.id,
      changed_by_name: allUsers.find((u: any) => u.id===user.id)?.name || user.name
    }

    await db.from('price_configs').upsert(newCfg)
    await db.from('price_history').insert(hist)

    // Save tiers
    const oldTierIds = priceTiers.filter((t: any) => t.product_code===prod.code).map((t: any) => t.id)
    for (const id of oldTierIds) await db.from('price_tiers').delete().eq('id', id)
    const newTiers = tiersForm.filter((t: any) => t.min_qty && t.price)
      .map((t: any, i: number) => ({
        id: 'pt_'+prod.code+'_'+i+'_'+Date.now(),
        product_code: prod.code,
        min_qty: Number(t.min_qty), price: Number(t.price), note: t.note||''
      }))
    if (newTiers.length > 0) await db.from('price_tiers').insert(newTiers)

    // Apply discount to all products in brand?
    if (applyAll && editForm.pricing_type === 'discount') {
      const brandProducts = products.filter((p2: any) => getBrand(p2) === getBrand(prod) && p2.code !== prod.code)
      for (const bp of brandProducts) {
        const bpCfg = { id:'pc_'+bp.code, product_code:bp.code, product_name:bp.name, brand:getBrand(bp),
          list_price:bp.base_price||0, pricing_type:'discount',
          fixed_price:0, discount_pct: newCfg.discount_pct, updated_at:now, updated_by:user.id }
        await db.from('price_configs').upsert(bpCfg)
      }
      setPriceConfigs((prev: any[]) => {
        const updated = [...prev.filter((c: any) => getBrand(products.find((p: any) => p.code===c.product_code))!==getBrand(prod)), newCfg,
          ...brandProducts.map((bp: any) => ({id:'pc_'+bp.code,product_code:bp.code,product_name:bp.name,brand:getBrand(bp),list_price:bp.base_price||0,pricing_type:'discount',fixed_price:0,discount_pct:newCfg.discount_pct,updated_at:now,updated_by:user.id}))]
        return updated
      })
    } else {
      setPriceConfigs((prev: any[]) => {
        const ex = prev.find((c: any) => c.product_code===prod.code)
        return ex ? prev.map((c: any) => c.product_code===prod.code ? newCfg : c) : [...prev, newCfg]
      })
    }

    setPriceTiers((prev: any[]) => [
      ...prev.filter((t: any) => t.product_code!==prod.code), ...newTiers
    ])
    setPriceHistory((prev: any[]) => [hist, ...prev])
    setSaving(false)
    setEditCode(null)
    setShowConfirmAll(null)
  }

  const handleSaveClick = (prod: any) => {
    if (editForm.pricing_type === 'discount') {
      setShowConfirmAll({ prod })
    } else {
      savePrice(prod, false)
    }
  }

  const myHistory = (code: string) => priceHistory.filter((h: any) => h.product_code===code).slice(0,5)
  const myTiers   = (code: string) => priceTiers.filter((t: any) => t.product_code===code)

  return (
    <div>
      {/* Search */}
      <Card style={{ padding:'10px 14px', marginBottom:12, display:'flex', gap:10, alignItems:'center' }}>
        <span style={{ fontSize:14 }}>🔍</span>
        <input value={search} onChange={e => setSearch(e.target.value)}
          placeholder="Tìm theo tên hoặc mã sản phẩm..."
          style={{ flex:1, border:'none', outline:'none', fontSize:13, fontFamily:'inherit', color:T.dark, background:'transparent' }}/>
        {search && <button onClick={() => setSearch('')}
          style={{ border:'none', background:'none', cursor:'pointer', color:T.light, fontSize:14 }}>✕</button>}
      </Card>

      {Object.entries(groups).map(([brand, prods]) => (
        <Card key={brand} style={{ padding:0, overflow:'hidden', marginBottom:14 }}>
          {/* Brand header */}
          <div style={{ background:`linear-gradient(90deg,${T.goldBg},#fff)`, padding:'10px 16px',
            borderBottom:`1px solid ${T.border}`, display:'flex', alignItems:'center', gap:10 }}>
            <span style={{ fontSize:16 }}>🏷️</span>
            <span style={{ fontWeight:700, fontSize:14, color:T.goldText }}>{brand}</span>
            <span style={{ fontSize:11, color:T.light }}>— {prods.length} sản phẩm</span>
          </div>

          {/* Table header */}
          <div style={{ display:'grid',
            gridTemplateColumns: mobile ? '1fr 80px 80px 36px' : '1fr 90px 120px 130px 36px',
            padding:'6px 14px', background:T.bg, fontSize:9, fontWeight:700,
            color:T.light, textTransform:'uppercase', letterSpacing:.5, gap:6 }}>
            <span>Sản phẩm · Mốc giá</span>
            {!mobile && <span style={{ textAlign:'right' }}>Niêm yết</span>}
            <span style={{ textAlign:'center' }}>Loại giá</span>
            <span style={{ textAlign:'right' }}>Giá bán</span>
            <span></span>
          </div>

          {prods.map((prod: any, pi: number) => {
            const cfg   = getCfg(prod.code)
            const sell  = getSellPrice(prod)
            const tiers = myTiers(prod.code)
            const hist  = myHistory(prod.code)
            const isExp = expandCode === prod.code
            const isEd  = editCode === prod.code
            const sortedTiers = [...tiers].sort((a: any, b: any) => a.min_qty - b.min_qty)

            return (
              <div key={prod.code} style={{ borderTop:`1px solid ${T.border}` }}>
                {/* Main row */}
                <div style={{ display:'grid',
                  gridTemplateColumns: mobile ? '1fr 80px 80px 36px' : '1fr 90px 120px 130px 36px',
                  padding:'8px 14px', gap:6, alignItems:'flex-start',
                  background: pi%2===0 ? '#fff' : T.rowAlt }}>

                  {/* Product name + code + inline tiers */}
                  <div>
                    <div style={{ fontSize:12, fontWeight:600, color:T.dark, lineHeight:1.4 }}>{prod.name}</div>
                    <div style={{ fontSize:10, color:T.light, marginBottom: sortedTiers.length>0 ? 5 : 0 }}>
                      {prod.code}
                    </div>
                    {/* Inline price tiers */}
                    {sortedTiers.length > 0 && (
                      <div style={{ display:'flex', gap:5, flexWrap:'wrap', marginTop:3 }}>
                        {sortedTiers.map((t: any, ti: number) => (
                          <div key={ti} style={{ display:'flex', alignItems:'center', gap:3,
                            background:T.blueBg, borderRadius:6, padding:'2px 7px' }}>
                            <span style={{ fontSize:9, color:T.light }}>≥{t.min_qty}</span>
                            <span style={{ fontSize:10, fontWeight:700, color:T.blue }}>{Number(t.price).toLocaleString()}đ</span>
                            {t.note && <span style={{ fontSize:9, color:T.light }}>({t.note})</span>}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {!mobile && (
                    <span style={{ fontSize:11, color:T.med, textAlign:'right', paddingTop:2 }}>
                      {realPrice(prod.base_price).toLocaleString()}đ
                    </span>
                  )}

                  <div style={{ textAlign:'center', paddingTop:2 }}>
                    <span style={{ fontSize:9, padding:'2px 7px', borderRadius:10, fontWeight:700,
                      background: cfg?.pricing_type==='discount' ? T.amberBg : T.blueBg,
                      color: cfg?.pricing_type==='discount' ? T.amber : T.blue }}>
                      {!cfg ? 'Chưa có' : cfg.pricing_type==='discount' ? `CK ${cfg.discount_pct}%` : 'Cố định'}
                    </span>
                  </div>

                  <div style={{ textAlign:'right', paddingTop:2 }}>
                    <span style={{ fontSize:13, fontWeight:700,
                      color: !cfg ? T.light : cfg.pricing_type==='discount' ? T.amber : T.blue }}>
                      {sell > 0 ? sell.toLocaleString()+'đ' : '—'}
                    </span>
                  </div>

                  <div style={{ display:'flex', flexDirection:'column', gap:4, alignItems:'flex-end' }}>
                    {/* History expand */}
                    {hist.length > 0 && (
                      <button onClick={() => setExpandCode(isExp ? null : prod.code)}
                        style={{ padding:'2px 6px', borderRadius:5, border:`1px solid ${T.border}`,
                          background:'transparent', cursor:'pointer', fontSize:9, color:T.light, fontFamily:'inherit' }}>
                        🕐{isExp ? '▲' : '▼'}
                      </button>
                    )}
                    {canEdit && (
                      <button onClick={() => isEd ? setEditCode(null) : openEdit(prod)}
                        style={{ padding:'3px 7px', borderRadius:6, border:'none',
                          background: isEd ? T.redBg : T.goldBg, cursor:'pointer',
                          fontSize:10, color: isEd ? T.red : T.goldText, fontFamily:'inherit', fontWeight:700 }}>
                        {isEd ? '✕' : '✏️'}
                      </button>
                    )}
                  </div>
                </div>

                {/* Edit form */}
                {isEd && (
                  <div style={{ padding:'12px 16px', background:'#FEFCE8', borderTop:`1px dashed ${T.gold}` }}>
                    <div style={{ fontSize:11, fontWeight:700, color:T.goldText, marginBottom:10 }}>
                      ✏️ Chỉnh giá — {prod.name}
                    </div>
                    <div style={{ display:'grid', gridTemplateColumns: mobile ? '1fr' : '1fr 1fr 1fr', gap:10, marginBottom:12 }}>
                      {/* Loại giá */}
                      <div>
                        <div style={{ fontSize:11, color:T.med, marginBottom:5, fontWeight:600 }}>Loại giá</div>
                        <div style={{ display:'flex', gap:6 }}>
                          {[['fixed','Cố định'],['discount','Chiết khấu %']].map(([v,l]) => (
                            <button key={v} type="button"
                              onClick={() => setEditForm((f: any) => ({...f, pricing_type:v}))}
                              style={{ flex:1, padding:'7px', borderRadius:7, cursor:'pointer',
                                fontFamily:'inherit', fontSize:12, border:'none', fontWeight:editForm.pricing_type===v?700:400,
                                background: editForm.pricing_type===v ? T.gold : T.bg,
                                color: editForm.pricing_type===v ? '#fff' : T.dark }}>
                              {l}
                            </button>
                          ))}
                        </div>
                      </div>
                      {/* Giá */}
                      {editForm.pricing_type==='fixed' ? (
                        <div>
                          <div style={{ fontSize:11, color:T.med, marginBottom:5, fontWeight:600 }}>Giá bán cố định (đ)</div>
                          <input type="number" value={editForm.fixed_price}
                            onChange={e => setEditForm((f: any) => ({...f, fixed_price:e.target.value}))}
                            style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                              borderRadius:7, fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none', boxSizing:'border-box' as any }}/>
                        </div>
                      ) : (
                        <div>
                          <div style={{ fontSize:11, color:T.med, marginBottom:5, fontWeight:600 }}>Chiết khấu (%)</div>
                          <input type="number" min="0" max="100" value={editForm.discount_pct}
                            onChange={e => setEditForm((f: any) => ({...f, discount_pct:e.target.value}))}
                            style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                              borderRadius:7, fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none', boxSizing:'border-box' as any }}/>
                        </div>
                      )}
                      {/* Preview */}
                      <div style={{ background:T.goldBg, borderRadius:8, padding:'7px 10px',
                        display:'flex', flexDirection:'column', justifyContent:'center' }}>
                        <div style={{ fontSize:10, color:T.goldText }}>Giá bán sau chiết khấu</div>
                        <div style={{ fontSize:18, fontWeight:700, color:T.goldText }}>
                          {editForm.pricing_type==='discount'
                            ? Math.round(realPrice(prod.base_price)*(1-(Number(editForm.discount_pct)||0)/100)).toLocaleString()+'đ'
                            : (Number(editForm.fixed_price)||0).toLocaleString()+'đ'}
                        </div>
                        {editForm.pricing_type==='discount' && (
                          <div style={{ fontSize:10, color:T.goldText }}>
                            NL: {realPrice(prod.base_price).toLocaleString()}đ × {100-(Number(editForm.discount_pct)||0)}%
                          </div>
                        )}
                      </div>
                    </div>

                    {/* Price tiers */}
                    <div style={{ marginBottom:12 }}>
                      <div style={{ fontSize:11, color:T.med, marginBottom:7, fontWeight:700 }}>
                        📊 Mốc giá theo số lượng
                      </div>
                      {tiersForm.map((tier, ti) => (
                        <div key={ti} style={{ display:'flex', gap:6, alignItems:'center', marginBottom:6 }}>
                          <div style={{ fontSize:10, color:T.light, width:50, flexShrink:0 }}>Từ SL:</div>
                          <input type="number" value={tier.min_qty}
                            onChange={e => setTiersForm(prev => prev.map((t, i) => i===ti ? {...t, min_qty:e.target.value} : t))}
                            style={{ width:55, padding:'5px 7px', border:`1px solid ${T.border}`, borderRadius:6,
                              fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}/>
                          <div style={{ fontSize:10, color:T.light }}>Giá:</div>
                          <input type="number" value={tier.price}
                            onChange={e => setTiersForm(prev => prev.map((t, i) => i===ti ? {...t, price:e.target.value} : t))}
                            style={{ width:90, padding:'5px 7px', border:`1px solid ${T.border}`, borderRadius:6,
                              fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}/>
                          <input value={tier.note} placeholder="Ghi chú..."
                            onChange={e => setTiersForm(prev => prev.map((t, i) => i===ti ? {...t, note:e.target.value} : t))}
                            style={{ flex:1, padding:'5px 7px', border:`1px solid ${T.border}`, borderRadius:6,
                              fontSize:11, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}/>
                          <button type="button" onClick={() => setTiersForm(prev => prev.filter((_,i) => i!==ti))}
                            style={{ border:'none', background:T.redBg, color:T.red, borderRadius:5,
                              cursor:'pointer', padding:'4px 7px', fontSize:11, fontFamily:'inherit' }}>✕</button>
                        </div>
                      ))}
                      <button type="button"
                        onClick={() => setTiersForm(prev => [...prev, { id:'', product_code:prod.code, min_qty:'', price:'', note:'' }])}
                        style={{ fontSize:11, padding:'4px 10px', borderRadius:6, border:`1px dashed ${T.border}`,
                          background:'transparent', cursor:'pointer', color:T.med, fontFamily:'inherit' }}>
                        + Thêm mốc giá
                      </button>
                    </div>

                    <div style={{ display:'flex', gap:8 }}>
                      <GoldBtn small onClick={() => handleSaveClick(prod)} disabled={saving}>
                        {saving ? '⏳ Đang lưu...' : '💾 Lưu giá'}
                      </GoldBtn>
                      <GoldBtn outline small onClick={() => setEditCode(null)}>Hủy</GoldBtn>
                    </div>
                  </div>
                )}

                {/* Expanded: history only (tiers shown inline above) */}
                {isExp && hist.length > 0 && (
                  <div style={{ background:T.bg, borderTop:`1px dashed ${T.border}`, padding:'10px 16px' }}>
                    <div style={{ fontSize:10, fontWeight:700, color:T.med, marginBottom:6, textTransform:'uppercase', letterSpacing:.5 }}>
                      🕐 Lịch sử thay đổi giá
                    </div>
                    {hist.map((h: any) => (
                      <div key={h.id} style={{ display:'flex', alignItems:'center', gap:10, marginBottom:5,
                        padding:'5px 10px', background:'#fff', borderRadius:7, border:`1px solid ${T.border}` }}>
                        <span style={{ fontSize:10, color:T.light, minWidth:110 }}>
                          {h.changed_at ? new Date(h.changed_at).toLocaleString('vi-VN',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'}) : '—'}
                        </span>
                        <span style={{ fontSize:11, color:T.light, textDecoration:'line-through' }}>
                          {(h.old_price||0).toLocaleString()}đ
                        </span>
                        <span style={{ fontSize:11 }}>→</span>
                        <span style={{ fontSize:12, fontWeight:700, color:T.blue }}>{(h.new_price||0).toLocaleString()}đ</span>
                        {h.pricing_type==='discount' && (
                          <span style={{ fontSize:9, padding:'1px 5px', borderRadius:8, background:T.amberBg, color:T.amber }}>
                            CK {h.discount_pct}%
                          </span>
                        )}
                        <span style={{ fontSize:10, color:T.light, marginLeft:'auto' }}>bởi {h.changed_by_name||'—'}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )
          })}
        </Card>
      ))}

      {/* Confirm apply discount to all modal */}
      {showConfirmAll && (
        <Modal open title="Áp dụng chiết khấu cho toàn nhãn hàng?" onClose={() => setShowConfirmAll(null)}>
          <div style={{ fontSize:13, color:T.dark, marginBottom:16 }}>
            Bạn có muốn áp dụng mức chiết khấu <b>{editForm.discount_pct}%</b> cho tất cả sản phẩm
            nhãn hàng <b>{getBrand(showConfirmAll.prod)}</b> không?
          </div>
          <div style={{ display:'flex', gap:10, justifyContent:'flex-end' }}>
            <GoldBtn outline small onClick={() => savePrice(showConfirmAll.prod, false)}>Chỉ SP này</GoldBtn>
            <GoldBtn small onClick={() => savePrice(showConfirmAll.prod, true)}>Áp dụng cả nhãn hàng</GoldBtn>
          </div>
        </Modal>
      )}
    </div>
  )
}

// ── PART 2: Brand Programs Tab ─────────────────────────────────
function BrandProgramsTab({ user, mobile, products, allUsers,
  brandPrograms, setBrandPrograms, canEdit }: any) {

  const [subTab, setSubTab]   = useState<'active'|'history'>('active')
  const [showForm, setShowForm] = useState(false)
  const [editProg, setEditProg] = useState<any>(null)
  const [saving, setSaving]   = useState(false)
  const [expandId, setExpandId] = useState<string|null>(null)
  const [showRewardConfirm, setShowRewardConfirm] = useState<any>(null)

  const today = new Date().toISOString().split('T')[0]
  const in7d  = new Date(Date.now()+7*86400000).toISOString().split('T')[0]

  // Lấy danh sách nhãn hàng từ field trademark của KiotViet
  const brands = [...new Set(products.map((p: any) => p.trademark || p.brand || '').filter(Boolean))].sort()

  const emptyForm: any = {
    brand_name:'', program_name:'', start_date:'', end_date:'', open_ended:false,
    is_fixed_annual:false,
    discount_type:'discount', discount_detail:'', condition_text:'',
    reward_monthly:'', reward_quarterly:'', reward_yearly:'',
    current_revenue:0, revenue_note:'',
    reward_status:'pending',
    exchange_amount:'', exchange_type:'cash', exchange_detail:'', exchange_date:'',
  }
  const [form, setForm] = useState<any>(emptyForm)
  const F = (k: string, v: any) => setForm((f: any) => ({...f, [k]:v}))

  const activeProgs  = brandPrograms.filter((p: any) => p.status==='active')
  const historyProgs = brandPrograms.filter((p: any) => p.status==='history')

  // Programs expiring within 7 days
  const expiringSoon = activeProgs.filter((p: any) =>
    !p.open_ended && p.end_date && p.end_date >= today && p.end_date <= in7d
  )

  const openCreate = () => { setEditProg(null); setForm(emptyForm); setShowForm(true) }
  const openEdit = (prog: any) => {
    setEditProg(prog)
    setForm({ ...prog, end_date: prog.open_ended ? '' : (prog.end_date||'') })
    setShowForm(true)
  }

  const saveProg = async () => {
    if (!form.brand_name || !form.program_name) return
    setSaving(true)
    const now = new Date().toISOString()
    const data = {
      ...form,
      current_revenue: Number(form.current_revenue)||0,
      exchange_amount: form.exchange_amount ? Number(form.exchange_amount) : null,
      status: editProg ? editProg.status : 'active',
      created_at: editProg ? editProg.created_at : now,
      created_by: editProg ? editProg.created_by : user.id,
    }
    if (editProg) {
      const updated = {...editProg, ...data}
      await db.from('brand_programs').upsert(updated)
      setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===editProg.id ? updated : p))
    } else {
      const newP = { id:'bp_'+Date.now()+'_'+Math.random().toString(36).slice(2,5), ...data }
      await db.from('brand_programs').insert(newP)
      setBrandPrograms((prev: any[]) => [newP, ...prev])
    }
    setSaving(false); setShowForm(false)
  }

  const updateRewardStatus = async (prog: any, newStatus: string) => {
    if (newStatus === 'done') {
      setShowRewardConfirm(prog); return
    }
    const updated = {...prog, reward_status: newStatus}
    await db.from('brand_programs').update({reward_status: newStatus}).eq('id', prog.id)
    setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? updated : p))
  }

  const moveToHistory = async (prog: any) => {
    const updated = {...prog, reward_status:'done', status:'history'}
    await db.from('brand_programs').update({reward_status:'done', status:'history'}).eq('id', prog.id)
    setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? updated : p))
    setShowRewardConfirm(null)
  }

  const renewProgram = async (prog: any) => {
    const updated = {...prog, status:'active'}
    await db.from('brand_programs').update({status:'active'}).eq('id', prog.id)
    setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? updated : p))
  }

  const deleteProg = async (id: string) => {
    if (!confirm('Xóa chương trình này?')) return
    await db.from('brand_programs').delete().eq('id', id)
    setBrandPrograms((prev: any[]) => prev.filter((p: any) => p.id!==id))
  }

  const REWARD_STATUS: any = {
    pending: { label:'Chưa trả thưởng', color:T.amber,   bg:T.amberBg },
    partial: { label:'Đã trả 1 phần',   color:T.blue,    bg:T.blueBg  },
    done:    { label:'Đã trả đủ',        color:T.green,   bg:T.greenBg },
  }

  const renderProgTable = (progs: any[]) => {
    if (progs.length === 0) return (
      <div style={{ textAlign:'center', padding:'40px', color:T.light, fontSize:13 }}>
        {subTab==='active' ? 'Chưa có chương trình nào đang áp dụng' : 'Chưa có chương trình nào trong lịch sử'}
      </div>
    )

    // Group by brand
    const byBrand: Record<string,any[]> = {}
    progs.forEach((p: any) => {
      if (!byBrand[p.brand_name]) byBrand[p.brand_name] = []
      byBrand[p.brand_name].push(p)
    })

    return Object.entries(byBrand).map(([brand, items]) => (
      <Card key={brand} style={{ padding:0, overflow:'hidden', marginBottom:14 }}>
        <div style={{ background:`linear-gradient(90deg,${T.blueBg},#fff)`, padding:'10px 16px',
          borderBottom:`1px solid ${T.border}`, display:'flex', alignItems:'center', gap:10 }}>
          <span style={{ fontSize:15 }}>🏢</span>
          <span style={{ fontWeight:700, fontSize:14, color:T.blue }}>{brand}</span>
          <span style={{ fontSize:11, color:T.light }}>— {items.length} chương trình</span>
        </div>

        {items.map((prog: any, pi: number) => {
          const isExp = expandId === prog.id
          const rs = REWARD_STATUS[prog.reward_status] || REWARD_STATUS.pending
          const daysLeft = prog.end_date && !prog.open_ended
            ? Math.ceil((new Date(prog.end_date).getTime()-Date.now())/86400000) : null
          const isExpiring = daysLeft !== null && daysLeft >= 0 && daysLeft <= 7
          const isOverdue  = daysLeft !== null && daysLeft < 0

          return (
            <div key={prog.id} style={{ borderTop:`1px solid ${T.border}`,
              background: isExpiring ? '#FFFBEB' : isOverdue ? '#FEF2F2' : pi%2===0?'#fff':T.rowAlt }}>
              {/* Row */}
              <div style={{ padding:'10px 14px' }}>
                <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:10, flexWrap:'wrap' }}>
                  <div style={{ flex:1, minWidth:200 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:7, flexWrap:'wrap', marginBottom:4 }}>
                      <span style={{ fontSize:13, fontWeight:700, color:T.dark }}>{prog.program_name}</span>
                      {isExpiring && <span style={{ fontSize:9, padding:'1px 6px', borderRadius:8, background:'#FEF3C7', color:'#92400E', fontWeight:700 }}>⚠️ Còn {daysLeft} ngày</span>}
                      {isOverdue  && <span style={{ fontSize:9, padding:'1px 6px', borderRadius:8, background:T.redBg, color:T.red, fontWeight:700 }}>⏰ Hết hạn</span>}
                    </div>
                    <div style={{ display:'flex', gap:10, flexWrap:'wrap', fontSize:11, color:T.med }}>
                      <span>📅 {prog.start_date||'?'} → {prog.open_ended ? '(Chưa rõ)' : (prog.end_date||'?')}</span>
                      <span>{prog.discount_type==='discount' ? '💸' : '🎁'} {prog.discount_detail||'—'}</span>
                    </div>
                    {prog.condition_text && (
                      <div style={{ fontSize:11, color:T.light, marginTop:3 }}>📋 ĐK: {prog.condition_text}</div>
                    )}
                  </div>

                  {/* Reward columns */}
                  <div style={{ display:'flex', gap:6, flexWrap:'wrap', alignItems:'center' }}>
                    {[['monthly','Tháng'], ['quarterly','Quý'], ['yearly','Năm']].map(([k,l]) => {
                      const val = prog[`reward_${k}`]
                      if (!val) return null
                      return (
                        <div key={k} style={{ background:'#fff', border:`1px solid ${T.border}`,
                          borderRadius:8, padding:'4px 10px', minWidth:80, textAlign:'center' }}>
                          <div style={{ fontSize:9, color:T.light }}>Thưởng {l}</div>
                          <div style={{ fontSize:12, fontWeight:700, color:T.goldText }}>{val}</div>
                        </div>
                      )
                    })}
                  </div>

                  {/* Revenue + status */}
                  <div style={{ display:'flex', alignItems:'center', gap:8, flexWrap:'wrap' }}>
                    <div style={{ background:T.bg, borderRadius:8, padding:'4px 10px', textAlign:'center' }}>
                      <div style={{ fontSize:9, color:T.light }}>Doanh số</div>
                      <div style={{ fontSize:12, fontWeight:700, color:T.dark }}>
                        {prog.current_revenue > 0 ? Number(prog.current_revenue).toLocaleString()+'đ' : '—'}
                      </div>
                    </div>
                    <span style={{ fontSize:10, padding:'3px 9px', borderRadius:10, fontWeight:700,
                      background:rs.bg, color:rs.color }}>{rs.label}</span>
                  </div>

                  {/* Actions */}
                  <div style={{ display:'flex', gap:5, alignItems:'center' }}>
                    <button onClick={() => setExpandId(isExp ? null : prog.id)}
                      style={{ padding:'3px 7px', borderRadius:6, border:`1px solid ${T.border}`,
                        background:'transparent', cursor:'pointer', fontSize:10, color:T.med, fontFamily:'inherit' }}>
                      {isExp ? '▲' : '▼'}
                    </button>
                    {canEdit && (
                      <>
                        <button onClick={() => openEdit(prog)}
                          style={{ padding:'3px 7px', borderRadius:6, border:'none',
                            background:T.goldBg, cursor:'pointer', fontSize:10, color:T.goldText, fontFamily:'inherit' }}>✏️</button>
                        {subTab==='history' && (
                          <button onClick={() => renewProgram(prog)}
                            style={{ padding:'3px 8px', borderRadius:6, border:`1px solid ${T.green}`,
                              background:T.greenBg, cursor:'pointer', fontSize:10, color:T.green, fontFamily:'inherit', fontWeight:700 }}>
                            ↩ Gia hạn
                          </button>
                        )}
                        <button onClick={() => deleteProg(prog.id)}
                          style={{ padding:'3px 7px', borderRadius:6, border:'none',
                            background:T.redBg, cursor:'pointer', fontSize:10, color:T.red, fontFamily:'inherit' }}>✕</button>
                      </>
                    )}
                  </div>
                </div>
              </div>

              {/* Expanded details */}
              {isExp && (
                <div style={{ background:T.bg, borderTop:`1px dashed ${T.border}`, padding:'12px 16px' }}>

                  {/* Fixed annual program: monthly breakdown */}
                  {prog.is_fixed_annual && (
                    <div style={{ marginBottom:14 }}>
                      <div style={{ fontSize:11, fontWeight:700, color:'#7C3AED', marginBottom:8 }}>
                        📅 Theo dõi theo tháng (Chương trình cố định cả năm)
                      </div>
                      <div style={{ display:'grid', gridTemplateColumns: mobile ? 'repeat(3,1fr)' : 'repeat(6,1fr)', gap:6 }}>
                        {['T1','T2','T3','T4','T5','T6','T7','T8','T9','T10','T11','T12'].map((month, mi) => {
                          const key = `month_${mi+1}`
                          const monthData = prog[key] ? JSON.parse(prog[key]) : { revenue:0, reward_status:'pending' }
                          const mStatus = monthData.reward_status || 'pending'
                          const mRS = REWARD_STATUS[mStatus] || REWARD_STATUS.pending
                          return (
                            <div key={month} style={{ background:'#fff', borderRadius:8, padding:'8px 10px',
                              border:`1.5px solid ${mStatus==='done'?T.green:mStatus==='partial'?T.blue:T.border}` }}>
                              <div style={{ fontSize:10, fontWeight:700, color:T.med, marginBottom:4 }}>{month}</div>
                              {canEdit ? (
                                <input type="number" placeholder="Doanh số"
                                  defaultValue={monthData.revenue||''}
                                  onBlur={async e => {
                                    const val = Number(e.target.value)||0
                                    const updated = { ...monthData, revenue: val }
                                    await db.from('brand_programs').update({ [key]: JSON.stringify(updated) }).eq('id', prog.id)
                                    setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? {...p, [key]: JSON.stringify(updated)} : p))
                                  }}
                                  style={{ width:'100%', padding:'4px 6px', border:`1px solid ${T.border}`,
                                    borderRadius:5, fontSize:11, fontFamily:'inherit', color:T.dark,
                                    background:'#fff', outline:'none', boxSizing:'border-box' as any, marginBottom:4 }}/>
                              ) : (
                                <div style={{ fontSize:11, fontWeight:600, color:T.dark, marginBottom:4 }}>
                                  {monthData.revenue > 0 ? Number(monthData.revenue).toLocaleString()+'đ' : '—'}
                                </div>
                              )}
                              {canEdit && (
                                <select value={mStatus}
                                  onChange={async e => {
                                    const updated = { ...monthData, reward_status: e.target.value }
                                    await db.from('brand_programs').update({ [key]: JSON.stringify(updated) }).eq('id', prog.id)
                                    setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? {...p, [key]: JSON.stringify(updated)} : p))
                                  }}
                                  style={{ width:'100%', padding:'3px 4px', border:`1px solid ${T.border}`,
                                    borderRadius:5, fontSize:9, fontFamily:'inherit', color:mRS.color,
                                    background:mRS.bg, outline:'none' }}>
                                  <option value="pending">Chưa trả</option>
                                  <option value="partial">Trả 1 phần</option>
                                  <option value="done">Đã trả đủ</option>
                                </select>
                              )}
                              {!canEdit && (
                                <span style={{ fontSize:9, padding:'1px 5px', borderRadius:8,
                                  background:mRS.bg, color:mRS.color, fontWeight:700 }}>{mRS.label}</span>
                              )}
                            </div>
                          )
                        })}
                      </div>
                    </div>
                  )}

                  <div style={{ display:'grid', gridTemplateColumns: mobile ? '1fr' : '1fr 1fr', gap:14 }}>
                    {/* Doanh số update */}
                    {canEdit && subTab==='active' && !prog.is_fixed_annual && (
                      <div style={{ background:'#fff', borderRadius:9, padding:'10px 12px', border:`1px solid ${T.border}` }}>
                        <div style={{ fontSize:11, fontWeight:700, color:T.med, marginBottom:8 }}>📊 Cập nhật doanh số</div>
                        <input type="number" defaultValue={prog.current_revenue||''}
                          onBlur={async e => {
                            const val = Number(e.target.value)||0
                            await db.from('brand_programs').update({current_revenue:val}).eq('id',prog.id)
                            setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===prog.id ? {...p,current_revenue:val} : p))
                          }}
                          style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                            borderRadius:7, fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff',
                            outline:'none', boxSizing:'border-box' as any, marginBottom:6 }}/>
                        <div style={{ fontSize:10, color:T.light }}>(Nhập doanh số hiện tại, blur để lưu)</div>
                      </div>
                    )}

                    {/* Trạng thái trả thưởng */}
                    {canEdit && subTab==='active' && (
                      <div style={{ background:'#fff', borderRadius:9, padding:'10px 12px', border:`1px solid ${T.border}` }}>
                        <div style={{ fontSize:11, fontWeight:700, color:T.med, marginBottom:8 }}>🎁 Trạng thái trả thưởng</div>
                        <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
                          {[['pending','Chưa trả'],['partial','Đã trả 1 phần'],['done','Đã trả đủ']].map(([v,l]) => (
                            <button key={v} type="button"
                              onClick={() => updateRewardStatus(prog, v)}
                              style={{ padding:'5px 10px', borderRadius:7, border:'none', cursor:'pointer',
                                fontFamily:'inherit', fontSize:11, fontWeight:prog.reward_status===v?700:400,
                                background: prog.reward_status===v ? (REWARD_STATUS[v]?.bg||T.bg) : T.bg,
                                color: prog.reward_status===v ? (REWARD_STATUS[v]?.color||T.med) : T.med }}>
                              {l}
                            </button>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Quy đổi thưởng */}
                    <div style={{ background:'#fff', borderRadius:9, padding:'10px 12px', border:`1px solid ${T.border}` }}>
                      <div style={{ fontSize:11, fontWeight:700, color:T.med, marginBottom:6 }}>💰 Quy đổi thưởng</div>
                      {prog.exchange_amount ? (
                        <div style={{ fontSize:12, color:T.dark }}>
                          <span style={{ fontWeight:700 }}>{Number(prog.exchange_amount).toLocaleString()}đ</span>
                          <span style={{ color:T.light, marginLeft:6 }}>
                            {prog.exchange_type==='cash' ? '(Tiền mặt)' : '(Hàng hóa)'}
                          </span>
                          {prog.exchange_detail && <div style={{ color:T.light, fontSize:11, marginTop:3 }}>{prog.exchange_detail}</div>}
                          {prog.exchange_date && <div style={{ color:T.light, fontSize:11 }}>📅 Ngày đổi: {prog.exchange_date}</div>}
                        </div>
                      ) : (
                        <div style={{ color:T.light, fontSize:11 }}>Chưa có thông tin quy đổi</div>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          )
        })}
      </Card>
    ))
  }

  return (
    <div>
      {/* Expiry warning banner */}
      {expiringSoon.length > 0 && (
        <div style={{ background:'#FFFBEB', border:`1.5px solid ${T.amber}`, borderRadius:10,
          padding:'10px 16px', marginBottom:14, display:'flex', alignItems:'center', gap:10 }}>
          <span style={{ fontSize:16 }}>⚠️</span>
          <span style={{ fontSize:12, color:'#92400E', fontWeight:600 }}>
            {expiringSoon.length} chương trình sắp hết hạn (trong 7 ngày tới): {' '}
            {expiringSoon.map((p: any) => p.program_name).join(', ')}
          </span>
        </div>
      )}

      {/* Top bar */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12, flexWrap:'wrap', gap:8 }}>
        <div style={{ display:'flex', gap:0, border:`1px solid ${T.border}`, borderRadius:8, overflow:'hidden', background:'#fff' }}>
          {([['active','🟢 Đang áp dụng'],['history','🗂️ Lịch sử']] as [string,string][]).map(([id,label]) => (
            <button key={id} onClick={() => setSubTab(id as any)}
              style={{ padding:'7px 16px', border:'none', cursor:'pointer', fontFamily:'inherit',
                fontSize:12, fontWeight:subTab===id?700:400,
                background:subTab===id?T.blue:'transparent',
                color:subTab===id?'#fff':T.med }}>
              {label}
            </button>
          ))}
        </div>
        {canEdit && <GoldBtn small onClick={openCreate}>+ Thêm chương trình</GoldBtn>}
      </div>

      {renderProgTable(subTab==='active' ? activeProgs : historyProgs)}

      {/* Move to history confirm */}
      {showRewardConfirm && (
        <Modal open title="Đã trả thưởng toàn bộ?" onClose={() => setShowRewardConfirm(null)}>
          <div style={{ fontSize:13, color:T.dark, marginBottom:16 }}>
            Chuyển chương trình <b>{showRewardConfirm.program_name}</b> sang tab Lịch sử?
          </div>
          <div style={{ display:'flex', gap:10, justifyContent:'flex-end' }}>
            <GoldBtn outline small onClick={async () => {
              await db.from('brand_programs').update({reward_status:'done'}).eq('id',showRewardConfirm.id)
              setBrandPrograms((prev: any[]) => prev.map((p: any) => p.id===showRewardConfirm.id ? {...p,reward_status:'done'} : p))
              setShowRewardConfirm(null)
            }}>Giữ lại tab hiện tại</GoldBtn>
            <GoldBtn small onClick={() => moveToHistory(showRewardConfirm)}>Chuyển sang Lịch sử</GoldBtn>
          </div>
        </Modal>
      )}

      {/* Add/Edit form modal */}
      <Modal open={showForm} onClose={() => setShowForm(false)}
        title={editProg ? 'Sửa chương trình' : 'Thêm chương trình nhãn hàng'} wide>
        <div style={{ display:'grid', gridTemplateColumns: mobile ? '1fr' : '1fr 1fr', gap:12 }}>
          {/* Brand */}
          <div>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:5 }}>Nhãn hàng *</div>
            <select value={form.brand_name} onChange={e => F('brand_name', e.target.value)}
              style={{ width:'100%', padding:'8px 10px', border:`1px solid ${T.border}`,
                borderRadius:7, fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff',
                outline:'none', boxSizing:'border-box' as any }}>
              <option value="">— Chọn nhãn hàng —</option>
              {brands.map((b: any) => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>
          <Inp label="Tên chương trình *" value={form.program_name} onChange={v => F('program_name',v)} placeholder="VD: Chương trình đại lý Q1/2026"/>

          {/* Fixed annual toggle */}
          <div style={{ gridColumn: mobile ? '1' : '1/-1' }}>
            <label style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer',
              padding:'8px 12px', borderRadius:8,
              background: form.is_fixed_annual ? '#EDE9FE' : T.bg,
              border: `1.5px solid ${form.is_fixed_annual ? '#7C3AED' : T.border}` }}>
              <input type="checkbox" checked={form.is_fixed_annual}
                onChange={e => F('is_fixed_annual', e.target.checked)}/>
              <div>
                <div style={{ fontSize:12, fontWeight:700, color: form.is_fixed_annual ? '#7C3AED' : T.dark }}>
                  📅 Chương trình cố định cả năm
                </div>
                <div style={{ fontSize:10, color:T.light }}>
                  Khi expand sẽ hiển thị theo dõi doanh số + trạng thái trả thưởng từng tháng
                </div>
              </div>
            </label>
          </div>

          {/* Dates */}
          <Inp label="📅 Ngày bắt đầu" type="date" value={form.start_date} onChange={v => F('start_date',v)}/>
          <div>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:5 }}>📅 Ngày kết thúc</div>
            <div style={{ display:'flex', gap:6, alignItems:'center' }}>
              <input type="date" value={form.open_ended ? '' : (form.end_date||'')}
                disabled={form.open_ended}
                onChange={e => F('end_date', e.target.value)}
                style={{ flex:1, padding:'7px 10px', border:`1px solid ${T.border}`,
                  borderRadius:7, fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff',
                  outline:'none', opacity: form.open_ended ? .4 : 1 }}/>
              <label style={{ display:'flex', alignItems:'center', gap:4, fontSize:11, color:T.med, whiteSpace:'nowrap', cursor:'pointer' }}>
                <input type="checkbox" checked={form.open_ended} onChange={e => F('open_ended', e.target.checked)}/>
                Chưa rõ
              </label>
            </div>
          </div>

          {/* Discount type */}
          <div style={{ gridColumn: mobile ? '1' : '1/-1' }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:5 }}>Chiết khấu / Quà tặng</div>
            <div style={{ display:'flex', gap:6, marginBottom:7 }}>
              {[['discount','💸 Chiết khấu'],['gift','🎁 Quà tặng']].map(([v,l]) => (
                <button key={v} type="button" onClick={() => F('discount_type',v)}
                  style={{ padding:'6px 14px', borderRadius:7, border:'none', cursor:'pointer',
                    fontFamily:'inherit', fontSize:12, fontWeight:form.discount_type===v?700:400,
                    background: form.discount_type===v ? T.gold : T.bg,
                    color: form.discount_type===v ? '#fff' : T.med }}>
                  {l}
                </button>
              ))}
            </div>
            <input value={form.discount_detail} onChange={e => F('discount_detail',e.target.value)}
              placeholder={form.discount_type==='discount' ? 'VD: CK thẳng 35% sau CK 30tr' : 'VD: Tặng 1 hộp sản phẩm mẫu'}
              style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                borderRadius:7, fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff',
                outline:'none', boxSizing:'border-box' as any }}/>
          </div>

          <div style={{ gridColumn: mobile ? '1' : '1/-1' }}>
            <Inp label="📋 Điều kiện áp dụng" value={form.condition_text}
              onChange={v => F('condition_text',v)}
              placeholder="VD: Doanh số tháng sau CK 30tr, Doanh số Quý 130tr"/>
          </div>

          {/* Rewards */}
          <div style={{ gridColumn: mobile ? '1' : '1/-1' }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:7 }}>🏆 Mức thưởng</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:8 }}>
              <Inp label="Thưởng tháng" value={form.reward_monthly}
                onChange={v => F('reward_monthly',v)} placeholder="VD: 5%" />
              <Inp label="Thưởng quý" value={form.reward_quarterly}
                onChange={v => F('reward_quarterly',v)} placeholder="VD: 5%" />
              <Inp label="Thưởng năm" value={form.reward_yearly}
                onChange={v => F('reward_yearly',v)} placeholder="VD: —" />
            </div>
          </div>

          {/* Quy đổi */}
          <div style={{ gridColumn: mobile ? '1' : '1/-1' }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:7 }}>💰 Quy đổi thưởng</div>
            <div style={{ display:'grid', gridTemplateColumns: mobile ? '1fr' : '1fr 1fr 1fr', gap:8 }}>
              <div>
                <div style={{ fontSize:11, color:T.light, marginBottom:4 }}>Hình thức</div>
                <select value={form.exchange_type} onChange={e => F('exchange_type',e.target.value)}
                  style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                    borderRadius:7, fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}>
                  <option value="cash">Tiền mặt</option>
                  <option value="goods">Hàng hóa</option>
                </select>
              </div>
              <Inp label="Số tiền / Giá trị" type="number" value={form.exchange_amount}
                onChange={v => F('exchange_amount',v)} placeholder="0"/>
              <Inp label="Ngày quy đổi" type="date" value={form.exchange_date}
                onChange={v => F('exchange_date',v)}/>
            </div>
            <div style={{ marginTop:7 }}>
              <Inp label="Chi tiết quy đổi" value={form.exchange_detail}
                onChange={v => F('exchange_detail',v)}
                placeholder="VD: Đã đổi b5 Candid 11/7, lấy re 0.5% đã trả 29/1/2026..."/>
            </div>
          </div>
        </div>

        <div style={{ display:'flex', justifyContent:'flex-end', gap:10, marginTop:16 }}>
          <GoldBtn outline small onClick={() => setShowForm(false)}>Hủy</GoldBtn>
          <GoldBtn small onClick={saveProg} disabled={saving || !form.brand_name || !form.program_name}>
            {saving ? '⏳ Đang lưu...' : '💾 Lưu chương trình'}
          </GoldBtn>
        </div>
      </Modal>
    </div>
  )
}

// ══ EXPIRY MODULE ════════════════════════════════════════════
function ExpiryModule({ user, mobile, products, batches, setBatches }: any) {
  const perm      = getPerm(user)
  const canManage = perm.manageExpiry || perm.manageInventory || perm.viewAllDashboard

  const [tab, setTab]               = useState<'overview'|'list'|'alert'>('overview')
  const [showAdd, setShowAdd]       = useState(false)
  const [editBatch, setEditBatch]   = useState<any>(null)
  const [searchQ, setSearchQ]       = useState('')
  const [filterStatus, setFilterStatus] = useState<string>('all')
  const [importErrors, setImportErrors]   = useState<string[]>([])
  const [importPreview, setImportPreview] = useState<any[]|null>(null)
  const [saving, setSaving]         = useState(false)

  const today = new Date()
  const pad   = mobile ? '16px' : '24px'

  const calcMonthsLeft = (expiry_date: string) => {
    if (!expiry_date) return 0
    const exp = new Date(expiry_date)
    return (exp.getFullYear() - today.getFullYear()) * 12 + (exp.getMonth() - today.getMonth())
  }

  const getStatus = (ml: number) => {
    if (ml <  6) return { label:'🔴 Dưới 6 tháng',  color:T.red,    bg:T.redBg,   key:'red'    }
    if (ml < 12) return { label:'🟠 Dưới 12 tháng', color:'#C2410C', bg:'#FFEDD5', key:'orange' }
    if (ml < 18) return { label:'🟡 Dưới 18 tháng', color:'#854D0E', bg:'#FEF9C3', key:'yellow' }
    return             { label:'🟢 Còn hàng',        color:T.green,  bg:T.greenBg, key:'green'  }
  }

  const fmtExpiry = (expiry_date: string) => {
    if (!expiry_date) return '—'
    const p = expiry_date.split('-')
    return `${p[1]}/${p[0]}`
  }

  const enriched = (batches || []).map((b: any) => {
    const ml   = calcMonthsLeft(b.expiry_date)
    const st   = getStatus(ml)
    const prod = products.find((pp: any) => pp.code === b.product_code)
    return { ...b, monthsLeft: ml, status: st, prod }
  })

  const batchTotalByCode: Record<string, number> = {}
  enriched.forEach((b: any) => {
    batchTotalByCode[b.product_code] = (batchTotalByCode[b.product_code] || 0) + (b.qty_remaining || 0)
  })

  const withQty     = enriched.filter((b: any) => (b.qty_remaining || 0) > 0)
  const countRed    = withQty.filter((b: any) => b.monthsLeft <  6).length
  const countOrange = withQty.filter((b: any) => b.monthsLeft >=  6 && b.monthsLeft < 12).length
  const countYellow = withQty.filter((b: any) => b.monthsLeft >= 12 && b.monthsLeft < 18).length
  const countGreen  = withQty.filter((b: any) => b.monthsLeft >= 18).length

  const normExp = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')
  const fuzzyExp = (b: any, q: string) => {
    if (!q.trim()) return true
    const hay = normExp(b.product_code + ' ' + b.product_name)
    return normExp(q).split(/\s+/).every((t: string) => hay.includes(t))
  }

  const filtered = enriched.filter((b: any) => {
    if (filterStatus !== 'all' && b.status.key !== filterStatus) return false
    if (searchQ) return fuzzyExp(b, searchQ)
    return true
  }).sort((a: any, b: any) => a.monthsLeft - b.monthsLeft)

  const alertList = enriched
    .filter((b: any) => b.monthsLeft < 12 && (b.qty_remaining || 0) > 0)
    .sort((a: any, b: any) => a.monthsLeft - b.monthsLeft)

  const tabs = [
    { id:'overview', icon:'📊', label:'Tổng quan' },
    { id:'list',     icon:'📦', label:'Danh sách lô' },
    { id:'alert',    icon:'🚨', label:`Cảnh báo (${alertList.length})` },
  ]

  // ── CRUD ──
  const saveBatch = async (form: any) => {
    setSaving(true)
    const now = new Date().toISOString()
    const [mm, yyyy] = form.expiry_mmyyyy.split('/')
    const expiry_date = `${yyyy}-${mm.padStart(2,'0')}-01`
    if (editBatch) {
      const upd = {
        product_code: form.product_code, product_name: form.product_name,
        unit: form.unit, expiry_date, qty_remaining: Number(form.qty_remaining),
        note: form.note, last_updated_at: now, last_updated_by: user.id
      }
      await db.from('product_batches').update(upd).eq('id', editBatch.id)
      setBatches((prev: any[]) => prev.map((b: any) => b.id === editBatch.id ? { ...b, ...upd } : b))
    } else {
      const newB = {
        id: 'bat_' + Date.now() + '_' + Math.random().toString(36).slice(2,7),
        product_code: form.product_code, product_name: form.product_name,
        unit: form.unit, expiry_date, qty_remaining: Number(form.qty_remaining),
        note: form.note, last_updated_at: now, last_updated_by: user.id,
        created_by: user.id, created_at: now
      }
      await db.from('product_batches').insert(newB)
      setBatches((prev: any[]) => [newB, ...prev])
    }
    setSaving(false); setShowAdd(false); setEditBatch(null)
  }

  const deleteBatch = async (id: string) => {
    if (!confirm('Xóa lô hàng này? Thao tác không thể hoàn tác.')) return
    await db.from('product_batches').delete().eq('id', id)
    setBatches((prev: any[]) => prev.filter((b: any) => b.id !== id))
  }

  // ── Import Excel ──
  const handleImportFile = async (file: File) => {
    const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
    const buf  = await file.arrayBuffer()
    const wb   = xlsx.read(buf, { type:'array' })
    const ws   = wb.Sheets[wb.SheetNames[0]]
    const rows: any[] = xlsx.utils.sheet_to_json(ws, { header:1, defval:'' })
    const dataRows = rows.slice(1).filter((r: any[]) => r[0] || r[1] || r[2])
    const errors: string[] = []
    const preview: any[]   = []

    // Convert Excel serial date → MM/YYYY
    const excelSerialToMMYYYY = (val: any): string | null => {
      const n = Number(val)
      if (!isNaN(n) && n > 30000 && n < 80000) {
        // Excel epoch: 1900-01-01 = 1 (with leap year bug)
        const d = new Date(Date.UTC(1899, 11, 30) + n * 86400000)
        const mm = String(d.getUTCMonth() + 1).padStart(2, '0')
        const yyyy = String(d.getUTCFullYear())
        return `${mm}/${yyyy}`
      }
      return null
    }

    dataRows.forEach((r: any[], i: number) => {
      const codeRaw   = String(r[0] || '').trim().toUpperCase()
      let   expiryRaw = String(r[1] || '').trim()
      const qty       = Number(r[2]) || 0
      const note      = String(r[3] || '').trim()
      const lineNum   = i + 2

      if (!codeRaw) { errors.push(`Dòng ${lineNum}: Thiếu Mã SP`); return }
      const prod = products.find((pp: any) => pp.code.toUpperCase() === codeRaw)
      if (!prod) {
        errors.push(`Dòng ${lineNum}: Mã SP "${codeRaw}" không tồn tại. Vui lòng kiểm tra lại đúng theo Mã SP hoặc Tên SP trong KiotViet.`)
        return
      }

      // Auto-convert Excel serial date nếu cần
      const converted = excelSerialToMMYYYY(expiryRaw)
      if (converted) expiryRaw = converted

      const match = expiryRaw.match(/^(\d{1,2})\/(\d{4})$/)
      if (!match) { errors.push(`Dòng ${lineNum}: Ngày HSD "${expiryRaw}" sai định dạng — cần MM/YYYY (VD: 06/2026)`); return }
      const [, mm, yyyy] = match
      if (Number(mm) < 1 || Number(mm) > 12) { errors.push(`Dòng ${lineNum}: Tháng "${mm}" không hợp lệ`); return }
      preview.push({
        product_code: prod.code, product_name: prod.name, unit: prod.unit || '',
        expiry_date: `${yyyy}-${mm.padStart(2,'0')}-01`,
        qty_remaining: qty, note, _disp: `${mm.padStart(2,'0')}/${yyyy}`
      })
    })
    setImportErrors(errors)
    setImportPreview(errors.length === 0 ? preview : null)
  }

  const confirmImport = async () => {
    if (!importPreview) return
    setSaving(true)
    const now = new Date().toISOString()
    const newBatches = importPreview.map((b, idx) => {
      // Loại bỏ _disp (chỉ dùng cho UI, không có trong DB)
      const { _disp, ...dbFields } = b
      return {
        id: 'bat_' + (Date.now() + idx) + '_' + Math.random().toString(36).slice(2,7),
        ...dbFields, last_updated_at: now, last_updated_by: user.id,
        created_by: user.id, created_at: now
      }
    })
    const { error } = await db.from('product_batches').insert(newBatches)
    if (error) {
      alert(`❌ Lỗi khi lưu vào DB: ${error.message}\n\nVui lòng thử lại hoặc liên hệ Admin.`)
      setSaving(false)
      return
    }
    setBatches((prev: any[]) => [...newBatches, ...prev])
    setImportPreview(null); setSaving(false); setTab('list')
  }

  const downloadTemplate = async () => {
    const xlsx = await import('https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm' as any)
    const ws = xlsx.utils.aoa_to_sheet([
      ['Mã SP *', 'Ngày HSD * (MM/YYYY)', 'SL Tồn', 'Ghi chú'],
      ['SP001', '06/2026', 120, 'Lô tháng 1'],
      ['SP002', '12/2027', 80,  ''],
      ['(Xóa 2 dòng mẫu này, giữ nguyên hàng tiêu đề)', '', '', ''],
    ])
    ws['!cols'] = [{wch:15},{wch:22},{wch:10},{wch:35}]
    const wb = xlsx.utils.book_new()
    xlsx.utils.book_append_sheet(wb, ws, 'Nhap Lo Hang')
    xlsx.writeFile(wb, 'mau_nhap_lo_hang_DATE_SP.xlsx')
  }

  return (
    <div style={{ padding: pad, paddingBottom: mobile ? 90 : pad }}>
      <Topbar mobile={mobile}
        title="📅 Quản lý Date SP"
        subtitle="Theo dõi hạn sử dụng theo lô hàng · Đồng bộ tồn KiotViet"
        action={canManage ? (
          <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
            <GoldBtn small onClick={downloadTemplate}>📥 File mẫu</GoldBtn>
            <label style={{ padding:'7px 14px', borderRadius:20, border:`1px solid ${T.border}`,
              cursor:'pointer', fontSize:12, color:T.med, background:'#fff',
              whiteSpace:'nowrap', fontFamily:'inherit', display:'flex', alignItems:'center' }}>
              📤 Import Excel
              <input type="file" accept=".xlsx,.xls" style={{ display:'none' }}
                onChange={e => e.target.files?.[0] && handleImportFile(e.target.files[0])}/>
            </label>
            <GoldBtn small onClick={() => { setEditBatch(null); setShowAdd(true) }}>+ Thêm lô</GoldBtn>
          </div>
        ) : undefined}
      />

      {/* Error panel */}
      {importErrors.length > 0 && (
        <div style={{ margin:'0 0 16px', padding:'12px 16px', background:T.redBg,
          border:`1px solid ${T.red}`, borderRadius:10 }}>
          <div style={{ fontWeight:700, color:T.red, marginBottom:8, fontSize:13 }}>
            ❌ {importErrors.length} lỗi cần sửa trước khi import:
          </div>
          {importErrors.map((e, i) => (
            <div key={i} style={{ fontSize:12, color:T.red, marginBottom:4 }}>• {e}</div>
          ))}
          <div style={{ fontSize:11, color:T.med, marginTop:8, fontStyle:'italic' }}>
            💡 Tải file mẫu để xem đúng định dạng. Mã SP phải trùng khớp với KiotViet.
          </div>
          <button onClick={() => setImportErrors([])}
            style={{ marginTop:10, padding:'4px 14px', borderRadius:20, border:`1px solid ${T.red}`,
              background:'transparent', color:T.red, cursor:'pointer', fontFamily:'inherit', fontSize:11 }}>
            Đóng
          </button>
        </div>
      )}

      {/* Import preview */}
      {importPreview && (
        <div style={{ margin:'0 0 16px', padding:'12px 16px', background:T.greenBg,
          border:`1px solid ${T.green}`, borderRadius:10 }}>
          <div style={{ fontWeight:700, color:T.green, marginBottom:8, fontSize:13 }}>
            ✅ Sẵn sàng import {importPreview.length} lô hàng:
          </div>
          {importPreview.slice(0, 5).map((b, i) => (
            <div key={i} style={{ fontSize:12, color:T.dark, marginBottom:3 }}>
              • {b.product_code} — {b.product_name} · HSD: {b._disp} · Tồn: {b.qty_remaining}
            </div>
          ))}
          {importPreview.length > 5 && (
            <div style={{ fontSize:11, color:T.light }}>...+{importPreview.length - 5} lô nữa</div>
          )}
          <div style={{ display:'flex', gap:8, marginTop:12 }}>
            <GoldBtn small onClick={confirmImport} disabled={saving}>
              {saving ? 'Đang import...' : '✅ Xác nhận import'}
            </GoldBtn>
            <button onClick={() => setImportPreview(null)}
              style={{ padding:'6px 14px', borderRadius:20, border:`1px solid ${T.border}`,
                background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
              Hủy
            </button>
          </div>
        </div>
      )}

      {/* Tab bar */}
      <div style={{ display:'flex', gap:4, marginBottom:16, flexWrap:'wrap' }}>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id as any)}
            style={{ padding:'7px 16px', borderRadius:20,
              border:`1.5px solid ${tab === t.id ? T.gold : T.border}`,
              background: tab === t.id ? T.goldBg : '#fff',
              color: tab === t.id ? T.goldText : T.med,
              cursor:'pointer', fontFamily:'inherit', fontSize:12,
              fontWeight: tab === t.id ? 700 : 400 }}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>

      {/* ════ Tab: Tổng quan ════ */}
      {tab === 'overview' && (
        <div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(155px,1fr))',
            gap:12, marginBottom:20 }}>
            {[
              { label:'🔴 Dưới 6 tháng',  count:countRed,    color:T.red,    bg:T.redBg   },
              { label:'🟠 Dưới 12 tháng', count:countOrange, color:'#C2410C', bg:'#FFEDD5' },
              { label:'🟡 Dưới 18 tháng', count:countYellow, color:'#854D0E', bg:'#FEF9C3' },
              { label:'🟢 Còn hàng',       count:countGreen,  color:T.green,  bg:T.greenBg },
            ].map((c, i) => (
              <div key={i} style={{ background:c.bg, border:`1.5px solid ${c.color}`,
                borderRadius:12, padding:'16px', textAlign:'center' }}>
                <div style={{ fontSize:28, fontWeight:800, color:c.color, lineHeight:1 }}>{c.count}</div>
                <div style={{ fontSize:11, color:c.color, fontWeight:600, marginTop:6 }}>{c.label}</div>
                <div style={{ fontSize:10, color:T.light, marginTop:3 }}>lô có tồn kho</div>
              </div>
            ))}
          </div>

          <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`,
            overflow:'hidden', marginBottom:20 }}>
            <div style={{ padding:'12px 16px', borderBottom:`1px solid ${T.border}`,
              display:'flex', alignItems:'center', gap:8 }}>
              <span style={{ fontWeight:700, color:T.dark, fontSize:13 }}>
                📊 Đối chiếu tổng tồn lô vs KiotViet
              </span>
              <span style={{ fontSize:11, color:T.light }}>(chênh ≥ 6 → đỏ)</span>
            </div>
            {!mobile && (
              <div style={{ display:'grid', gridTemplateColumns:'100px 1fr 80px 80px 90px',
                padding:'7px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                fontSize:10, fontWeight:700, color:T.light,
                textTransform:'uppercase', letterSpacing:.6, gap:8 }}>
                <span>Mã SP</span><span>Tên SP</span>
                <span style={{ textAlign:'right' }}>Tổng lô</span>
                <span style={{ textAlign:'right' }}>Tồn KV</span>
                <span style={{ textAlign:'right' }}>Chênh lệch</span>
              </div>
            )}
            {Object.entries(batchTotalByCode).map(([code, total], i) => {
              const prod     = products.find((pp: any) => pp.code === code)
              const kv       = prod?.stock ?? 0
              const diff     = (total as number) - kv
              const diffAbs  = Math.abs(diff)
              const diffColor = diff === 0 ? T.green : diffAbs <= 5 ? T.amber : T.red
              return (
                <div key={code} style={{
                  display: mobile ? 'flex' : 'grid',
                  gridTemplateColumns:'100px 1fr 80px 80px 90px',
                  padding:'9px 14px', gap:8, alignItems:'center',
                  borderBottom: i < Object.keys(batchTotalByCode).length - 1 ? `1px solid ${T.border}` : 'none',
                  background: i % 2 === 0 ? '#fff' : T.rowAlt,
                  justifyContent: mobile ? 'space-between' : undefined }}>
                  {mobile ? (
                    <>
                      <div>
                        <div style={{ fontSize:10, color:T.light }}>{code}</div>
                        <div style={{ fontSize:12, fontWeight:600, color:T.dark }}>{prod?.name || code}</div>
                      </div>
                      <div style={{ textAlign:'right', flexShrink:0 }}>
                        <div style={{ fontSize:11, color:T.med }}>Lô: <b>{total as number}</b> · KV: <b>{kv}</b></div>
                        <div style={{ fontSize:12, fontWeight:700, color:diffColor }}>
                          {diff === 0 ? '✅ Khớp' : diff > 0 ? `+${diff}` : `${diff}`}
                        </div>
                      </div>
                    </>
                  ) : (
                    <>
                      <span style={{ fontSize:10, color:T.light }}>{code}</span>
                      <span style={{ fontSize:12, color:T.dark, overflow:'hidden',
                        textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{prod?.name || code}</span>
                      <span style={{ fontSize:12, fontWeight:700, textAlign:'right', color:T.dark }}>
                        {total as number}
                      </span>
                      <span style={{ fontSize:12, textAlign:'right', color:T.med }}>{kv}</span>
                      <span style={{ fontSize:12, fontWeight:700, textAlign:'right', color:diffColor }}>
                        {diff === 0 ? '✅ Khớp' : diff > 0 ? `+${diff}` : `${diff}`}
                      </span>
                    </>
                  )}
                </div>
              )
            })}
            {Object.keys(batchTotalByCode).length === 0 && (
              <EmptyState icon={Ico.boxes}
                title="Chưa có lô hàng nào"
                description="Nhấn + Thêm lô để thêm thủ công, hoặc dùng Import Excel để nhập hàng loạt từ file mẫu."/>
            )}
          </div>
        </div>
      )}

      {/* ════ Tab: Danh sách lô ════ */}
      {tab === 'list' && (
        <div>
          <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap', alignItems:'center' }}>
            <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
              placeholder="🔍 Tìm mã SP hoặc tên..."
              style={{ flex:1, minWidth:180, padding:'7px 12px', border:`1px solid ${T.border}`,
                borderRadius:20, fontSize:12, fontFamily:'inherit', outline:'none',
                color:T.dark, background:'#fff' }}/>
            {['all','red','orange','yellow','green'].map(f => (
              <button key={f} onClick={() => setFilterStatus(f)}
                style={{ padding:'5px 12px', borderRadius:20, cursor:'pointer',
                  fontFamily:'inherit', fontSize:11,
                  border:`1.5px solid ${filterStatus === f ? T.gold : T.border}`,
                  background: filterStatus === f ? T.goldBg : '#fff',
                  color: filterStatus === f ? T.goldText : T.med }}>
                {f==='all'?'Tất cả':f==='red'?'🔴 <6T':f==='orange'?'🟠 <12T':f==='yellow'?'🟡 <18T':'🟢 Còn'}
              </button>
            ))}
          </div>
          <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
            {!mobile && (
              <div style={{ display:'grid',
                gridTemplateColumns: canManage
                  ? '90px 1fr 80px 50px 55px 55px 55px 1fr 100px'
                  : '90px 1fr 80px 50px 55px 55px 55px 1fr',
                padding:'8px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                fontSize:10, fontWeight:700, color:T.light,
                textTransform:'uppercase', letterSpacing:.6,
                position:'sticky', top:0, zIndex:2, gap:8 }}>
                <span>Mã SP</span><span>Tên SP</span>
                <span style={{ textAlign:'center' }}>HSD</span>
                <span style={{ textAlign:'center' }}>Còn</span>
                <span style={{ textAlign:'right' }}>Tồn lô</span>
                <span style={{ textAlign:'right' }}>Tồn KV</span>
                <span style={{ textAlign:'right' }}>Chênh</span>
                <span>Ghi chú</span>
                {canManage && <span style={{ textAlign:'center' }}>Thao tác</span>}
              </div>
            )}
            {filtered.map((b: any, i: number) => {
              const kv         = b.prod?.stock ?? 0
              const batchTotal = batchTotalByCode[b.product_code] || 0
              const diff       = batchTotal - kv
              const diffColor  = diff === 0 ? T.green : Math.abs(diff) <= 5 ? T.amber : T.red
              return (
                <div key={b.id} style={{
                  display: mobile ? 'block' : 'grid',
                  gridTemplateColumns: canManage
                    ? '90px 1fr 80px 50px 55px 55px 55px 1fr 100px'
                    : '90px 1fr 80px 50px 55px 55px 55px 1fr',
                  padding:'10px 14px', gap:8, alignItems:'center',
                  borderBottom: i < filtered.length - 1 ? `1px solid ${T.border}` : 'none',
                  background: i % 2 === 0 ? '#fff' : T.rowAlt }}>
                  {mobile ? (
                    <div style={{ display:'flex', justifyContent:'space-between', gap:8 }}>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:10, color:T.light }}>{b.product_code}</div>
                        <div style={{ fontSize:13, fontWeight:600, color:T.dark,
                          overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                          {b.product_name}
                        </div>
                        <div style={{ display:'flex', gap:6, marginTop:4, flexWrap:'wrap', alignItems:'center' }}>
                          <span style={{ fontSize:11, padding:'2px 8px', borderRadius:10,
                            background:b.status.bg, color:b.status.color, fontWeight:600 }}>
                            {b.status.label}
                          </span>
                          <span style={{ fontSize:11, color:T.med }}>
                            HSD: {fmtExpiry(b.expiry_date)} · Tồn: {b.qty_remaining}
                          </span>
                        </div>
                        {b.note && <div style={{ fontSize:11, color:T.light, marginTop:3 }}>{b.note}</div>}
                      </div>
                      {canManage && (
                        <div style={{ display:'flex', flexDirection:'column', gap:4, flexShrink:0 }}>
                          <button onClick={() => { setEditBatch(b); setShowAdd(true) }}
                            style={{ padding:'4px 12px', borderRadius:8, border:`1px solid ${T.border}`,
                              background:'#fff', cursor:'pointer', fontSize:11,
                              fontFamily:'inherit', color:T.med }}>Sửa</button>
                          <button onClick={() => deleteBatch(b.id)}
                            style={{ padding:'4px 12px', borderRadius:8, border:`1px solid ${T.red}`,
                              background:'transparent', cursor:'pointer', fontSize:11,
                              fontFamily:'inherit', color:T.red }}>✕ Xóa</button>
                        </div>
                      )}
                    </div>
                  ) : (
                    <>
                      <span style={{ fontSize:10, color:T.light, overflow:'hidden',
                        textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.product_code}</span>
                      <span style={{ fontSize:12, color:T.dark, overflow:'hidden',
                        textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.product_name}</span>
                      <span style={{ fontSize:11, textAlign:'center', display:'block',
                        padding:'2px 6px', borderRadius:10,
                        background:b.status.bg, color:b.status.color, fontWeight:600 }}>
                        {fmtExpiry(b.expiry_date)}
                      </span>
                      <span style={{ fontSize:11, textAlign:'center', fontWeight:700, color:b.status.color }}>
                        {b.monthsLeft}T
                      </span>
                      <span style={{ fontSize:12, fontWeight:700, textAlign:'right',
                        color:(b.qty_remaining||0)===0?T.light:T.dark }}>{b.qty_remaining??0}</span>
                      <span style={{ fontSize:12, textAlign:'right', color:T.med }}>{kv}</span>
                      <span style={{ fontSize:11, fontWeight:700, textAlign:'right', color:diffColor }}>
                        {diff===0?'✅':diff>0?`+${diff}`:`${diff}`}
                      </span>
                      <span style={{ fontSize:11, color:T.light, overflow:'hidden',
                        textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.note||'—'}</span>
                      {canManage && (
                        <div style={{ display:'flex', gap:6, justifyContent:'center' }}>
                          <button onClick={() => { setEditBatch(b); setShowAdd(true) }}
                            style={{ padding:'4px 10px', borderRadius:8, border:`1px solid ${T.border}`,
                              background:'#fff', cursor:'pointer', fontSize:11,
                              fontFamily:'inherit', color:T.med }}>Sửa</button>
                          <button onClick={() => deleteBatch(b.id)}
                            style={{ padding:'4px 8px', borderRadius:8, border:`1px solid ${T.red}`,
                              background:'transparent', cursor:'pointer', fontSize:11,
                              fontFamily:'inherit', color:T.red }}>✕</button>
                        </div>
                      )}
                    </>
                  )}
                </div>
              )
            })}
            {filtered.length === 0 && (
              <div style={{ padding:'32px', textAlign:'center', color:T.light, fontSize:13 }}>
                {searchQ || filterStatus !== 'all'
                  ? 'Không tìm thấy lô nào phù hợp'
                  : 'Chưa có lô hàng. Nhấn "+ Thêm lô" hoặc Import Excel.'}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ════ Tab: Cảnh báo ════ */}
      {tab === 'alert' && (
        <div>
          {alertList.length === 0 ? (
            <div style={{ textAlign:'center', padding:'56px 24px', fontSize:14,
              color:T.green, fontWeight:600 }}>
              🎉 Không có lô hàng nào dưới 12 tháng còn tồn kho. Tốt lắm!
            </div>
          ) : (
            <>
              <div style={{ padding:'10px 14px', marginBottom:12, background:T.amberBg,
                border:`1px solid ${T.amber}`, borderRadius:10, fontSize:12,
                color:T.amber, fontWeight:600 }}>
                ⚠️ {alertList.length} lô hàng cần chú ý — phòng Sale lên phương án xử lý
              </div>
              <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`,
                overflow:'hidden' }}>
                {!mobile && (
                  <div style={{ display:'grid',
                    gridTemplateColumns:'90px 1fr 80px 120px 60px 1fr',
                    padding:'8px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                    fontSize:10, fontWeight:700, color:T.light,
                    textTransform:'uppercase', letterSpacing:.6,
                    position:'sticky', top:0, zIndex:2, gap:8 }}>
                    <span>Mã SP</span><span>Tên SP</span>
                    <span style={{ textAlign:'center' }}>HSD</span>
                    <span style={{ textAlign:'center' }}>Trạng thái</span>
                    <span style={{ textAlign:'right' }}>Tồn</span>
                    <span>Ghi chú</span>
                  </div>
                )}
                {alertList.map((b: any, i: number) => (
                  <div key={b.id} style={{
                    display: mobile ? 'block' : 'grid',
                    gridTemplateColumns:'90px 1fr 80px 120px 60px 1fr',
                    padding:'10px 14px', gap:8, alignItems:'center',
                    borderBottom: i < alertList.length - 1 ? `1px solid ${T.border}` : 'none',
                    background: i % 2 === 0 ? '#fff' : T.rowAlt,
                    borderLeft:`3px solid ${b.status.color}` }}>
                    {mobile ? (
                      <div>
                        <div style={{ fontSize:10, color:T.light }}>{b.product_code}</div>
                        <div style={{ fontSize:13, fontWeight:600, color:T.dark }}>{b.product_name}</div>
                        <div style={{ display:'flex', gap:6, marginTop:4, flexWrap:'wrap' }}>
                          <span style={{ fontSize:11, padding:'2px 8px', borderRadius:10,
                            background:b.status.bg, color:b.status.color, fontWeight:600 }}>
                            {b.status.label}
                          </span>
                          <span style={{ fontSize:11, color:T.med }}>
                            HSD: {fmtExpiry(b.expiry_date)} · Tồn: {b.qty_remaining}
                          </span>
                        </div>
                        {b.note && <div style={{ fontSize:11, color:T.light, marginTop:3 }}>{b.note}</div>}
                      </div>
                    ) : (
                      <>
                        <span style={{ fontSize:10, color:T.light }}>{b.product_code}</span>
                        <span style={{ fontSize:12, color:T.dark, overflow:'hidden',
                          textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.product_name}</span>
                        <span style={{ fontSize:12, textAlign:'center', color:T.med }}>
                          {fmtExpiry(b.expiry_date)}
                        </span>
                        <span style={{ fontSize:11, textAlign:'center', display:'block',
                          padding:'2px 8px', borderRadius:10,
                          background:b.status.bg, color:b.status.color, fontWeight:600 }}>
                          {b.status.label}
                        </span>
                        <span style={{ fontSize:12, fontWeight:700, textAlign:'right', color:T.dark }}>
                          {b.qty_remaining}
                        </span>
                        <span style={{ fontSize:11, color:T.light, overflow:'hidden',
                          textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.note||'—'}</span>
                      </>
                    )}
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      )}

      {showAdd && canManage && (
        <BatchForm
          edit={editBatch}
          products={products}
          onSave={saveBatch}
          onClose={() => { setShowAdd(false); setEditBatch(null) }}
          saving={saving}
          mobile={mobile}
        />
      )}
    </div>
  )
}
// ══ PAYMENT MODULE — Lệnh Chuyển Khoản ══════════════════════

const fmtMoney = (n: any) => {
  const num = Number(String(n).replace(/[^0-9]/g,''))
  if (!num) return ''
  return num.toLocaleString('vi-VN')
}
const parseMoney = (s: string) => {
  const n = parseInt(String(s).replace(/[^0-9]/g,''), 10)
  return isNaN(n) ? 0 : n
}
const normPay = (s: string) =>
  (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d')

const PAYMENT_STATUS: any = {
  draft:     { label:'📝 Nháp',       color:'#854D0E', bg:'#FEF9C3', short:'Nháp'    },
  pending:   { label:'⏳ Chờ CK',     color:T.blue,   bg:T.blueBg,  short:'Chờ CK'  },
  paid:      { label:'✅ Đã CK',      color:'#15803D', bg:'#DCFCE7', short:'Đã CK'   },
  completed: { label:'🏁 Hoàn thành', color:T.teal,   bg:T.tealBg,  short:'Xong'    },
}

function CopyBtn({ value, label }: any) {
  const [copied, setCopied] = useState(false)
  const copy = () => {
    navigator.clipboard.writeText(String(value||'')).then(() => {
      setCopied(true); setTimeout(() => setCopied(false), 1500)
    })
  }
  return (
    <button onClick={copy}
      style={{ padding:'3px 9px', borderRadius:6, border:`1px solid ${T.border}`,
        background: copied ? T.greenBg : '#fff', color: copied ? T.green : T.med,
        cursor:'pointer', fontFamily:'inherit', fontSize:11, flexShrink:0,
        transition:'all .15s' }}>
      {copied ? '✓' : '📋'} {label||'Copy'}
    </button>
  )
}

// ── Form tạo/sửa lệnh ──────────────────────────────────────
function PaymentOrderForm({ suppliers, accounts, onSave, onClose, edit, mobile }: any) {
  const [mode, setMode]           = useState<'stk'|'ncc'>('ncc')
  const [stkInput, setStkInput]   = useState(edit?.account_number || '')
  const [nccSearch, setNccSearch] = useState(edit?.supplier_name  || '')
  const [selSup, setSelSup]       = useState<any>(edit ? { id: edit.supplier_id, name: edit.supplier_name } : null)
  const [selAcc, setSelAcc]       = useState<any>(edit ? {
    id: edit.account_id, account_number: edit.account_number,
    account_name: edit.account_name, bank_name: edit.bank_name
  } : null)
  const [amount, setAmount]       = useState(edit ? fmtMoney(edit.amount) : '')
  const [content, setContent]     = useState(edit?.transfer_content || 'CONG TY TNHH THUONG MAI LA GLOBAL BEAUTY Chuyen tien')
  const [purpose, setPurpose]     = useState(edit?.purpose || 'Thanh toán công nợ')
  const [note, setNote]           = useState(edit?.note || '')
  const [orderRef, setOrderRef]   = useState(edit?.order_ref || '')
  const [status, setStatus]       = useState(edit?.status || 'pending')
  const [confirmMulti, setConfirmMulti] = useState(false)
  const [saving, setSaving]       = useState(false)
  const [newStkPrompt, setNewStkPrompt] = useState(false)
  const [newStkSupMode, setNewStkSupMode] = useState<'existing'|'new'>('existing')
  const [newStkNccSearch, setNewStkNccSearch] = useState('')
  const [newStkSelSup, setNewStkSelSup] = useState<any>(null)
  const [newStkNewName, setNewStkNewName] = useState('')
  // Thông tin STK mới (khi chưa có trong danh mục)
  const [newStkAccName, setNewStkAccName] = useState('')
  const [newStkBankName, setNewStkBankName] = useState('')

  // Approved accounts only
  const approvedAccounts = accounts.filter((a: any) => a.status === 'approved' && a.active)

  // STK mode: match by full exact number after strip
  const stkClean = stkInput.replace(/[^0-9]/g,'')
  const stkMatches = stkClean.length >= 6
    ? approvedAccounts.filter((a: any) => a.account_number.replace(/[^0-9]/g,'') === stkClean)
    : []

  // NCC fuzzy search
  const nccFiltered = nccSearch
    ? suppliers.filter((s: any) =>
        s.active && normPay(s.name).includes(normPay(nccSearch)))
    : suppliers.filter((s: any) => s.active)

  // Accounts of selected supplier
  const supAccounts = selSup
    ? approvedAccounts.filter((a: any) => a.supplier_id === selSup.id)
    : []

  const isValid = selSup && selAcc && parseMoney(amount) > 0 &&
    (!selAcc.id?.startsWith('acc_new_') || !!selAcc.bank_name?.trim())

  const handleSelectSup = (sup: any) => {
    setSelSup(sup); setNccSearch(sup.name); setSelAcc(null)
    const accs = approvedAccounts.filter((a: any) => a.supplier_id === sup.id)
    if (accs.length === 1) { setSelAcc(accs[0]) }
    else if (accs.length > 1) { setConfirmMulti(true) }
  }

  const handleStkMatch = (acc: any) => {
    const sup = suppliers.find((s: any) => s.id === acc.supplier_id)
    setSelAcc(acc); setSelSup(sup || null)
    if (sup) setNccSearch(sup.name)
    const supAccs = approvedAccounts.filter((a: any) => a.supplier_id === acc.supplier_id)
    if (supAccs.length > 1) setConfirmMulti(true)
  }

  const handleSubmit = async (forceStatus?: string) => {
    // Defense: chỉ nhận string. Nếu React pass event object thì treat as undefined.
    const finalStatus = typeof forceStatus === 'string' ? forceStatus : status
    // Draft không yêu cầu điền đủ thông tin
    if (finalStatus !== 'draft' && !isValid) return
    if (!selSup) return  // Ít nhất phải có NCC
    setSaving(true)
    try {
      // Nếu NCC mới (id='__new__'), tạo supplier trước rồi mới save order
      let finalSupId = selSup.id
      let finalSupName = selSup.name
      if (selSup.id === '__new__') {
        const now = new Date().toISOString()
        const newSup = {
          id: 'sup_' + Date.now() + '_' + Math.random().toString(36).slice(2,5),
          name: String(selSup.name||''), short_name: '', note: '', active: true,
          created_at: now, created_by: ''
        }
        await db.from('suppliers').insert(newSup)
        finalSupId = newSup.id
        finalSupName = newSup.name
      }

      // Sanitize selAcc — chỉ lấy plain fields, tránh circular DOM refs
      const cleanAcc = selAcc ? {
        id:           String(selAcc.id||''),
        account_number: String(selAcc.account_number||''),
        account_name:   String(selAcc.account_name||''),
        bank_name:      String(selAcc.bank_name||''),
        supplier_id:    String(selAcc.supplier_id||''),
      } : null

      // Check if STK is new
      const isNewStk = cleanAcc ? !accounts.find((a: any) =>
        a.account_number.replace(/[^0-9]/g,'') === cleanAcc.account_number.replace(/[^0-9]/g,'')
      ) : false

      await onSave({
        supplier_id:      String(finalSupId||''),
        supplier_name:    String(finalSupName||''),
        account_id:       cleanAcc?.id || 'acc_new_' + Date.now(),
        account_number:   cleanAcc?.account_number || '',
        account_name:     cleanAcc?.account_name || '',
        bank_name:        cleanAcc?.bank_name || '',
        amount:           parseMoney(amount),
        transfer_content: String(content||''),
        purpose:          String(purpose||''),
        note:             String(note||''),
        order_ref:        String(orderRef||''),
        status:           finalStatus,
        _isNewStk:        isNewStk,
        _newStkData:      isNewStk && cleanAcc
          ? { ...cleanAcc, supplier_id: String(finalSupId||'') }
          : null,
      })
    } catch (err: any) {
      alert('❌ Lỗi khi lưu: ' + (err?.message || 'Không xác định'))
    } finally {
      setSaving(false)
    }
  }

  const p = mobile ? 16 : 24

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:3000,
      display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}>
      <div style={{ background:'#fff', borderRadius:16, width:'100%', maxWidth:560,
        maxHeight:'92vh', overflowY:'auto', display:'flex', flexDirection:'column' }}>

        {/* Header */}
        <div style={{ padding:'16px 20px', borderBottom:`1px solid ${T.border}`,
          display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <div style={{ fontWeight:700, fontSize:15, color:T.dark }}>
            {edit ? '✏️ Sửa lệnh' : '💸 Tạo lệnh chuyển khoản'}
          </div>
          <button onClick={onClose}
            style={{ background:'none', border:'none', fontSize:20, cursor:'pointer', color:T.light }}>✕</button>
        </div>

        <div style={{ padding:'16px 20px', overflowY:'auto', flex:1 }}>

          {/* Mode switch */}
          {!edit && (
            <div style={{ display:'flex', gap:6, marginBottom:16 }}>
              {[['ncc','🏢 Tìm theo NCC'],['stk','🔢 Nhập số tài khoản']].map(([m,l]) => (
                <button key={m} onClick={() => { setMode(m as any); setSelSup(null); setSelAcc(null); setStkInput(''); setNccSearch('') }}
                  style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:12,
                    border:`1.5px solid ${mode===m?T.gold:T.border}`,
                    background:mode===m?T.goldBg:'#fff', color:mode===m?T.goldText:T.med, fontWeight:mode===m?700:400 }}>
                  {l}
                </button>
              ))}
            </div>
          )}

          {/* STK mode */}
          {mode === 'stk' && !edit && (
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
                letterSpacing:.5, display:'block', marginBottom:6 }}>Số tài khoản *</label>
              <input value={stkInput} onChange={e => { setStkInput(e.target.value); setSelAcc(null); setSelSup(null) }}
                placeholder="Paste hoặc nhập STK (chỉ số, không dấu cách)..."
                style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:13, fontFamily:'inherit', outline:'none', color:T.dark, background:'#fff', boxSizing:'border-box' }}/>
              {stkInput && stkClean.length < 6 && (
                <div style={{ fontSize:11, color:T.amber, marginTop:4 }}>
                  ⚠️ Nhập đủ số tài khoản để gợi ý NCC
                </div>
              )}
              {stkClean.length >= 6 && stkMatches.length > 0 && !selAcc && (
                <div style={{ border:`1px solid ${T.border}`, borderRadius:8, marginTop:4,
                  background:'#fff', boxShadow:'0 4px 12px rgba(0,0,0,0.08)' }}>
                  {stkMatches.map((a: any) => {
                    const sup = suppliers.find((s: any) => s.id === a.supplier_id)
                    return (
                      <div key={a.id} onClick={() => handleStkMatch(a)}
                        style={{ padding:'10px 12px', cursor:'pointer', borderBottom:`1px solid ${T.border}`,
                          display:'flex', justifyContent:'space-between', alignItems:'center' }}
                        onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
                        onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = '#fff' }}>
                        <div>
                          <div style={{ fontSize:13, fontWeight:600, color:T.dark }}>{sup?.name || '?'}</div>
                          <div style={{ fontSize:12, fontWeight:700, color:T.blue }}>{a.bank_name||'—'}</div>
                          <div style={{ fontSize:11, color:T.light }}>{a.account_name}</div>
                        </div>
                        <div style={{ fontSize:11, color:T.green, fontWeight:600 }}>✓ Khớp</div>
                      </div>
                    )
                  })}
                </div>
              )}
              {stkClean.length >= 6 && stkMatches.length === 0 && (
                <div style={{ marginTop:6, padding:'10px 12px', background:T.amberBg,
                  border:`1px solid ${T.amber}`, borderRadius:8, fontSize:12, color:T.amber }}>
                  ⚠️ STK này chưa có trong danh mục. Điền thêm thông tin để tiếp tục.
                  <div style={{ marginTop:8, display:'flex', flexDirection:'column', gap:6 }}>
                    <input value={newStkAccName} onChange={e => {
                        setNewStkAccName(e.target.value)
                        setSelAcc((prev: any) => prev ? {...prev, account_name:e.target.value} :
                          { id:'acc_new_'+Date.now(), account_number:stkInput.replace(/[^0-9]/g,''), account_name:e.target.value, bank_name:newStkBankName })
                      }}
                      placeholder="Tên tài khoản (tên công ty)..."
                      style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                        borderRadius:8, fontSize:12, fontFamily:'inherit', outline:'none',
                        background:'#fff', color:T.dark, boxSizing:'border-box' as any }}/>
                    <input value={newStkBankName} onChange={e => {
                        setNewStkBankName(e.target.value)
                        setSelAcc((prev: any) => prev ? {...prev, bank_name:e.target.value} :
                          { id:'acc_new_'+Date.now(), account_number:stkInput.replace(/[^0-9]/g,''), account_name:newStkAccName, bank_name:e.target.value })
                      }}
                      placeholder="Ngân hàng * (VD: VCB, ACB, MB...)"
                      style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.amber}`,
                        borderRadius:8, fontSize:12, fontFamily:'inherit', outline:'none',
                        background:'#fff', color:T.dark, boxSizing:'border-box' as any }}/>
                  </div>
                  <div style={{ marginTop:8 }}>
                    <input value={nccSearch} onChange={e => setNccSearch(e.target.value)}
                      placeholder="Gõ tên NCC..."
                      style={{ width:'100%', padding:'7px 10px', border:`1px solid ${T.border}`,
                        borderRadius:8, fontSize:12, fontFamily:'inherit', outline:'none', boxSizing:'border-box' as any }}/>
                    {nccSearch && !selSup && (
                      <div style={{ border:`1px solid ${T.border}`, borderRadius:8, marginTop:4, maxHeight:160, overflowY:'auto', background:'#fff' }}>
                        {nccFiltered.slice(0,8).map((s: any) => (
                          <div key={s.id} onClick={() => { setSelSup(s); setNccSearch(s.name) }}
                            style={{ padding:'8px 12px', cursor:'pointer', fontSize:12, color:T.dark,
                              borderBottom:`1px solid ${T.border}` }}
                            onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
                            onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = '#fff' }}>
                            {s.name}
                          </div>
                        ))}
                        <div onClick={() => { setSelSup({ id:'__new__', name: nccSearch }); }}
                          style={{ padding:'8px 12px', cursor:'pointer', fontSize:12,
                            color:T.blue, borderTop:`1px solid ${T.border}` }}>
                          + Tạo NCC mới: "{nccSearch}"
                        </div>
                      </div>
                    )}
                  </div>
                  {selSup && (
                    <div style={{ marginTop:8, display:'flex', alignItems:'center', gap:8 }}>
                      <span style={{ fontSize:12, fontWeight:600, color:T.dark }}>{selSup.name}</span>
                      <button onClick={() => { setSelSup(null); setNccSearch('') }}
                        style={{ background:'none', border:'none', cursor:'pointer', color:T.light, fontSize:14 }}>✕</button>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}

          {/* NCC mode */}
          {(mode === 'ncc' || edit) && !selSup && (
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
                letterSpacing:.5, display:'block', marginBottom:6 }}>Nhà cung cấp *</label>
              <input value={nccSearch} onChange={e => setNccSearch(e.target.value)}
                placeholder="Gõ tên NCC để tìm..."
                style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:13, fontFamily:'inherit', outline:'none', color:T.dark, background:'#fff', boxSizing:'border-box' }}/>
              {nccSearch && (
                <div style={{ border:`1px solid ${T.border}`, borderRadius:8, marginTop:4,
                  maxHeight:200, overflowY:'auto', background:'#fff', boxShadow:'0 4px 12px rgba(0,0,0,0.08)' }}>
                  {nccFiltered.slice(0,10).map((s: any) => (
                    <div key={s.id} onClick={() => handleSelectSup(s)}
                      style={{ padding:'9px 12px', cursor:'pointer', borderBottom:`1px solid ${T.border}`,
                        display:'flex', justifyContent:'space-between', alignItems:'center' }}
                      onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
                      onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = '#fff' }}>
                      <span style={{ fontSize:13, color:T.dark }}>{s.name}</span>
                      <span style={{ fontSize:10, color:T.light }}>
                        {approvedAccounts.filter((a: any) => a.supplier_id === s.id).length} STK
                      </span>
                    </div>
                  ))}
                  {nccFiltered.length === 0 && (
                    <div style={{ padding:'10px 12px', fontSize:12, color:T.light }}>Không tìm thấy NCC</div>
                  )}
                </div>
              )}
            </div>
          )}

          {/* Selected NCC chip */}
          {selSup && (
            <div style={{ marginBottom:14, padding:'10px 14px', background:T.goldBg,
              border:`1px solid ${T.goldBorder}`, borderRadius:10,
              display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div>
                <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>{selSup.name}</div>
                {selAcc && (
                  <div style={{ marginTop:4 }}>
                    <div style={{ fontSize:12, fontWeight:700, color:T.blue }}>{selAcc.bank_name||'—'}</div>
                    <div style={{ fontSize:11, color:T.goldText }}>
                      STK: {selAcc.account_number} · {selAcc.account_name}
                    </div>
                  </div>
                )}
              </div>
              {!edit && (
                <button onClick={() => { setSelSup(null); setSelAcc(null); setNccSearch(''); setConfirmMulti(false) }}
                  style={{ background:'none', border:'none', cursor:'pointer', color:T.light, fontSize:18 }}>✕</button>
              )}
            </div>
          )}

          {/* Multi-STK confirm */}
          {confirmMulti && selSup && !selAcc && (
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:12, fontWeight:600, color:T.amber, marginBottom:8 }}>
                ⚠️ {selSup.name} có {supAccounts.length} tài khoản — chọn STK cần chuyển:
              </div>
              <div style={{ border:`1px solid ${T.border}`, borderRadius:10, overflow:'hidden' }}>
                {supAccounts.map((a: any, i: number) => (
                  <div key={a.id} onClick={() => { setSelAcc(a); setConfirmMulti(false) }}
                    style={{ padding:'10px 14px', cursor:'pointer',
                      borderBottom: i < supAccounts.length-1 ? `1px solid ${T.border}` : 'none',
                      background: i%2===0?'#fff':T.rowAlt, display:'flex', justifyContent:'space-between' }}
                    onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.goldBg }}
                    onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = i%2===0?'#fff':T.rowAlt }}>
                    <div>
                      <div style={{ fontSize:13, fontWeight:600, color:T.dark }}>{a.account_number}</div>
                      <div style={{ fontSize:11, color:T.light }}>{a.account_name}</div>
                    </div>
                    <div style={{ fontSize:11, color:T.med, fontWeight:600 }}>{a.bank_name}</div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Amount */}
          <div style={{ marginBottom:13 }}>
            <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
              letterSpacing:.5, display:'block', marginBottom:6 }}>Số tiền *</label>
            <input value={amount}
              onChange={e => setAmount(fmtMoney(e.target.value))}
              placeholder="VD: 1.500.000"
              style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                fontSize:13, fontFamily:'inherit', outline:'none', color:T.dark, background:'#fff', boxSizing:'border-box' }}/>
            {amount && (
              <div style={{ fontSize:11, color:T.green, marginTop:3 }}>
                = {parseMoney(amount).toLocaleString('vi-VN')} ₫
              </div>
            )}
          </div>

          {/* Transfer content */}
          <div style={{ marginBottom:13 }}>
            <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
              letterSpacing:.5, display:'block', marginBottom:6 }}>Nội dung chuyển khoản</label>
            <input value={content} onChange={e => setContent(e.target.value)}
              style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                fontSize:12, fontFamily:'inherit', outline:'none', color:T.dark, background:'#fff', boxSizing:'border-box' }}/>
          </div>

          {/* Purpose */}
          <div style={{ marginBottom:13 }}>
            <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
              letterSpacing:.5, display:'block', marginBottom:6 }}>Mục đích</label>
            <div style={{ display:'flex', gap:8 }}>
              {['Thanh toán công nợ','Lấy hàng'].map(p => (
                <button key={p} onClick={() => setPurpose(p)}
                  style={{ flex:1, padding:'8px', borderRadius:8, cursor:'pointer', fontFamily:'inherit', fontSize:12,
                    border:`1.5px solid ${purpose===p?T.gold:T.border}`,
                    background:purpose===p?T.goldBg:'#fff', color:purpose===p?T.goldText:T.med,
                    fontWeight:purpose===p?700:400 }}>
                  {p}
                </button>
              ))}
            </div>
          </div>

          {/* Order ref + Note */}
          <Inp label="Mã đơn hàng / Tham chiếu (tùy chọn)" value={orderRef}
            onChange={setOrderRef} placeholder="VD: HD001"/>
          <Inp label="Ghi chú (tùy chọn)" value={note} onChange={setNote}/>

          {/* Status if edit */}
          {edit && (
            <div style={{ marginBottom:13 }}>
              <label style={{ fontSize:11, fontWeight:600, color:T.med, textTransform:'uppercase',
                letterSpacing:.5, display:'block', marginBottom:6 }}>Trạng thái</label>
              <select value={status} onChange={e => setStatus(e.target.value)}
                style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}>
                {Object.entries(PAYMENT_STATUS).map(([k,v]: any) => (
                  <option key={k} value={k}>{v.label}</option>
                ))}
              </select>
            </div>
          )}
        </div>

        <div style={{ padding:'12px 20px', borderTop:`1px solid ${T.border}`,
          display:'flex', gap:10, flexShrink:0 }}>
          <GoldBtn onClick={() => handleSubmit()}
            disabled={(status !== 'draft' && !isValid) || saving}>
            {saving ? 'Đang lưu...' : edit
              ? (edit.status==='draft' && status==='pending' ? '📤 Gửi lên chờ CK' : 'Cập nhật')
              : status==='draft' ? 'Lưu nháp' : 'Tạo lệnh'}
          </GoldBtn>
          {/* Nút lưu nháp - chỉ hiện khi tạo mới hoặc edit pending->draft */}
          {(!edit || edit.status==='draft') && status !== 'draft' && (
            <button onClick={() => handleSubmit('draft')}
              style={{ padding:'8px 16px', borderRadius:8, border:`1px solid ${T.border}`,
                background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
              💾 Lưu nháp
            </button>
          )}
          <button onClick={onClose}
            style={{ padding:'8px 16px', borderRadius:8, border:`1px solid ${T.border}`,
              background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
            Hủy
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Supplier Manager Tab ────────────────────────────────────
function SupplierManagerTab({ suppliers, setSuppliers, accounts, setAccounts, user, mobile }: any) {
  const [search, setSearch]       = useState('')
  const [showAddSup, setShowAddSup] = useState(false)
  const [editSup, setEditSup]     = useState<any>(null)
  const [expandedSup, setExpandedSup] = useState<string|null>(null)
  const [showAddAcc, setShowAddAcc]   = useState<string|null>(null)
  const [supForm, setSupForm]     = useState({ name:'', short_name:'', note:'' })
  const [accForm, setAccForm]     = useState({ account_number:'', account_name:'', bank_name:'' })
  const [saving, setSaving]       = useState(false)

  const filtered = suppliers.filter((s: any) =>
    !search || normPay(s.name + ' ' + (s.short_name||'')).includes(normPay(search))
  )

  const getAccounts = (supId: string) =>
    accounts.filter((a: any) => a.supplier_id === supId && a.active)

  const saveSup = async () => {
    if (!supForm.name.trim()) return
    setSaving(true)
    const now = new Date().toISOString()
    if (editSup) {
      const upd = { name:supForm.name, short_name:supForm.short_name, note:supForm.note }
      await db.from('suppliers').update(upd).eq('id', editSup.id)
      setSuppliers((prev: any[]) => prev.map((s: any) => s.id===editSup.id ? {...s,...upd} : s))
    } else {
      const newS = { id:'sup_'+Date.now()+'_'+Math.random().toString(36).slice(2,5),
        name:supForm.name, short_name:supForm.short_name, note:supForm.note,
        active:true, created_at:now, created_by:user.id }
      await db.from('suppliers').insert(newS)
      setSuppliers((prev: any[]) => [...prev, newS])
    }
    setSaving(false); setShowAddSup(false); setEditSup(null)
    setSupForm({ name:'', short_name:'', note:'' })
  }

  const saveAcc = async (supId: string) => {
    if (!accForm.account_number.trim()) return
    setSaving(true)
    const now = new Date().toISOString()
    const newA = { id:'acc_'+Date.now()+'_'+Math.random().toString(36).slice(2,5),
      supplier_id:supId, account_number:accForm.account_number.replace(/[^0-9]/g,''),
      account_name:accForm.account_name, bank_name:accForm.bank_name.toUpperCase(),
      status:'approved', active:true, created_at:now, created_by:user.id }
    await db.from('supplier_accounts').insert(newA)
    setAccounts((prev: any[]) => [...prev, newA])
    setSaving(false); setShowAddAcc(null)
    setAccForm({ account_number:'', account_name:'', bank_name:'' })
  }

  const toggleActive = async (s: any) => {
    await db.from('suppliers').update({ active: !s.active }).eq('id', s.id)
    setSuppliers((prev: any[]) => prev.map((x: any) => x.id===s.id ? {...x, active:!x.active} : x))
  }

  const deleteAcc = async (accId: string) => {
    if (!confirm('Xóa tài khoản này?')) return
    await db.from('supplier_accounts').update({ active:false }).eq('id', accId)
    setAccounts((prev: any[]) => prev.map((a: any) => a.id===accId ? {...a,active:false} : a))
  }

  return (
    <div>
      <div style={{ display:'flex', gap:8, marginBottom:14, alignItems:'center' }}>
        <input value={search} onChange={e => setSearch(e.target.value)}
          placeholder="🔍 Tìm NCC..."
          style={{ flex:1, padding:'7px 12px', border:`1px solid ${T.border}`, borderRadius:20,
            fontSize:12, fontFamily:'inherit', outline:'none', color:T.dark, background:'#fff' }}/>
        <GoldBtn small onClick={() => { setShowAddSup(true); setEditSup(null); setSupForm({name:'',short_name:'',note:''}) }}>
          + Thêm NCC
        </GoldBtn>
      </div>

      {(showAddSup || editSup) && (
        <div style={{ marginBottom:16, padding:'16px', background:T.goldBg,
          border:`1px solid ${T.goldBorder}`, borderRadius:12 }}>
          <div style={{ fontWeight:700, color:T.dark, marginBottom:12 }}>
            {editSup ? '✏️ Sửa NCC' : '➕ Thêm NCC mới'}
          </div>
          <Inp label="Tên NCC *" value={supForm.name}
            onChange={(v: string) => setSupForm(f => ({...f, name:v}))} placeholder="VD: Bioderma"/>
          <Inp label="Tên viết tắt" value={supForm.short_name}
            onChange={(v: string) => setSupForm(f => ({...f, short_name:v}))} placeholder="VD: BDM"/>
          <Inp label="Ghi chú" value={supForm.note}
            onChange={(v: string) => setSupForm(f => ({...f, note:v}))}/>
          <div style={{ display:'flex', gap:8 }}>
            <GoldBtn small onClick={saveSup} disabled={saving || !supForm.name.trim()}>
              {saving ? '...' : 'Lưu'}
            </GoldBtn>
            <button onClick={() => { setShowAddSup(false); setEditSup(null) }}
              style={{ padding:'6px 14px', borderRadius:8, border:`1px solid ${T.border}`,
                background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
              Hủy
            </button>
          </div>
        </div>
      )}

      <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
        {filtered.map((s: any, i: number) => {
          const accs = getAccounts(s.id)
          const isExpanded = expandedSup === s.id
          return (
            <div key={s.id} style={{ borderBottom: i < filtered.length-1 ? `1px solid ${T.border}` : 'none' }}>
              {/* NCC row */}
              <div style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 14px',
                background: isExpanded ? T.goldBg : (i%2===0?'#fff':T.rowAlt),
                cursor:'pointer' }}
                onClick={() => setExpandedSup(isExpanded ? null : s.id)}>
                <span style={{ fontSize:14 }}>{isExpanded?'▼':'▶'}</span>
                <div style={{ flex:1 }}>
                  <span style={{ fontSize:13, fontWeight:600, color: s.active?T.dark:T.light }}>
                    {s.name}
                    {!s.active && <span style={{ fontSize:10, color:T.light, marginLeft:6 }}>(Đã ẩn)</span>}
                  </span>
                  {s.short_name && <span style={{ fontSize:11, color:T.light, marginLeft:8 }}>{s.short_name}</span>}
                </div>
                <span style={{ fontSize:11, color:T.light }}>{accs.length} STK</span>
                <button onClick={e => { e.stopPropagation(); setEditSup(s); setSupForm({name:s.name,short_name:s.short_name||'',note:s.note||''}); setShowAddSup(true) }}
                  style={{ padding:'3px 10px', borderRadius:6, border:`1px solid ${T.border}`,
                    background:'#fff', cursor:'pointer', fontSize:11, fontFamily:'inherit', color:T.med }}>
                  Sửa
                </button>
                <button onClick={e => { e.stopPropagation(); toggleActive(s) }}
                  style={{ padding:'3px 10px', borderRadius:6, fontSize:11, fontFamily:'inherit', cursor:'pointer',
                    border:`1px solid ${s.active?T.amber:T.green}`, background:'transparent',
                    color:s.active?T.amber:T.green }}>
                  {s.active?'Ẩn':'Hiện'}
                </button>
              </div>

              {/* Expanded accounts */}
              {isExpanded && (
                <div style={{ background:T.bg, padding:'8px 14px 12px 32px' }}>
                  {accs.map((a: any) => (
                    <div key={a.id} style={{ display:'flex', alignItems:'center', gap:8,
                      padding:'8px 12px', background:'#fff', borderRadius:8,
                      border:`1px solid ${T.border}`, marginBottom:6 }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:13, fontWeight:700, color:T.dark, display:'flex', alignItems:'center', gap:6 }}>
                          {a.account_number}
                          {a.status === 'pending' && (
                            <span style={{ fontSize:10, padding:'1px 6px', borderRadius:10,
                              background:T.amberBg, color:T.amber, fontWeight:600 }}>Chờ duyệt</span>
                          )}
                        </div>
                        <div style={{ fontSize:11, color:T.light }}>
                          {a.account_name} · {a.bank_name}
                        </div>
                      </div>
                      <CopyBtn value={a.account_number} label="Copy STK"/>
                      <button onClick={() => deleteAcc(a.id)}
                        style={{ padding:'3px 8px', borderRadius:6, border:`1px solid ${T.red}`,
                          background:'transparent', color:T.red, cursor:'pointer', fontSize:11, fontFamily:'inherit' }}>
                        ✕
                      </button>
                    </div>
                  ))}

                  {/* Add account */}
                  {showAddAcc === s.id ? (
                    <div style={{ padding:'12px', background:'#fff', borderRadius:8,
                      border:`1px solid ${T.goldBorder}`, marginTop:4 }}>
                      <div style={{ fontSize:12, fontWeight:600, color:T.dark, marginBottom:8 }}>
                        Thêm STK mới (sẽ chờ Admin duyệt)
                      </div>
                      <Inp label="Số tài khoản *" value={accForm.account_number}
                        onChange={(v: string) => setAccForm(f => ({...f, account_number:v}))}
                        placeholder="Chỉ nhập số"/>
                      <Inp label="Tên tài khoản (tên công ty)" value={accForm.account_name}
                        onChange={(v: string) => setAccForm(f => ({...f, account_name:v}))}/>
                      <Inp label="Ngân hàng" value={accForm.bank_name}
                        onChange={(v: string) => setAccForm(f => ({...f, bank_name:v}))}
                        placeholder="VD: VCB, ACB, MB..."/>
                      <div style={{ display:'flex', gap:8, marginTop:8 }}>
                        <GoldBtn small onClick={() => saveAcc(s.id)}
                          disabled={saving || !accForm.account_number.trim()}>
                          {saving?'...':'Lưu STK'}
                        </GoldBtn>
                        <button onClick={() => setShowAddAcc(null)}
                          style={{ padding:'5px 12px', borderRadius:8, border:`1px solid ${T.border}`,
                            background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
                          Hủy
                        </button>
                      </div>
                    </div>
                  ) : (
                    <button onClick={() => { setShowAddAcc(s.id); setAccForm({account_number:'',account_name:'',bank_name:''}) }}
                      style={{ padding:'5px 14px', borderRadius:8, border:`1.5px dashed ${T.border}`,
                        background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:11,
                        marginTop:4, width:'100%' }}>
                      + Thêm STK
                    </button>
                  )}
                </div>
              )}
            </div>
          )
        })}
        {filtered.length === 0 && (
          <div style={{ padding:'32px', textAlign:'center', color:T.light, fontSize:13 }}>
            {search ? 'Không tìm thấy NCC' : 'Chưa có NCC nào'}
          </div>
        )}
      </div>
    </div>
  )
}

// ── STK Approval Tab (Admin only) — xem STK mới, không cần duyệt ──
function STKApprovalTab({ accounts, suppliers, mobile }: any) {
  // Hiện tất cả STK đã được thêm trong 30 ngày gần đây (status='approved' nhưng mới)
  const thirtyAgo = new Date(Date.now() - 30 * 86400000).toISOString()
  const recentNew = accounts.filter((a: any) =>
    a.active && a.created_at > thirtyAgo
  ).sort((x: any, y: any) => (y.created_at||'').localeCompare(x.created_at||''))

  if (recentNew.length === 0) return (
    <div style={{ textAlign:'center', padding:'56px', color:T.green, fontWeight:600, fontSize:14 }}>
      ✅ Không có STK nào mới được thêm trong 30 ngày qua
    </div>
  )

  return (
    <div>
      <div style={{ padding:'10px 14px', marginBottom:12, background:T.blueBg,
        border:`1px solid ${T.blue}`, borderRadius:10, fontSize:12, color:T.blue, fontWeight:600 }}>
        ℹ️ {recentNew.length} tài khoản ngân hàng mới được thêm trong 30 ngày qua (tự động được duyệt)
      </div>
      <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
        {!mobile && (
          <div style={{ display:'grid', gridTemplateColumns:'1fr 160px 80px 90px',
            padding:'7px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
            fontSize:10, fontWeight:700, color:T.light, textTransform:'uppercase', letterSpacing:.6, gap:8 }}>
            <span>NCC · Số tài khoản · Tên công ty</span>
            <span>Ngân hàng</span>
            <span>Người thêm</span>
            <span>Ngày thêm</span>
          </div>
        )}
        {recentNew.map((a: any, i: number) => {
          const sup = suppliers.find((s: any) => s.id === a.supplier_id)
          return (
            <div key={a.id} style={{
              display: mobile ? 'block' : 'grid',
              gridTemplateColumns:'1fr 160px 80px 90px',
              padding:'10px 14px', gap:8, alignItems:'center',
              borderBottom: i < recentNew.length-1 ? `1px solid ${T.border}` : 'none',
              background: i%2===0?'#fff':T.rowAlt }}>
              {mobile ? (
                <div>
                  <div style={{ fontSize:13, fontWeight:600, color:T.dark }}>{sup?.name || '?'}</div>
                  <div style={{ fontSize:12, color:T.med }}>{a.account_number} · {a.bank_name}</div>
                  <div style={{ fontSize:11, color:T.light }}>{a.account_name}</div>
                  <div style={{ fontSize:10, color:T.light, marginTop:2 }}>{fmtDate(a.created_at)} · {a.created_by}</div>
                </div>
              ) : (
                <>
                  <div>
                    <div style={{ fontSize:12, fontWeight:700, color:T.dark }}>{sup?.name || '?'}</div>
                    <div style={{ fontSize:13, color:T.blue, fontWeight:600 }}>{a.account_number}</div>
                    <div style={{ fontSize:11, color:T.light }}>{a.account_name}</div>
                  </div>
                  <span style={{ fontSize:12, fontWeight:600, color:T.med }}>{a.bank_name}</span>
                  <span style={{ fontSize:11, color:T.light }}>{a.created_by}</span>
                  <span style={{ fontSize:11, color:T.light }}>{fmtDate(a.created_at)}</span>
                </>
              )}
            </div>
          )
        })}
      </div>
    </div>
  )
}

// ── Main PaymentModule ──────────────────────────────────────
function PaymentModule({ user, mobile, allUsers }: any) {
  const perm       = getPerm(user)
  const canCreate  = perm.managePayment || perm.viewAllDashboard
  const canPay     = perm.viewAllDashboard   // Chỉ Admin/GĐ tích "Đã CK"
  const canKiot    = perm.managePayment || perm.viewAllDashboard  // QM + Admin tích "Nhập KV"
  const canManage  = perm.managePayment || perm.viewAllDashboard
  const canApprove = perm.viewAllDashboard

  const [tab, setTab]       = useState<'list'|'history'|'suppliers'|'approve'>('list')
  const [orders, setOrders] = useState<any[]>([])
  const [suppliers, setSuppliers]   = useState<any[]>([])
  const [accounts, setAccounts]     = useState<any[]>([])
  const [loading, setLoading]       = useState(true)
  const [showForm, setShowForm]     = useState(false)
  const [editOrder, setEditOrder]   = useState<any>(null)
  const [filterStatus, setFilterStatus] = useState('pending')
  const [expanded, setExpanded]     = useState<string|null>(null)
  const [newStkPrompt, setNewStkPrompt] = useState<any>(null)
  const [newStkSupMode, setNewStkSupMode] = useState<'existing'|'new'>('existing')
  const [newStkNccSearch, setNewStkNccSearch] = useState('')
  const [newStkSelSup, setNewStkSelSup] = useState<any>(null)
  const [newStkNewName, setNewStkNewName] = useState('')
  const [savingNewStk, setSavingNewStk] = useState(false)

  // History tab state
  const [histMonth, setHistMonth]   = useState(() => {
    const n = new Date(); return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`
  })
  const [histSort, setHistSort]     = useState<'date_desc'|'date_asc'|'amount_desc'|'ncc'>('date_desc')
  const [histSearch, setHistSearch] = useState('')

  const pad = mobile ? '16px' : '24px'

  // ── Load data ──
  useEffect(() => {
    Promise.all([
      db.from('suppliers').select('*').eq('active',true).order('name'),
      db.from('supplier_accounts').select('*').eq('active',true).order('created_at'),
      db.from('payment_orders').select('*').eq('is_history',false).order('created_at',{ascending:false}).limit(2000),
    ]).then(([sup, acc, ord]) => {
      setSuppliers(sup.data||[])
      setAccounts(acc.data||[])
      setOrders(ord.data||[])
      setLoading(false)
    })
  }, [])

  // ── History data ──
  const [histOrders, setHistOrders] = useState<any[]>([])
  const [histLoading, setHistLoading] = useState(false)
  useEffect(() => {
    if (tab !== 'history') return
    setHistLoading(true)
    const [yyyy, mm] = histMonth.split('-')
    const start = `${yyyy}-${mm}-01`
    const endDate = new Date(Number(yyyy), Number(mm), 0)
    const end = `${yyyy}-${mm}-${String(endDate.getDate()).padStart(2,'0')}`
    // Lịch sử: orders đã completed (is_history=true) trong tháng chọn
    db.from('payment_orders').select('*')
      .eq('is_history', true)
      .gte('paid_at', start).lte('paid_at', end + 'T23:59:59')
      .order('paid_at', {ascending:false}).limit(1000)
      .then(({data}) => { setHistOrders(data||[]); setHistLoading(false) })
  }, [tab, histMonth])

  // ── Save order ──
  const saveOrder = async (form: any) => {
    const now = new Date().toISOString()
    // Sanitize toàn bộ — tránh circular DOM refs
    const newO = {
      id: 'pay_' + Date.now() + '_' + Math.random().toString(36).slice(2,6),
      supplier_id:      String(form.supplier_id||''),
      supplier_name:    String(form.supplier_name||''),
      account_id:       String(form.account_id||''),
      account_number:   String(form.account_number||''),
      account_name:     String(form.account_name||''),
      bank_name:        String(form.bank_name||''),
      amount:           Number(form.amount)||0,
      transfer_content: String(form.transfer_content||''),
      purpose:          String(form.purpose||''),
      note:             String(form.note||''),
      order_ref:        String(form.order_ref||''),
      status:           String(form.status||'draft'),
      created_by: user.id, created_at: now,
      paid_at:'', paid_by:'', kiot_at:'', kiot_by:'', is_history:false,
    }
    const { error } = await db.from('payment_orders').insert(newO)
    if (error) { alert('❌ Lỗi lưu lệnh: ' + error.message); return }
    setOrders(prev => [newO, ...prev])
    if (form.status === 'draft') setFilterStatus('draft')
    setShowForm(false)
    if (form._isNewStk && form._newStkData) {
      setNewStkPrompt({ order: newO, stkData: form._newStkData })
    }
  }

  const updateOrder = async (form: any) => {
    if (!editOrder) return
    // Sanitize toàn bộ — tránh circular DOM refs
    const upd = {
      supplier_id:      String(form.supplier_id||''),
      supplier_name:    String(form.supplier_name||''),
      account_id:       String(form.account_id||''),
      account_number:   String(form.account_number||''),
      account_name:     String(form.account_name||''),
      bank_name:        String(form.bank_name||''),
      amount:           Number(form.amount)||0,
      transfer_content: String(form.transfer_content||''),
      purpose:          String(form.purpose||''),
      note:             String(form.note||''),
      order_ref:        String(form.order_ref||''),
      status:           String(form.status||''),
    }
    const { error } = await db.from('payment_orders').update(upd).eq('id', String(editOrder.id))
    if (error) { alert('❌ Lỗi cập nhật: ' + error.message); return }
    setOrders(prev => prev.map(o => o.id===editOrder.id ? {...o,...upd} : o))
    // Bug fix: tự chuyển tab lọc sang trạng thái mới nếu có thay đổi status
    // (trước đây chỉ handle draft→pending, các case khác đơn "biến mất" khỏi view)
    if (form.status && form.status !== editOrder.status) {
      setFilterStatus(String(form.status))
    }
    alert('✅ Đã cập nhật lệnh')
    setEditOrder(null); setShowForm(false)
  }

  const tickPaid = async (o: any) => {
    const now = new Date().toISOString()
    const upd = { status:'paid', paid_at:now, paid_by:user.id }
    const { error } = await db.from('payment_orders').update(upd).eq('id', o.id)
    if (error) { alert('❌ Lỗi đánh dấu Đã CK: ' + error.message); return }
    setOrders(prev => prev.map(x => x.id===o.id ? {...x,...upd} : x))
  }

  const tickKiot = async (o: any) => {
    const now = new Date().toISOString()
    // Đánh dấu completed + chuyển sang history để không chiếm chỗ list active
    const upd = { status:'completed', kiot_at:now, kiot_by:user.id, is_history:true }
    const { error } = await db.from('payment_orders').update(upd).eq('id', o.id)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    // Xóa khỏi list active vì đã vào lịch sử
    setOrders(prev => prev.filter(x => x.id !== o.id))
  }

  const [paymentConfirmDelete, setPaymentConfirmDelete] = useState<any>(null)

  const deleteOrder = (id: string, status: string) => {
    const ord = orders.find((o: any) => o.id === id)
    if (!ord) return
    const label = status === 'pending' ? 'lệnh chờ CK' : status === 'paid' ? 'lệnh đã CK' : 'lệnh nháp'
    setPaymentConfirmDelete({
      title: `Xóa ${label}`,
      message: `Bạn sắp xóa lệnh thanh toán cho "${ord.supplier_name || 'supplier'}".`,
      detail: `Số tiền: ${(ord.amount||0).toLocaleString('vi-VN')}đ\nTrạng thái: ${status}\n\nThao tác này sẽ được ghi vào nhật ký.`,
      action: async () => {
        await logAudit({
          user,
          action: 'delete',
          table: 'payment_orders',
          recordId: id,
          snapshot: ord,
          note: `Xóa lệnh ${label}: ${ord.supplier_name} - ${(ord.amount||0).toLocaleString('vi-VN')}đ`,
        })
        const { error } = await db.from('payment_orders').delete().eq('id', id)
        if (error) { alert('❌ Lỗi xóa: ' + error.message); setPaymentConfirmDelete(null); return }
        setOrders(prev => prev.filter(o => o.id !== id))
        setPaymentConfirmDelete(null)
      }
    })
  }

  const promoteOrder = async (o: any) => {
    // Kiểm tra đủ thông tin trước khi gửi
    if (!o.supplier_name || !o.account_number || !o.amount) {
      alert('❌ Lệnh chưa đủ thông tin (NCC, STK, Số tiền). Hãy sửa lệnh trước khi gửi.')
      return
    }
    const upd = { status:'pending' }
    const { error } = await db.from('payment_orders').update(upd).eq('id', o.id)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setOrders(prev => prev.map(x => x.id===o.id ? {...x,...upd} : x))
    setFilterStatus('pending')
  }

  // Save new STK after order
  const saveNewStk = async () => {
    if (!newStkPrompt) return
    setSavingNewStk(true)
    const now = new Date().toISOString()
    const { stkData } = newStkPrompt

    let supId = newStkSelSup?.id
    if (newStkSupMode === 'new' && newStkNewName.trim()) {
      const newSup = { id:'sup_'+Date.now()+'_'+Math.random().toString(36).slice(2,5),
        name:newStkNewName.trim(), short_name:'', note:'', active:true, created_at:now, created_by:user.id }
      await db.from('suppliers').insert(newSup)
      setSuppliers(prev => [...prev, newSup])
      supId = newSup.id
    }

    if (supId) {
      const newA = { id:'acc_'+Date.now()+'_'+Math.random().toString(36).slice(2,5),
        supplier_id:supId, account_number:stkData.account_number,
        account_name:stkData.account_name||'', bank_name:stkData.bank_name||'',
        status:'approved', active:true, created_at:now, created_by:user.id }
      await db.from('supplier_accounts').insert(newA)
      setAccounts(prev => [...prev, newA])
      // Tạo thông báo cho Admin về STK mới
      const sup = suppliers.find((s: any) => s.id === supId)
      await db.from('announcements').insert({
        id:'ann_stk_'+Date.now(), type:'system',
        title:`STK mới: ${sup?.name || 'NCC mới'}`,
        content:`${user.name||user.id} vừa thêm STK ${stkData.account_number} (${stkData.bank_name||'?'}) cho NCC "${sup?.name||newStkNewName||'?'}". Đã tự động duyệt.`,
        created_at:now, created_by:user.id, target_dept:'admin'
      }).select()
    }
    setSavingNewStk(false); setNewStkPrompt(null)
  }

  // ── Filtered orders ──
  const filteredOrders = orders.filter((o: any) => {
    if (filterStatus === 'all') return true
    return o.status === filterStatus
  })

  // Counts for filter badges
  const countByStatus = orders.reduce((acc: any, o: any) => {
    acc[o.status] = (acc[o.status]||0)+1; return acc
  }, {} as Record<string,number>)

  // Sorted history
  const histFiltered = histOrders.filter((o: any) => {
    if (!histSearch) return true
    return normPay(o.supplier_name + o.account_number).includes(normPay(histSearch))
  }).sort((a: any, b: any) => {
    if (histSort==='date_asc')     return (a.paid_at||'').localeCompare(b.paid_at||'')
    if (histSort==='amount_desc')  return b.amount - a.amount
    if (histSort==='ncc')          return (a.supplier_name||'').localeCompare(b.supplier_name||'')
    return (b.paid_at||'').localeCompare(a.paid_at||'')
  })

  const histTotal = histFiltered.reduce((s: number, o: any) => s + (o.amount||0), 0)

  const thirtyAgo = new Date(Date.now() - 30 * 86400000).toISOString()
  const recentSTKCount = accounts.filter((a: any) => a.active && a.created_at > thirtyAgo).length

  const tabs = [
    { id:'list',      icon:'📋', label:'Danh sách' },
    { id:'history',   icon:'📜', label:'Lịch sử' },
    canManage && { id:'suppliers', icon:'🏢', label:'Nhà cung cấp' },
    canApprove && { id:'approve',  icon:'📋', label:`STK mới${recentSTKCount>0?` (${recentSTKCount})`:''}` },
  ].filter(Boolean) as any[]

  if (loading) return (
    <div style={{ padding:pad, color:T.light, fontSize:13 }}>Đang tải...</div>
  )

  return (
    <div style={{ padding:pad, paddingBottom: mobile ? 90 : pad }}>
      <Topbar mobile={mobile}
        title="💸 Lệnh Chuyển Khoản"
        subtitle="Quản lý lệnh bank cho nhà cung cấp"
        action={canCreate ? (
          <GoldBtn small onClick={() => { setEditOrder(null); setShowForm(true) }}>
            + Tạo lệnh
          </GoldBtn>
        ) : undefined}
      />

      {/* Tab bar */}
      <div style={{ display:'flex', gap:4, marginBottom:16, flexWrap:'wrap' }}>
        {tabs.map((t: any) => (
          <button key={t.id} onClick={() => setTab(t.id)}
            style={{ padding:'7px 16px', borderRadius:20,
              border:`1.5px solid ${tab===t.id?T.gold:T.border}`,
              background:tab===t.id?T.goldBg:'#fff', color:tab===t.id?T.goldText:T.med,
              cursor:'pointer', fontFamily:'inherit', fontSize:12, fontWeight:tab===t.id?700:400 }}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>

      {/* ════ Tab: Danh sách ════ */}
      {tab === 'list' && (
        <div>
          {/* Status filter */}
          <div style={{ display:'flex', gap:4, marginBottom:12, flexWrap:'wrap' }}>
            {[
              ['all',       '📂 Tất cả'],
              ['draft',     '📝 Nháp'],
              ['pending',   '⏳ Chờ CK'],
              ['paid',      '✅ Đã CK'],
            ].map(([s,l]) => {
              const cnt = s==='all' ? orders.length : (countByStatus[s]||0)
              return (
                <button key={s} onClick={() => setFilterStatus(s)}
                  style={{ padding:'5px 12px', borderRadius:20, cursor:'pointer',
                    fontFamily:'inherit', fontSize:11,
                    border:`1.5px solid ${filterStatus===s?T.gold:T.border}`,
                    background:filterStatus===s?T.goldBg:'#fff',
                    color:filterStatus===s?T.goldText:T.med }}>
                  {l} {cnt>0?`(${cnt})`:''}
                </button>
              )
            })}
          </div>

          {/* Order list */}
          <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
            {!mobile && (
              <div style={{ display:'grid', gridTemplateColumns:'1fr 120px 110px 100px 90px 100px',
                padding:'8px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                fontSize:10, fontWeight:700, color:T.light, textTransform:'uppercase',
                letterSpacing:.6, position:'sticky', top:0, zIndex:2, gap:8 }}>
                <span>NCC · Tài khoản</span>
                <span style={{ textAlign:'right' }}>Số tiền</span>
                <span style={{ textAlign:'center' }}>Mục đích</span>
                <span style={{ textAlign:'center' }}>Người tạo</span>
                <span style={{ textAlign:'center' }}>Trạng thái</span>
                <span style={{ textAlign:'center' }}>Thao tác</span>
              </div>
            )}

            {filteredOrders.map((o: any, i: number) => {
              const st   = PAYMENT_STATUS[o.status] || PAYMENT_STATUS.draft
              const isEx = expanded === o.id
              const creator = allUsers?.find((u: any) => u.id === o.created_by)
              const payer   = allUsers?.find((u: any) => u.id === o.paid_by)
              const kioter  = allUsers?.find((u: any) => u.id === o.kiot_by)

              return (
                <div key={o.id} style={{ borderBottom: i < filteredOrders.length-1 ? `1px solid ${T.border}` : 'none' }}>
                  {/* Main row */}
                  <div style={{ display:'flex', alignItems:'center', gap:8, padding:'10px 14px',
                    background: isEx ? T.goldBg : (i%2===0?'#fff':T.rowAlt),
                    cursor:'pointer', transition:'background .1s' }}
                    onClick={() => setExpanded(isEx ? null : o.id)}>

                    {mobile ? (
                      <>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ display:'flex', alignItems:'center', gap:6 }}>
                            <span style={{ fontSize:13, fontWeight:700, color:T.dark,
                              overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                              {o.supplier_name}
                            </span>
                            <span style={{ fontSize:10, padding:'1px 6px', borderRadius:10, flexShrink:0,
                              background:st.bg, color:st.color, fontWeight:600 }}>
                              {st.short}
                            </span>
                          </div>
                          <div style={{ fontSize:11, color:T.med }}>
                            {fmtMoney(o.amount)} · {o.purpose}
                          </div>
                        </div>
                        <span style={{ fontSize:16, color:T.light, flexShrink:0 }}>{isEx?'▲':'▼'}</span>
                      </>
                    ) : (
                      <>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:13, fontWeight:600, color:T.dark,
                            overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                            {o.supplier_name}
                          </div>
                          <div style={{ fontSize:11, color:T.light }}>
                            {o.account_number} · {o.bank_name}
                          </div>
                        </div>
                        <span style={{ fontSize:13, fontWeight:700, textAlign:'right', color:T.dark, minWidth:120 }}>
                          {fmtMoney(o.amount)}
                        </span>
                        <span style={{ fontSize:11, textAlign:'center', minWidth:110,
                          padding:'2px 8px', borderRadius:10, display:'block',
                          background: o.purpose==='Lấy hàng'?T.blueBg:T.grayBg,
                          color: o.purpose==='Lấy hàng'?T.blue:T.gray }}>
                          {o.purpose}
                        </span>
                        <span style={{ fontSize:11, textAlign:'center', minWidth:90, color:T.med }}>
                          {creator?.ini || creator?.name?.split(' ').pop() || '—'}
                          <div style={{ fontSize:9, color:T.light }}>{fmtDateTime(o.created_at).split(',')[0]}</div>
                        </span>
                        <span style={{ fontSize:11, textAlign:'center', minWidth:100,
                          padding:'2px 8px', borderRadius:10, display:'block',
                          background:st.bg, color:st.color, fontWeight:600 }}>
                          {st.short}
                        </span>
                        <div style={{ display:'flex', gap:4, justifyContent:'center', minWidth:100 }}>
                          {o.status==='draft' && canCreate && (
                            <button onClick={e => { e.stopPropagation(); promoteOrder(o) }}
                              style={{ padding:'4px 10px', borderRadius:6, border:`1px solid ${T.blue}`,
                                background:T.blueBg, color:T.blue, cursor:'pointer', fontSize:11, fontFamily:'inherit' }}>
                              Gửi
                            </button>
                          )}
                          {o.status==='pending' && canPay && (
                            <button onClick={e => { e.stopPropagation(); tickPaid(o) }}
                              style={{ padding:'4px 10px', borderRadius:6, border:`1px solid ${T.green}`,
                                background:T.greenBg, color:T.green, cursor:'pointer', fontSize:11, fontFamily:'inherit' }}>
                              Đã CK
                            </button>
                          )}
                          {o.status==='paid' && canKiot && (
                            <button onClick={e => { e.stopPropagation(); tickKiot(o) }}
                              style={{ padding:'4px 10px', borderRadius:6, border:`1px solid ${T.teal}`,
                                background:T.tealBg, color:T.teal, cursor:'pointer', fontSize:11, fontFamily:'inherit' }}>
                              Nhập KV
                            </button>
                          )}
                          {canCreate && (o.status==='draft' || o.status==='pending') && (
                            <button onClick={e => { e.stopPropagation(); deleteOrder(o.id, o.status) }}
                              style={{ padding:'4px 8px', borderRadius:6, border:`1px solid ${T.red}`,
                                background:'transparent', color:T.red, cursor:'pointer', fontSize:11, fontFamily:'inherit' }}>
                              ✕
                            </button>
                          )}
                        </div>
                      </>
                    )}
                  </div>

                  {/* Expanded detail */}
                  {isEx && (
                    <div style={{ padding:'12px 20px 16px', background: mobile?T.goldBg:'#FFFDF8',
                      borderTop:`1px solid ${T.goldBorder}` }}>
                      <div style={{ display:'grid', gridTemplateColumns: mobile?'1fr':'1fr 1fr', gap:12, marginBottom:12 }}>
                        <div>
                          <div style={{ fontSize:10, color:T.light, textTransform:'uppercase', letterSpacing:.5, marginBottom:3 }}>
                            Thông tin CK
                          </div>
                          <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:6 }}>
                            <span style={{ fontSize:12, color:T.med }}>Ngân hàng:</span>
                            <span style={{ fontSize:13, fontWeight:700, color:T.blue }}>{o.bank_name||'—'}</span>
                          </div>
                          <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:6 }}>
                            <span style={{ fontSize:12, color:T.med }}>STK:</span>
                            <span style={{ fontSize:13, fontWeight:700, color:T.dark }}>{o.account_number}</span>
                            <CopyBtn value={o.account_number} label="Copy"/>
                          </div>
                          <div style={{ fontSize:11, color:T.light, marginBottom:6 }}>
                            Tên TK: {o.account_name||'—'}
                          </div>
                          <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:6 }}>
                            <span style={{ fontSize:12, color:T.med }}>Số tiền:</span>
                            <span style={{ fontSize:13, fontWeight:700, color:T.dark }}>{fmtMoney(o.amount)}</span>
                            <CopyBtn value={String(parseMoney(o.amount)||o.amount)} label="Copy"/>
                          </div>
                          <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:4 }}>
                            <span style={{ fontSize:12, color:T.med }}>Nội dung:</span>
                            <span style={{ fontSize:11, color:T.dark, flex:1 }}>{o.transfer_content}</span>
                            <CopyBtn value={o.transfer_content} label="Copy"/>
                          </div>
                        </div>
                        <div>
                          <div style={{ fontSize:10, color:T.light, textTransform:'uppercase', letterSpacing:.5, marginBottom:6 }}>
                            Lịch sử xử lý
                          </div>
                          <div style={{ fontSize:11, color:T.med, marginBottom:3 }}>
                            📝 Tạo: {creator?.name||o.created_by||'?'} · {fmtDateTime(o.created_at)}
                          </div>
                          {o.paid_at && (
                            <div style={{ fontSize:11, color:T.green, marginBottom:3 }}>
                              ✅ Đã CK: {payer?.name||o.paid_by||'?'} · {fmtDateTime(o.paid_at)}
                            </div>
                          )}
                          {o.kiot_at && (
                            <div style={{ fontSize:11, color:T.teal }}>
                              🏁 Nhập KV: {kioter?.name||o.kiot_by||'?'} · {fmtDateTime(o.kiot_at)}
                            </div>
                          )}
                          {o.note && (
                            <div style={{ fontSize:11, color:T.light, marginTop:6, fontStyle:'italic' }}>
                              Ghi chú: {o.note}
                            </div>
                          )}
                          {o.order_ref && (
                            <div style={{ fontSize:11, color:T.light }}>Ref: {o.order_ref}</div>
                          )}
                        </div>
                      </div>

                      {/* Mobile actions */}
                      {mobile && (
                        <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginTop:8 }}>
                          {o.status==='draft' && canCreate && (
                            <GoldBtn small onClick={() => promoteOrder(o)}>📤 Gửi Admin</GoldBtn>
                          )}
                          {o.status==='pending' && canPay && (
                            <GoldBtn small onClick={() => tickPaid(o)}>✅ Đã CK</GoldBtn>
                          )}
                          {o.status==='paid' && canKiot && (
                            <GoldBtn small onClick={() => tickKiot(o)}>📥 Nhập KV</GoldBtn>
                          )}
                          {canCreate && (
                            <GoldBtn small outline onClick={() => { setEditOrder(o); setShowForm(true) }}>✏️ Sửa</GoldBtn>
                          )}
                          {canCreate && (o.status==='draft' || o.status==='pending') && (
                            <GoldBtn small danger onClick={() => deleteOrder(o.id, o.status)}>✕ Xóa</GoldBtn>
                          )}
                        </div>
                      )}
                      {!mobile && canCreate && (
                        <button onClick={() => { setEditOrder(o); setShowForm(true) }}
                          style={{ padding:'5px 14px', borderRadius:8, border:`1px solid ${T.border}`,
                            background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:11 }}>
                          ✏️ Sửa lệnh
                        </button>
                      )}
                    </div>
                  )}
                </div>
              )
            })}

            {filteredOrders.length === 0 && (
              <div style={{ padding:'40px', textAlign:'center', color:T.light, fontSize:13 }}>
                {filterStatus==='all' ? 'Chưa có lệnh nào' : `Không có lệnh "${PAYMENT_STATUS[filterStatus]?.short||filterStatus}"`}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ════ Tab: Lịch sử ════ */}
      {tab === 'history' && (
        <div>
          <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap', alignItems:'center' }}>
            <input type="month" value={histMonth} onChange={e => setHistMonth(e.target.value)}
              style={{ padding:'7px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none' }}/>
            <select value={histSort} onChange={e => setHistSort(e.target.value as any)}
              style={{ padding:'7px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none', cursor:'pointer' }}>
              <option value="date_desc">📅 Mới nhất</option>
              <option value="date_asc">📅 Cũ nhất</option>
              <option value="amount_desc">💰 Tiền nhiều → ít</option>
              <option value="ncc">🏢 Theo NCC (A-Z)</option>
            </select>
            <input value={histSearch} onChange={e => setHistSearch(e.target.value)}
              placeholder="🔍 Tìm NCC hoặc STK..."
              style={{ flex:1, minWidth:150, padding:'7px 12px', border:`1px solid ${T.border}`,
                borderRadius:20, fontSize:12, fontFamily:'inherit', outline:'none',
                color:T.dark, background:'#fff' }}/>
          </div>

          {histLoading ? (
            <div style={{ padding:'32px', textAlign:'center', color:T.light }}>Đang tải...</div>
          ) : (
            <>
              <div style={{ display:'flex', gap:12, marginBottom:12 }}>
                <div style={{ padding:'10px 16px', background:T.goldBg, border:`1px solid ${T.goldBorder}`,
                  borderRadius:10, fontSize:12 }}>
                  <span style={{ color:T.light }}>Tổng lệnh: </span>
                  <b style={{ color:T.dark }}>{histFiltered.length}</b>
                </div>
                <div style={{ padding:'10px 16px', background:T.greenBg, border:`1px solid ${T.green}`,
                  borderRadius:10, fontSize:12 }}>
                  <span style={{ color:T.light }}>Tổng tiền: </span>
                  <b style={{ color:T.green }}>{fmtMoney(histTotal)}</b>
                </div>
              </div>

              <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`, overflow:'hidden' }}>
                {!mobile && (
                  <div style={{ display:'grid', gridTemplateColumns:'90px 1fr 140px 110px 80px',
                    padding:'7px 14px', background:T.bg, borderBottom:`2px solid ${T.border}`,
                    fontSize:10, fontWeight:700, color:T.light, textTransform:'uppercase',
                    letterSpacing:.6, gap:8 }}>
                    <span>Ngày CK</span>
                    <span>NCC · Tài khoản</span>
                    <span>Nội dung CK</span>
                    <span>Mục đích</span>
                    <span style={{ textAlign:'right' }}>Số tiền</span>
                  </div>
                )}
                {histFiltered.map((o: any, i: number) => (
                  <div key={o.id} style={{
                    display: mobile ? 'flex' : 'grid',
                    gridTemplateColumns:'90px 1fr 140px 110px 80px',
                    padding:'9px 14px', gap:8, alignItems:'center',
                    borderBottom: i < histFiltered.length-1 ? `1px solid ${T.border}` : 'none',
                    background: i%2===0?'#fff':T.rowAlt,
                    justifyContent: mobile?'space-between':undefined }}>
                    {mobile ? (
                      <>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ fontSize:12, fontWeight:600, color:T.dark,
                            overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                            {o.supplier_name}
                          </div>
                          <div style={{ fontSize:11, color:T.light }}>
                            {fmtDate(o.paid_at)} · {o.account_number} · {o.bank_name}
                          </div>
                        </div>
                        <div style={{ fontWeight:700, fontSize:13, color:T.dark, flexShrink:0 }}>
                          {fmtMoney(o.amount)}
                        </div>
                      </>
                    ) : (
                      <>
                        <span style={{ fontSize:11, color:T.med }}>{fmtDate(o.paid_at)}</span>
                        <div>
                          <div style={{ fontSize:12, fontWeight:600, color:T.dark }}>{o.supplier_name}</div>
                          <div style={{ fontSize:11, color:T.light }}>{o.account_number} · {o.bank_name}</div>
                        </div>
                        <span style={{ fontSize:11, color:T.light, overflow:'hidden',
                          textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{o.transfer_content}</span>
                        <span style={{ fontSize:11, padding:'2px 8px', borderRadius:10, display:'block',
                          textAlign:'center',
                          background:o.purpose==='Lấy hàng'?T.blueBg:T.grayBg,
                          color:o.purpose==='Lấy hàng'?T.blue:T.gray }}>
                          {o.purpose}
                        </span>
                        <span style={{ fontSize:12, fontWeight:700, textAlign:'right', color:T.dark }}>
                          {fmtMoney(o.amount)}
                        </span>
                      </>
                    )}
                  </div>
                ))}
                {histFiltered.length === 0 && (
                  <div style={{ padding:'32px', textAlign:'center', color:T.light, fontSize:13 }}>
                    Không có lệnh nào trong tháng này
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      )}

      {/* ════ Tab: NCC ════ */}
      {tab === 'suppliers' && canManage && (
        <SupplierManagerTab
          suppliers={suppliers} setSuppliers={setSuppliers}
          accounts={accounts} setAccounts={setAccounts}
          user={user} mobile={mobile}/>
      )}

      {/* ════ Tab: Duyệt STK ════ */}
      {tab === 'approve' && canApprove && (
        <STKApprovalTab
          accounts={accounts}
          suppliers={suppliers} mobile={mobile}/>
      )}

      {/* Form tạo/sửa lệnh */}
      {showForm && (
        <PaymentOrderForm
          suppliers={suppliers.filter((s: any) => s.active)}
          accounts={accounts}
          onSave={editOrder ? updateOrder : saveOrder}
          onClose={() => { setShowForm(false); setEditOrder(null) }}
          edit={editOrder}
          mobile={mobile}/>
      )}

      {/* New STK prompt */}
      {newStkPrompt && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:3100,
          display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}>
          <div style={{ background:'#fff', borderRadius:14, padding:'20px 24px', maxWidth:440, width:'100%' }}>
            <div style={{ fontWeight:700, fontSize:14, color:T.dark, marginBottom:8 }}>
              💾 Lưu tài khoản mới?
            </div>
            <div style={{ fontSize:12, color:T.med, marginBottom:16 }}>
              STK <b>{newStkPrompt.stkData?.account_number}</b> chưa có trong danh mục.
              Lưu lại để dùng lần sau?
            </div>
            <div style={{ display:'flex', gap:8, marginBottom:12 }}>
              {['existing','new'].map(m => (
                <button key={m} onClick={() => setNewStkSupMode(m as any)}
                  style={{ flex:1, padding:'7px', borderRadius:8, cursor:'pointer',
                    fontFamily:'inherit', fontSize:12,
                    border:`1.5px solid ${newStkSupMode===m?T.gold:T.border}`,
                    background:newStkSupMode===m?T.goldBg:'#fff',
                    color:newStkSupMode===m?T.goldText:T.med }}>
                  {m==='existing'?'Gán vào NCC có sẵn':'Tạo NCC mới'}
                </button>
              ))}
            </div>
            {newStkSupMode === 'existing' ? (
              <div>
                <input value={newStkNccSearch} onChange={e => setNewStkNccSearch(e.target.value)}
                  placeholder="Tìm NCC..."
                  style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`,
                    borderRadius:8, fontSize:12, fontFamily:'inherit', outline:'none',
                    color:T.dark, background:'#fff', boxSizing:'border-box', marginBottom:6 }}/>
                {newStkNccSearch && (
                  <div style={{ border:`1px solid ${T.border}`, borderRadius:8,
                    maxHeight:160, overflowY:'auto', background:'#fff', marginBottom:8 }}>
                    {suppliers.filter((s: any) => s.active &&
                      normPay(s.name).includes(normPay(newStkNccSearch))).slice(0,8).map((s: any) => (
                      <div key={s.id} onClick={() => { setNewStkSelSup(s); setNewStkNccSearch(s.name) }}
                        style={{ padding:'8px 12px', cursor:'pointer', fontSize:12, color:T.dark,
                          background: newStkSelSup?.id===s.id?T.goldBg:'#fff',
                          borderBottom:`1px solid ${T.border}` }}
                        onMouseEnter={e => { (e.currentTarget as HTMLElement).style.background = T.bg }}
                        onMouseLeave={e => { (e.currentTarget as HTMLElement).style.background = newStkSelSup?.id===s.id?T.goldBg:'#fff' }}>
                        {s.name}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ) : (
              <Inp label="Tên NCC mới *" value={newStkNewName}
                onChange={setNewStkNewName} placeholder="VD: Bioderma"/>
            )}
            <div style={{ display:'flex', gap:8, marginTop:12 }}>
              <GoldBtn small onClick={saveNewStk} disabled={savingNewStk ||
                (newStkSupMode==='existing' && !newStkSelSup) ||
                (newStkSupMode==='new' && !newStkNewName.trim())}>
                {savingNewStk?'Đang lưu...':'💾 Lưu STK'}
              </GoldBtn>
              <button onClick={() => setNewStkPrompt(null)}
                style={{ padding:'6px 14px', borderRadius:8, border:`1px solid ${T.border}`,
                  background:'transparent', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
                Bỏ qua
              </button>
            </div>
          </div>
        </div>
      )}

      {paymentConfirmDelete && (
        <ConfirmDeleteModal
          title={paymentConfirmDelete.title}
          message={paymentConfirmDelete.message}
          detail={paymentConfirmDelete.detail}
          onConfirm={paymentConfirmDelete.action}
          onCancel={() => setPaymentConfirmDelete(null)}
        />
      )}
    </div>
  )
}


// ══════════════════════════════════════════════════════════════════════
// ══ PICKING MODULE v2 — Nhặt Hàng (redesign desktop-friendly) ════════
// ══════════════════════════════════════════════════════════════════════

// Shared: compress image (dùng cho cả Picking + Packing)
async function compressImageV2(file: File, maxW = 1920, quality = 0.82): Promise<Blob> {
  return new Promise((resolve, reject) => {
    const img = new Image()
    const reader = new FileReader()
    reader.onload = () => {
      img.onload = () => {
        let { width, height } = img
        if (width > maxW) {
          height = Math.round((height * maxW) / width)
          width = maxW
        }
        const canvas = document.createElement('canvas')
        canvas.width = width
        canvas.height = height
        const ctx = canvas.getContext('2d')
        if (!ctx) { reject(new Error('canvas ctx')); return }
        ctx.drawImage(img, 0, 0, width, height)
        canvas.toBlob(blob => blob ? resolve(blob) : reject(new Error('compress fail')), 'image/jpeg', quality)
      }
      img.onerror = () => reject(new Error('img load fail'))
      img.src = reader.result as string
    }
    reader.onerror = () => reject(new Error('read fail'))
    reader.readAsDataURL(file)
  })
}

function photoCountRangeV2(totalItems: number) {
  // Min luôn là 1 theo yêu cầu của anh. max giữ để hạn chế dung lượng.
  // Suggest: gợi ý số ảnh lý tưởng (không bắt buộc, chỉ để popup nhắc)
  const min = 1
  const max = Math.min(10, Math.max(3, Math.ceil(totalItems / 10)))
  const suggest = Math.max(1, Math.ceil(totalItems / 10))  // 10 SP = 1 ảnh gợi ý
  return { min, max, suggest }
}

function PickingModule({ user, allUsers, mobile, products }: any) {
  const perm      = getPerm(user)
  const canPick   = perm.pickOrders || perm.viewAllDashboard
  const isAdmin   = perm.viewAllDashboard
  const p = mobile ? '16px' : '24px'

  // Map product code → {stock, name} để hiển thị tồn kho realtime
  const productMap = useMemo(() => {
    const m = new Map<string, any>()
    ;(products || []).forEach((p: any) => m.set(p.code, p))
    return m
  }, [products])

  const [orders, setOrders]     = useState<any[]>([])
  const [loading, setLoading]   = useState(true)
  const [syncing, setSyncing]   = useState(false)
  const [lastSync, setLastSync] = useState<Date|null>(null)
  const [selectedCode, setSelectedCode] = useState<string|null>(null)
  const [searchQ, setSearchQ] = useState('')
  const [tab, setTab] = useState<'todo'|'done_today'>('todo')
  // Cutoff date: chỉ hiển thị đơn từ ngày này trở đi (null = không filter)
  const [cutoffDate, setCutoffDate] = useState<string|null>(null)
  const [showCutoffModal, setShowCutoffModal] = useState(false)

  const fetchCutoff = async () => {
    const { data } = await db.from('settings')
      .select('picking_start_date').eq('id','main').maybeSingle()
    setCutoffDate(data?.picking_start_date || null)
  }
  useEffect(() => { fetchCutoff() }, [])

  const fetchData = async (quiet=false) => {
    if (!quiet) setSyncing(true)
    // Query 1: ALL orders đang picking
    const { data: pickingData } = await db.from('packing_workflow').select('*')
      .eq('status', 'picking')
      .order('purchase_date', { ascending: false })
    // Query 2: orders đã nhặt trong 3 ngày gần nhất (status packing hoặc done)
    const threeDaysAgo = new Date(Date.now() - 3*86400000).toISOString()
    const { data: donePickData } = await db.from('packing_workflow').select('*')
      .in('status', ['packing','done'])
      .gte('picked_at', threeDaysAgo)
      .order('picked_at', { ascending: false })
      .limit(500)
    setOrders([...(pickingData||[]), ...(donePickData||[])])
    setLastSync(new Date())
    if (!quiet) setSyncing(false)
    setLoading(false)
  }

  const syncKV = async () => {
    setSyncing(true)
    try {
      const res = await fetch(`${SUPABASE_URL}/functions/v1/kiotviet-picking`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${SUPABASE_ANON}` }
      })
      const json = await res.json()
      if (json.error) alert('❌ Sync lỗi: ' + json.error)
      await fetchData(true)
    } catch(e: any) {
      alert('❌ Sync lỗi: ' + e.message)
    }
    setSyncing(false)
  }

  useEffect(() => {
    fetchData()
  }, [])

  // Auto-sync KV mỗi 2 phút — PAUSE khi user đang mở đơn (tránh disrupt công việc)
  useEffect(() => {
    if (selectedCode) return  // user đang làm việc → không auto-sync
    const interval = setInterval(() => {
      syncKV().then(() => fetchData(true))
    }, 120000)
    return () => clearInterval(interval)
  }, [selectedCode])

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const filterByQ = (list: any[]) => {
    const q = norm(searchQ)
    if (!q) return list
    return list.filter((o: any) => norm(`${o.order_code} ${o.customer_name} ${o.sold_by_name}`).includes(q))
  }

  // Cutoff filter: ẩn đơn có purchase_date < cutoff (nếu có set)
  const cutoffFilter = (o: any) => {
    if (!cutoffDate) return true
    if (!o.purchase_date) return true
    return new Date(o.purchase_date) >= new Date(cutoffDate + 'T00:00:00')
  }

  // Tab 'todo': đơn status='picking' (chờ nhặt)
  const todoOrders = filterByQ(orders.filter((o: any) => o.status === 'picking' && cutoffFilter(o))
    .sort((a: any, b: any) => new Date(a.purchase_date).getTime() - new Date(b.purchase_date).getTime()))

  // Tab 'done_today': đơn đã nhặt xong hôm nay (picked_at = today, status='packing' hoặc 'done')
  const todayStart = new Date()
  todayStart.setHours(0,0,0,0)
  const doneTodayOrders = filterByQ(orders.filter((o: any) =>
    o.picked_at && new Date(o.picked_at) >= todayStart && cutoffFilter(o)
  ).sort((a: any, b: any) => new Date(b.picked_at).getTime() - new Date(a.picked_at).getTime()))

  const displayOrders = tab === 'todo' ? todoOrders : doneTodayOrders

  // Tổng số lượng mỗi SP trong TẤT CẢ đơn status='picking' (để tham khảo khi thiếu hàng)
  const totalOrderedByCode = useMemo(() => {
    const m = new Map<string, number>()
    orders.filter((o: any) => o.status === 'picking').forEach((o: any) => {
      (o.items || []).forEach((it: any) => {
        m.set(it.code, (m.get(it.code) || 0) + (it.qty || 0))
      })
    })
    return m
  }, [orders])

  // Update item picked qty
  const updatePickedQty = async (orderCode: string, itemCode: string, newQty: number) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const newItems = (ord.items || []).map((it: any) => {
      if (it.code === itemCode) {
        const clamped = Math.max(0, Math.min(newQty, it.qty))
        return { ...it, picked_qty: clamped, picked_at: clamped>0 ? new Date().toISOString() : null }
      }
      return it
    })
    const upd: any = {
      items: newItems,
      picking_started_at: ord.picking_started_at || new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    // Ghi nhận NV đầu tiên tác động vào đơn là người nhặt
    if (!ord.assigned_to) upd.assigned_to = user.id
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  // Nhặt đủ toàn bộ: set picked_qty = qty cho TẤT CẢ items, bỏ short
  const markAllPicked = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const now = new Date().toISOString()
    const newItems = (ord.items || []).map((it: any) => ({
      ...it,
      picked_qty: it.qty,
      short_qty: 0,
      short_note: '',
      picked_at: now,
    }))
    const upd: any = {
      items: newItems,
      picking_started_at: ord.picking_started_at || now,
      updated_at: now,
    }
    // Ghi nhận NV đầu tiên tác động vào đơn là người nhặt
    if (!ord.assigned_to) upd.assigned_to = user.id
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  const reportShort = async (orderCode: string, itemCode: string, shortQty: number, note: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const newItems = (ord.items || []).map((it: any) => {
      if (it.code === itemCode) return { ...it, short_qty: shortQty, short_note: note }
      return it
    })
    await db.from('packing_workflow').update({ items: newItems, updated_at: new Date().toISOString() })
      .eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, items: newItems} : o))
    const item = (ord.items||[]).find((it: any) => it.code === itemCode)
    if (item && shortQty > 0) {
      await db.from('shortage_items').insert({
        id: `sh_pick_${orderCode}_${itemCode}_${Date.now()}`,
        product_code: itemCode, product_name: item.name,
        qty_short: shortQty, unit: item.unit || '',
        reported_by: user.id, status: 'pending',
        note: `Từ đơn nhặt ${orderCode}. ${note||''}`.trim(),
        created_at: new Date().toISOString(),
      })
    }
  }

  const finishPicking = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const allPicked = (ord.items||[]).every((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty)
    if (!allPicked) {
      if (!confirm('Còn SP chưa nhặt đủ. Xác nhận hoàn tất nhặt?')) return
    }
    const upd: any = {
      status: 'packing',
      picked_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    // Đảm bảo có người nhặt được ghi nhận
    if (!ord.assigned_to) upd.assigned_to = user.id
    const { error } = await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
    setSelectedCode(null)
    alert('✅ Đã hoàn tất nhặt, đơn chuyển sang bước Đóng hàng')
  }

  if (loading) return <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>⏳ Đang tải...</div>

  const selected = selectedCode ? orders.find((o: any) => o.order_code === selectedCode) : null

  // Desktop layout: 2 cột (list + detail)
  // Mobile: stack (chỉ thấy 1 cái tại 1 lần)
  const showDetail = selected !== null
  const showList = !mobile || !showDetail

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="📥 Nhặt hàng"
        subtitle={`${todoOrders.length} đơn chờ nhặt • ${doneTodayOrders.length} đã xong hôm nay`}
        action={
          <div style={{ display:'flex', gap:8, alignItems:'center' }}>
            {lastSync && (
              <span style={{ fontSize:10, color: selectedCode ? T.amber : T.light }}>
                {syncing ? '🔄 Sync...' :
                 selectedCode ? '⏸ Pause (đang mở đơn)' :
                 '✓ ' + lastSync.toLocaleTimeString('vi-VN', {hour:'2-digit',minute:'2-digit'})}
              </span>
            )}
            <button onClick={syncKV} disabled={syncing}
              style={{ padding:'5px 12px', borderRadius:20, border:`1px solid ${T.gold}`,
                background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                fontSize:11, fontWeight:600 }}>
              🔄 Sync KV
            </button>
          </div>
        }/>

      {/* Cutoff banner — Giai đoạn chuyển giao */}
      {cutoffDate ? (
        <Card style={{ padding:10, marginBottom:10, background:T.goldBg,
          border:`1px solid ${T.gold}` }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10, flexWrap:'wrap' }}>
            <div style={{ fontSize:11, color:T.goldText }}>
              🚦 Chỉ theo dõi đơn từ <b>{cutoffDate.split('-').reverse().join('/')}</b> trở đi.
              Đơn cũ xử lý theo quy trình cũ được bỏ qua.
            </div>
            {isAdmin && (
              <button onClick={() => setShowCutoffModal(true)}
                style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.gold}`,
                  background:'#fff', color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                  fontSize:10, fontWeight:600, whiteSpace:'nowrap' }}>
                🔧 Đổi ngày
              </button>
            )}
          </div>
        </Card>
      ) : (
        isAdmin && (
          <Card style={{ padding:10, marginBottom:10, background:T.bg, border:`1px dashed ${T.border}` }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10, flexWrap:'wrap' }}>
              <div style={{ fontSize:11, color:T.light }}>
                ℹ️ Chưa set ngày bắt đầu — tất cả đơn có "Đã đóng" đều được sync
              </div>
              <button onClick={() => setShowCutoffModal(true)}
                style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.gold}`,
                  background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                  fontSize:10, fontWeight:600, whiteSpace:'nowrap' }}>
                🚦 Set ngày bắt đầu
              </button>
            </div>
          </Card>
        )
      )}

      {/* Tabs */}
      <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
        {[
          { id:'todo',       label:`📥 Chờ nhặt${todoOrders.length?` (${todoOrders.length})`:''}` },
          { id:'done_today', label:`✅ Xong hôm nay${doneTodayOrders.length?` (${doneTodayOrders.length})`:''}` },
        ].map((t: any) => (
          <button key={t.id} onClick={() => { setTab(t.id as any); setSelectedCode(null) }}
            style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${tab===t.id?T.gold:T.border}`,
              background:tab===t.id?T.goldBg:'transparent',
              color:tab===t.id?T.goldText:T.med, fontWeight:tab===t.id?700:400 }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* 2-column layout (desktop) / stacked (mobile) */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: mobile ? '1fr' : (showDetail ? '380px 1fr' : '1fr'),
        gap: 14,
        alignItems: 'flex-start',
      }}>
        {/* ─── Column 1: List ─── */}
        {showList && (
          <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
            {/* Search */}
            <Card style={{ padding:10 }}>
              <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
                placeholder="🔍 Tìm mã đơn, khách, sale..."
                style={{ width:'100%', padding:'7px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
                  boxSizing:'border-box' as any }}/>
            </Card>

            {/* List orders */}
            {displayOrders.length === 0 ? (
              <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
                {tab==='todo' ? '🎉 Không còn đơn chờ nhặt!' : 'Chưa có đơn nào xong hôm nay.'}
              </div>
            ) : (
              displayOrders.map((o: any) => {
                const totalItems  = (o.items||[]).length
                const pickedItems = (o.items||[]).filter((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty).length
                const short = (o.items||[]).filter((it: any) => (it.short_qty||0) > 0).length
                const isSelected = o.order_code === selectedCode
                const daysOld = Math.floor((Date.now() - new Date(o.purchase_date).getTime())/86400000)
                const pickerName = o.assigned_to
                  ? (allUsers.find((u: any) => u.id === o.assigned_to)?.name || '?')
                  : null
                const pickedTime = o.picked_at
                  ? new Date(o.picked_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const packedTime = o.packed_at
                  ? new Date(o.packed_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const detectedTime = o.detected_at
                  ? new Date(o.detected_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const detectedDate = o.detected_at
                  ? new Date(o.detected_at).toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'})
                  : null
                const isDetectedToday = o.detected_at &&
                  new Date(o.detected_at).toDateString() === new Date().toDateString()
                // Đơn đã đóng xong hay chưa
                const fullyPacked = o.status === 'done' && !!o.packed_at
                return (
                  <Card key={o.order_code}
                    onClick={() => setSelectedCode(o.order_code)}
                    style={{ padding:10, cursor:'pointer',
                      borderLeft: isSelected ? `4px solid ${T.gold}` : `4px solid transparent`,
                      background: isSelected ? T.goldBg : '#fff',
                      transition:'all .15s' }}>
                    <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:6 }}>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:T.dark,
                          whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                          {o.order_code} • {o.customer_name || 'KH lẻ'}
                        </div>
                        <div style={{ fontSize:10, color:T.light, marginTop:2 }}>
                          Sale: {o.sold_by_name||'—'} • {daysOld>0?`${daysOld}N trước`:'hôm nay'}
                          {o.printed_by_name && <> • 🖨 {o.printed_by_name}</>}
                        </div>
                        {/* Tab "Chờ nhặt" hiện thời điểm đơn được sync từ KV (có ghi chú "đã đóng") */}
                        {tab === 'todo' && detectedTime && (
                          <div style={{ fontSize:10, color:T.amber, marginTop:3, fontWeight:600 }}>
                            📥 Vào kho: {isDetectedToday ? detectedTime : `${detectedDate} ${detectedTime}`}
                          </div>
                        )}
                        {/* Tab "Xong hôm nay" hiện timeline đầy đủ: Nhặt + Đã đóng */}
                        {tab === 'done_today' && (
                          <>
                            {pickerName && (
                              <div style={{ fontSize:10, color:T.green, marginTop:3, fontWeight:600 }}>
                                👤 Nhặt: {pickerName}
                                {pickedTime && <span style={{ color:T.light, fontWeight:400 }}> • {pickedTime}</span>}
                              </div>
                            )}
                            {fullyPacked ? (
                              <div style={{ fontSize:10, color:T.blue, marginTop:2, fontWeight:600 }}>
                                📮 Đã đóng xong
                                {packedTime && <span style={{ color:T.light, fontWeight:400 }}> • {packedTime}</span>}
                              </div>
                            ) : (
                              <div style={{ fontSize:10, color:T.amber, marginTop:2, fontWeight:600 }}>
                                ⏳ Đang chờ đóng gói
                              </div>
                            )}
                          </>
                        )}
                      </div>
                      <div style={{ textAlign:'right', fontSize:10, color:T.med, flexShrink:0 }}>
                        <div style={{ fontWeight:700, color: pickedItems===totalItems?T.green:T.dark }}>
                          {pickedItems}/{totalItems}
                        </div>
                        {short>0 && <div style={{ color:T.red, fontSize:9 }}>⚠️{short}</div>}
                      </div>
                    </div>
                  </Card>
                )
              })
            )}
          </div>
        )}

        {/* ─── Column 2: Detail ─── */}
        {showDetail && selected && (
          <PickingDetailPanel
            ord={selected}
            mobile={mobile}
            productMap={productMap}
            totalOrderedByCode={totalOrderedByCode}
            onClose={() => setSelectedCode(null)}
            onUpdateQty={(code: string, qty: number) => updatePickedQty(selected.order_code, code, qty)}
            onReportShort={(code: string, qty: number, note: string) => reportShort(selected.order_code, code, qty, note)}
            onMarkAllPicked={() => markAllPicked(selected.order_code)}
            onFinish={() => finishPicking(selected.order_code)}
            canPick={canPick && selected.status === 'picking'}
          />
        )}
      </div>

      {showCutoffModal && isAdmin && (
        <CutoffDateModal
          user={user}
          currentDate={cutoffDate}
          orderCount={orders.filter((o: any) =>
            (o.status === 'picking' || o.status === 'packing') &&
            (!cutoffDate || new Date(o.purchase_date) < new Date((cutoffDate||'') + 'T00:00:00'))
          ).length}
          onSave={async (newDate: string|null) => {
            const { error } = await db.from('settings').update({
              picking_start_date: newDate,
              picking_start_note: newDate ? `Set bởi ${user.name || user.ini} lúc ${new Date().toLocaleString('vi-VN')}` : '',
            }).eq('id', 'main')
            if (error) { alert('❌ Lỗi: ' + error.message); return }
            setCutoffDate(newDate)
            setShowCutoffModal(false)
            alert(newDate
              ? `✅ Đã set ngày bắt đầu = ${newDate.split('-').reverse().join('/')}\nLần sync tiếp theo sẽ bỏ qua đơn trước ngày này.`
              : '✅ Đã xoá ngày bắt đầu. Tất cả đơn "Đã đóng" sẽ được sync.'
            )
          }}
          onCleanupOld={async () => {
            if (!cutoffDate) return
            const cutoffTime = new Date(cutoffDate + 'T00:00:00').getTime()
            // Safeguard: CHỈ xoá đơn picking/packing có cả purchase_date VÀ updated_at trước cutoff
            // Điều này bảo vệ đơn cũ nhưng đang được Kho xử lý (updated_at mới)
            const toDelete = orders.filter((o: any) => {
              if (o.status !== 'picking' && o.status !== 'packing') return false
              // Phải có purchase_date cũ
              if (!o.purchase_date || new Date(o.purchase_date).getTime() >= cutoffTime) return false
              // Phải KHÔNG được update gần đây (tránh xoá đơn đang xử lý)
              const lastUpd = o.updated_at || o.created_at
              if (lastUpd && new Date(lastUpd).getTime() >= cutoffTime) return false
              // Phải KHÔNG có ảnh đã chụp (NV đã bắt đầu công việc)
              if ((o.photos_picked||[]).length > 0) return false
              if ((o.photos_packed||[]).length > 0) return false
              // Phải KHÔNG có item đã picked
              const hasPickedItems = (o.items||[]).some((it: any) =>
                (Number(it.picked_qty)||0) > 0 || (Number(it.short_qty)||0) > 0
              )
              if (hasPickedItems) return false
              return true
            })
            if (toDelete.length === 0) {
              alert('✅ Không có đơn nào cần dọn dẹp.\n\nLưu ý: đơn nào đang được Kho xử lý (đã có ảnh/items đã nhặt/updated gần đây) sẽ được BẢO VỆ không xoá, dù purchase_date cũ.')
              return
            }
            if (!confirm(`Xoá ${toDelete.length} đơn cũ (trước ngày ${cutoffDate.split('-').reverse().join('/')}) đang ở trạng thái picking/packing?\n\n⚠️ Đã loại trừ các đơn đang xử lý (có ảnh, có items đã nhặt, hoặc updated gần đây).\n\nHành động này không thể hoàn tác.`)) return
            const codes = toDelete.map(o => o.order_code)
            for (const code of codes) {
              await logAudit({
                user, action: 'delete', table: 'packing_workflow', recordId: code,
                snapshot: toDelete.find(o => o.order_code === code),
                note: `Dọn dẹp đơn cũ (trước cutoff ${cutoffDate})`,
              })
            }
            await db.from('packing_workflow').delete().in('order_code', codes)
            setOrders(prev => prev.filter(o => !codes.includes(o.order_code)))
            alert(`✅ Đã xoá ${codes.length} đơn cũ. Đã ghi vào audit log.`)
          }}
          onClose={() => setShowCutoffModal(false)}
        />
      )}
    </div>
  )
}

// ── Modal set cutoff date ──
function CutoffDateModal({ user, currentDate, orderCount, onSave, onCleanupOld, onClose }: any) {
  const [date, setDate] = useState<string>(currentDate || new Date().toISOString().split('T')[0])
  const [mode, setMode] = useState<'keep'|'clear'>(currentDate ? 'keep' : 'keep')

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:520, width:'100%',
        maxHeight:'90vh', overflow:'auto' }}>
        <div style={{ padding:'14px 20px', background:T.goldBg, borderBottom:`1px solid ${T.gold}` }}>
          <div style={{ fontSize:14, fontWeight:700, color:T.goldText }}>
            🚦 Ngày bắt đầu sync đơn
          </div>
          <div style={{ fontSize:11, color:T.med, marginTop:3 }}>
            Giai đoạn chuyển giao: bỏ qua đơn cũ đã xử lý theo quy trình cũ
          </div>
        </div>

        <div style={{ padding:20 }}>
          <div style={{ fontSize:12, color:T.dark, lineHeight:1.6, marginBottom:14 }}>
            Chọn ngày bắt đầu theo dõi. Hệ thống sẽ <b>chỉ sync đơn có ngày tạo (purchase_date) từ ngày này trở đi</b>. Đơn cũ hơn sẽ bị bỏ qua.
          </div>

          <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
            Ngày bắt đầu
          </label>
          <input type="date" value={date} onChange={e => setDate(e.target.value)}
            max={new Date().toISOString().split('T')[0]}
            style={{ width:'100%', padding:'10px 13px', border:`1px solid ${T.border}`, borderRadius:6,
              fontSize:14, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
              boxSizing:'border-box' as any, marginBottom:14 }}/>

          <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
            <button onClick={() => setDate(new Date().toISOString().split('T')[0])}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              Hôm nay
            </button>
            <button onClick={() => {
              const d = new Date(); d.setDate(d.getDate() + 1)
              setDate(d.toISOString().split('T')[0])
            }}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              Mai
            </button>
            <button onClick={() => {
              const d = new Date(); d.setDate(d.getDate() + 7 - d.getDay())
              setDate(d.toISOString().split('T')[0])
            }}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              CN tuần này
            </button>
          </div>

          {currentDate && orderCount > 0 && (
            <Card style={{ padding:12, marginBottom:14, background:T.amberBg,
              border:`1px solid ${T.amber}` }}>
              <div style={{ fontSize:11, color:T.amber, fontWeight:700, marginBottom:4 }}>
                ⚠️ Có <b>{orderCount}</b> đơn cũ (trước {currentDate.split('-').reverse().join('/')}) vẫn đang ở trạng thái picking/packing
              </div>
              <div style={{ fontSize:10, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
                Các đơn này đã được lọc khỏi list nhưng vẫn còn trong database. Có thể xoá hẳn để dọn dẹp.
              </div>
              <button onClick={onCleanupOld}
                style={{ padding:'5px 12px', borderRadius:6, border:`1px solid ${T.red}`,
                  background:'#fff', color:T.red, cursor:'pointer', fontFamily:'inherit',
                  fontSize:11, fontWeight:700 }}>
                🗑️ Xoá {orderCount} đơn cũ
              </button>
            </Card>
          )}

          <div style={{ padding:10, background:T.bg, borderRadius:6, fontSize:10,
            color:T.med, lineHeight:1.5 }}>
            💡 <b>Gợi ý chọn ngày:</b>
            <br/>• Ngày đầu tiên anh dùng quy trình mới (VD: hôm nay nếu go-live ngay)
            <br/>• Hoặc ngày thông báo chính thức cho NV Kho dùng app
            <br/>• Sale cũng nên được thông báo: "Từ ngày X, chỉ đơn mới mới vào hệ thống chụp ảnh"
          </div>
        </div>

        <div style={{ display:'flex', gap:10, padding:16, borderTop:`1px solid ${T.border}` }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
            Hủy
          </button>
          {currentDate && (
            <button onClick={() => {
              if (!confirm('Xoá ngày bắt đầu? Tất cả đơn "Đã đóng" sẽ được sync lại.')) return
              onSave(null)
            }}
              style={{ padding:'9px 12px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.red, cursor:'pointer', fontFamily:'inherit',
                fontSize:11, fontWeight:600 }}>
              🗑️ Xoá set
            </button>
          )}
          <button onClick={() => onSave(date)}
            disabled={!date}
            style={{ flex:2, padding:'9px', borderRadius:6, border:'none',
              background: date ? T.gold : T.border,
              color: date ? '#fff' : T.light,
              cursor: date ? 'pointer' : 'not-allowed',
              fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
            💾 Lưu ngày bắt đầu
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Picking Detail Panel (cột phải) ──
function PickingDetailPanel({ ord, mobile, productMap, totalOrderedByCode, onClose, onUpdateQty, onReportShort, onMarkAllPicked, onFinish, canPick }: any) {
  const [searchSP, setSearchSP] = useState('')
  const [showShortModal, setShowShortModal] = useState<any>(null)
  const [showImgModal, setShowImgModal] = useState<string|null>(null)

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const items = ord.items || []
  const filtered = items.filter((it: any) => {
    if (!searchSP.trim()) return true
    return norm(`${it.code} ${it.name}`).includes(norm(searchSP))
  })

  const totalQty   = items.reduce((s: number, it: any) => s + it.qty, 0)
  const pickedQty  = items.reduce((s: number, it: any) => s + (it.picked_qty||0) + (it.short_qty||0), 0)
  const progress   = totalQty > 0 ? Math.round(pickedQty*100/totalQty) : 0
  const pickedItems = items.filter((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty).length

  const getStock = (code: string, fallback: number) => {
    const p = productMap?.get(code)
    if (p && p.stock !== null && p.stock !== undefined) return p.stock
    return fallback || 0
  }
  const getTotalOrdered = (code: string) => totalOrderedByCode?.get(code) || 0

  return (
    <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`,
      padding:16, position: mobile ? 'static' : 'sticky', top: 0, maxHeight: mobile ? 'none' : 'calc(100vh - 40px)',
      overflowY: 'auto', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' }}>

      {/* Header */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
        paddingBottom:12, borderBottom:`1px solid ${T.border}`, marginBottom:12 }}>
        <div>
          <div style={{ fontSize:14, fontWeight:700, color:T.dark }}>
            {ord.order_code} • {ord.customer_name}
          </div>
          <div style={{ fontSize:11, color:T.light, marginTop:2 }}>
            Sale: {ord.sold_by_name||'—'} • {Number(ord.total_amount||0).toLocaleString('vi-VN')}đ
            {ord.printed_by_name && <> • 🖨 Người in: <b style={{ color:T.dark }}>{ord.printed_by_name}</b></>}
          </div>
        </div>
        <button onClick={onClose}
          style={{ padding:'5px 10px', borderRadius:6, border:`1px solid ${T.border}`,
            background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:11 }}>
          ✕ Đóng
        </button>
      </div>

      {ord.description_kv && (
        <div style={{ padding:'8px 12px', marginBottom:12, background:T.goldBg,
          border:`1px solid ${T.goldBorder}`, borderRadius:6 }}>
          <div style={{ fontSize:10, color:T.goldText, fontWeight:600 }}>📝 Ghi chú KV:</div>
          <div style={{ fontSize:11, color:T.dark, marginTop:3 }}>{ord.description_kv}</div>
        </div>
      )}

      {ord.status !== 'picking' && (
        <div style={{ padding:'8px 12px', marginBottom:12, background:T.greenBg,
          borderRadius:6, fontSize:11, color:T.green, fontWeight:600 }}>
          ✓ Đơn này đã hoàn tất nhặt
          {ord.picked_at && <> lúc {new Date(ord.picked_at).toLocaleString('vi-VN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit'})}</>}
        </div>
      )}

      {/* Progress */}
      <div style={{ marginBottom:12 }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:6, fontSize:11, color:T.med }}>
          <span>Tiến độ: <b style={{ color:T.dark }}>{pickedItems}/{items.length}</b> SP đủ</span>
          <span>{progress}%</span>
        </div>
        <div style={{ height:8, background:T.border, borderRadius:4 }}>
          <div style={{ height:'100%', borderRadius:4,
            background: progress===100 ? T.green : T.gold,
            width:`${progress}%`, transition:'width .3s' }}/>
        </div>
      </div>

      <input value={searchSP} onChange={e => setSearchSP(e.target.value)}
        placeholder="🔍 Tìm SP trong đơn..."
        style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
          fontSize:11, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
          boxSizing:'border-box' as any, marginBottom:10 }}/>

      {/* Items — Số lượng ĐƠN NÀY = TO, tồn + tổng đặt = nhỏ bên */}
      <div style={{ display:'flex', flexDirection:'column', gap:8, marginBottom:12 }}>
        {filtered.map((it: any) => {
          const done = (it.picked_qty||0) + (it.short_qty||0) >= it.qty
          const hasShort = (it.short_qty||0) > 0
          const realStock = getStock(it.code, it.stock)
          const totalOrdered = getTotalOrdered(it.code)
          const stockShort = realStock < totalOrdered  // tổng đặt lớn hơn tồn → cảnh báo
          return (
            <div key={it.code} style={{ padding:12, borderRadius:10,
              background: done ? (hasShort ? T.redBg : T.greenBg) : '#fff',
              border: `1px solid ${done ? (hasShort?T.red:T.green) : T.border}`,
              borderLeft: `4px solid ${done ? (hasShort?T.red:T.green) : (stockShort?T.amber:T.border)}` }}>

              {/* Row 1: Tên + Nút ảnh */}
              <div style={{ display:'flex', alignItems:'flex-start', gap:8, marginBottom:8 }}>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:13, fontWeight:700, color:T.dark, lineHeight:1.35 }}>
                    {it.name}
                  </div>
                  <div style={{ fontSize:10, color:T.light, marginTop:2, display:'flex', gap:8, flexWrap:'wrap' }}>
                    <span>{it.code}</span>
                    {it.unit && <span>{it.unit}</span>}
                    <span>• 📦 Tồn: <b style={{ color: stockShort ? T.amber : T.dark }}>{realStock}</b></span>
                    <span>• 🛒 Tổng KH đặt: <b style={{ color: stockShort ? T.amber : T.dark }}>{totalOrdered}</b></span>
                    {stockShort && <span style={{ color:T.amber, fontWeight:700 }}>⚠️ KHẢ NĂNG THIẾU</span>}
                  </div>
                </div>
                <button onClick={() => setShowImgModal(it.code)}
                  style={{ padding:'6px 10px', borderRadius:6, border:`1px solid ${T.gold}`,
                    background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                    fontSize:11, fontWeight:600, flexShrink:0, whiteSpace:'nowrap' }}>
                  🖼 Ảnh SP
                </button>
              </div>

              {/* Row 2: SỐ LƯỢNG ĐƠN NÀY — TO HOÀNH TRÁNG */}
              <div style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 14px',
                background: done ? 'transparent' : T.bg, borderRadius:8,
                border: done ? 'none' : `1px solid ${T.border}`, marginBottom:10 }}>
                <div style={{ flex:1, textAlign:'center' }}>
                  <div style={{ fontSize:10, color:T.light, fontWeight:700, letterSpacing:1, marginBottom:2 }}>
                    SỐ LƯỢNG CẦN NHẶT
                  </div>
                  <div style={{ fontSize:42, fontWeight:900, color: done ? T.green : T.dark,
                    lineHeight:1, letterSpacing:-1 }}>
                    {it.qty}
                  </div>
                </div>
                {canPick && (
                  <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:6 }}>
                      <button onClick={() => onUpdateQty(it.code, Math.max(0, (it.picked_qty||0)-1))}
                        disabled={(it.picked_qty||0)<=0}
                        style={{ width:42, height:42, borderRadius:8, border:`2px solid ${T.border}`,
                          background:'#fff', cursor:'pointer', fontSize:22, fontWeight:700, fontFamily:'inherit',
                          color:(it.picked_qty||0)<=0?T.light:T.dark, padding:0 }}>−</button>
                      <div style={{ minWidth:60, textAlign:'center' }}>
                        <div style={{ fontSize:9, color:T.light, fontWeight:600 }}>ĐÃ NHẶT</div>
                        <div style={{ fontSize:24, fontWeight:800, color: done?T.green:T.dark, lineHeight:1 }}>
                          {it.picked_qty||0}
                        </div>
                      </div>
                      <button onClick={() => onUpdateQty(it.code, (it.picked_qty||0)+1)}
                        disabled={(it.picked_qty||0)>=it.qty}
                        style={{ width:42, height:42, borderRadius:8, border:`2px solid ${T.border}`,
                          background:'#fff', cursor:'pointer', fontSize:22, fontWeight:700, fontFamily:'inherit',
                          color:(it.picked_qty||0)>=it.qty?T.light:T.dark, padding:0 }}>+</button>
                    </div>
                  </div>
                )}
              </div>

              {/* Row 3: nút thao tác nhanh */}
              {canPick && (
                <div style={{ display:'flex', gap:8 }}>
                  <button onClick={() => onUpdateQty(it.code, it.qty)}
                    style={{ flex:1, padding:'10px', borderRadius:6,
                      border:`1.5px solid ${T.green}`,
                      background: done && !hasShort ? T.green : '#fff',
                      color: done && !hasShort ? '#fff' : T.green,
                      cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                    ✓ Đủ hàng
                  </button>
                  <button onClick={() => setShowShortModal(it)}
                    style={{ flex:1, padding:'10px', borderRadius:6,
                      border:`1.5px solid ${T.red}`,
                      background: hasShort ? T.red : '#fff',
                      color: hasShort ? '#fff' : T.red,
                      cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                    ⚠️ Báo thiếu
                  </button>
                </div>
              )}

              {hasShort && (
                <div style={{ fontSize:11, color:T.red, marginTop:8, padding:'6px 10px',
                  background:'#fff', borderRadius:6, border:`1px solid ${T.red}` }}>
                  ⚠️ Thiếu <b>{it.short_qty}</b>{it.short_note?`: ${it.short_note}`:''}
                </div>
              )}
            </div>
          )
        })}
      </div>

      {/* Footer */}
      {canPick && (
        <>
          {/* Nút nhặt đủ toàn bộ */}
          <div style={{ marginBottom:10 }}>
            <button onClick={() => {
              if (confirm(`Bạn xác nhận đã nhặt đủ đơn ${ord.order_code}?\n\nThao tác này sẽ đánh dấu TẤT CẢ sản phẩm là đã nhặt đủ số lượng yêu cầu.`)) {
                onMarkAllPicked()
              }
            }}
              style={{ width:'100%', padding:'10px', borderRadius:8, border:`2px dashed ${T.green}`,
                background:T.greenBg, color:T.green, cursor:'pointer', fontFamily:'inherit',
                fontSize:12, fontWeight:700 }}>
              ✅ Nhặt đủ toàn bộ
            </button>
          </div>
          <div style={{ display:'flex', gap:8, paddingTop:10, borderTop:`1px solid ${T.border}` }}>
            <button onClick={onClose}
              style={{ flex:1, padding:'10px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
              ⏸ Tạm
            </button>
            <button onClick={onFinish}
              style={{ flex:2, padding:'10px', borderRadius:6, border:'none',
                background:`linear-gradient(135deg, ${T.green} 0%, #107035 100%)`, color:'#fff',
                cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              ✓ Hoàn tất nhặt
            </button>
          </div>
        </>
      )}

      {showShortModal && (
        <ShortageModalV2 item={showShortModal} onClose={() => setShowShortModal(null)}
          onSubmit={(qty: number, note: string) => {
            onReportShort(showShortModal.code, qty, note)
            setShowShortModal(null)
          }}/>
      )}
      {showImgModal && (
        <ProductImageModalV2 code={showImgModal} onClose={() => setShowImgModal(null)}/>
      )}
    </div>
  )
}

function ShortageModalV2({ item, onClose, onSubmit }: any) {
  const [qty, setQty]   = useState(String(item.short_qty || (item.qty - (item.picked_qty||0))))
  const [note, setNote] = useState(item.short_note || '')
  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, padding:20, maxWidth:420, width:'100%' }}>
        <div style={{ fontSize:15, fontWeight:700, color:T.dark, marginBottom:6 }}>⚠️ Báo thiếu hàng</div>
        <div style={{ fontSize:12, color:T.med, marginBottom:14 }}>{item.name} ({item.code})</div>
        <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
          Số lượng thiếu (còn {item.qty} cần nhặt)
        </label>
        <input type="number" value={qty} onChange={e => setQty(e.target.value)} min="0" max={item.qty}
          style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:6,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any, marginBottom:12 }}/>
        <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
          Ghi chú (VD: Hết hàng, Vỡ hỏng...)
        </label>
        <input value={note} onChange={e => setNote(e.target.value)}
          style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:6,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any, marginBottom:16 }}/>
        <div style={{ display:'flex', gap:10 }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'8px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
            Hủy
          </button>
          <button onClick={() => onSubmit(Number(qty)||0, note)}
            style={{ flex:1, padding:'8px', borderRadius:6, border:'none',
              background:T.red, color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:12, fontWeight:600 }}>
            📤 Báo thiếu
          </button>
        </div>
      </div>
    </div>
  )
}

function ProductImageModalV2({ code, onClose }: any) {
  const [info, setInfo]       = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError]     = useState<string|null>(null)

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(
          `${SUPABASE_URL}/functions/v1/kiotviet-product-info?code=${encodeURIComponent(code)}`,
          { headers: { 'Authorization': `Bearer ${SUPABASE_ANON}` } }
        )
        const data = await res.json()
        if (data.error) setError(data.error)
        else setInfo(data)
      } catch(e: any) {
        setError(e.message)
      }
      setLoading(false)
    })()
  }, [code])

  const imgs: string[] = info?.images || []

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.85)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
      onClick={onClose}>
      <div style={{ background:'#fff', borderRadius:12, padding:20, maxWidth:600, width:'100%',
        maxHeight:'90vh', overflow:'auto' }} onClick={e => e.stopPropagation()}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
          <div>
            <div style={{ fontSize:14, fontWeight:700, color:T.dark }}>{info?.name || code}</div>
            <div style={{ fontSize:11, color:T.light, marginTop:3 }}>
              Mã: {code}
              {info && <> • Tồn: <b style={{ color:T.green }}>{info.stock}</b></>}
              {info?.unit && <> • {info.unit}</>}
            </div>
          </div>
          <button onClick={onClose}
            style={{ background:'transparent', border:'none', fontSize:22, cursor:'pointer',
              color:T.med, padding:'0 6px', lineHeight:1 }}>
            ×
          </button>
        </div>

        {loading && <div style={{ padding:30, textAlign:'center', color:T.light, fontSize:13 }}>
          ⏳ Đang tải ảnh từ KiotViet...
        </div>}

        {error && (
          <div style={{ padding:20, textAlign:'center', color:T.red, fontSize:13,
            background:T.redBg, borderRadius:8 }}>
            ❌ Lỗi: {error}
          </div>
        )}

        {!loading && !error && imgs.length === 0 && (
          <div style={{ padding:40, textAlign:'center', color:T.light, fontSize:13,
            background:T.bg, borderRadius:8 }}>
            📷 SP này chưa có ảnh trên KiotViet.<br/>
            <span style={{ fontSize:11 }}>Admin có thể vào KV → Hàng hoá → Thêm ảnh.</span>
          </div>
        )}

        {!loading && imgs.length > 0 && (
          <div style={{ display:'grid', gridTemplateColumns:'1fr', gap:10 }}>
            {imgs.map((url: string, i: number) => (
              <img key={i} src={url} alt={info?.name}
                style={{ width:'100%', borderRadius:8, border:`1px solid ${T.border}`,
                  display:'block' }}
                onError={(e: any) => { e.currentTarget.style.display = 'none' }}/>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ PACKING MODULE v2 — Đóng Đơn (2 loại ảnh: nhặt + thùng) ═══════════
// ══════════════════════════════════════════════════════════════════════
function PackingModule({ user, allUsers, mobile, products }: any) {
  const perm    = getPerm(user)
  const canPack = perm.packOrders || perm.viewAllDashboard
  const p = mobile ? '16px' : '24px'

  const [orders, setOrders]   = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [tab, setTab]         = useState<'pending'|'done_today'|'lookup'>('pending')
  const [selectedCode, setSelectedCode] = useState<string|null>(null)
  const [searchQ, setSearchQ] = useState('')
  const [joinConfirm, setJoinConfirm] = useState<any>(null)

  const fetchData = async () => {
    setLoading(true)
    // Query 1: ALL orders đang packing (không limit vì thường <100 đơn cùng lúc)
    const { data: pendingData } = await db.from('packing_workflow').select('*')
      .eq('status', 'packing')
      .order('picked_at', { ascending: true })
    // Query 2: orders done trong 3 ngày gần nhất (đủ cho tab "Xong hôm nay" + buffer)
    const threeDaysAgo = new Date(Date.now() - 3*86400000).toISOString()
    const { data: doneData } = await db.from('packing_workflow').select('*')
      .eq('status', 'done')
      .gte('packed_at', threeDaysAgo)
      .order('packed_at', { ascending: false })
      .limit(500)
    setOrders([...(pendingData||[]), ...(doneData||[])])
    setLoading(false)
  }

  useEffect(() => {
    fetchData()
  }, [])

  // Auto-refresh mỗi 30 giây — PAUSE khi user đang mở đơn (tránh disrupt công việc đóng đơn)
  useEffect(() => {
    if (selectedCode) return  // user đang làm việc
    const interval = setInterval(fetchData, 30000)
    return () => clearInterval(interval)
  }, [selectedCode])

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const filterByQ = (list: any[]) => {
    const q = norm(searchQ)
    if (!q) return list
    return list.filter((o: any) => norm(`${o.order_code} ${o.customer_name} ${o.sold_by_name}`).includes(q))
  }

  const todayStart = new Date()
  todayStart.setHours(0,0,0,0)
  const pendingOrds = filterByQ(orders.filter((o: any) => o.status === 'packing'))
  const doneTodayOrds = filterByQ(orders.filter((o: any) =>
    o.status === 'done' && o.packed_at && new Date(o.packed_at) >= todayStart
  ))

  const finishPacking = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const totalItems = (ord.items||[]).length
    const { min, suggest } = photoCountRangeV2(totalItems)
    const picked = (ord.photos_picked||[]).length
    const packed = (ord.photos_packed||[]).length
    // Bắt buộc min (giờ là 1) cho photos_picked
    if (picked < min) {
      alert(`❌ Cần tối thiểu ${min} ảnh hàng đã nhặt (hiện có ${picked}).`)
      return
    }
    // Bắt buộc min cho photos_packed nếu không phải bookship
    if (!ord.no_box && packed < min) {
      alert(`❌ Cần tối thiểu ${min} ảnh thùng hàng (hiện có ${packed}).\nNếu đơn bookship không đóng thùng, hãy tick vào ô "Đơn bookship — không đóng thùng".`)
      return
    }
    // Soft popup: nếu đơn >=3 SP mà ảnh hàng đã nhặt < suggest
    if (totalItems >= 3 && picked < suggest) {
      const ok = confirm(
        `⚠️ Đơn này có ${totalItems} SP nhưng bạn chỉ chụp ${picked} ảnh hàng đã nhặt.\n` +
        `Gợi ý nên chụp ít nhất ${suggest} ảnh để có bằng chứng rõ ràng nếu KH khiếu nại.\n\n` +
        `Tiếp tục hoàn tất đóng hàng với chỉ ${picked} ảnh?`
      )
      if (!ok) return
    }
    // Soft popup cho thùng hàng
    if (!ord.no_box && totalItems >= 3 && packed < suggest) {
      const ok = confirm(
        `⚠️ Đơn này có ${totalItems} SP nhưng bạn chỉ chụp ${packed} ảnh thùng hàng.\n` +
        `Gợi ý nên chụp ít nhất ${suggest} ảnh để có bằng chứng rõ ràng.\n\n` +
        `Tiếp tục hoàn tất?`
      )
      if (!ok) return
    }
    // Multi-packer: packed_by_ids = union of (active_packers, current user)
    // packed_by vẫn set = current user (người cuối bấm hoàn tất) cho backward compat
    const activePackers: string[] = ord.active_packers || []
    const finalPackerIds = Array.from(new Set([...activePackers, user.id]))
    const upd = {
      status: 'done',
      packed_by: user.id,
      packed_by_ids: finalPackerIds,
      active_packers: [],
      packed_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    const { error } = await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    if (error) { alert('❌ Lỗi: ' + error.message); return false }
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
    setSelectedCode(null)
    alert(`✅ Đã hoàn tất đóng hàng${finalPackerIds.length>1?` (${finalPackerIds.length} người cùng đóng)`:''}`)

    // Trigger AI check async — KHÔNG await, không chặn flow
    // Edge function sẽ tự update DB khi xong, NV không cần đợi
    fetch(`${SUPABASE_URL}/functions/v1/ai-check-order`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SUPABASE_ANON}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ order_code: orderCode }),
    }).catch(() => { /* silent — AI check là optional */ })

    return true
  }

  // Thêm user vào active_packers khi qua Gate (chụp xong ảnh nhặt, chuẩn bị đóng)
  const joinPackingGroup = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const current: string[] = ord.active_packers || []
    if (current.includes(user.id)) return  // đã trong group
    const next = [...current, user.id]
    const upd: any = { active_packers: next, updated_at: new Date().toISOString() }
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  // Rời khỏi active_packers khi user đóng detail panel mà chưa hoàn tất
  const leavePackingGroup = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const current: string[] = ord.active_packers || []
    if (!current.includes(user.id)) return
    const next = current.filter(id => id !== user.id)
    const upd: any = { active_packers: next, updated_at: new Date().toISOString() }
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  // QM review AI flag: 'qm_ok' = AI đúng, 'qm_wrong' = AI sai
  const reviewAiFlag = async (orderCode: string, verdict: 'qm_ok'|'qm_wrong') => {
    const upd: any = {
      ai_check_status: verdict,
      ai_qm_reviewed_by: user.id,
      ai_qm_reviewed_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    const { error } = await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  const updatePhotoList = async (orderCode: string, type: 'picked'|'packed', newPhotos: string[]) => {
    const col = type === 'picked' ? 'photos_picked' : 'photos_packed'
    const upd: any = { [col]: newPhotos, updated_at: new Date().toISOString() }
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  const updateNoBox = async (orderCode: string, noBox: boolean) => {
    const upd: any = { no_box: noBox, updated_at: new Date().toISOString() }
    // Nếu tick no_box → xoá photos_packed cũ để không lẫn lộn
    if (noBox) upd.photos_packed = []
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  if (loading) return <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>⏳ Đang tải...</div>

  const tryOpenOrder = (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    // Done order → đọc lịch sử, không cần confirm
    if (ord.status === 'done') {
      setSelectedCode(orderCode)
      return
    }
    const activePackers: string[] = ord.active_packers || []
    const otherPackers = activePackers.filter(id => id !== user.id)
    if (otherPackers.length > 0) {
      const names = otherPackers.map(id =>
        allUsers.find((u: any) => u.id === id)?.name || '?'
      ).join(', ')
      setJoinConfirm({ orderCode, names })
      return
    }
    setSelectedCode(orderCode)
  }

  const selected = selectedCode ? orders.find((o: any) => o.order_code === selectedCode) : null
  const showDetail = selected !== null
  const showList = !mobile || !showDetail

  const displayOrders = tab === 'pending' ? pendingOrds : doneTodayOrds

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="📸 Đóng đơn"
        subtitle={`${pendingOrds.length} chờ đóng • ${doneTodayOrds.length} đã xong hôm nay`}
        action={
          <div style={{ display:'flex', gap:8, alignItems:'center' }}>
            {selectedCode && (
              <span style={{ fontSize:10, color:T.amber }}>
                ⏸ Pause (đang mở đơn)
              </span>
            )}
            <button onClick={fetchData}
              style={{ padding:'5px 12px', borderRadius:20, border:`1px solid ${T.border}`,
                background:'transparent', cursor:'pointer', fontFamily:'inherit', fontSize:11, color:T.med }}>
              🔄 Refresh
            </button>
          </div>
        }/>

      {/* Tabs */}
      <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
        {[
          { id:'pending',    label:`📦 Chờ đóng${pendingOrds.length?` (${pendingOrds.length})`:''}` },
          { id:'done_today', label:`✅ Xong hôm nay${doneTodayOrds.length?` (${doneTodayOrds.length})`:''}` },
          { id:'lookup',     label:`🔍 Tra cứu đơn` },
        ].map((t: any) => (
          <button key={t.id} onClick={() => { setTab(t.id as any); setSelectedCode(null) }}
            style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${tab===t.id?T.gold:T.border}`,
              background:tab===t.id?T.goldBg:'transparent',
              color:tab===t.id?T.goldText:T.med, fontWeight:tab===t.id?700:400 }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Lookup tab — render riêng, không vào 2-col layout */}
      {tab === 'lookup' && (
        <OrderLookupTab user={user} allUsers={allUsers} mobile={mobile}/>
      )}

      {/* 2-column layout (chỉ cho pending / done_today) */}
      {tab !== 'lookup' && (
      <div style={{
        display: 'grid',
        gridTemplateColumns: mobile ? '1fr' : (showDetail ? '380px 1fr' : '1fr'),
        gap: 14,
        alignItems: 'flex-start',
      }}>
        {/* Left: list */}
        {showList && (
          <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
            <Card style={{ padding:10 }}>
              <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
                placeholder="🔍 Tìm mã đơn, khách..."
                style={{ width:'100%', padding:'7px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
                  boxSizing:'border-box' as any }}/>
            </Card>

            {displayOrders.length === 0 ? (
              <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
                {tab==='pending' ? 'Chưa có đơn nào chờ đóng.' : 'Chưa có đơn xong hôm nay.'}
              </div>
            ) : (
              displayOrders.map((o: any) => {
                const totalItems = (o.items||[]).length
                const { min } = photoCountRangeV2(totalItems)
                const picked = (o.photos_picked||[]).length
                const packed = (o.photos_packed||[]).length
                const isSelected = o.order_code === selectedCode
                const modCount = o.modification_count || 0
                const latestChange = (o.change_log||[])[((o.change_log||[]).length - 1)]
                const wasReverted = o.had_mod_after_done === true
                // Multi-packer info
                const activePackerIds: string[] = o.active_packers || []
                const finalPackerIds: string[] = o.packed_by_ids || (o.packed_by ? [o.packed_by] : [])
                const pickerName = o.assigned_to
                  ? (allUsers.find((u: any) => u.id === o.assigned_to)?.name || '?')
                  : null
                const getName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || '?'
                const activePackerNames = activePackerIds.map(getName).join(', ')
                const finalPackerNames = finalPackerIds.map(getName).join(', ')
                // Timestamps
                const fmtTime = (iso: string|null) => {
                  if (!iso) return null
                  const d = new Date(iso)
                  const isToday = d.toDateString() === new Date().toDateString()
                  return isToday
                    ? d.toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                    : d.toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'}) + ' ' +
                      d.toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                }
                const pickedAtTxt = fmtTime(o.picked_at)
                const packedAtTxt = fmtTime(o.packed_at)
                return (
                  <Card key={o.order_code}
                    onClick={() => tryOpenOrder(o.order_code)}
                    style={{ padding:10, cursor:'pointer',
                      borderLeft: wasReverted
                        ? `4px solid ${T.red}`
                        : (isSelected ? `4px solid ${T.gold}` : `4px solid transparent`),
                      background: wasReverted ? '#fff5f5' : (isSelected ? T.goldBg : '#fff') }}>
                    <div style={{ fontSize:12, fontWeight:700, color:T.dark,
                      whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                      {o.order_code} • {o.customer_name}
                    </div>
                    <div style={{ fontSize:10, color:T.light, marginTop:2 }}>
                      {totalItems} SP • {Number(o.total_amount||0).toLocaleString('vi-VN')}đ
                      {o.no_box && <> • 📮 Bookship</>}
                    </div>
                    {/* Tab 'Chờ đóng': tên NV nhặt + thời điểm chuyển sang đóng + active packers nếu có */}
                    {tab === 'pending' && (
                      <>
                        {pickerName ? (
                          <div style={{ fontSize:10, color:T.med, marginTop:3 }}>
                            📥 Nhặt bởi: <b style={{ color:T.dark }}>{pickerName}</b>
                            {pickedAtTxt && <span style={{ color:T.light }}> • {pickedAtTxt}</span>}
                          </div>
                        ) : pickedAtTxt && (
                          <div style={{ fontSize:10, color:T.med, marginTop:3 }}>
                            📥 Nhặt xong lúc <b style={{ color:T.dark }}>{pickedAtTxt}</b>
                            <span style={{ color:T.light, fontStyle:'italic' }}> (không rõ NV)</span>
                          </div>
                        )}
                        {activePackerIds.length > 0 && (
                          <div style={{ marginTop:4, padding:'3px 8px', borderRadius:6,
                            background:T.blue, color:'#fff', fontSize:9, fontWeight:700 }}>
                            ⏳ ĐANG ĐÓNG: {activePackerNames}
                          </div>
                        )}
                      </>
                    )}
                    {/* Tab 'Xong hôm nay': NV nhặt + NV đóng (tất cả) + timeline */}
                    {tab === 'done_today' && (
                      <div style={{ marginTop:3 }}>
                        {pickerName && (
                          <div style={{ fontSize:10, color:T.green, fontWeight:600 }}>
                            👤 Nhặt: {pickerName}
                            {pickedAtTxt && <span style={{ color:T.light, fontWeight:400 }}> • {pickedAtTxt}</span>}
                          </div>
                        )}
                        {finalPackerIds.length > 0 && (
                          <div style={{ fontSize:10, color:T.blue, fontWeight:600, marginTop:1 }}>
                            📮 Đóng: {finalPackerNames}
                            {packedAtTxt && <span style={{ color:T.light, fontWeight:400 }}> • {packedAtTxt}</span>}
                          </div>
                        )}
                      </div>
                    )}
                    {/* AI check badge */}
                    {tab === 'done_today' && o.ai_check_status && (
                      <div style={{ marginTop:5, padding:'3px 8px', borderRadius:6, fontSize:9, fontWeight:700,
                        ...(o.ai_check_status === 'pending' ? { background:T.bg, color:T.light } :
                            o.ai_check_status === 'matched' ? { background:T.greenBg, color:T.green } :
                            o.ai_check_status === 'qm_ok'   ? { background:T.greenBg, color:T.green } :
                            o.ai_check_status === 'qm_wrong'? { background:T.bg, color:T.light } :
                            o.ai_check_status === 'mismatch'? { background:T.redBg, color:T.red } :
                            o.ai_check_status === 'unclear' ? { background:T.amberBg, color:T.amber } :
                            { background:T.bg, color:T.light }) }}>
                        {o.ai_check_status === 'pending'  && '🤖 AI đang check...'}
                        {o.ai_check_status === 'matched'  && '🤖✓ AI khớp'}
                        {o.ai_check_status === 'qm_ok'    && '✓ QM đã duyệt (AI đúng)'}
                        {o.ai_check_status === 'qm_wrong' && '✓ QM đã duyệt (AI sai)'}
                        {o.ai_check_status === 'mismatch' && (
                          <>🤖⚠️ AI LỆCH: đơn {o.ai_check_result?.order_total_qty ?? '?'} vs AI {o.ai_check_result?.ai_total_qty ?? '?'}</>
                        )}
                        {o.ai_check_status === 'unclear'  && '🤖❓ AI không rõ ảnh'}
                        {o.ai_check_status === 'error'    && '🤖 AI lỗi'}
                      </div>
                    )}
                    {wasReverted && (
                      <div style={{ marginTop:5, padding:'3px 8px', borderRadius:6,
                        background:T.red, color:'#fff', fontSize:9, fontWeight:800, letterSpacing:.3 }}>
                        🚨 ĐƠN ĐÃ MỞ LẠI — SALE SỬA SAU KHI ĐÓNG
                      </div>
                    )}
                    {modCount > 0 && latestChange && (
                      <div style={{ marginTop:5, padding:'3px 8px', borderRadius:6,
                        background:T.amberBg, color:T.amber, fontSize:9, fontWeight:700,
                        whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}
                        title={latestChange.summary}>
                        📝 ĐÃ SỬA {modCount}× • {latestChange.summary}
                      </div>
                    )}
                    <div style={{ display:'flex', gap:6, marginTop:5, fontSize:9 }}>
                      <span style={{ padding:'1px 6px', borderRadius:10,
                        background: picked>=1?T.greenBg:T.amberBg,
                        color: picked>=1?T.green:T.amber, fontWeight:600 }}>
                        📦 Hàng: {picked}
                      </span>
                      {!o.no_box && (
                        <span style={{ padding:'1px 6px', borderRadius:10,
                          background: packed>=1?T.greenBg:T.amberBg,
                          color: packed>=1?T.green:T.amber, fontWeight:600 }}>
                          📮 Thùng: {packed}
                        </span>
                      )}
                    </div>
                  </Card>
                )
              })
            )}
          </div>
        )}

        {/* Right: detail */}
        {showDetail && selected && (
          <PackingDetailPanel
            ord={selected}
            mobile={mobile}
            user={user}
            allUsers={allUsers}
            products={products}
            onClose={() => setSelectedCode(null)}
            onFinish={() => finishPacking(selected.order_code)}
            onUpdatePhotos={(type: 'picked'|'packed', photos: string[]) =>
              updatePhotoList(selected.order_code, type, photos)}
            onUpdateNoBox={(v: boolean) => updateNoBox(selected.order_code, v)}
            onJoinGroup={() => joinPackingGroup(selected.order_code)}
            onLeaveGroup={() => leavePackingGroup(selected.order_code)}
            onAiReview={(verdict: 'qm_ok'|'qm_wrong') => reviewAiFlag(selected.order_code, verdict)}
            readOnly={selected.status === 'done' || !canPack}
          />
        )}
      </div>
      )}

      {/* Modal xác nhận khi có NV khác đang đóng */}
      {joinConfirm && (
        <JoinPackConfirmModal
          names={joinConfirm.names}
          onCancel={() => setJoinConfirm(null)}
          onConfirm={() => {
            const code = joinConfirm.orderCode
            setJoinConfirm(null)
            setSelectedCode(code)
          }}
        />
      )}
    </div>
  )
}

// ── Modal xác nhận đóng cùng ──
function JoinPackConfirmModal({ names, onCancel, onConfirm }: any) {
  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:420, width:'100%' }}>
        <div style={{ padding:'16px 20px', background:T.blueBg||'#DBEAFE',
          borderBottom:`1px solid ${T.blue}` }}>
          <div style={{ fontSize:14, fontWeight:800, color:T.blue }}>
            ⚠️ Đơn hàng đang được đóng
          </div>
        </div>
        <div style={{ padding:20 }}>
          <div style={{ fontSize:13, color:T.dark, lineHeight:1.6, marginBottom:14 }}>
            Đơn hàng này đã có <b style={{ color:T.blue }}>{names}</b> đóng.
          </div>
          <div style={{ fontSize:12, color:T.med, lineHeight:1.5,
            padding:10, background:T.bg, borderRadius:6 }}>
            💡 Nếu đóng cùng, bạn sẽ được ghi nhận là đồng đóng đơn này.
            Hiệu suất sẽ được chia đều giữa các NV cùng đóng.
          </div>
        </div>
        <div style={{ display:'flex', gap:10, padding:16, borderTop:`1px solid ${T.border}` }}>
          <button onClick={onCancel}
            style={{ flex:1, padding:'10px', borderRadius:8, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
              fontSize:13, fontWeight:600 }}>
            Không, để họ đóng
          </button>
          <button onClick={onConfirm}
            style={{ flex:1, padding:'10px', borderRadius:8, border:'none',
              background:T.blue, color:'#fff', cursor:'pointer', fontFamily:'inherit',
              fontSize:13, fontWeight:700 }}>
            ✓ Có, tôi đóng cùng
          </button>
        </div>
      </div>
    </div>
  )
}

// ── AiCheckBanner — hiển thị kết quả AI check + QM review ──
function AiCheckBanner({ ord, onReview, canReview }: any) {
  const status = ord.ai_check_status
  const result = ord.ai_check_result || {}

  const config: any = {
    matched:  { bg:T.greenBg, border:T.green, color:T.green, icon:'🤖✓',
                title:`AI đã check: ${result.order_total_qty ?? '?'} items khớp` },
    qm_ok:    { bg:T.greenBg, border:T.green, color:T.green, icon:'✓',
                title:`QM đã duyệt (AI đúng)` },
    qm_wrong: { bg:T.bg, border:T.border, color:T.med, icon:'✓',
                title:`QM đã duyệt (AI sai — đã bỏ qua)` },
    mismatch: { bg:T.redBg, border:T.red, color:T.red, icon:'🤖⚠️',
                title:`AI CHECK: Lệch ${Math.abs((result.ai_total_qty||0) - (result.order_total_qty||0))} items` },
    unclear:  { bg:T.amberBg, border:T.amber, color:T.amber, icon:'🤖❓',
                title:`AI không thể đếm chính xác` },
    error:    { bg:T.bg, border:T.border, color:T.light, icon:'🤖',
                title:`AI check lỗi` },
  }
  const c = config[status] || config.error

  return (
    <div style={{ padding:'10px 12px', marginBottom:12, background:c.bg,
      border:`2px solid ${c.border}`, borderRadius:8 }}>
      <div style={{ fontSize:12, fontWeight:800, color:c.color, marginBottom:6 }}>
        {c.icon} {c.title}
      </div>

      {/* Chi tiết AI đếm */}
      {(status === 'mismatch' || status === 'unclear' || status === 'matched') && (
        <div style={{ fontSize:11, color:T.dark, lineHeight:1.6, marginBottom:canReview?10:0 }}>
          <div>📋 <b>Đơn có:</b> {result.order_total_qty ?? '?'} items</div>
          <div>🤖 <b>AI đếm được:</b> {result.ai_total_qty ?? '?'} items
            {result.ai_confidence && <span style={{ color:T.light, fontSize:10 }}> (confidence: {result.ai_confidence})</span>}
          </div>
          {result.ai_description && (
            <div style={{ marginTop:5, padding:'6px 8px', background:'#fff', borderRadius:4,
              fontSize:10, color:T.med, lineHeight:1.5, fontStyle:'italic' }}>
              💬 "{result.ai_description}"
            </div>
          )}
          {result.unclear_reason && (
            <div style={{ marginTop:3, fontSize:10, color:T.amber }}>
              ⚠️ Lý do không rõ: {result.unclear_reason}
            </div>
          )}
        </div>
      )}

      {/* QM review buttons */}
      {canReview && (
        <div style={{ display:'flex', gap:8 }}>
          <button onClick={() => {
            if (confirm('Xác nhận AI báo ĐÚNG (đơn có sai sót cần xử lý)?')) onReview('qm_ok')
          }}
            style={{ flex:1, padding:'7px', borderRadius:6, border:`1px solid ${T.red}`,
              background:'#fff', color:T.red, cursor:'pointer', fontFamily:'inherit',
              fontSize:11, fontWeight:700 }}>
            ⚠️ AI đúng (đơn có sai)
          </button>
          <button onClick={() => {
            if (confirm('Xác nhận AI báo SAI (đơn thực tế OK, bỏ qua flag)?')) onReview('qm_wrong')
          }}
            style={{ flex:1, padding:'7px', borderRadius:6, border:`1px solid ${T.green}`,
              background:'#fff', color:T.green, cursor:'pointer', fontFamily:'inherit',
              fontSize:11, fontWeight:700 }}>
            ✓ AI sai (đơn OK)
          </button>
        </div>
      )}

      {/* Đã QM reviewed — hiển thị ai + khi nào */}
      {(status === 'qm_ok' || status === 'qm_wrong') && ord.ai_qm_reviewed_at && (
        <div style={{ fontSize:10, color:T.light, marginTop:4 }}>
          Reviewed: {new Date(ord.ai_qm_reviewed_at).toLocaleString('vi-VN', {
            day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit'
          })}
        </div>
      )}
    </div>
  )
}

// ── ChangeLogBanner — hiển thị banner đỏ/vàng khi đơn bị Sale sửa ──
function ChangeLogBanner({ ord }: any) {
  const [showAll, setShowAll] = useState(false)
  const log = ord.change_log || []
  const reverted = ord.had_mod_after_done === true
  const modCount = ord.modification_count || 0
  const latest = log[log.length - 1]
  if (!latest) return null

  return (
    <div style={{ padding:'12px 14px', marginBottom:14, borderRadius:8,
      background: reverted ? '#fef2f2' : T.amberBg,
      border: `2px solid ${reverted ? T.red : T.amber}` }}>
      <div style={{ fontSize:13, fontWeight:800,
        color: reverted ? T.red : T.amber, marginBottom:6 }}>
        {reverted
          ? '🚨 ĐƠN ĐÃ MỞ LẠI — SALE SỬA SAU KHI ĐÓNG'
          : `⚠️ ĐƠN NÀY ĐÃ BỊ SỬA ${modCount} LẦN`}
      </div>
      {reverted && (
        <div style={{ fontSize:11, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
          NV Kho cần <b>mở thùng, kiểm tra lại SP, chụp ảnh bổ sung</b> trước khi đóng lại.
        </div>
      )}
      <div style={{ fontSize:11, color:T.med, marginBottom:4 }}>
        Thay đổi gần nhất lúc {new Date(latest.at).toLocaleString('vi-VN')}:
      </div>
      <div style={{ fontSize:12, color:T.dark, fontWeight:600, lineHeight:1.5,
        padding:'6px 10px', background:'#fff', borderRadius:6, border:`1px solid ${T.border}` }}>
        {latest.changes.map((c: any, i: number) => (
          <div key={i} style={{ display:'flex', gap:8, alignItems:'center', padding:'2px 0' }}>
            {c.type === 'add' && (
              <>
                <span style={{ color:T.green, fontWeight:800, minWidth:40 }}>+{c.qty}</span>
                <span>{c.name}</span>
              </>
            )}
            {c.type === 'remove' && (
              <>
                <span style={{ color:T.red, fontWeight:800, minWidth:40 }}>-{c.qty}</span>
                <span style={{ textDecoration:'line-through', color:T.light }}>{c.name}</span>
              </>
            )}
            {c.type === 'qty_change' && (
              <>
                <span style={{ color: c.diff > 0 ? T.green : T.red, fontWeight:800, minWidth:40 }}>
                  {c.diff > 0 ? '+' : ''}{c.diff}
                </span>
                <span>{c.name}</span>
                <span style={{ color:T.light, fontSize:10 }}>({c.oldQty}→{c.newQty})</span>
              </>
            )}
          </div>
        ))}
      </div>
      {log.length > 1 && (
        <button onClick={() => setShowAll(!showAll)}
          style={{ marginTop:8, padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
            background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
            fontSize:10, fontWeight:600 }}>
          {showAll ? '▲ Ẩn lịch sử' : `▼ Xem toàn bộ lịch sử (${log.length - 1} lần trước đó)`}
        </button>
      )}
      {showAll && (
        <div style={{ marginTop:8, maxHeight:250, overflowY:'auto' }}>
          {log.slice(0, -1).reverse().map((entry: any, i: number) => (
            <div key={i} style={{ padding:'8px 10px', marginBottom:6, background:'#fff',
              borderRadius:6, border:`1px solid ${T.border}` }}>
              <div style={{ fontSize:10, color:T.light, marginBottom:4 }}>
                🕒 {new Date(entry.at).toLocaleString('vi-VN')}
                {entry.status_at_time && <> • trạng thái lúc đó: <b>{entry.status_at_time}</b></>}
              </div>
              <div style={{ fontSize:11, color:T.dark, fontWeight:600 }}>
                {entry.summary}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

function PackingDetailPanel({ ord, mobile, user, allUsers, products, onClose, onFinish, onUpdatePhotos, onUpdateNoBox, onJoinGroup, onLeaveGroup, onAiReview, readOnly }: any) {
  const getName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || '?'
  const totalItems = (ord.items || []).length
  const { min, max } = photoCountRangeV2(totalItems)
  const [showImgModal, setShowImgModal] = useState<string|null>(null)
  const [previewPhotoUrl, setPreviewPhotoUrl] = useState<string|null>(null)

  // Multi-packer info
  const activePackerIds: string[] = ord.active_packers || []
  const otherPackers = activePackerIds.filter(id => id !== user?.id)
  const hasOtherPackers = otherPackers.length > 0
  const iAmInGroup = activePackerIds.includes(user?.id)

  // PHASE GATE: bắt buộc chụp ảnh hàng đã nhặt trước khi vào detail
  // 1) Nếu photos_picked đã đủ min → vào thẳng DETAIL (đơn làm dở)
  // 2) Nếu có NV khác đã đang đóng → skip gate (theo yêu cầu điểm 5) → vào thẳng DETAIL
  //    Vì ảnh đã có từ trước bởi NV thứ nhất
  const hasPhotosAlready = (ord.photos_picked||[]).length >= min
  const initialPhase = (hasPhotosAlready || hasOtherPackers) ? 'detail' : 'gate'
  const [phase, setPhase] = useState<'gate'|'detail'>(initialPhase)
  // Một khi qua gate thì không quay lại, kể cả xoá ảnh
  const [hasPassedGate, setHasPassedGate] = useState(initialPhase === 'detail')

  // Auto join group khi vào phase DETAIL (chỉ nếu chưa trong group + đơn chưa done + !readOnly)
  useEffect(() => {
    if (phase === 'detail' && !iAmInGroup && !readOnly && ord.status !== 'done' && onJoinGroup) {
      onJoinGroup()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [phase])

  // Enhanced onClose: rời group nếu chưa hoàn tất (vẫn status packing)
  const handleClose = () => {
    if (iAmInGroup && ord.status !== 'done' && onLeaveGroup) {
      onLeaveGroup()
    }
    onClose()
  }

  // Map product → stock realtime
  const productMap = useMemo(() => {
    const m = new Map<string, any>()
    ;(products || []).forEach((p: any) => m.set(p.code, p))
    return m
  }, [products])
  const getStock = (code: string, fallback: number) => {
    const p = productMap.get(code)
    if (p && p.stock !== null && p.stock !== undefined) return p.stock
    return fallback || 0
  }

  const pickedCount = (ord.photos_picked || []).length
  const packedCount = (ord.photos_packed || []).length
  const canProceedToDetail = pickedCount >= min

  // Format tiền không có "đ"
  const fmtMoney = (n: number) => Number(n||0).toLocaleString('vi-VN')

  return (
    <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`,
      padding:0, position: mobile ? 'static' : 'sticky', top: 0, maxHeight: mobile ? 'none' : 'calc(100vh - 40px)',
      overflowY: 'auto', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' }}>

      {/* ══ HEADER STICKY — luôn hiển thị khi scroll trong panel ══ */}
      <div style={{ position:'sticky', top:0, zIndex:5, background:'#fff',
        padding:'14px 16px', borderBottom:`1px solid ${T.border}`,
        boxShadow:'0 2px 6px rgba(0,0,0,0.04)' }}>
        <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:10 }}>
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ display:'flex', alignItems:'center', gap:10, flexWrap:'wrap' }}>
              <div style={{ fontSize:15, fontWeight:800, color:T.dark }}>
                {ord.order_code}
              </div>
              <div style={{ fontSize:13, color:T.med, flex:1, minWidth:0,
                whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                • {ord.customer_name}
              </div>
              <div style={{ fontSize:18, fontWeight:800, color:T.goldText,
                background:T.goldBg, padding:'3px 12px', borderRadius:8,
                letterSpacing:.3, whiteSpace:'nowrap' }}>
                {fmtMoney(ord.total_amount)}
              </div>
            </div>
            <div style={{ fontSize:11, color:T.light, marginTop:4, display:'flex',
              gap:10, flexWrap:'wrap' }}>
              <span>Sale: <b style={{ color:T.dark }}>{ord.sold_by_name||'—'}</b></span>
              <span>• {totalItems} SP</span>
              {ord.printed_by_name && <span>• 🖨 Người in: <b style={{ color:T.dark }}>{ord.printed_by_name}</b></span>}
              {ord.no_box && <span style={{ color:T.amber, fontWeight:600 }}>• 📮 Bookship (không đóng thùng)</span>}
            </div>
          </div>
          <button onClick={handleClose}
            style={{ padding:'5px 10px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
              fontSize:11, flexShrink:0 }}>
            ✕ Đóng
          </button>
        </div>
      </div>

      <div style={{ padding:16 }}>

      {ord.description_kv && (
        <div style={{ padding:'8px 12px', marginBottom:12, background:T.goldBg,
          border:`1px solid ${T.goldBorder}`, borderRadius:6, fontSize:11, color:T.dark }}>
          📝 {ord.description_kv}
        </div>
      )}

      {/* ══ BANNER đơn đã bị sửa ══ */}
      {(ord.modification_count || 0) > 0 && (
        <ChangeLogBanner ord={ord}/>
      )}

      {/* ══ AI CHECK BANNER ══ */}
      {ord.ai_check_status && ord.ai_check_status !== 'pending' && (
        <AiCheckBanner ord={ord} onReview={onAiReview}
          canReview={!readOnly && (ord.ai_check_status === 'mismatch' || ord.ai_check_status === 'unclear')}/>
      )}

      {/* ══ Multi-packer: banner ai đang cùng đóng ══ */}
      {activePackerIds.length > 0 && (
        <div style={{ padding:'10px 14px', marginBottom:12, borderRadius:8,
          background:T.blueBg||'#DBEAFE', border:`1px solid ${T.blue}` }}>
          <div style={{ fontSize:12, fontWeight:700, color:T.blue, marginBottom:3 }}>
            👥 ĐANG CÓ {activePackerIds.length} NGƯỜI ĐÓNG ĐƠN NÀY
          </div>
          <div style={{ fontSize:11, color:T.dark, lineHeight:1.5 }}>
            {activePackerIds.map((id, idx) => {
              const name = getName(id)
              const isMe = id === user?.id
              return (
                <span key={id}>
                  {idx > 0 && ', '}
                  <b style={{ color: isMe ? T.green : T.blue }}>{name}{isMe ? ' (bạn)' : ''}</b>
                </span>
              )
            })}
            <br/>
            <span style={{ color:T.med, fontSize:10 }}>
              💡 Hiệu suất sẽ chia đều {activePackerIds.length} người. Bất kỳ ai chụp đủ ảnh thùng và bấm "Hoàn tất" là xong.
            </span>
          </div>
        </div>
      )}

      {/* ══ PHASE 1: GATE — bắt buộc chụp ảnh hàng đã nhặt ══ */}
      {phase === 'gate' && !hasPassedGate && (
        <>
          <div style={{ padding:'12px 14px', marginBottom:14, background:T.amberBg,
            border:`2px solid ${T.amber}`, borderRadius:8 }}>
            <div style={{ fontSize:14, fontWeight:800, color:T.amber, marginBottom:4 }}>
              🚦 BƯỚC 1: Chụp ảnh hàng đã nhặt
            </div>
            <div style={{ fontSize:12, color:T.dark, lineHeight:1.5 }}>
              Trước khi thấy chi tiết SP để đóng, bạn <b>BẮT BUỘC</b> phải chụp tối thiểu <b>{min} ảnh</b> hàng đã nhặt (xếp ra bàn, đầy đủ, rõ ràng).
              Điều này đảm bảo có bằng chứng đơn hàng đúng trước khi đóng thùng.
            </div>
          </div>

          <PhotoSection
            title="📦 Ảnh hàng đã nhặt"
            subtitle="Chụp ảnh các SP đã nhặt xếp ra bàn/khay trước khi đóng vào thùng."
            photos={ord.photos_picked || []}
            min={min} max={max}
            readOnly={readOnly}
            orderCode={ord.order_code}
            photoType="picked"
            userId={user?.id}
            onUpdate={(photos: any[]) => onUpdatePhotos('picked', photos)}
          />

          <div style={{ marginTop:16, display:'flex', gap:8 }}>
            <button onClick={handleClose}
              style={{ flex:1, padding:'11px', borderRadius:8, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
              ⏸ Để làm sau
            </button>
            <button
              onClick={() => { setPhase('detail'); setHasPassedGate(true) }}
              disabled={!canProceedToDetail}
              style={{ flex:2, padding:'11px', borderRadius:8, border:'none',
                background: canProceedToDetail
                  ? `linear-gradient(135deg, ${T.green} 0%, #107035 100%)`
                  : T.border,
                color: canProceedToDetail ? '#fff' : T.light,
                cursor: canProceedToDetail ? 'pointer' : 'not-allowed',
                fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              {canProceedToDetail
                ? `✓ Tiếp tục đóng đơn → (${pickedCount}/${min} ảnh)`
                : `🔒 Cần thêm ${min - pickedCount} ảnh để tiếp tục`}
            </button>
          </div>
        </>
      )}

      {/* ══ PHASE 2: DETAIL — SP list + chụp thùng / bookship ══ */}
      {phase === 'detail' && (
        <>
          {/* Metadata */}
          <div style={{ padding:'8px 10px', marginBottom:12, background:T.bg, borderRadius:6,
            fontSize:10, color:T.med, lineHeight:1.6 }}>
            {ord.picked_at && <div>✓ Xong nhặt: <b style={{ color:T.dark }}>{new Date(ord.picked_at).toLocaleString('vi-VN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit'})}</b></div>}
            {ord.packed_by && <div>📮 Người đóng: <b style={{ color:T.green }}>{getName(ord.packed_by)}</b></div>}
          </div>

          {/* Items — Số lượng đơn này TO, tồn + thiếu nhỏ để tham khảo */}
          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:11, fontWeight:600, color:T.med, marginBottom:8 }}>
              📋 {totalItems} sản phẩm trong đơn
            </div>
            <div style={{ maxHeight:380, overflowY:'auto', display:'flex', flexDirection:'column', gap:6 }}>
              {(ord.items||[]).map((it: any, i: number) => {
                const realStock = getStock(it.code, it.stock)
                const hasShort = (it.short_qty||0) > 0
                return (
                  <div key={i} style={{ padding:10, borderRadius:8, background:'#fff',
                    border:`1px solid ${hasShort ? T.red : T.border}`,
                    borderLeft:`4px solid ${hasShort ? T.red : T.green}` }}>
                    <div style={{ display:'flex', alignItems:'flex-start', gap:8, marginBottom:6 }}>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:T.dark, lineHeight:1.35 }}>
                          {it.name}
                        </div>
                        <div style={{ fontSize:9, color:T.light, marginTop:2, display:'flex', gap:6, flexWrap:'wrap' }}>
                          <span>{it.code}</span>
                          {it.unit && <span>• {it.unit}</span>}
                          <span>• 📦 Tồn: <b style={{ color:T.dark }}>{realStock}</b></span>
                          {hasShort && <span style={{ color:T.red, fontWeight:700 }}>• ⚠️ Thiếu {it.short_qty}</span>}
                        </div>
                      </div>
                      <button onClick={() => setShowImgModal(it.code)}
                        style={{ padding:'5px 10px', borderRadius:6, border:`1px solid ${T.gold}`,
                          background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                          fontSize:10, fontWeight:600, flexShrink:0, whiteSpace:'nowrap' }}>
                          🖼 Ảnh SP
                      </button>
                    </div>
                    {/* Số lượng TO */}
                    <div style={{ textAlign:'center', padding:'8px 0', background:T.bg, borderRadius:6,
                      border:`1px solid ${T.border}` }}>
                      <div style={{ fontSize:9, color:T.light, fontWeight:700, letterSpacing:.8 }}>
                        SỐ LƯỢNG CẦN ĐÓNG
                      </div>
                      <div style={{ fontSize:30, fontWeight:900, color:T.dark, lineHeight:1, marginTop:2 }}>
                        {it.qty - (it.short_qty||0)}
                        {hasShort && (
                          <span style={{ fontSize:14, color:T.light, fontWeight:400, marginLeft:6 }}>
                            (đặt {it.qty})
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          </div>

          {/* Ảnh hàng đã nhặt (readonly info — đã chụp ở Phase 1) */}
          <div style={{ padding:'10px 12px', marginBottom:14, background:T.greenBg,
            border:`1px solid ${T.green}`, borderRadius:8 }}>
            <div style={{ fontSize:12, fontWeight:700, color:T.green, marginBottom:8 }}>
              ✓ Đã chụp {pickedCount} ảnh hàng đã nhặt
            </div>
            {/* Thumbnails */}
            {pickedCount > 0 && (
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(80px, 1fr))',
                gap:6, marginBottom:8 }}>
                {(ord.photos_picked || []).map((ph: any, i: number) => {
                  const url = typeof ph === 'string' ? ph : (ph?.url || '')
                  const at  = typeof ph === 'string' ? '' : (ph?.at || '')
                  if (!url) return null
                  return (
                    <div key={i} style={{ position:'relative', borderRadius:6, overflow:'hidden',
                      border:`1px solid ${T.border}`, cursor:'pointer', background:'#fff' }}
                      onClick={() => setPreviewPhotoUrl(url)}>
                      <div style={{ aspectRatio:'1/1', overflow:'hidden' }}>
                        <img src={url} alt={`Ảnh nhặt ${i+1}`}
                          style={{ width:'100%', height:'100%', objectFit:'cover', display:'block' }}/>
                      </div>
                      {at && (
                        <div style={{ fontSize:8, color:T.light, padding:'2px 4px', background:T.bg,
                          textAlign:'center', lineHeight:1.2 }}>
                          {new Date(at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})}
                          {' '}
                          {new Date(at).toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'})}
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            )}
            {!readOnly && (
              <button onClick={() => { setPhase('gate'); setHasPassedGate(false) }}
                style={{ padding:'3px 10px', borderRadius:12, border:`1px solid ${T.green}`,
                  background:'#fff', color:T.green, cursor:'pointer', fontFamily:'inherit',
                  fontSize:10, fontWeight:600 }}>
                📷 Chụp thêm ảnh hàng đã nhặt
              </button>
            )}
          </div>

          {/* Checkbox bookship không đóng thùng */}
          {!readOnly && (
            <label style={{ display:'flex', alignItems:'flex-start', gap:10, padding:12, marginBottom:12,
              background: ord.no_box ? T.amberBg : T.bg, borderRadius:8,
              border:`2px solid ${ord.no_box ? T.amber : T.border}`, cursor:'pointer' }}>
              <input type="checkbox" checked={!!ord.no_box}
                onChange={e => onUpdateNoBox(e.target.checked)}
                style={{ marginTop:2, width:18, height:18, cursor:'pointer', accentColor:T.amber }}/>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>
                  📮 Đơn bookship — không đóng thùng
                </div>
                <div style={{ fontSize:11, color:T.med, marginTop:3, lineHeight:1.4 }}>
                  Tick nếu đơn này là bookship (giao nội bộ, giao tận nơi) không cần đóng thùng. Khi tick, không cần chụp ảnh thùng hàng.
                </div>
              </div>
            </label>
          )}

          {/* Section ảnh thùng hàng — ẨN khi no_box */}
          {!ord.no_box && (
            <PhotoSection
              title="📮 Ảnh thùng hàng (sau khi đóng xong)"
              subtitle="Chụp ảnh thùng hàng đã đóng kín, dán nhãn/ghi địa chỉ."
              photos={ord.photos_packed || []}
              min={min} max={max}
              readOnly={readOnly}
              orderCode={ord.order_code}
              photoType="packed"
              userId={user?.id}
              onUpdate={(photos: any[]) => onUpdatePhotos('packed', photos)}
            />
          )}

          {/* Thông báo nếu bookship */}
          {ord.no_box && (
            <div style={{ padding:'12px 14px', marginBottom:14, background:T.amberBg,
              border:`1px solid ${T.amber}`, borderRadius:8,
              fontSize:12, color:T.amber, fontWeight:600 }}>
              ℹ️ Đã đánh dấu là đơn bookship — bỏ qua bước chụp ảnh thùng hàng.
            </div>
          )}

          {/* Footer */}
          {!readOnly && (
            <div style={{ display:'flex', gap:8, paddingTop:14, marginTop:14, borderTop:`1px solid ${T.border}` }}>
              <button onClick={handleClose}
                style={{ flex:1, padding:'10px', borderRadius:8, border:`1px solid ${T.border}`,
                  background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
                ⏸ Thoát
              </button>
              <button onClick={onFinish}
                style={{ flex:2, padding:'10px', borderRadius:8, border:'none',
                  background:`linear-gradient(135deg, ${T.green} 0%, #107035 100%)`, color:'#fff',
                  cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                ✓ Hoàn tất đóng hàng
              </button>
            </div>
          )}
        </>
      )}

      </div>

      {showImgModal && (
        <ProductImageModalV2 code={showImgModal} onClose={() => setShowImgModal(null)}/>
      )}

      {/* Preview ảnh đã nhặt — fullscreen, click để đóng */}
      {previewPhotoUrl && (
        <div onClick={() => setPreviewPhotoUrl(null)}
          style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.9)', zIndex:9999,
            display:'flex', alignItems:'center', justifyContent:'center', padding:20,
            cursor:'zoom-out' }}>
          <img src={previewPhotoUrl} alt="Preview"
            style={{ maxWidth:'100%', maxHeight:'100%', objectFit:'contain' }}/>
          <button onClick={e => { e.stopPropagation(); setPreviewPhotoUrl(null) }}
            style={{ position:'absolute', top:20, right:20, width:40, height:40,
              borderRadius:20, border:'none', background:'rgba(255,255,255,0.2)', color:'#fff',
              cursor:'pointer', fontSize:20, fontFamily:'inherit' }}>
            ✕
          </button>
        </div>
      )}
    </div>
  )
}

function PhotoSection({ title, subtitle, photos, min, max, readOnly, orderCode, photoType, onUpdate, userId }: any) {
  const [uploading, setUploading] = useState(false)
  const [previewIdx, setPreviewIdx] = useState<number|null>(null)
  const fileInputCameraRef = useRef<HTMLInputElement>(null)
  const fileInputGalleryRef = useRef<HTMLInputElement>(null)

  // Helper: normalize photo entry (string URL hoặc object {url, at, by})
  const getUrl = (p: any): string => typeof p === 'string' ? p : (p?.url || '')
  const getAt  = (p: any): string => typeof p === 'string' ? '' : (p?.at || '')

  const canAddMore = !readOnly && photos.length < max

  const handleFiles = async (files: FileList) => {
    if (!files || files.length === 0) return
    if (photos.length + files.length > max) {
      alert(`❌ Đã vượt số ảnh tối đa (${max}).`)
      return
    }
    setUploading(true)
    const newEntries: any[] = []
    try {
      for (const file of Array.from(files)) {
        const blob = await compressImageV2(file)
        const ts = Date.now()
        const idx = photos.length + newEntries.length
        const path = `${orderCode}/${photoType}_${ts}_${idx}.jpg`
        const { data, error } = await db.storage.from('packing-photos').upload(path, blob, {
          contentType: 'image/jpeg', upsert: false,
        })
        if (error) { alert('❌ Upload lỗi: ' + error.message); continue }
        const { data: urlData } = db.storage.from('packing-photos').getPublicUrl(data.path)
        newEntries.push({
          url: urlData.publicUrl,
          at: new Date().toISOString(),
          by: userId || '',
        })
      }
      const updated = [...photos, ...newEntries]
      await onUpdate(updated)
    } catch(e: any) {
      alert('❌ Lỗi: ' + e.message)
    } finally {
      setUploading(false)
      if (fileInputCameraRef.current)  fileInputCameraRef.current.value = ''
      if (fileInputGalleryRef.current) fileInputGalleryRef.current.value = ''
    }
  }

  const deletePhoto = async (idx: number) => {
    if (readOnly) return
    if (!confirm('Xóa ảnh này?')) return
    const url = getUrl(photos[idx])
    const pathMatch = url.match(/packing-photos\/(.+)$/)
    const path = pathMatch ? pathMatch[1] : null
    if (path) {
      await db.storage.from('packing-photos').remove([path])
    }
    const updated = photos.filter((_: any, i: number) => i !== idx)
    await onUpdate(updated)
  }

  const enough = photos.length >= min

  return (
    <div style={{ border:`1px solid ${enough?T.green:T.border}`, borderRadius:8, padding:12,
      background: enough ? T.greenBg : '#fff' }}>
      <div style={{ fontSize:12, fontWeight:700, color:T.dark, marginBottom:2 }}>{title}</div>
      <div style={{ fontSize:10, color:T.light, marginBottom:8 }}>{subtitle}</div>

      <div style={{ fontSize:11, color: enough ? T.green : T.amber, fontWeight:600, marginBottom:10 }}>
        📷 {photos.length} ảnh {enough && '✓'} {!enough && `(cần tối thiểu ${min})`}
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(90px, 1fr))',
        gap:8 }}>
        {photos.map((ph: any, i: number) => {
          const url = getUrl(ph)
          const at  = getAt(ph)
          return (
            <div key={i} style={{ position:'relative', borderRadius:6, overflow:'hidden',
              border:`1px solid ${T.border}`, cursor:'pointer' }}
              onClick={() => setPreviewIdx(i)}>
              <div style={{ aspectRatio:'1/1', overflow:'hidden' }}>
                <img src={url} alt={`Photo ${i+1}`}
                  style={{ width:'100%', height:'100%', objectFit:'cover', display:'block' }}/>
              </div>
              {at && (
                <div style={{ fontSize:8, color:T.light, padding:'3px 4px', background:T.bg,
                  textAlign:'center', lineHeight:1.2 }}>
                  {new Date(at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})}
                  {' '}
                  {new Date(at).toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'})}
                </div>
              )}
              {!readOnly && (
                <button onClick={e => { e.stopPropagation(); deletePhoto(i) }}
                  style={{ position:'absolute', top:2, right:2, width:20, height:20,
                    borderRadius:10, border:'none', background:'rgba(185,28,28,0.9)', color:'#fff',
                    cursor:'pointer', fontSize:10, fontFamily:'inherit', padding:0, lineHeight:'20px' }}>
                  ×
                </button>
              )}
            </div>
          )
        })}

        {/* Nút upload: tách camera và thư viện */}
        {canAddMore && (
          <>
            {/* 📷 Chụp ảnh (mở camera) */}
            <label style={{ display:'flex', alignItems:'center', justifyContent:'center',
              aspectRatio:'1/1', borderRadius:6,
              border:`2px dashed ${T.gold}`, background:T.goldBg,
              cursor:uploading?'wait':'pointer',
              color:T.goldText, fontSize:10, fontWeight:600,
              textAlign:'center', flexDirection:'column', gap:2 }}>
              {uploading ? '⏳' : <>
                <span style={{ fontSize:18 }}>📷</span>
                <span>Chụp ảnh</span>
              </>}
              <input ref={fileInputCameraRef} type="file" accept="image/*"
                capture="environment"
                onChange={e => e.target.files && handleFiles(e.target.files)}
                disabled={uploading} style={{ display:'none' }}/>
            </label>

            {/* 🖼 Chọn từ thư viện (multi-select, không mở camera) */}
            <label style={{ display:'flex', alignItems:'center', justifyContent:'center',
              aspectRatio:'1/1', borderRadius:6,
              border:`2px dashed ${T.blue||'#3b82f6'}`, background:'#eff6ff',
              cursor:uploading?'wait':'pointer',
              color:T.blue||'#3b82f6', fontSize:10, fontWeight:600,
              textAlign:'center', flexDirection:'column', gap:2 }}>
              {uploading ? '⏳' : <>
                <span style={{ fontSize:18 }}>🖼</span>
                <span>Thư viện</span>
              </>}
              <input ref={fileInputGalleryRef} type="file" accept="image/*"
                multiple
                onChange={e => e.target.files && handleFiles(e.target.files)}
                disabled={uploading} style={{ display:'none' }}/>
            </label>
          </>
        )}
      </div>

      {previewIdx !== null && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.9)', zIndex:9999,
          display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
          onClick={() => setPreviewIdx(null)}>
          <div style={{ position:'relative', maxWidth:'100%', maxHeight:'100%' }}
            onClick={e => e.stopPropagation()}>
            <button onClick={() => setPreviewIdx(null)}
              style={{ position:'absolute', top:10, right:10, width:36, height:36,
                borderRadius:18, border:'none', background:'rgba(255,255,255,0.9)', color:T.dark,
                cursor:'pointer', fontSize:18, fontFamily:'inherit' }}>×</button>
            <img src={getUrl(photos[previewIdx])} alt={`Photo ${previewIdx+1}`}
              style={{ maxWidth:'90vw', maxHeight:'90vh', borderRadius:8 }}/>
            {getAt(photos[previewIdx]) && (
              <div style={{ position:'absolute', bottom:10, left:'50%', transform:'translateX(-50%)',
                background:'rgba(0,0,0,0.7)', color:'#fff', padding:'4px 14px', borderRadius:20, fontSize:11 }}>
                🕒 Chụp lúc {new Date(getAt(photos[previewIdx])).toLocaleString('vi-VN')}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  )
}


// ══════════════════════════════════════════════════════════════════════
// ══ PERSONAL NOTES MODULE — Ghi chú cá nhân ══════════════════════════
// ══════════════════════════════════════════════════════════════════════
function PersonalNotesModule({ user, mobile }: any) {
  const p = mobile ? '16px' : '24px'
  const [notes, setNotes] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [searchQ, setSearchQ] = useState('')
  const [editingId, setEditingId] = useState<string|null>(null)
  const [showNew, setShowNew] = useState(false)

  // Note colors
  const COLORS: any = {
    default: { bg:'#FFFFFF',  border:T.border, name:'Trắng' },
    yellow:  { bg:'#FFF8E8',  border:'#E5CFA0', name:'Vàng' },
    green:   { bg:'#DCFCE7',  border:'#86EFAC', name:'Xanh lá' },
    blue:    { bg:'#DBEAFE',  border:'#93C5FD', name:'Xanh dương' },
    red:     { bg:'#FEE2E2',  border:'#FCA5A5', name:'Đỏ' },
  }

  // Fetch notes
  const fetchNotes = async () => {
    setLoading(true)
    const { data, error } = await db.from('personal_notes').select('*')
      .eq('user_id', user.id)
      .order('is_pinned', { ascending:false })
      .order('updated_at', { ascending:false })
    if (!error) setNotes(data || [])
    setLoading(false)
  }

  useEffect(() => { fetchNotes() }, [])

  // Fuzzy search (Vietnamese-aware)
  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()

  const filtered = (() => {
    const q = norm(searchQ)
    if (!q) return notes
    const tokens = q.split(/\s+/).filter(Boolean)
    return notes.filter((n: any) => {
      const text = norm(n.title + ' ' + n.content)
      return tokens.every(t => text.includes(t))
    })
  })()

  // Create new note
  const createNote = async () => {
    const id = `note_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
    const newNote = {
      id, user_id:user.id,
      title:'', content:'',
      is_pinned:false, color:'default',
      created_at:new Date().toISOString(),
      updated_at:new Date().toISOString(),
    }
    const { error } = await db.from('personal_notes').insert(newNote)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setNotes([newNote, ...notes])
    setEditingId(id)
    setShowNew(false)
  }

  // Save note
  const saveNote = async (id: string, updates: any) => {
    const upd = { ...updates, updated_at:new Date().toISOString() }
    const { error } = await db.from('personal_notes').update(upd).eq('id', id).eq('user_id', user.id)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setNotes(notes.map(n => n.id === id ? { ...n, ...upd } : n))
  }

  // Delete note
  const deleteNote = async (id: string) => {
    if (!confirm('Xoá ghi chú này?')) return
    const { error } = await db.from('personal_notes').delete().eq('id', id).eq('user_id', user.id)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setNotes(notes.filter(n => n.id !== id))
    if (editingId === id) setEditingId(null)
  }

  // Toggle pin
  const togglePin = async (id: string) => {
    const note = notes.find(n => n.id === id)
    if (!note) return
    await saveNote(id, { is_pinned: !note.is_pinned })
    // Resort after pin change
    fetchNotes()
  }

  const fmtDate = (iso: string) => {
    const d = new Date(iso)
    const today = new Date()
    const isToday = d.toDateString() === today.toDateString()
    if (isToday) return d.toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
    const diff = Math.floor((today.getTime() - d.getTime()) / 86400000)
    if (diff === 1) return 'Hôm qua'
    if (diff < 7) return `${diff} ngày trước`
    return d.toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit', year:'2-digit'})
  }

  return (
    <div style={{ padding:p }}>
      {/* Topbar */}
      <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:16, flexWrap:'wrap' }}>
        <div style={{ flex:1, minWidth:200 }}>
          <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:4 }}>
            <span style={{ color:T.gold, display:'flex', alignItems:'center' }}>
              {Ico.stickyNote(22)}
            </span>
            <h2 style={{ margin:0, fontSize:FS.xl, fontWeight:800, color:T.dark }}>
              Ghi chú cá nhân
            </h2>
          </div>
          <div style={{ fontSize:FS.sm, color:T.light }}>
            {loading ? 'Đang tải...' : `${notes.length} ghi chú${searchQ ? ` • ${filtered.length} kết quả` : ''}`}
          </div>
        </div>
        <button onClick={createNote}
          style={{ display:'flex', alignItems:'center', gap:6,
            padding:'10px 16px', borderRadius:RD.md, border:'none',
            background:T.gold, color:'#fff', cursor:'pointer',
            fontFamily:'inherit', fontSize:FS.md, fontWeight:600,
            boxShadow:'0 2px 8px rgba(196,151,58,0.3)' }}>
          {Ico.plus(16)}
          <span>Thêm ghi chú</span>
        </button>
      </div>

      {/* Search */}
      <div style={{ position:'relative', marginBottom:16 }}>
        <span style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)',
          color:T.light, display:'flex', alignItems:'center' }}>
          {Ico.search(16)}
        </span>
        <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
          placeholder="Tìm trong ghi chú..."
          style={{ width:'100%', padding:'10px 12px 10px 38px',
            borderRadius:RD.md, border:`1px solid ${T.border}`,
            fontSize:FS.md, fontFamily:'inherit', outline:'none',
            background:'#fff', color:T.dark, boxSizing:'border-box' }}/>
      </div>

      {/* Notes grid */}
      {loading ? (
        <div style={{ textAlign:'center', padding:40, color:T.light, fontSize:FS.md }}>
          ⏳ Đang tải...
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign:'center', padding:'60px 20px', color:T.light }}>
          <div style={{ display:'inline-flex', marginBottom:12, color:T.light }}>
            {Ico.stickyNote(48)}
          </div>
          <div style={{ fontSize:FS.md, marginBottom:6 }}>
            {searchQ ? 'Không tìm thấy ghi chú nào.' : 'Chưa có ghi chú nào.'}
          </div>
          {!searchQ && (
            <button onClick={createNote}
              style={{ marginTop:12, padding:'8px 16px', borderRadius:RD.md,
                border:`1.5px solid ${T.gold}`, background:T.goldBg, color:T.goldText,
                cursor:'pointer', fontFamily:'inherit', fontSize:FS.sm, fontWeight:600 }}>
              + Tạo ghi chú đầu tiên
            </button>
          )}
        </div>
      ) : (
        <div style={{ display:'grid',
          gridTemplateColumns: mobile ? '1fr' : 'repeat(auto-fill, minmax(260px, 1fr))',
          gap:12 }}>
          {filtered.map((n: any) => {
            const isEditing = editingId === n.id
            const color = COLORS[n.color] || COLORS.default
            return (
              <NoteCard key={n.id} note={n} color={color} isEditing={isEditing}
                mobile={mobile}
                onStartEdit={() => setEditingId(n.id)}
                onStopEdit={() => setEditingId(null)}
                onSave={(updates: any) => saveNote(n.id, updates)}
                onDelete={() => deleteNote(n.id)}
                onTogglePin={() => togglePin(n.id)}
                fmtDate={fmtDate}
                colors={COLORS}/>
            )
          })}
        </div>
      )}
    </div>
  )
}

// Individual note card with view/edit state
function NoteCard({ note, color, isEditing, mobile, onStartEdit, onStopEdit, onSave, onDelete, onTogglePin, fmtDate, colors }: any) {
  const [title, setTitle] = useState(note.title || '')
  const [content, setContent] = useState(note.content || '')
  const [showColorPicker, setShowColorPicker] = useState(false)

  // Sync local state when entering edit mode
  useEffect(() => {
    if (isEditing) {
      setTitle(note.title || '')
      setContent(note.content || '')
    }
  }, [isEditing])

  const handleSave = () => {
    if (title !== note.title || content !== note.content) {
      onSave({ title, content })
    }
    onStopEdit()
  }

  const setColor = (c: string) => {
    onSave({ color: c })
    setShowColorPicker(false)
  }

  if (isEditing) {
    return (
      <div style={{ background:color.bg, border:`2px solid ${T.gold}`,
        borderRadius:RD.lg, padding:12, boxShadow:'0 4px 12px rgba(0,0,0,0.1)',
        display:'flex', flexDirection:'column', minHeight:200 }}>
        <input value={title} onChange={e => setTitle(e.target.value)}
          placeholder="Tiêu đề..."
          autoFocus
          style={{ border:'none', background:'transparent',
            fontSize:FS.lg, fontWeight:700, color:T.dark,
            fontFamily:'inherit', outline:'none', marginBottom:8,
            padding:'4px 0', width:'100%', boxSizing:'border-box' }}/>
        <textarea value={content} onChange={e => setContent(e.target.value)}
          placeholder="Nội dung..."
          style={{ flex:1, border:'none', background:'transparent',
            fontSize:FS.md, color:T.dark, fontFamily:'inherit',
            outline:'none', resize:'none', minHeight:100, width:'100%',
            padding:'4px 0', boxSizing:'border-box', lineHeight:1.5 }}/>

        {/* Color picker */}
        {showColorPicker && (
          <div style={{ display:'flex', gap:6, margin:'8px 0',
            padding:8, background:'#fff', borderRadius:RD.md,
            border:`1px solid ${T.border}` }}>
            {Object.entries(colors).map(([key, c]: any) => (
              <button key={key} onClick={() => setColor(key)}
                title={c.name}
                style={{ width:22, height:22, borderRadius:'50%',
                  border: note.color === key ? `2px solid ${T.gold}` : `1px solid ${c.border}`,
                  background:c.bg, cursor:'pointer', padding:0 }}/>
            ))}
          </div>
        )}

        {/* Toolbar */}
        <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:8,
          paddingTop:8, borderTop:`1px solid ${color.border}` }}>
          <button onClick={() => setShowColorPicker(!showColorPicker)}
            title="Đổi màu"
            style={{ padding:6, border:'none', background:'transparent',
              cursor:'pointer', color:T.med, borderRadius:RD.sm,
              display:'flex', alignItems:'center' }}>
            <div style={{ width:16, height:16, borderRadius:'50%',
              background:color.bg, border:`1.5px solid ${color.border}` }}/>
          </button>
          <button onClick={onTogglePin}
            title={note.is_pinned ? 'Bỏ ghim' : 'Ghim lên đầu'}
            style={{ padding:6, border:'none', background:'transparent',
              cursor:'pointer', color: note.is_pinned ? T.gold : T.med,
              borderRadius:RD.sm, display:'flex', alignItems:'center' }}>
            {Ico.pin(16)}
          </button>
          <button onClick={onDelete}
            title="Xoá"
            style={{ padding:6, border:'none', background:'transparent',
              cursor:'pointer', color:T.red, borderRadius:RD.sm,
              display:'flex', alignItems:'center' }}>
            {Ico.trash(16)}
          </button>
          <div style={{ flex:1 }}/>
          <button onClick={handleSave}
            style={{ padding:'6px 14px', borderRadius:RD.md, border:'none',
              background:T.gold, color:'#fff', cursor:'pointer',
              fontFamily:'inherit', fontSize:FS.sm, fontWeight:600 }}>
            Xong
          </button>
        </div>
      </div>
    )
  }

  // View mode
  return (
    <div onClick={onStartEdit}
      style={{ background:color.bg, border:`1px solid ${color.border}`,
        borderRadius:RD.lg, padding:12, cursor:'pointer',
        transition:'all .15s', display:'flex', flexDirection:'column',
        minHeight:120, position:'relative' }}
      onMouseEnter={e => (e.currentTarget.style.transform = 'translateY(-2px)',
                          e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.08)')}
      onMouseLeave={e => (e.currentTarget.style.transform = '',
                          e.currentTarget.style.boxShadow = '')}>
      {note.is_pinned && (
        <div style={{ position:'absolute', top:8, right:8, color:T.gold,
          display:'flex', alignItems:'center' }}>
          {Ico.pin(14)}
        </div>
      )}
      {note.title && (
        <div style={{ fontSize:FS.md, fontWeight:700, color:T.dark,
          marginBottom:6, paddingRight: note.is_pinned ? 20 : 0,
          overflow:'hidden', textOverflow:'ellipsis',
          display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical' }}>
          {note.title}
        </div>
      )}
      {note.content && (
        <div style={{ fontSize:FS.sm, color:T.med, flex:1,
          whiteSpace:'pre-wrap', lineHeight:1.5,
          overflow:'hidden', textOverflow:'ellipsis',
          display:'-webkit-box', WebkitLineClamp:6, WebkitBoxOrient:'vertical' }}>
          {note.content}
        </div>
      )}
      {!note.title && !note.content && (
        <div style={{ fontSize:FS.sm, color:T.light, fontStyle:'italic' }}>
          (Ghi chú trống — nhấn để chỉnh sửa)
        </div>
      )}
      <div style={{ fontSize:FS.xs, color:T.light, marginTop:8,
        paddingTop:6, borderTop:`1px solid ${color.border}` }}>
        {fmtDate(note.updated_at)}
      </div>
    </div>
  )
}


// ══════════════════════════════════════════════════════════════════════
// ══ AUDIT LOG MODULE — Nhật ký hoạt động ═════════════════════════════
// ══════════════════════════════════════════════════════════════════════
function AuditLogModule({ user, allUsers, mobile }: any) {
  const perm = getPerm(user)
  const p = mobile ? '16px' : '24px'
  const [logs, setLogs]       = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [filterUser, setFilterUser]   = useState<string>('')
  const [filterTable, setFilterTable] = useState<string>('')
  const [filterAction, setFilterAction] = useState<string>('')
  const [dayRange, setDayRange] = useState(30)
  const [expandedLog, setExpandedLog] = useState<string|null>(null)
  const [showRestoreModal, setShowRestoreModal] = useState<any>(null)

  if (!perm.viewAuditLog) {
    return (
      <div style={{ padding:p, textAlign:'center', color:T.light, marginTop:40 }}>
        <div style={{ fontSize:48, marginBottom:10 }}>🔒</div>
        <div style={{ fontSize:14 }}>Bạn không có quyền xem nhật ký hoạt động.</div>
      </div>
    )
  }

  const fetchLogs = async () => {
    setLoading(true)
    const fromDate = new Date(Date.now() - dayRange * 86400000).toISOString()
    const { data } = await db.from('audit_log').select('*')
      .gte('created_at', fromDate)
      .order('created_at', { ascending: false })
      .limit(1000)
    setLogs(data||[])
    setLoading(false)
  }

  useEffect(() => { fetchLogs() }, [dayRange])

  const filtered = logs.filter((l: any) => {
    if (filterUser && l.user_id !== filterUser) return false
    if (filterTable && l.table_name !== filterTable) return false
    if (filterAction && l.action !== filterAction) return false
    return true
  })

  // Unique values for filter dropdowns
  const uniqueUsers  = [...new Set(logs.map((l: any) => l.user_id))]
  const uniqueTables = [...new Set(logs.map((l: any) => l.table_name))]
  const uniqueActions = [...new Set(logs.map((l: any) => l.action))]
  const getUserName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || id

  // Restore snapshot (cho inventory_sessions bulk_delete)
  const handleRestore = async (log: any) => {
    const snap = log.record_snapshot
    if (!snap) { alert('Không có snapshot để restore.'); return }
    try {
      if (log.table_name === 'inventory_sessions' && snap.session && Array.isArray(snap.checks)) {
        // Restore session + checks
        const sessExists = await db.from('inventory_sessions').select('id').eq('id', snap.session.id).maybeSingle()
        if (sessExists.data) {
          if (!confirm('Phiên KK này đã tồn tại lại. Overwrite không?')) return
        }
        await db.from('inventory_sessions').upsert(snap.session)
        if (snap.checks.length > 0) {
          // Chunked insert để tránh payload quá lớn
          const chunks = []
          for (let i = 0; i < snap.checks.length; i += 500) {
            chunks.push(snap.checks.slice(i, i+500))
          }
          for (const chunk of chunks) {
            await db.from('inventory_checks').upsert(chunk)
          }
        }
        await logAudit({
          user, action: 'restore', table: log.table_name,
          recordId: snap.session.id, snapshot: snap,
          note: `Restore phiên KK ${snap.session.date} từ audit log ${log.id}`,
        })
        alert(`✅ Đã restore phiên KK ngày ${snap.session.date} với ${snap.checks.length} bản ghi`)
      } else if (log.table_name && log.record_id) {
        // Generic restore 1 record
        await db.from(log.table_name).upsert(snap)
        await logAudit({
          user, action: 'restore', table: log.table_name,
          recordId: log.record_id, note: `Restore từ audit log ${log.id}`,
        })
        alert('✅ Đã restore record')
      }
      setShowRestoreModal(null)
      fetchLogs()
    } catch (e: any) {
      alert('❌ Lỗi restore: ' + e.message)
    }
  }

  const actionLabel = (a: string) => ({
    'delete': '🗑️ Xóa', 'bulk_delete': '🗑️ Xóa hàng loạt',
    'update_critical': '✏️ Sửa quan trọng', 'restore': '♻️ Khôi phục',
  } as any)[a] || a

  const tableLabel = (t: string) => ({
    'inventory_sessions': 'Phiên kiểm kê',
    'inventory_checks': 'Bản ghi KK',
    'positions': 'Vị trí',
    'payment_orders': 'Lệnh CK',
    'wrong_orders': 'Đơn sai',
    'return_items': 'Phiếu hoàn',
    'shortage_items': 'Hàng thiếu',
    'users': 'NV',
    'packing_workflow': 'Đơn nhặt/đóng',
  } as any)[t] || t

  if (loading) return <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>⏳ Đang tải...</div>

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="📜 Nhật ký hoạt động"
        subtitle={`${filtered.length}/${logs.length} hành động trong ${dayRange} ngày`}
        action={
          <button onClick={fetchLogs}
            style={{ padding:'5px 12px', borderRadius:20, border:`1px solid ${T.border}`,
              background:'transparent', cursor:'pointer', fontFamily:'inherit', fontSize:11, color:T.med }}>
            🔄 Refresh
          </button>
        }/>

      {/* Filters */}
      <Card style={{ padding:12, marginBottom:12 }}>
        <div style={{ display:'grid', gridTemplateColumns: mobile?'1fr 1fr':'repeat(4, 1fr)', gap:8 }}>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>NV</label>
            <select value={filterUser} onChange={e => setFilterUser(e.target.value)}
              style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value="">Tất cả</option>
              {uniqueUsers.map((uid: string) => (
                <option key={uid} value={uid}>{getUserName(uid)}</option>
              ))}
            </select>
          </div>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>Bảng</label>
            <select value={filterTable} onChange={e => setFilterTable(e.target.value)}
              style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value="">Tất cả</option>
              {uniqueTables.map((t: string) => (
                <option key={t} value={t}>{tableLabel(t)}</option>
              ))}
            </select>
          </div>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>Hành động</label>
            <select value={filterAction} onChange={e => setFilterAction(e.target.value)}
              style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value="">Tất cả</option>
              {uniqueActions.map((a: string) => (
                <option key={a} value={a}>{actionLabel(a)}</option>
              ))}
            </select>
          </div>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>Khoảng thời gian</label>
            <select value={dayRange} onChange={e => setDayRange(Number(e.target.value))}
              style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value={7}>7 ngày</option>
              <option value={30}>30 ngày</option>
              <option value={90}>90 ngày</option>
              <option value={365}>1 năm</option>
            </select>
          </div>
        </div>
      </Card>

      {/* List */}
      {filtered.length === 0 ? (
        <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
          Không có hoạt động nào phù hợp filter.
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
          {filtered.map((log: any) => {
            const expanded = expandedLog === log.id
            const isDestruct = ['delete','bulk_delete'].includes(log.action)
            return (
              <Card key={log.id} style={{ padding:10, cursor:'pointer',
                borderLeft: isDestruct ? `3px solid ${T.red}` : `3px solid ${T.blue}`,
                background: expanded ? T.bg : '#fff' }}
                onClick={() => setExpandedLog(expanded ? null : log.id)}>
                <div style={{ display:'flex', alignItems:'flex-start', gap:10 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:12, fontWeight:600, color:T.dark }}>
                      {actionLabel(log.action)} • {tableLabel(log.table_name)}
                      {log.record_id && <span style={{ color:T.light, fontWeight:400, marginLeft:6 }}>#{log.record_id.slice(0,20)}</span>}
                    </div>
                    <div style={{ fontSize:11, color:T.med, marginTop:2 }}>
                      <b>{log.user_name || getUserName(log.user_id)}</b> • {new Date(log.created_at).toLocaleString('vi-VN')}
                    </div>
                    {log.note && (
                      <div style={{ fontSize:11, color:T.light, marginTop:3, fontStyle:'italic' }}>
                        {log.note}
                      </div>
                    )}
                  </div>
                  {isDestruct && log.record_snapshot && (
                    <button onClick={e => { e.stopPropagation(); setShowRestoreModal(log) }}
                      style={{ padding:'4px 10px', borderRadius:20, border:`1px solid ${T.green}`,
                        background:T.greenBg, color:T.green, cursor:'pointer', fontFamily:'inherit',
                        fontSize:10, fontWeight:600, flexShrink:0 }}>
                      ♻️ Restore
                    </button>
                  )}
                </div>
                {expanded && log.record_snapshot && (
                  <div style={{ marginTop:10, padding:10, background:T.bg, borderRadius:6,
                    fontSize:10, fontFamily:'monospace', color:T.med, maxHeight:300, overflow:'auto',
                    border:`1px solid ${T.border}` }}>
                    <pre style={{ margin:0, whiteSpace:'pre-wrap', wordBreak:'break-all' }}>
                      {JSON.stringify(log.record_snapshot, null, 2)}
                    </pre>
                  </div>
                )}
              </Card>
            )
          })}
        </div>
      )}

      {/* Restore modal */}
      {showRestoreModal && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:9999,
          display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:12, padding:20, maxWidth:500, width:'100%',
            border:`2px solid ${T.green}` }}>
            <div style={{ fontSize:15, fontWeight:700, color:T.green, marginBottom:6 }}>
              ♻️ Khôi phục dữ liệu
            </div>
            <div style={{ fontSize:13, color:T.dark, marginBottom:10, lineHeight:1.5 }}>
              Bạn sắp khôi phục {tableLabel(showRestoreModal.table_name)} đã bị xóa bởi <b>{showRestoreModal.user_name}</b>.
            </div>
            <div style={{ padding:'8px 10px', background:T.bg, borderRadius:6, marginBottom:14,
              fontSize:11, color:T.med, border:`1px solid ${T.border}` }}>
              {showRestoreModal.note}
            </div>
            <div style={{ fontSize:11, color:T.amber, fontWeight:600, marginBottom:14 }}>
              ⚠️ Nếu dữ liệu đã được tạo lại từ sau thời điểm xóa, restore có thể ghi đè. Hãy xem xét kỹ.
            </div>
            <div style={{ display:'flex', gap:10 }}>
              <button onClick={() => setShowRestoreModal(null)}
                style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
                  background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
                Hủy
              </button>
              <button onClick={() => handleRestore(showRestoreModal)}
                style={{ flex:1, padding:'9px', borderRadius:6, border:'none',
                  background:T.green, color:'#fff', cursor:'pointer', fontFamily:'inherit',
                  fontSize:13, fontWeight:700 }}>
                ♻️ Khôi phục
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ PRIORITY REQUEST — Báo ưu tiên từ Sale → Kho =====================
// ══════════════════════════════════════════════════════════════════════

// Banner nhấp nháy khi có phiếu ưu tiên chưa acknowledge (cho Kho)
function PriorityAlertBanner({ user, onOpen }: any) {
  const perm = getPerm(user)
  const [pending, setPending] = useState<any[]>([])
  const [seenAlertIds, setSeenAlertIds] = useState<Set<string>>(new Set())

  const fetchPending = async () => {
    const { data } = await db.from('priority_requests').select('*')
      .eq('status', 'pending').order('submitted_at', { ascending: true })
    setPending(data || [])
  }

  useEffect(() => {
    if (!perm.handlePriority) return
    fetchPending()
    const interval = setInterval(fetchPending, 15000) // poll 15s
    return () => clearInterval(interval)
  }, [perm.handlePriority])

  // Play sound khi có request mới
  useEffect(() => {
    if (!perm.handlePriority || pending.length === 0) return
    const newOnes = pending.filter(p => !seenAlertIds.has(p.id))
    if (newOnes.length > 0) {
      // Simple beep via Web Audio API
      try {
        const AC = (window as any).AudioContext || (window as any).webkitAudioContext
        if (AC) {
          const ctx = new AC()
          const o = ctx.createOscillator(), g = ctx.createGain()
          o.connect(g); g.connect(ctx.destination)
          o.frequency.value = 800; o.type = 'sine'
          g.gain.setValueAtTime(0.2, ctx.currentTime)
          g.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5)
          o.start(); o.stop(ctx.currentTime + 0.5)
        }
      } catch {}
      setSeenAlertIds(new Set(pending.map(p => p.id)))
    }
  }, [pending, perm.handlePriority])

  if (!perm.handlePriority || pending.length === 0) return null

  return (
    <>
      <style>{`
        @keyframes pulseRed {
          0%, 100% { box-shadow: 0 0 0 0 rgba(185,28,28,0.6); }
          50% { box-shadow: 0 0 0 12px rgba(185,28,28,0); }
        }
      `}</style>
      <div onClick={onOpen}
        style={{ position:'sticky', top:0, zIndex:500, cursor:'pointer',
          background:`linear-gradient(90deg, #dc2626 0%, #b91c1c 50%, #dc2626 100%)`,
          color:'#fff', padding:'12px 20px', display:'flex', alignItems:'center', gap:12,
          animation:'pulseRed 1.5s infinite', borderBottom:'2px solid #7f1d1d' }}>
        <div style={{ fontSize:24, animation:'pulseRed 1s infinite' }}>🚨</div>
        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ fontSize:14, fontWeight:800, letterSpacing:.5 }}>
            CÓ {pending.length} PHIẾU ƯU TIÊN MỚI — CẦN XỬ LÝ NGAY
          </div>
          <div style={{ fontSize:11, opacity:0.9, whiteSpace:'nowrap', overflow:'hidden',
            textOverflow:'ellipsis', marginTop:2 }}>
            {pending.slice(0, 2).map(p => `${p.from_user_name}: ${p.content?.slice(0,40)}`).join(' • ')}
            {pending.length > 2 && ` • và ${pending.length - 2} phiếu nữa`}
          </div>
        </div>
        <div style={{ padding:'6px 14px', background:'rgba(255,255,255,0.2)', borderRadius:20,
          fontSize:12, fontWeight:700, border:'1px solid rgba(255,255,255,0.4)' }}>
          Mở ngay →
        </div>
      </div>
    </>
  )
}

// Modal hiển thị danh sách phiếu ưu tiên pending (cho Kho) — bắt buộc ack từng phiếu
function PriorityAckModal({ user, onClose }: any) {
  const [pending, setPending] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [ackingId, setAckingId] = useState<string|null>(null)

  const fetchPending = async () => {
    setLoading(true)
    const { data } = await db.from('priority_requests').select('*')
      .eq('status', 'pending').order('submitted_at', { ascending: true })
    setPending(data || [])
    setLoading(false)
  }

  useEffect(() => { fetchPending() }, [])

  const acknowledge = async (req: any) => {
    setAckingId(req.id)
    const upd = {
      status: 'acknowledged',
      acknowledged_by: user.id,
      acknowledged_by_name: user.name || user.ini,
      acknowledged_at: new Date().toISOString(),
    }
    const { error } = await db.from('priority_requests').update(upd).eq('id', req.id)
    setAckingId(null)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    setPending(prev => prev.filter(p => p.id !== req.id))
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:560, width:'100%',
        maxHeight:'90vh', overflow:'auto', border:`2px solid ${T.red}` }}>
        <div style={{ padding:'14px 20px', background:T.red, color:'#fff',
          display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div style={{ fontSize:15, fontWeight:800 }}>🚨 Phiếu ưu tiên chờ xử lý ({pending.length})</div>
          <button onClick={onClose}
            style={{ background:'transparent', border:'none', color:'#fff', cursor:'pointer',
              fontSize:22, padding:0, lineHeight:1 }}>
            ×
          </button>
        </div>

        <div style={{ padding:20 }}>
          {loading && <div style={{ textAlign:'center', color:T.light }}>⏳ Đang tải...</div>}
          {!loading && pending.length === 0 && (
            <div style={{ textAlign:'center', padding:30, color:T.green, fontWeight:600, fontSize:14 }}>
              ✅ Không còn phiếu ưu tiên nào chờ xử lý!
            </div>
          )}
          {!loading && pending.map((req: any) => {
            const minutesAgo = Math.floor((Date.now() - new Date(req.submitted_at).getTime()) / 60000)
            return (
              <div key={req.id} style={{ padding:14, marginBottom:10, borderRadius:8,
                background: minutesAgo > 15 ? '#fef2f2' : T.bg,
                border:`2px solid ${minutesAgo > 15 ? T.red : T.amber}` }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:6 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:T.dark }}>
                    👤 {req.from_user_name}
                  </div>
                  <div style={{ fontSize:11,
                    color: minutesAgo > 15 ? T.red : T.amber, fontWeight:600 }}>
                    ⏱ {minutesAgo} phút trước
                  </div>
                </div>
                <div style={{ fontSize:13, color:T.dark, lineHeight:1.5, marginBottom:10,
                  padding:'8px 10px', background:'#fff', borderRadius:6,
                  border:`1px solid ${T.border}`, whiteSpace:'pre-wrap' }}>
                  {req.content}
                </div>
                <div style={{ fontSize:10, color:T.light, marginBottom:10 }}>
                  🕒 Gửi lúc: {new Date(req.submitted_at).toLocaleString('vi-VN')}
                </div>
                <button onClick={() => acknowledge(req)} disabled={ackingId === req.id}
                  style={{ width:'100%', padding:'10px', borderRadius:6, border:'none',
                    background: ackingId === req.id ? T.border :
                      `linear-gradient(135deg, ${T.green} 0%, #107035 100%)`,
                    color:'#fff', cursor: ackingId === req.id ? 'wait' : 'pointer',
                    fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                  {ackingId === req.id ? '⏳ Đang xác nhận...' : '✓ Xác nhận đã nhận — tôi sẽ xử lý'}
                </button>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

// Modal form submit phiếu ưu tiên (cho Sale)
function PrioritySubmitModal({ user, onClose, onSubmitted }: any) {
  const [content, setContent] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const submit = async () => {
    if (!content.trim()) { alert('Vui lòng nhập nội dung'); return }
    setSubmitting(true)
    const req = {
      id: `pri_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
      from_user_id: user.id,
      from_user_name: user.name || user.ini,
      content: content.trim(),
      submitted_at: new Date().toISOString(),
      status: 'pending',
      created_at: new Date().toISOString(),
    }
    const { error } = await db.from('priority_requests').insert(req)
    setSubmitting(false)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    alert('✅ Đã gửi phiếu ưu tiên! Kho sẽ nhận thông báo ngay.')
    setContent('')
    onSubmitted && onSubmitted(req)
    onClose()
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:480, width:'100%',
        border:`2px solid ${T.red}`, overflow:'hidden' }}>
        <div style={{ padding:'14px 20px', background:T.red, color:'#fff' }}>
          <div style={{ fontSize:15, fontWeight:800 }}>🚨 Gửi phiếu ưu tiên cho Kho</div>
          <div style={{ fontSize:11, opacity:0.9, marginTop:3 }}>
            Phiếu này sẽ hiện banner khẩn cấp trên màn hình Kho — chỉ dùng khi cần hỗ trợ gấp
          </div>
        </div>
        <div style={{ padding:20 }}>
          <label style={{ fontSize:12, color:T.med, fontWeight:600, display:'block', marginBottom:6 }}>
            Nội dung phiếu ưu tiên *
          </label>
          <textarea value={content} onChange={e => setContent(e.target.value)} autoFocus rows={5}
            placeholder="VD: Sửa đơn DH007732, thêm 1 SP X cho KH, khách chờ ngoài cửa hàng..."
            style={{ width:'100%', padding:'10px 12px', border:`1px solid ${T.border}`, borderRadius:6,
              fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
              boxSizing:'border-box' as any, resize:'vertical', marginBottom:14 }}/>

          <div style={{ padding:'8px 12px', background:T.amberBg, border:`1px solid ${T.amber}`,
            borderRadius:6, fontSize:11, color:T.amber, fontWeight:600, marginBottom:14 }}>
            ⚠️ Cả thao tác gửi và xác nhận đều được lưu timestamp. Hãy dùng đúng mục đích.
          </div>

          <div style={{ display:'flex', gap:10 }}>
            <button onClick={onClose}
              style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
              Hủy
            </button>
            <button onClick={submit} disabled={!content.trim() || submitting}
              style={{ flex:2, padding:'9px', borderRadius:6, border:'none',
                background: content.trim() && !submitting ? T.red : T.border,
                color: content.trim() ? '#fff' : T.light,
                cursor: content.trim() && !submitting ? 'pointer' : 'not-allowed',
                fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              {submitting ? '⏳ Đang gửi...' : '🚨 Gửi phiếu ưu tiên'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// Trang quản lý phiếu ưu tiên (dành cho cả Sale và Kho để xem lịch sử)
function PriorityRequestModule({ user, allUsers, mobile }: any) {
  const perm = getPerm(user)
  const canSubmit = perm.submitPriority
  const canHandle = perm.handlePriority
  const isAdmin = perm.viewAllDashboard
  const p = mobile ? '16px' : '24px'

  const [requests, setRequests] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [tab, setTab] = useState<'pending'|'acknowledged'|'mine'>('pending')
  const [showSubmit, setShowSubmit] = useState(false)
  const [searchQ, setSearchQ] = useState('')

  const fetchData = async (isInitial = false) => {
    if (isInitial) setLoading(true)
    const { data } = await db.from('priority_requests').select('*')
      .order('created_at', { ascending: false })
      .limit(500)
    setRequests(data || [])
    if (isInitial) setLoading(false)
  }

  useEffect(() => {
    fetchData(true)
  }, [])

  // Auto-refresh mỗi 20s — PAUSE khi đang mở modal submit (user đang gõ nội dung)
  useEffect(() => {
    if (showSubmit) return
    const interval = setInterval(() => fetchData(false), 20000)
    return () => clearInterval(interval)
  }, [showSubmit])

  // Fuzzy search theo nội dung, tên người gửi
  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const filterByQ = (list: any[]) => {
    const q = norm(searchQ)
    if (!q) return list
    const tokens = q.split(/\s+/).filter(Boolean)
    return list.filter((r: any) => {
      const hay = norm(`${r.content||''} ${r.from_user_name||''} ${r.acknowledged_by_name||''}`)
      return tokens.every(t => hay.includes(t))
    })
  }

  const pendingList = filterByQ(requests.filter(r => r.status === 'pending'))
  const ackList     = filterByQ(requests.filter(r => r.status === 'acknowledged'))
  const myList      = filterByQ(requests.filter(r => r.from_user_id === user.id))
  const displayList =
    tab === 'pending'      ? pendingList :
    tab === 'acknowledged' ? ackList : myList

  const acknowledge = async (req: any) => {
    const upd = {
      status: 'acknowledged',
      acknowledged_by: user.id,
      acknowledged_by_name: user.name || user.ini,
      acknowledged_at: new Date().toISOString(),
    }
    const { error } = await db.from('priority_requests').update(upd).eq('id', req.id)
    if (error) { alert('❌ Lỗi: ' + error.message); return }
    fetchData()
  }

  if (loading) return <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>⏳ Đang tải...</div>

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="🚨 Phiếu ưu tiên"
        subtitle={`${pendingList.length} đang chờ xử lý • ${ackList.length} đã xác nhận`}
        action={
          canSubmit ? (
            <button onClick={() => setShowSubmit(true)}
              style={{ padding:'7px 14px', borderRadius:20, border:'none',
                background:T.red, color:'#fff', cursor:'pointer', fontFamily:'inherit',
                fontSize:12, fontWeight:700 }}>
              🚨 Gửi phiếu ưu tiên
            </button>
          ) : null
        }/>

      {/* Tabs */}
      <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
        {[
          { id:'pending',       label:`🚨 Chờ xử lý${pendingList.length?` (${pendingList.length})`:''}` },
          { id:'acknowledged',  label:`✓ Đã xác nhận${ackList.length?` (${ackList.length})`:''}` },
          { id:'mine',          label:`📤 Phiếu của tôi${myList.length?` (${myList.length})`:''}` },
        ].map((t: any) => (
          <button key={t.id} onClick={() => setTab(t.id as any)}
            style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${tab===t.id?T.red:T.border}`,
              background:tab===t.id?T.redBg:'transparent',
              color:tab===t.id?T.red:T.med, fontWeight:tab===t.id?700:400 }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Search — tìm theo nội dung, người gửi, người ack */}
      <Card style={{ padding:10, marginBottom:10 }}>
        <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
          placeholder="🔍 Tìm trong nội dung phiếu (VD: mã đơn, tên SP, tên KH, lý do...)"
          style={{ width:'100%', padding:'8px 12px', border:`1px solid ${T.border}`, borderRadius:8,
            fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any }}/>
        {searchQ.trim() && (
          <div style={{ fontSize:10, color:T.light, marginTop:6 }}>
            Tìm thấy {displayList.length} phiếu phù hợp
          </div>
        )}
      </Card>

      {/* List */}
      {displayList.length === 0 ? (
        <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
          {searchQ.trim() ? `Không có phiếu nào khớp "${searchQ}"` :
           tab==='pending' ? '✅ Không có phiếu nào chờ xử lý!' :
           tab==='acknowledged' ? 'Chưa có phiếu nào đã xác nhận.' :
           'Bạn chưa gửi phiếu nào.'}
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
          {displayList.map((req: any) => {
            const isPending = req.status === 'pending'
            const minutesAgo = Math.floor((Date.now() - new Date(req.submitted_at).getTime()) / 60000)
            return (
              <Card key={req.id} style={{ padding:14,
                borderLeft: `4px solid ${isPending ? T.red : T.green}` }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:10, marginBottom:8 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>
                      {isPending ? '🚨' : '✓'} {req.from_user_name}
                    </div>
                    <div style={{ fontSize:10, color:T.light, marginTop:2 }}>
                      📤 {new Date(req.submitted_at).toLocaleString('vi-VN')}
                      {isPending && <> • <span style={{ color:minutesAgo>15?T.red:T.amber, fontWeight:700 }}>{minutesAgo}p trước</span></>}
                    </div>
                  </div>
                  <div style={{ padding:'3px 10px', borderRadius:12,
                    background: isPending ? T.redBg : T.greenBg,
                    color: isPending ? T.red : T.green, fontSize:10, fontWeight:700 }}>
                    {isPending ? 'CHỜ XỬ LÝ' : 'ĐÃ XÁC NHẬN'}
                  </div>
                </div>
                <div style={{ fontSize:12, color:T.dark, lineHeight:1.5, padding:'8px 10px',
                  background:T.bg, borderRadius:6, border:`1px solid ${T.border}`,
                  whiteSpace:'pre-wrap', marginBottom:8 }}>
                  {req.content}
                </div>
                {req.acknowledged_at && (
                  <div style={{ fontSize:10, color:T.green, fontWeight:600 }}>
                    ✓ {req.acknowledged_by_name} xác nhận lúc {new Date(req.acknowledged_at).toLocaleString('vi-VN')}
                    {' '}(sau {Math.floor((new Date(req.acknowledged_at).getTime() - new Date(req.submitted_at).getTime())/60000)} phút)
                  </div>
                )}
                {isPending && canHandle && (
                  <button onClick={() => acknowledge(req)}
                    style={{ marginTop:8, width:'100%', padding:'8px', borderRadius:6, border:'none',
                      background:T.green, color:'#fff', cursor:'pointer',
                      fontFamily:'inherit', fontSize:12, fontWeight:700 }}>
                    ✓ Xác nhận đã nhận phiếu
                  </button>
                )}
              </Card>
            )
          })}
        </div>
      )}

      {showSubmit && (
        <PrioritySubmitModal user={user} onClose={() => setShowSubmit(false)}
          onSubmitted={() => fetchData()}/>
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ ORDER LOOKUP TAB — Tra cứu đơn theo sản phẩm + chia sẻ ảnh =======
// ══════════════════════════════════════════════════════════════════════

function OrderLookupTab({ user, allUsers, mobile }: any) {
  const [searchQ, setSearchQ] = useState('')
  const [dayRange, setDayRange] = useState(15)
  const [statusFilter, setStatusFilter] = useState<string>('all')
  const [allOrders, setAllOrders] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [expanded, setExpanded] = useState<string|null>(null)

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()

  const fetchOrders = async () => {
    setLoading(true)
    const fromDate = new Date(Date.now() - dayRange * 86400000).toISOString()
    const { data } = await db.from('packing_workflow').select('*')
      .gte('purchase_date', fromDate)
      .order('purchase_date', { ascending: false })
      .limit(1500)
    setAllOrders(data || [])
    setLoading(false)
  }

  useEffect(() => { fetchOrders() }, [dayRange])

  // Filter orders: phải có SP match query, + status filter
  const filtered = useMemo(() => {
    const q = norm(searchQ)
    if (!q.trim()) return []
    const tokens = q.split(/\s+/).filter(Boolean)
    return allOrders.filter((o: any) => {
      if (statusFilter !== 'all' && o.status !== statusFilter) return false
      const items = o.items || []
      return items.some((it: any) => {
        const hay = norm(`${it.code} ${it.name}`)
        return tokens.every(t => hay.includes(t))
      })
    })
  }, [searchQ, allOrders, statusFilter])

  const getName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || '—'
  const getUrl = (p: any): string => typeof p === 'string' ? p : (p?.url || '')
  const getAt  = (p: any): string => typeof p === 'string' ? '' : (p?.at || '')

  return (
    <div>
      {/* Filters */}
      <Card style={{ padding:12, marginBottom:12 }}>
        <input value={searchQ} onChange={e => setSearchQ(e.target.value)} autoFocus
          placeholder="🔍 Tên SP hoặc mã SP (VD: kyunglab, KCN, tay trang...)"
          style={{ width:'100%', padding:'10px 13px', border:`1px solid ${T.border}`, borderRadius:8,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any, marginBottom:10 }}/>
        <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>
              Khoảng thời gian
            </label>
            <select value={dayRange} onChange={e => setDayRange(Number(e.target.value))}
              style={{ padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value={3}>3 ngày</option>
              <option value={7}>7 ngày</option>
              <option value={15}>15 ngày</option>
              <option value={30}>30 ngày</option>
            </select>
          </div>
          <div>
            <label style={{ fontSize:10, color:T.med, fontWeight:600, display:'block', marginBottom:3 }}>
              Trạng thái
            </label>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}
              style={{ padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:11, fontFamily:"inherit", background:"#fff", color:T.dark, outline:"none" }}>
              <option value="all">Tất cả</option>
              <option value="picking">Chờ nhặt</option>
              <option value="packing">Chờ đóng</option>
              <option value="done">Đã xong</option>
              <option value="cancelled">Đã huỷ</option>
            </select>
          </div>
        </div>
      </Card>

      {!searchQ.trim() && (
        <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
          🔍 Nhập tên hoặc mã SP để tra cứu đơn có chứa SP đó
        </div>
      )}

      {loading && (
        <div style={{ padding:'20px', textAlign:'center', color:T.light, fontSize:12 }}>
          ⏳ Đang tải...
        </div>
      )}

      {searchQ.trim() && !loading && (
        <>
          <div style={{ padding:'8px 12px', marginBottom:10, background:T.goldBg,
            borderRadius:6, fontSize:12, color:T.goldText, fontWeight:600 }}>
            Tìm thấy <b>{filtered.length}</b> đơn có chứa "{searchQ}" trong {dayRange} ngày
          </div>

          <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
            {filtered.map((o: any) => {
              const isExp = expanded === o.order_code
              const matchingItems = (o.items||[]).filter((it: any) => {
                const hay = norm(`${it.code} ${it.name}`)
                const tokens = norm(searchQ).split(/\s+/).filter(Boolean)
                return tokens.every(t => hay.includes(t))
              })
              const statusLabel = ({
                picking:'Chờ nhặt', packing:'Chờ đóng',
                done:'Đã xong', cancelled:'Đã huỷ'
              } as any)[o.status] || o.status
              const statusColor = ({
                picking:T.amber, packing:T.blue, done:T.green, cancelled:T.light
              } as any)[o.status] || T.light
              return (
                <Card key={o.order_code} style={{ padding:12, cursor:'pointer' }}
                  onClick={() => setExpanded(isExp ? null : o.order_code)}>
                  <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:10 }}>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:700, color:T.dark }}>
                        {o.order_code} • {o.customer_name}
                      </div>
                      <div style={{ fontSize:10, color:T.light, marginTop:3 }}>
                        Sale: {o.sold_by_name||'—'} • {new Date(o.purchase_date).toLocaleDateString('vi-VN')}
                        {o.packed_by && <> • Đóng: {getName(o.packed_by)}</>}
                      </div>
                      <div style={{ marginTop:5, fontSize:11, color:T.dark }}>
                        Match: {matchingItems.map((it: any) => `${it.qty}× ${it.name}`).join(', ')}
                      </div>
                    </div>
                    <div style={{ padding:'3px 10px', borderRadius:12,
                      background: statusColor + '22', color: statusColor,
                      fontSize:10, fontWeight:700, flexShrink:0 }}>
                      {statusLabel}
                    </div>
                  </div>

                  {isExp && (
                    <div style={{ marginTop:12, paddingTop:12, borderTop:`1px dashed ${T.border}` }}
                      onClick={e => e.stopPropagation()}>
                      {/* Metadata */}
                      <div style={{ fontSize:11, color:T.med, marginBottom:10, lineHeight:1.7 }}>
                        <div>💰 Tổng: <b style={{ color:T.dark }}>{Number(o.total_amount||0).toLocaleString('vi-VN')}</b></div>
                        {o.picked_at && <div>✓ Xong nhặt: <b style={{ color:T.dark }}>{new Date(o.picked_at).toLocaleString('vi-VN')}</b></div>}
                        {o.packed_at && <div>📮 Xong đóng: <b style={{ color:T.green }}>{new Date(o.packed_at).toLocaleString('vi-VN')}</b> • bởi {getName(o.packed_by)}</div>}
                        {o.no_box && <div style={{ color:T.amber, fontWeight:600 }}>📮 Đơn bookship (không đóng thùng)</div>}
                        {(o.modification_count||0) > 0 && <div style={{ color:T.amber, fontWeight:600 }}>📝 Đã sửa {o.modification_count} lần</div>}
                      </div>

                      {/* Full items list */}
                      <div style={{ marginBottom:10, padding:10, background:T.bg, borderRadius:6,
                        border:`1px solid ${T.border}` }}>
                        <div style={{ fontSize:10, fontWeight:700, color:T.med, marginBottom:6 }}>
                          📋 TOÀN BỘ SP TRONG ĐƠN ({(o.items||[]).length})
                        </div>
                        {(o.items||[]).map((it: any, i: number) => (
                          <div key={i} style={{ fontSize:10, padding:'2px 0',
                            color: matchingItems.some((m: any) => m.code === it.code) ? T.dark : T.light,
                            fontWeight: matchingItems.some((m: any) => m.code === it.code) ? 700 : 400 }}>
                            {it.qty}× {it.name}
                          </div>
                        ))}
                      </div>

                      {/* Photos: hàng đã nhặt */}
                      {(o.photos_picked||[]).length > 0 && (
                        <PhotoGallery title="📦 Ảnh hàng đã nhặt"
                          photos={o.photos_picked}
                          allUsers={allUsers}
                          orderCode={o.order_code}
                          kind="picked"/>
                      )}

                      {/* Photos: thùng hàng */}
                      {(o.photos_packed||[]).length > 0 && (
                        <PhotoGallery title="📮 Ảnh thùng hàng"
                          photos={o.photos_packed}
                          allUsers={allUsers}
                          orderCode={o.order_code}
                          kind="packed"/>
                      )}

                      {(o.photos_picked||[]).length === 0 && (o.photos_packed||[]).length === 0 && (
                        <div style={{ padding:'10px', textAlign:'center', color:T.light, fontSize:11,
                          background:T.bg, borderRadius:6 }}>
                          📷 Đơn này chưa có ảnh nào
                        </div>
                      )}
                    </div>
                  )}
                </Card>
              )
            })}
          </div>

          {filtered.length === 0 && (
            <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
              Không tìm thấy đơn nào chứa "{searchQ}" trong {dayRange} ngày
            </div>
          )}
        </>
      )}
    </div>
  )
}

// ── Gallery + nút chia sẻ Zalo/Download cho từng set ảnh ──
function PhotoGallery({ title, photos, allUsers, orderCode, kind }: any) {
  const [previewIdx, setPreviewIdx] = useState<number|null>(null)
  const [sharing, setSharing] = useState(false)
  const [downloading, setDownloading] = useState(false)

  const getUrl = (p: any): string => typeof p === 'string' ? p : (p?.url || '')
  const getAt  = (p: any): string => typeof p === 'string' ? '' : (p?.at || '')
  const getBy  = (p: any): string => typeof p === 'string' ? '' : (p?.by || '')
  const getName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || ''

  // ── SHARE: tải ảnh về dạng blob → gắn vào navigator.share (native)
  //    Fallback: download từng ảnh về máy
  const shareAll = async () => {
    setSharing(true)
    try {
      const hasShareFiles = 'share' in navigator && 'canShare' in navigator
      const files: File[] = []

      for (let i = 0; i < photos.length; i++) {
        const url = getUrl(photos[i])
        if (!url) continue
        try {
          const res = await fetch(url)
          const blob = await res.blob()
          const filename = `${orderCode}_${kind}_${i+1}.jpg`
          files.push(new File([blob], filename, { type: blob.type || 'image/jpeg' }))
        } catch (e) {
          console.error('Fetch failed for photo', i, e)
        }
      }

      if (files.length === 0) { alert('❌ Không tải được ảnh nào'); return }

      // Chỉ share files, không kèm title/text/url
      const shareData: any = { files }

      if (hasShareFiles && (navigator as any).canShare(shareData)) {
        await (navigator as any).share(shareData)
      } else {
        // Fallback: download từng file
        for (const file of files) {
          const url = URL.createObjectURL(file)
          const a = document.createElement('a')
          a.href = url; a.download = file.name
          document.body.appendChild(a); a.click()
          document.body.removeChild(a)
          URL.revokeObjectURL(url)
          await new Promise(r => setTimeout(r, 100))
        }
        alert(`✅ Đã tải ${files.length} ảnh về máy.\nBạn có thể mở Zalo và kéo thả/chọn từ thư mục Downloads để gửi cho KH.`)
      }
    } catch (e: any) {
      if (e.name !== 'AbortError') alert('❌ Lỗi chia sẻ: ' + e.message)
    }
    setSharing(false)
  }

  // Share single photo
  const shareOne = async (idx: number) => {
    const url = getUrl(photos[idx])
    if (!url) return
    try {
      const res = await fetch(url)
      const blob = await res.blob()
      const filename = `${orderCode}_${kind}_${idx+1}.jpg`
      const file = new File([blob], filename, { type: blob.type || 'image/jpeg' })

      const shareData: any = { files: [file] }

      if ('share' in navigator && 'canShare' in navigator && (navigator as any).canShare(shareData)) {
        await (navigator as any).share(shareData)
      } else {
        // Fallback: copy link
        await navigator.clipboard.writeText(url)
        alert('✅ Đã copy link ảnh vào clipboard.\nPaste vào Zalo để gửi cho KH.')
      }
    } catch (e: any) {
      if (e.name !== 'AbortError') alert('❌ Lỗi: ' + e.message)
    }
  }

  const copyAllLinks = async () => {
    try {
      const urls = photos.map((p: any) => getUrl(p)).filter(Boolean).join('\n')
      await navigator.clipboard.writeText(urls)
      alert(`✅ Đã copy ${photos.length} link ảnh vào clipboard.\nPaste vào Zalo để gửi cho KH.`)
    } catch (e: any) {
      alert('❌ Lỗi copy: ' + e.message)
    }
  }

  // Download toàn bộ ảnh về máy (cho Sale chia sẻ KH)
  const downloadAll = async () => {
    if (photos.length === 0) return
    setDownloading(true)
    let ok = 0
    for (let i = 0; i < photos.length; i++) {
      const url = getUrl(photos[i])
      if (!url) continue
      try {
        const res = await fetch(url)
        const blob = await res.blob()
        const blobUrl = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = blobUrl
        a.download = `${orderCode}_${kind}_${i+1}.jpg`
        document.body.appendChild(a); a.click()
        document.body.removeChild(a)
        setTimeout(() => URL.revokeObjectURL(blobUrl), 1000)
        ok++
        await new Promise(r => setTimeout(r, 150))
      } catch {}
    }
    setDownloading(false)
    alert(`✅ Đã tải ${ok}/${photos.length} ảnh về máy.\nMở Zalo → đính kèm ảnh từ thư mục Downloads để gửi KH.`)
  }

  return (
    <div style={{ marginBottom:10 }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:6 }}>
        <div style={{ fontSize:11, fontWeight:700, color:T.dark }}>
          {title} ({photos.length})
        </div>
        <div style={{ display:'flex', gap:6 }}>
          <button onClick={copyAllLinks}
            style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
              fontSize:10, fontWeight:600 }}>
            🔗 Copy link
          </button>
          <button onClick={downloadAll} disabled={downloading}
            style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.green}`,
              background:T.greenBg, color:T.green,
              cursor:downloading?'wait':'pointer', fontFamily:'inherit',
              fontSize:10, fontWeight:600 }}>
            {downloading ? '⏳' : `📥 Tải ${photos.length} ảnh`}
          </button>
          <button onClick={shareAll} disabled={sharing}
            style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.blue}`,
              background:T.blue, color:'#fff', cursor:sharing?'wait':'pointer', fontFamily:'inherit',
              fontSize:10, fontWeight:600 }}>
            {sharing ? '⏳ Đang...' : '📤 Chia sẻ'}
          </button>
        </div>
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(85px, 1fr))', gap:6 }}>
        {photos.map((p: any, i: number) => {
          const url = getUrl(p)
          const at  = getAt(p)
          return (
            <div key={i} style={{ position:'relative', borderRadius:6, overflow:'hidden',
              border:`1px solid ${T.border}`, cursor:'pointer' }}
              onClick={() => setPreviewIdx(i)}>
              <div style={{ aspectRatio:'1/1', overflow:'hidden' }}>
                <img src={url} alt="" style={{ width:'100%', height:'100%', objectFit:'cover', display:'block' }}/>
              </div>
              {at && (
                <div style={{ fontSize:8, color:T.light, padding:'2px 3px', background:T.bg,
                  textAlign:'center', lineHeight:1.2 }}>
                  {new Date(at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})}
                  {' '}
                  {new Date(at).toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'})}
                </div>
              )}
            </div>
          )
        })}
      </div>

      {previewIdx !== null && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.92)', zIndex:9999,
          display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}
          onClick={() => setPreviewIdx(null)}>
          <div style={{ position:'relative', maxWidth:'100%', maxHeight:'100%' }}
            onClick={e => e.stopPropagation()}>
            <button onClick={() => setPreviewIdx(null)}
              style={{ position:'absolute', top:10, right:10, width:36, height:36, zIndex:2,
                borderRadius:18, border:'none', background:'rgba(255,255,255,0.9)', color:T.dark,
                cursor:'pointer', fontSize:18, fontFamily:'inherit' }}>×</button>
            <img src={getUrl(photos[previewIdx])} alt=""
              style={{ maxWidth:'90vw', maxHeight:'85vh', borderRadius:8, display:'block' }}/>
            <div style={{ position:'absolute', bottom:10, left:'50%', transform:'translateX(-50%)',
              display:'flex', gap:8 }}>
              {getAt(photos[previewIdx]) && (
                <div style={{ background:'rgba(0,0,0,0.7)', color:'#fff', padding:'4px 12px',
                  borderRadius:20, fontSize:11 }}>
                  🕒 {new Date(getAt(photos[previewIdx])).toLocaleString('vi-VN')}
                  {getBy(photos[previewIdx]) && <> • {getName(getBy(photos[previewIdx]))}</>}
                </div>
              )}
              <button onClick={() => shareOne(previewIdx)}
                style={{ padding:'4px 12px', borderRadius:20, border:'none',
                  background:T.blue, color:'#fff', cursor:'pointer', fontFamily:'inherit',
                  fontSize:11, fontWeight:600 }}>
                📤 Chia sẻ ảnh này
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ WAREHOUSE STATS — Thống kê hiệu suất NV đóng hàng ════════════════
// ══════════════════════════════════════════════════════════════════════

function WarehouseStatsModule({ user, allUsers, mobile }: any) {
  const perm = getPerm(user)
  const p = mobile ? '16px' : '24px'

  // Filter
  const now = new Date()
  const [fromDate, setFromDate] = useState(() => {
    const d = new Date(now.getFullYear(), now.getMonth(), 1)
    return d.toISOString().split('T')[0]
  })
  const [toDate, setToDate] = useState(() => new Date().toISOString().split('T')[0])
  const [preset, setPreset] = useState<'month'|'week'|'7d'|'30d'|'custom'>('month')

  const [orders, setOrders] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [viewTab, setViewTab] = useState<'pack'|'pick'|'sale'>('pack')

  if (!perm.viewWarehouseStats) {
    return (
      <div style={{ padding:p, textAlign:'center', color:T.light, marginTop:40 }}>
        <div style={{ fontSize:48, marginBottom:10 }}>🔒</div>
        <div style={{ fontSize:14 }}>Bạn không có quyền xem thống kê hiệu suất kho.</div>
      </div>
    )
  }

  // Preset handlers
  const applyPreset = (p: string) => {
    const today = new Date()
    let from = new Date(), to = new Date()
    if (p === 'month')   { from = new Date(today.getFullYear(), today.getMonth(), 1) }
    else if (p === 'week') {
      const day = today.getDay() || 7
      from = new Date(today); from.setDate(today.getDate() - day + 1)
    }
    else if (p === '7d')  { from = new Date(today); from.setDate(today.getDate() - 6) }
    else if (p === '30d') { from = new Date(today); from.setDate(today.getDate() - 29) }
    setFromDate(from.toISOString().split('T')[0])
    setToDate(to.toISOString().split('T')[0])
    setPreset(p as any)
  }

  // Fetch đơn có picked_at HOẶC packed_at trong range (cho cả 3 tab)
  const fetchOrders = async () => {
    setLoading(true)
    const fromISO = new Date(fromDate + 'T00:00:00').toISOString()
    const toISO   = new Date(toDate   + 'T23:59:59').toISOString()
    // Query 2 lần: đơn packed trong range, đơn picked trong range, rồi merge
    const [packRes, pickRes] = await Promise.all([
      db.from('packing_workflow').select('*')
        .gte('packed_at', fromISO).lte('packed_at', toISO).limit(5000),
      db.from('packing_workflow').select('*')
        .gte('picked_at', fromISO).lte('picked_at', toISO).limit(5000),
    ])
    const merged = new Map<string, any>()
    ;[...(packRes.data||[]), ...(pickRes.data||[])].forEach(o => merged.set(o.order_code, o))
    setOrders(Array.from(merged.values()))
    setLoading(false)
  }

  useEffect(() => { fetchOrders() }, [fromDate, toDate])

  // In-range checks
  const inRange = (iso: string|null) => {
    if (!iso) return false
    const t = new Date(iso).getTime()
    return t >= new Date(fromDate + 'T00:00:00').getTime()
        && t <= new Date(toDate   + 'T23:59:59').getTime()
  }

  // ═══ PACKER STATS (chia 1/N cho multi-packer) ═══
  const packerStats = useMemo(() => {
    const map = new Map<string, any>()
    orders.forEach((o: any) => {
      if (o.status !== 'done' || !inRange(o.packed_at)) return
      // packed_by_ids (array) hoặc fallback packed_by (single)
      const ids: string[] = (o.packed_by_ids && o.packed_by_ids.length > 0)
        ? o.packed_by_ids
        : (o.packed_by ? [o.packed_by] : [])
      if (ids.length === 0) return
      const N = ids.length
      ids.forEach(pid => {
        if (!map.has(pid)) {
          map.set(pid, {
            user_id: pid, order_count: 0, total_value: 0, total_items: 0,
            total_sp_qty: 0, sum_pack_duration_ms: 0, pack_duration_count: 0,
            modified_count: 0, bookship_count: 0, total_photos: 0, shared_count: 0,
          })
        }
        const s = map.get(pid)
        s.order_count += 1 / N
        s.total_value += Number(o.total_amount || 0) / N
        const items = o.items || []
        s.total_items += items.length / N
        s.total_sp_qty += items.reduce((t: number, it: any) => t + Number(it.qty||0), 0) / N
        if (o.picked_at && o.packed_at) {
          const dur = new Date(o.packed_at).getTime() - new Date(o.picked_at).getTime()
          if (dur > 0 && dur < 86400000 * 2) {
            s.sum_pack_duration_ms += dur
            s.pack_duration_count += 1
          }
        }
        if (o.had_mod_after_done) s.modified_count += 1 / N
        if (o.no_box) s.bookship_count += 1 / N
        s.total_photos += ((o.photos_picked||[]).length + (o.photos_packed||[]).length) / N
        if (N > 1) s.shared_count += 1
      })
    })
    return Array.from(map.values()).map(s => ({
      ...s,
      avg_value: s.order_count > 0 ? s.total_value / s.order_count : 0,
      avg_pack_minutes: s.pack_duration_count > 0
        ? Math.round(s.sum_pack_duration_ms / s.pack_duration_count / 60000)
        : 0,
      avg_photos: s.order_count > 0 ? (s.total_photos / s.order_count) : 0,
      mod_rate: s.order_count > 0 ? (s.modified_count / s.order_count * 100) : 0,
    })).sort((a, b) => b.order_count - a.order_count)
  }, [orders, fromDate, toDate])

  // ═══ PICKER STATS ═══
  const pickerStats = useMemo(() => {
    const map = new Map<string, any>()
    orders.forEach((o: any) => {
      if (!o.assigned_to || !inRange(o.picked_at)) return
      const pid = o.assigned_to
      if (!map.has(pid)) {
        map.set(pid, {
          user_id: pid, order_count: 0, total_value: 0, total_items: 0,
          total_sp_qty: 0, sum_pick_duration_ms: 0, pick_duration_count: 0,
          short_count: 0,
        })
      }
      const s = map.get(pid)
      s.order_count += 1
      s.total_value += Number(o.total_amount || 0)
      const items = o.items || []
      s.total_items += items.length
      s.total_sp_qty += items.reduce((t: number, it: any) => t + Number(it.qty||0), 0)
      // Duration từ detected_at → picked_at
      if (o.detected_at && o.picked_at) {
        const dur = new Date(o.picked_at).getTime() - new Date(o.detected_at).getTime()
        if (dur > 0 && dur < 86400000 * 2) {
          s.sum_pick_duration_ms += dur
          s.pick_duration_count += 1
        }
      }
      // Đếm số item có short_qty
      if ((items as any[]).some((it: any) => (it.short_qty||0) > 0)) s.short_count += 1
    })
    return Array.from(map.values()).map(s => ({
      ...s,
      avg_value: s.order_count > 0 ? s.total_value / s.order_count : 0,
      avg_pick_minutes: s.pick_duration_count > 0
        ? Math.round(s.sum_pick_duration_ms / s.pick_duration_count / 60000)
        : 0,
      short_rate: s.order_count > 0 ? (s.short_count / s.order_count * 100) : 0,
    })).sort((a, b) => b.order_count - a.order_count)
  }, [orders, fromDate, toDate])

  // ═══ SALE STATS (theo sold_by_name) ═══
  const saleStats = useMemo(() => {
    const map = new Map<string, any>()
    orders.forEach((o: any) => {
      if (!o.sold_by_name) return
      // Tính đơn Sale: đơn phải có picked_at HOẶC packed_at trong range
      const pickedInRange = inRange(o.picked_at)
      const packedInRange = inRange(o.packed_at)
      if (!pickedInRange && !packedInRange) return
      const key = o.sold_by_name
      if (!map.has(key)) {
        map.set(key, {
          sold_by_name: key, picked_count: 0, packed_count: 0,
          total_value_picked: 0, total_value_packed: 0,
        })
      }
      const s = map.get(key)
      if (pickedInRange) {
        s.picked_count += 1
        s.total_value_picked += Number(o.total_amount || 0)
      }
      if (packedInRange && o.status === 'done') {
        s.packed_count += 1
        s.total_value_packed += Number(o.total_amount || 0)
      }
    })
    return Array.from(map.values())
      .sort((a, b) => b.packed_count - a.packed_count)
  }, [orders, fromDate, toDate])

  const totals = useMemo(() => ({
    total_orders: orders.filter((o: any) => o.status === 'done' && inRange(o.packed_at)).length,
    total_value: orders
      .filter((o: any) => o.status === 'done' && inRange(o.packed_at))
      .reduce((s, o: any) => s + Number(o.total_amount||0), 0),
    total_packers: packerStats.length,
    total_pickers: pickerStats.length,
    total_picked: pickerStats.reduce((s, ps: any) => s + ps.order_count, 0),
  }), [orders, packerStats, pickerStats])

  const getName = (id: string) => allUsers.find((u: any) => u.id === id)?.name || id.slice(0,8)
  const fmtMoney = (n: number) => Number(n||0).toLocaleString('vi-VN')

  // Chọn stats hiện tại theo tab
  const stats = viewTab === 'pack' ? packerStats : viewTab === 'pick' ? pickerStats : []

  const maxOrderCount = Math.max(1, ...stats.map((s: any) => s.order_count))
  const maxValue = Math.max(1, ...stats.map((s: any) => s.total_value))

  if (loading) return (
    <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>
      ⏳ Đang tải thống kê...
    </div>
  )

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="📊 Hiệu suất kho"
        subtitle={`${totals.total_orders} đơn đóng • ${Math.round(totals.total_picked)} đơn nhặt • ${fmtMoney(totals.total_value)}đ`}/>

      {/* Tab switcher */}
      <div style={{ display:'flex', gap:6, marginBottom:12, flexWrap:'wrap' }}>
        {[
          { id:'pack', label:`📮 NV Đóng (${packerStats.length})` },
          { id:'pick', label:`📥 NV Nhặt (${pickerStats.length})` },
          { id:'sale', label:`👤 Theo Sale (${saleStats.length})` },
        ].map((t: any) => (
          <button key={t.id} onClick={() => setViewTab(t.id)}
            style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer',
              fontFamily:'inherit', fontSize:12, fontWeight:600,
              border:`1.5px solid ${viewTab===t.id?T.gold:T.border}`,
              background: viewTab===t.id?T.goldBg:'#fff',
              color: viewTab===t.id?T.goldText:T.med }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Filter */}
      <Card style={{ padding:12, marginBottom:12 }}>
        <div style={{ display:'flex', gap:6, flexWrap:'wrap', marginBottom:10 }}>
          {[
            { id:'month', label:'Tháng này' },
            { id:'week',  label:'Tuần này'  },
            { id:'7d',    label:'7 ngày'    },
            { id:'30d',   label:'30 ngày'   },
          ].map((t: any) => (
            <button key={t.id} onClick={() => applyPreset(t.id)}
              style={{ padding:'4px 12px', borderRadius:16, cursor:'pointer',
                fontFamily:'inherit', fontSize:11, fontWeight:600,
                border:`1px solid ${preset===t.id?T.gold:T.border}`,
                background: preset===t.id?T.goldBg:'#fff',
                color: preset===t.id?T.goldText:T.med }}>
              {t.label}
            </button>
          ))}
        </div>
        <div style={{ display:'flex', gap:8, alignItems:'center', flexWrap:'wrap' }}>
          <label style={{ fontSize:11, color:T.med }}>Từ:</label>
          <input type="date" value={fromDate} onChange={e => { setFromDate(e.target.value); setPreset('custom') }}
            style={{ padding:'5px 10px', border:`1px solid ${T.border}`, borderRadius:6,
              fontSize:11, fontFamily:'inherit' }}/>
          <label style={{ fontSize:11, color:T.med }}>Đến:</label>
          <input type="date" value={toDate} onChange={e => { setToDate(e.target.value); setPreset('custom') }}
            style={{ padding:'5px 10px', border:`1px solid ${T.border}`, borderRadius:6,
              fontSize:11, fontFamily:'inherit' }}/>
        </div>
      </Card>

      {/* ═══ TAB SALE: bảng theo sold_by_name ═══ */}
      {viewTab === 'sale' && (
        saleStats.length === 0 ? (
          <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
            Không có đơn nào được xử lý trong khoảng thời gian này.
          </div>
        ) : (
          <Card style={{ padding:0, overflow:'hidden' }}>
            <div style={{ padding:'12px 16px', fontSize:13, fontWeight:700,
              color:T.dark, borderBottom:`1px solid ${T.border}`, background:T.bg }}>
              👤 Đơn xử lý theo Sale
            </div>
            <div style={{ overflowX:'auto' }}>
              <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                <thead>
                  <tr style={{ background:T.bg, borderBottom:`2px solid ${T.border}` }}>
                    <th style={{ padding:'12px 14px', textAlign:'left', fontWeight:700, color:T.med }}>Sale</th>
                    <th style={{ padding:'12px 10px', textAlign:'right', fontWeight:700, color:T.med }}>📥 Đơn nhặt</th>
                    <th style={{ padding:'12px 10px', textAlign:'right', fontWeight:700, color:T.med }}>📮 Đơn đóng</th>
                    <th style={{ padding:'12px 10px', textAlign:'right', fontWeight:700, color:T.med }}>💰 Giá trị đóng</th>
                  </tr>
                </thead>
                <tbody>
                  {saleStats.map((s: any, idx) => (
                    <tr key={s.sold_by_name} style={{ borderBottom:`1px solid ${T.border}` }}>
                      <td style={{ padding:'12px 14px', color:T.dark, fontWeight: idx===0?700:500 }}>
                        {idx===0 && '🥇 '}{idx===1 && '🥈 '}{idx===2 && '🥉 '}
                        {s.sold_by_name}
                      </td>
                      <td style={{ padding:'12px 10px', textAlign:'right', color:T.blue, fontWeight:700 }}>
                        {s.picked_count}
                      </td>
                      <td style={{ padding:'12px 10px', textAlign:'right', color:T.green, fontWeight:700 }}>
                        {s.packed_count}
                      </td>
                      <td style={{ padding:'12px 10px', textAlign:'right', color:T.goldText, fontWeight:600 }}>
                        {fmtMoney(s.total_value_packed)}
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot>
                  <tr style={{ background:T.goldBg, borderTop:`2px solid ${T.gold}` }}>
                    <td style={{ padding:'12px 14px', color:T.dark, fontWeight:800 }}>TỔNG</td>
                    <td style={{ padding:'12px 10px', textAlign:'right', color:T.blue, fontWeight:800 }}>
                      {saleStats.reduce((s: number, x: any) => s + x.picked_count, 0)}
                    </td>
                    <td style={{ padding:'12px 10px', textAlign:'right', color:T.green, fontWeight:800 }}>
                      {saleStats.reduce((s: number, x: any) => s + x.packed_count, 0)}
                    </td>
                    <td style={{ padding:'12px 10px', textAlign:'right', color:T.goldText, fontWeight:800 }}>
                      {fmtMoney(saleStats.reduce((s: number, x: any) => s + x.total_value_packed, 0))}
                    </td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </Card>
        )
      )}

      {/* ═══ TAB PACK / PICK: bar chart + bảng NV ═══ */}
      {viewTab !== 'sale' && (
        stats.length === 0 ? (
          <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
            Không có đơn nào {viewTab==='pack'?'đã đóng':'đã nhặt'} trong khoảng thời gian này.
          </div>
        ) : (
          <>
            {/* Bar chart: số đơn */}
            <Card style={{ padding:16, marginBottom:12 }}>
              <div style={{ fontSize:13, fontWeight:700, color:T.dark, marginBottom:12 }}>
                {viewTab==='pack' ? '📮 Số đơn đóng theo NV' : '📥 Số đơn nhặt theo NV'}
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {stats.map((s: any, idx) => (
                  <div key={s.user_id}>
                    <div style={{ display:'flex', justifyContent:'space-between',
                      fontSize:11, marginBottom:4 }}>
                      <span style={{ color:T.dark, fontWeight: idx===0?700:500 }}>
                        {idx===0 && '🥇 '}{idx===1 && '🥈 '}{idx===2 && '🥉 '}
                        {getName(s.user_id)}
                        {viewTab==='pack' && s.shared_count > 0 && (
                          <span style={{ fontSize:9, color:T.blue, marginLeft:6, fontWeight:600 }}>
                            ({s.shared_count} đơn chia sẻ)
                          </span>
                        )}
                      </span>
                      <span style={{ color:T.dark, fontWeight:700 }}>
                        {viewTab==='pack' ? s.order_count.toFixed(1) : s.order_count} đơn
                      </span>
                    </div>
                    <div style={{ height:14, background:T.bg, borderRadius:7, overflow:'hidden' }}>
                      <div style={{ height:'100%',
                        background: idx===0 ? T.gold : (idx<3?T.blue:T.green),
                        width:`${(s.order_count / maxOrderCount) * 100}%`,
                        transition:'width .5s' }}/>
                    </div>
                  </div>
                ))}
              </div>
            </Card>

            {/* Bar chart: giá trị */}
            <Card style={{ padding:16, marginBottom:12 }}>
              <div style={{ fontSize:13, fontWeight:700, color:T.dark, marginBottom:12 }}>
                {viewTab==='pack' ? '💰 Tổng giá trị đơn đã đóng' : '💰 Tổng giá trị đơn đã nhặt'}
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {[...stats].sort((a: any, b: any) => b.total_value - a.total_value).map((s: any, idx) => (
                  <div key={s.user_id}>
                    <div style={{ display:'flex', justifyContent:'space-between',
                      fontSize:11, marginBottom:4 }}>
                      <span style={{ color:T.dark, fontWeight: idx===0?700:500 }}>
                        {idx===0 && '🥇 '}{idx===1 && '🥈 '}{idx===2 && '🥉 '}
                        {getName(s.user_id)}
                      </span>
                      <span style={{ color:T.goldText, fontWeight:700 }}>
                        {fmtMoney(Math.round(s.total_value))}
                      </span>
                    </div>
                    <div style={{ height:14, background:T.bg, borderRadius:7, overflow:'hidden' }}>
                      <div style={{ height:'100%',
                        background:`linear-gradient(90deg, ${T.gold} 0%, #b8860b 100%)`,
                        width:`${(s.total_value / maxValue) * 100}%`,
                        transition:'width .5s' }}/>
                    </div>
                  </div>
                ))}
              </div>
            </Card>

            {/* Bảng chi tiết */}
            <Card style={{ padding:0, marginBottom:12, overflow:'hidden' }}>
              <div style={{ padding:'12px 16px', fontSize:13, fontWeight:700,
                color:T.dark, borderBottom:`1px solid ${T.border}`, background:T.bg }}>
                📊 Chi tiết hiệu suất {viewTab==='pack'?'đóng':'nhặt'}
              </div>
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:11 }}>
                  <thead>
                    <tr style={{ background:T.bg, borderBottom:`2px solid ${T.border}` }}>
                      <th style={{ padding:'10px 12px', textAlign:'left', fontWeight:700, color:T.med }}>NV</th>
                      <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Đơn</th>
                      <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Giá trị</th>
                      <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>TB/đơn</th>
                      <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>SP</th>
                      <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>TB phút</th>
                      {viewTab==='pack' && <>
                        <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Bookship</th>
                        <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Bị sửa</th>
                        <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Ảnh/đơn</th>
                      </>}
                      {viewTab==='pick' && (
                        <th style={{ padding:'10px 8px', textAlign:'right', fontWeight:700, color:T.med }}>Tỷ lệ thiếu</th>
                      )}
                    </tr>
                  </thead>
                  <tbody>
                    {stats.map((s: any, idx) => (
                      <tr key={s.user_id} style={{ borderBottom:`1px solid ${T.border}` }}>
                        <td style={{ padding:'10px 12px', color:T.dark, fontWeight: idx===0?700:500 }}>
                          {idx===0 && '🥇 '}{getName(s.user_id)}
                        </td>
                        <td style={{ padding:'10px 8px', textAlign:'right', color:T.dark, fontWeight:700 }}>
                          {viewTab==='pack' ? s.order_count.toFixed(1) : s.order_count}
                        </td>
                        <td style={{ padding:'10px 8px', textAlign:'right', color:T.goldText, fontWeight:600 }}>
                          {fmtMoney(Math.round(s.total_value))}
                        </td>
                        <td style={{ padding:'10px 8px', textAlign:'right', color:T.med }}>
                          {fmtMoney(Math.round(s.avg_value))}
                        </td>
                        <td style={{ padding:'10px 8px', textAlign:'right', color:T.med }}>
                          {Math.round(s.total_sp_qty)}
                        </td>
                        <td style={{ padding:'10px 8px', textAlign:'right', color:T.med }}>
                          {viewTab==='pack'
                            ? (s.avg_pack_minutes > 0 ? `${s.avg_pack_minutes}p` : '—')
                            : (s.avg_pick_minutes > 0 ? `${s.avg_pick_minutes}p` : '—')}
                        </td>
                        {viewTab==='pack' && <>
                          <td style={{ padding:'10px 8px', textAlign:'right', color:T.med }}>
                            {Math.round(s.bookship_count)}
                          </td>
                          <td style={{ padding:'10px 8px', textAlign:'right',
                            color: s.mod_rate > 10 ? T.red : T.med, fontWeight: s.mod_rate>10?700:400 }}>
                            {Math.round(s.modified_count)} ({s.mod_rate.toFixed(0)}%)
                          </td>
                          <td style={{ padding:'10px 8px', textAlign:'right', color:T.med }}>
                            {s.avg_photos.toFixed(1)}
                          </td>
                        </>}
                        {viewTab==='pick' && (
                          <td style={{ padding:'10px 8px', textAlign:'right',
                            color: s.short_rate > 10 ? T.amber : T.med }}>
                            {s.short_count} ({s.short_rate.toFixed(0)}%)
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Card>

            <div style={{ padding:'10px 12px', background:T.bg, borderRadius:6, fontSize:11,
              color:T.med, lineHeight:1.6 }}>
              {viewTab==='pack' && <>
                <div><b>📖 Giải thích chỉ số:</b></div>
                <div>• <b>Đơn chia sẻ</b>: đơn có nhiều NV cùng đóng, mỗi người tính 1/N</div>
                <div>• <b>TB/đơn</b>: Giá trị trung bình 1 đơn</div>
                <div>• <b>TB phút</b>: Thời gian từ lúc nhặt xong đến đóng xong</div>
                <div>• <b>Bị sửa {'>'}10%</b>: Cần chú ý</div>
              </>}
              {viewTab==='pick' && <>
                <div><b>📖 Giải thích chỉ số:</b></div>
                <div>• <b>TB phút</b>: Thời gian từ lúc đơn xuất hiện trong hệ thống đến lúc nhặt xong</div>
                <div>• <b>Tỷ lệ thiếu</b>: % đơn có báo thiếu hàng</div>
              </>}
            </div>
          </>
        )
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════
// ══ WAREHOUSE SCHEDULE — Lịch Kho ═════════════════════════════════════
// ══════════════════════════════════════════════════════════════════════

function WarehouseScheduleModule({ user, allUsers, leaveRequests, attendance, mobile }: any) {
  const perm = getPerm(user)
  const canManage = perm.manageSchedule
  const p = mobile ? '16px' : '24px'

  const now = new Date()
  const [year, setYear]   = useState(now.getFullYear())
  const [month, setMonth] = useState(now.getMonth())  // 0-indexed

  const [schedules, setSchedules] = useState<any[]>([])     // raw rows
  const [roles, setRoles]         = useState<any[]>([])
  const [loading, setLoading]     = useState(true)
  const [editCell, setEditCell]   = useState<{date:string, role_id:string}|null>(null)
  const [showRotation, setShowRotation] = useState(false)
  const [showCopyPrev, setShowCopyPrev] = useState(false)

  // Fetch roles + schedules của tháng
  const fetchAll = async () => {
    setLoading(true)
    const fromDate = `${year}-${String(month+1).padStart(2,'0')}-01`
    const toDate = new Date(year, month+1, 0).toISOString().split('T')[0]

    const [rolesRes, schedRes] = await Promise.all([
      db.from('warehouse_schedule_roles').select('*').eq('active', true).order('sort_order'),
      db.from('warehouse_schedule').select('*').gte('date', fromDate).lte('date', toDate),
    ])
    setRoles(rolesRes.data || [])
    setSchedules(schedRes.data || [])
    setLoading(false)
  }

  useEffect(() => { fetchAll() }, [year, month])

  // Generate days of month
  const daysInMonth = new Date(year, month+1, 0).getDate()
  const days = Array.from({length: daysInMonth}, (_, i) => {
    const date = new Date(year, month, i+1)
    const dateStr = `${year}-${String(month+1).padStart(2,'0')}-${String(i+1).padStart(2,'0')}`
    const dow = date.getDay() // 0=CN, 6=T7
    return { date, dateStr, day: i+1, dow, isWeekend: dow === 0 || dow === 6 }
  })

  // Map schedule: (dateStr, role_id) → { user_ids }
  const scheduleMap = useMemo(() => {
    const m = new Map<string, any>()
    schedules.forEach((s: any) => {
      m.set(`${s.date}::${s.role_id}`, s)
    })
    return m
  }, [schedules])

  // Leave map: userId → Set<dateStr of leave>
  const leaveMap = useMemo(() => {
    const m = new Map<string, Set<string>>()
    ;(leaveRequests || []).filter((r: any) => r.status === 'approved').forEach((r: any) => {
      const from = new Date(r.from_date)
      const to = new Date(r.to_date)
      const uid = r.user_id
      if (!m.has(uid)) m.set(uid, new Set())
      for (let d = new Date(from); d <= to; d.setDate(d.getDate()+1)) {
        m.get(uid)!.add(d.toISOString().split('T')[0])
      }
    })
    return m
  }, [leaveRequests])

  // Detect conflicts: NV được xếp nhưng nghỉ phép ngày đó
  const conflicts = useMemo(() => {
    const list: any[] = []
    schedules.forEach((s: any) => {
      (s.user_ids || []).forEach((uid: string) => {
        if (leaveMap.get(uid)?.has(s.date)) {
          const role = roles.find(r => r.id === s.role_id)
          const u = allUsers.find((u: any) => u.id === uid)
          list.push({
            date: s.date,
            role_id: s.role_id,
            role_name: role?.name || s.role_id,
            user_id: uid,
            user_name: u?.name || uid,
          })
        }
      })
    })
    return list
  }, [schedules, leaveMap, roles, allUsers])

  // Save cell
  const saveCell = async (dateStr: string, roleId: string, userIds: string[]) => {
    const existing = scheduleMap.get(`${dateStr}::${roleId}`)
    if (existing) {
      await db.from('warehouse_schedule').update({
        user_ids: userIds, updated_by: user.id, updated_at: new Date().toISOString(),
      }).eq('id', existing.id)
      setSchedules(prev => prev.map(s => s.id === existing.id
        ? { ...s, user_ids: userIds, updated_at: new Date().toISOString() }
        : s))
    } else {
      const rec = {
        id: `ws_${dateStr}_${roleId}_${Date.now().toString(36)}`,
        date: dateStr, role_id: roleId, user_ids: userIds,
        updated_by: user.id, updated_at: new Date().toISOString(),
        created_at: new Date().toISOString(),
      }
      await db.from('warehouse_schedule').insert(rec)
      setSchedules(prev => [...prev, rec])
    }
  }

  // Navigation
  const prevMonth = () => {
    if (month === 0) { setMonth(11); setYear(year-1) }
    else setMonth(month-1)
  }
  const nextMonth = () => {
    if (month === 11) { setMonth(0); setYear(year+1) }
    else setMonth(month+1)
  }

  const monthLabel = `Tháng ${month+1}/${year}`

  // Get name helper
  const getName = (id: string) => {
    const u = allUsers.find((u: any) => u.id === id)
    return u?.name?.split(' ').pop() || u?.ini || id.slice(0,5)
  }
  const renderCellContent = (userIds: string[]) => {
    if (userIds.length === 0) return <span style={{ color:T.light, fontStyle:'italic' }}>—</span>
    return userIds.map(uid => getName(uid)).join('-')
  }

  // Today
  const todayStr = new Date().toISOString().split('T')[0]

  if (loading) return (
    <div style={{ padding:p, textAlign:'center', color:T.light, paddingTop:40 }}>
      ⏳ Đang tải lịch kho...
    </div>
  )

  return (
    <div style={{ padding:`0 ${p} ${mobile?'80px':p}` }}>
      <Topbar mobile={mobile} title="📅 Lịch Kho"
        subtitle={canManage ? 'QM Kho chia lịch theo ngày và vai trò' : 'Xem lịch làm việc của Kho'}
        action={
          canManage && (
            <div style={{ display:'flex', gap:6 }}>
              <button onClick={() => setShowCopyPrev(true)}
                style={{ padding:'5px 12px', borderRadius:20, border:`1px solid ${T.border}`,
                  background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                  fontSize:11, fontWeight:600 }}>
                📋 Copy tháng trước
              </button>
              <button onClick={() => setShowRotation(true)}
                style={{ padding:'5px 12px', borderRadius:20, border:'none',
                  background:T.gold, color:'#fff', cursor:'pointer', fontFamily:'inherit',
                  fontSize:11, fontWeight:700 }}>
                🔄 Tạo theo xoay ca
              </button>
            </div>
          )
        }/>

      {/* Today schedule for Sale */}
      {!canManage && (
        <Card style={{ padding:14, marginBottom:12, background:T.goldBg, border:`1px solid ${T.gold}` }}>
          <div style={{ fontSize:12, fontWeight:700, color:T.goldText, marginBottom:8 }}>
            📍 Lịch hôm nay ({new Date().toLocaleDateString('vi-VN')})
          </div>
          <div style={{ display:'flex', flexWrap:'wrap', gap:8 }}>
            {roles.map((r: any) => {
              const sc = scheduleMap.get(`${todayStr}::${r.id}`)
              const userIds = sc?.user_ids || []
              return (
                <div key={r.id} style={{ padding:'8px 12px', borderRadius:8, background:'#fff',
                  border:`1px solid ${T.border}`, minWidth:150 }}>
                  <div style={{ fontSize:10, color:T.light, fontWeight:600 }}>
                    {r.icon} {r.name}
                  </div>
                  <div style={{ fontSize:12, color:T.dark, fontWeight:700, marginTop:3 }}>
                    {userIds.length > 0 ? userIds.map(getName).join(', ') : '— trống —'}
                  </div>
                </div>
              )
            })}
          </div>
        </Card>
      )}

      {/* Navigation tháng */}
      <Card style={{ padding:10, marginBottom:12, display:'flex', alignItems:'center',
        justifyContent:'space-between' }}>
        <button onClick={prevMonth}
          style={{ padding:'5px 12px', borderRadius:6, border:`1px solid ${T.border}`,
            background:'#fff', color:T.dark, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
          ◀ Trước
        </button>
        <div style={{ fontSize:15, fontWeight:700, color:T.dark }}>{monthLabel}</div>
        <button onClick={nextMonth}
          style={{ padding:'5px 12px', borderRadius:6, border:`1px solid ${T.border}`,
            background:'#fff', color:T.dark, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
          Tiếp ▶
        </button>
      </Card>

      {/* Conflicts warning */}
      {conflicts.length > 0 && (
        <Card style={{ padding:12, marginBottom:12, background:T.redBg, border:`1px solid ${T.red}` }}>
          <div style={{ fontSize:12, fontWeight:700, color:T.red, marginBottom:6 }}>
            ⚠️ CẢNH BÁO: {conflicts.length} xung đột với lịch nghỉ phép
          </div>
          <div style={{ fontSize:11, color:T.dark, maxHeight:100, overflowY:'auto' }}>
            {conflicts.map((c, i) => (
              <div key={i} style={{ padding:'2px 0' }}>
                • <b>{c.user_name}</b> được xếp <b>{c.role_name}</b> ngày {c.date.split('-').reverse().join('/')} nhưng đã có đơn nghỉ phép duyệt
              </div>
            ))}
          </div>
        </Card>
      )}

      {/* Grid lịch */}
      <Card style={{ padding:0, overflow:'hidden' }}>
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:11, minWidth:mobile?400:700 }}>
            <thead>
              <tr style={{ background:'#3b82f6' }}>
                <th style={{ padding:'8px 6px', color:'#fff', fontWeight:700, textAlign:'center',
                  minWidth:70, position:'sticky', left:0, background:'#3b82f6', zIndex:2 }}>
                  Ngày
                </th>
                {roles.map((r: any) => (
                  <th key={r.id} style={{ padding:'8px 6px', color:'#fff', fontWeight:700,
                    textAlign:'center', minWidth:100 }}>
                    {r.icon} {r.name}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {days.map((d: any) => {
                const isToday = d.dateStr === todayStr
                const bgRow = d.isWeekend ? '#d4edda' : (isToday ? T.goldBg : '#fff')
                return (
                  <tr key={d.dateStr} style={{ background:bgRow, borderBottom:`1px solid ${T.border}` }}>
                    <td style={{ padding:'6px 8px', textAlign:'center', fontWeight:700,
                      color: isToday?T.goldText:T.dark,
                      position:'sticky', left:0, background:bgRow, zIndex:1 }}>
                      {d.day}/{month+1}
                      <div style={{ fontSize:9, color:T.light, fontWeight:400 }}>
                        {['CN','T2','T3','T4','T5','T6','T7'][d.dow]}
                      </div>
                    </td>
                    {roles.map((r: any) => {
                      const sc = scheduleMap.get(`${d.dateStr}::${r.id}`)
                      const userIds = sc?.user_ids || []
                      const hasConflict = userIds.some((uid: string) => leaveMap.get(uid)?.has(d.dateStr))
                      return (
                        <td key={r.id}
                          onClick={canManage ? () => setEditCell({date:d.dateStr, role_id:r.id}) : undefined}
                          style={{ padding:'6px 8px', textAlign:'center',
                            cursor: canManage?'pointer':'default',
                            color: hasConflict ? T.red : T.dark,
                            fontWeight: hasConflict ? 700 : 500,
                            fontSize: userIds.length > 2 ? 10 : 11 }}>
                          {hasConflict && '⚠️ '}
                          {renderCellContent(userIds)}
                        </td>
                      )
                    })}
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </Card>

      {!canManage && (
        <div style={{ marginTop:10, fontSize:11, color:T.light, textAlign:'center' }}>
          Chỉ QM Kho mới có thể chỉnh sửa lịch. Liên hệ QM nếu có thắc mắc.
        </div>
      )}

      {/* Edit cell modal */}
      {editCell && canManage && (
        <ScheduleEditModal
          date={editCell.date}
          roleId={editCell.role_id}
          role={roles.find(r => r.id === editCell.role_id)}
          currentUserIds={scheduleMap.get(`${editCell.date}::${editCell.role_id}`)?.user_ids || []}
          allUsers={allUsers.filter((u: any) => u.dept_id === 'kho')}
          leaveMap={leaveMap}
          onSave={(uids: string[]) => {
            saveCell(editCell.date, editCell.role_id, uids)
            setEditCell(null)
          }}
          onClose={() => setEditCell(null)}
        />
      )}

      {/* Rotation modal */}
      {showRotation && canManage && (
        <RotationWizard
          roles={roles}
          year={year} month={month}
          khoUsers={allUsers.filter((u: any) => u.dept_id === 'kho')}
          existingSchedules={schedules}
          onApply={async (entries: any[]) => {
            // entries: [{date, role_id, user_ids}]
            for (const e of entries) {
              await saveCell(e.date, e.role_id, e.user_ids)
            }
            setShowRotation(false)
            fetchAll()
          }}
          onClose={() => setShowRotation(false)}
        />
      )}

      {/* Copy previous month */}
      {showCopyPrev && canManage && (
        <CopyPrevMonthModal
          year={year} month={month}
          daysInCurrent={daysInMonth}
          onApply={async (prevMonth: number, prevYear: number) => {
            const fromDate = `${prevYear}-${String(prevMonth+1).padStart(2,'0')}-01`
            const toDate = new Date(prevYear, prevMonth+1, 0).toISOString().split('T')[0]
            const { data } = await db.from('warehouse_schedule').select('*')
              .gte('date', fromDate).lte('date', toDate)
            if (!data || data.length === 0) {
              alert('❌ Tháng trước không có lịch nào để copy.')
              return
            }
            const prevFirstDow = new Date(prevYear, prevMonth, 1).getDay()
            const curFirstDow = new Date(year, month, 1).getDay()
            // Copy theo thứ trong tuần (align dow) — an toàn hơn copy theo ngày
            for (const rec of data) {
              const oldDate = new Date(rec.date)
              const oldDay = oldDate.getDate()
              if (oldDay > daysInMonth) continue
              const newDate = `${year}-${String(month+1).padStart(2,'0')}-${String(oldDay).padStart(2,'0')}`
              await saveCell(newDate, rec.role_id, rec.user_ids || [])
            }
            alert('✅ Đã copy lịch từ tháng trước')
            setShowCopyPrev(false)
            fetchAll()
          }}
          onClose={() => setShowCopyPrev(false)}
        />
      )}
    </div>
  )
}

// ── Modal chọn NV cho 1 ô ──
function ScheduleEditModal({ date, roleId, role, currentUserIds, allUsers, leaveMap, onSave, onClose }: any) {
  const [selected, setSelected] = useState<Set<string>>(new Set(currentUserIds))
  const toggle = (uid: string) => {
    const s = new Set(selected)
    if (s.has(uid)) s.delete(uid); else s.add(uid)
    setSelected(s)
  }
  const dateLabel = date.split('-').reverse().join('/')

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:480, width:'100%',
        maxHeight:'85vh', overflow:'auto' }}>
        <div style={{ padding:'14px 20px', background:T.goldBg, borderBottom:`1px solid ${T.gold}` }}>
          <div style={{ fontSize:14, fontWeight:700, color:T.goldText }}>
            {role?.icon} {role?.name} • {dateLabel}
          </div>
          <div style={{ fontSize:11, color:T.med, marginTop:3 }}>
            Chọn NV thực hiện vai trò này (có thể chọn nhiều người)
          </div>
        </div>
        <div style={{ padding:16 }}>
          <div style={{ display:'flex', flexDirection:'column', gap:6, maxHeight:360, overflowY:'auto' }}>
            {allUsers.map((u: any) => {
              const onLeave = leaveMap.get(u.id)?.has(date)
              const sel = selected.has(u.id)
              return (
                <label key={u.id} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 10px',
                  borderRadius:6, cursor:'pointer',
                  background: sel ? T.goldBg : '#fff',
                  border:`1px solid ${sel?T.gold:T.border}` }}>
                  <input type="checkbox" checked={sel} onChange={() => toggle(u.id)}
                    style={{ width:16, height:16, cursor:'pointer', accentColor:T.gold }}/>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:12, fontWeight:600, color:T.dark }}>
                      {u.name}
                      {u.position_name && <span style={{ color:T.light, fontWeight:400 }}> • {u.position_name}</span>}
                    </div>
                  </div>
                  {onLeave && (
                    <span style={{ padding:'2px 8px', background:T.redBg, color:T.red,
                      borderRadius:10, fontSize:9, fontWeight:700 }}>
                      ⚠️ NGHỈ PHÉP
                    </span>
                  )}
                </label>
              )
            })}
          </div>
        </div>
        <div style={{ display:'flex', gap:10, padding:16, borderTop:`1px solid ${T.border}` }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
            Hủy
          </button>
          <button onClick={() => onSave(Array.from(selected))}
            style={{ flex:2, padding:'9px', borderRadius:6, border:'none',
              background:T.gold, color:'#fff', cursor:'pointer',
              fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
            💾 Lưu ({selected.size} NV)
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Rotation Wizard: nhập 1 chu kỳ → auto xoay cả tháng ──
function RotationWizard({ roles, year, month, khoUsers, existingSchedules, onApply, onClose }: any) {
  const [cycleDays, setCycleDays] = useState(4)
  // pattern[cycleIndex][roleId] = set of user_ids
  const [pattern, setPattern] = useState<Map<string, Set<string>>>(new Map())
  const [overwrite, setOverwrite] = useState(false)

  const key = (cycleIdx: number, roleId: string) => `${cycleIdx}::${roleId}`

  const togglePatternUser = (cycleIdx: number, roleId: string, uid: string) => {
    const k = key(cycleIdx, roleId)
    const cur = pattern.get(k) || new Set<string>()
    const nextSet = new Set(cur)
    if (nextSet.has(uid)) nextSet.delete(uid); else nextSet.add(uid)
    const next = new Map(pattern)
    next.set(k, nextSet)
    setPattern(next)
  }

  const apply = () => {
    const daysInMonth = new Date(year, month+1, 0).getDate()
    const entries: any[] = []
    for (let day = 1; day <= daysInMonth; day++) {
      const dateStr = `${year}-${String(month+1).padStart(2,'0')}-${String(day).padStart(2,'0')}`
      const cycleIdx = (day - 1) % cycleDays
      roles.forEach((r: any) => {
        const users = pattern.get(key(cycleIdx, r.id))
        if (users && users.size > 0) {
          // Skip nếu overwrite=false và đã có schedule
          const ex = existingSchedules.find((s: any) => s.date === dateStr && s.role_id === r.id)
          if (ex && !overwrite) return
          entries.push({
            date: dateStr,
            role_id: r.id,
            user_ids: Array.from(users),
          })
        }
      })
    }
    if (entries.length === 0) {
      alert('❌ Chưa nhập NV nào vào chu kỳ. Hãy tick ít nhất 1 NV ở 1 ngày.')
      return
    }
    if (!confirm(`Sẽ tạo/cập nhật ${entries.length} ô lịch cho cả tháng. Tiếp tục?`)) return
    onApply(entries)
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:720, width:'100%',
        maxHeight:'90vh', overflow:'auto' }}>
        <div style={{ padding:'14px 20px', background:T.goldBg, borderBottom:`1px solid ${T.gold}` }}>
          <div style={{ fontSize:14, fontWeight:700, color:T.goldText }}>
            🔄 Tạo lịch theo xoay ca — Tháng {month+1}/{year}
          </div>
          <div style={{ fontSize:11, color:T.med, marginTop:3 }}>
            Nhập NV cho từng ngày trong chu kỳ. Hệ thống sẽ tự lặp lại cho cả tháng.
          </div>
        </div>
        <div style={{ padding:16 }}>
          <div style={{ marginBottom:12, display:'flex', alignItems:'center', gap:10 }}>
            <label style={{ fontSize:12, color:T.med, fontWeight:600 }}>Số ngày/chu kỳ:</label>
            <select value={cycleDays} onChange={e => setCycleDays(Number(e.target.value))}
              style={{ padding:'5px 10px', border:`1px solid ${T.border}`, borderRadius:6,
                fontSize:12, fontFamily:'inherit', background:'#fff' }}>
              {[2,3,4,5,6,7].map(n => <option key={n} value={n}>{n} ngày</option>)}
            </select>
            <span style={{ fontSize:11, color:T.light }}>
              (VD: 4 = cứ 4 ngày xoay 1 lần)
            </span>
          </div>

          <div style={{ marginBottom:12 }}>
            {Array.from({length: cycleDays}, (_, i) => (
              <Card key={i} style={{ padding:10, marginBottom:8, background:T.bg }}>
                <div style={{ fontSize:12, fontWeight:700, color:T.dark, marginBottom:8 }}>
                  📅 Ngày {i+1} trong chu kỳ
                </div>
                <div style={{ display:'grid',
                  gridTemplateColumns:'repeat(auto-fit, minmax(200px, 1fr))', gap:8 }}>
                  {roles.map((r: any) => {
                    const selected = pattern.get(key(i, r.id)) || new Set()
                    return (
                      <div key={r.id} style={{ padding:8, background:'#fff', borderRadius:6,
                        border:`1px solid ${T.border}` }}>
                        <div style={{ fontSize:10, fontWeight:700, color:T.med, marginBottom:5 }}>
                          {r.icon} {r.name}
                        </div>
                        <div style={{ display:'flex', flexWrap:'wrap', gap:4 }}>
                          {khoUsers.map((u: any) => {
                            const sel = selected.has(u.id)
                            return (
                              <button key={u.id}
                                onClick={() => togglePatternUser(i, r.id, u.id)}
                                style={{ padding:'3px 8px', borderRadius:12,
                                  border:`1px solid ${sel?T.gold:T.border}`,
                                  background: sel?T.gold:'#fff',
                                  color: sel?'#fff':T.dark,
                                  cursor:'pointer', fontFamily:'inherit',
                                  fontSize:10, fontWeight:sel?700:500 }}>
                                {u.name.split(' ').pop()}
                              </button>
                            )
                          })}
                        </div>
                      </div>
                    )
                  })}
                </div>
              </Card>
            ))}
          </div>

          <label style={{ display:'flex', alignItems:'center', gap:8, padding:10,
            background:T.amberBg, borderRadius:6, border:`1px solid ${T.amber}`, cursor:'pointer' }}>
            <input type="checkbox" checked={overwrite}
              onChange={e => setOverwrite(e.target.checked)}
              style={{ width:16, height:16, cursor:'pointer' }}/>
            <span style={{ fontSize:11, color:T.amber, fontWeight:600 }}>
              Ghi đè lịch đã có (nếu không tick, chỉ điền vào ô trống)
            </span>
          </label>
        </div>
        <div style={{ display:'flex', gap:10, padding:16, borderTop:`1px solid ${T.border}` }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
            Hủy
          </button>
          <button onClick={apply}
            style={{ flex:2, padding:'9px', borderRadius:6, border:'none',
              background:T.gold, color:'#fff', cursor:'pointer',
              fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
            🔄 Áp dụng cho cả tháng
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Copy prev month modal ──
